-- Poems batch 398
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-772','水龙吟','卢祖皋','宋','宋词','song-ci','水龙吟','[]','会昌湖上扁舟，几年不醉西山路。',126,'宋词/ci.song.13000.json','["会昌湖上扁舟，几年不醉西山路。", "流光又是，宫衣初试，安榴半吐。", "千里江山，满川烟草，薰风淮楚。", "念离骚恨远，独醒人去，阑干外，谁怀古。", "亦有鱼龙戏舞。", "艳晴川、绮罗歌鼓。", "乡情节意，尊前同是，天涯羁旅。", "涨渌池塘，翠阴庭院，归期无据。", "问明年此夜，一眉新月，照人何处。"]'),
('song-ci-773','水龙吟','卢祖皋','宋','宋词','song-ci','水龙吟','[]','世间谁似蓬仙，坐间八帙齐眉寿。',126,'宋词/ci.song.13000.json','["世间谁似蓬仙，坐间八帙齐眉寿。", "兰阶更喜，孙枝相映，红芳绿秀。", "鹤舞修庭，鹭飞青嶂，帘垂晴昼。", "向闲中时有，奚囊背锦，开松户，看云岫。", "不羡印金垂斗。", "笑纷纷、白云苍狗。", "银髯似戟，红颜如炼，风流依旧。", "野□晴初，陇梅花下，玉笙吹酒。", "怅今年又是，题笺寄远，倩传杯手。"]'),
('song-ci-774','渡江云','卢祖皋','宋','宋词','song-ci','渡江云','["\u897f\u6e56"]','锦云香满镜，岸巾横笛，浮醉一舟轻。',124,'宋词/ci.song.13000.json','["锦云香满镜，岸巾横笛，浮醉一舟轻。", "别愁萦短鬓，晚凉池阁，此地忽逢迎。", "柄圆敧绿，倚风流、还恁娉婷。", "凭画阑，嫣然输笑，无语寄心情。", "盈盈。", "露华匀玉，日影酣红，记晚妆慵整。", "还暗惊、人间离合，羞对池萍。", "三年一觉西湖梦，又等闲、金井秋声。", "销魂久，夜深月冷风清。"]'),
('song-ci-775','洞仙歌','卢祖皋','宋','宋词','song-ci','洞仙歌','[]','玉肌翠袖，较似酴醿瘦。',102,'宋词/ci.song.13000.json','["玉肌翠袖，较似酴醿瘦。", "几度熏醒夜窗酒。", "问炎洲何事，得许清凉，尘不到，一段冰壶翦就。", "晚来庭户悄，暗数流光，细拾芳英黯回首。", "念日暮江东，偏为魂销，人易老、幽韵清标似旧。", "正簟纹如水帐如烟，更奈向，月明露浓时候。"]'),
('song-ci-776','洞仙歌','卢祖皋','宋','宋词','song-ci','洞仙歌','["\u897f\u6e56"]','月痕霜晕，雪染冰裁翦。',102,'宋词/ci.song.13000.json','["月痕霜晕，雪染冰裁翦。", "车马尘中甚曾见。", "自扬州吟罢，踏遍西湖，堪爱处，偏是情高韵远。", "冷香惊梦破，姑射人归，图画空遗旧妆面。", "问何事东君，先与春心，还又是、容易飞花片片。", "对暮寒修竹哽无言，更画角层城，夜闻吹怨。"]'),
('song-ci-777','洞仙歌','卢祖皋','宋','宋词','song-ci','洞仙歌','[]','东楼佳丽，缥缈风烟表。',102,'宋词/ci.song.13000.json','["东楼佳丽，缥缈风烟表。", "幻得楼山更深窈。", "有苍崖乔木，石磴鸣泉，尘不到，掩映十洲三岛。", "平生丘壑趣，圭衮何心，自是清时重元老。", "想月下云根，鹤唳猿吟，人犹道、作计归游太早。", "待他年功退学商颜，却旋种木奴，缓寻瑶草。"]'),
('song-ci-778','洞仙歌','卢祖皋','宋','宋词','song-ci','洞仙歌','[]','梅窗雪屋，还赋蓬仙寿。',102,'宋词/ci.song.13000.json','["梅窗雪屋，还赋蓬仙寿。", "闻说今年胜於旧。", "有芝书催下，竹史颁春，山好处，留待文章太守。", "商霖消息近，缥缈闲云，一笑无心又出岫。", "纵高卧十年，八帙初开，天未许、闲向人间袖手。", "问西州千骑几时来，对月鹤霜猿，也教知否。"]'),
('song-ci-779','洞仙歌','卢祖皋','宋','宋词','song-ci','洞仙歌','[]','扁舟入浙，便有家山意。',102,'宋词/ci.song.13000.json','["扁舟入浙，便有家山意。", "全胜轺车驾边地。", "爱官尘不到，书眼争明，称寿处，春傍梅花影里。", "平生丘壑志，未老求闲，天亦徘徊就归计。", "想叠嶂双溪，千骑弓刀，浑不似、白石山中胜趣。", "怕竹屋梅窗欲成时，又飞诏东山，谢公催起。"]'),
('song-ci-780','望江南・忆江南','卢祖皋','宋','宋词','song-ci','望江南・忆江南','[]','疏雨过，芳节到戎葵。',64,'宋词/ci.song.13000.json','["疏雨过，芳节到戎葵。", "缠臂细交纹线缕，称身初试碧绡衣。", "闲步小亭池。", "花下意，脉脉有谁知。", "试把花梢和恨数，因看胡蝶著双飞。", "凝扇立多时。"]'),
('song-ci-781','临江仙','卢祖皋','宋','宋词','song-ci','临江仙','[]','南馆西池迎笑处，轻行不耐冰绡。',70,'宋词/ci.song.13000.json','["南馆西池迎笑处，轻行不耐冰绡。", "粉香飞过碧阑桥。", "芙蕖争态度，杨柳学飘摇。", "醉里鸾飙乘月去，碧云依旧迢迢。", "深情谁为寄娇娆。", "簟纹风外展，香篆过边销。"]'),
('song-ci-782','临江仙','卢祖皋','宋','宋词','song-ci','临江仙','[]','洞府堂深花气满，娉婷绿展红围。',70,'宋词/ci.song.13000.json','["洞府堂深花气满，娉婷绿展红围。", "个中年少出琼姬。", "双笼金约腕，独把玉参差。", "子晋台前无鹤驭，人间空有清诗。", "何如娇小贮帘帷。", "仙风知有待，凉月渐当时。"]'),
('song-ci-783','临江仙','卢祖皋','宋','宋词','song-ci','临江仙','[]','跨鹤云间犹未久，风流全胜年时。',70,'宋词/ci.song.13000.json','["跨鹤云间犹未久，风流全胜年时。", "唤回和气上梅枝。", "酒边春市动，琴外画帘垂。", "长是细吟攻愧寿，还歌连桂新词。", "早催凫舄向南飞。", "一官传鼎鼐，四海看埙篪。"]'),
('song-ci-784','丑奴儿慢・采桑子慢','卢祖皋','宋','宋词','song-ci','丑奴儿慢・采桑子慢','[]','湘筠展梦，还是带恨敧枕。',111,'宋词/ci.song.13000.json','["湘筠展梦，还是带恨敧枕。", "对千顷、风荷凉艳，水竹清阴。", "半掩龟纱，几回小语月华侵。", "娉婷何处，回首画桥，朱户沈沈。", "闻道近时，题红传素，长是沾襟。", "想当日、冰弦弹断，总废清音。", "准拟归来，扇鸾钗凤巧相寻。", "如今无奈，七十二峰，划地云深。"]'),
('song-ci-785','木兰花慢','卢祖皋','宋','宋词','song-ci','木兰花慢','[]','汀莲凋晚艳，又苹末、起秋风。',121,'宋词/ci.song.13000.json','["汀莲凋晚艳，又苹末、起秋风。", "漫搔首徐吟，微云河汉，疏雨梧桐。", "飘零倦寻酒盏，记那回、歌管小楼中。", "玉果蛛丝暗卜，细钗蝉鬓轻笼。", "吴云别后重重。", "凉宴几时同。", "纵人间信有，犀灵鹊喜，密意难通。", "双星分携最苦，念经年、犹有一相逢。", "寂寞桥边旧月，可堪频照西东。"]'),
('song-ci-786','木兰花慢','卢祖皋','宋','宋词','song-ci','木兰花慢','[]','洒窗声未定，怪襟袖、峭寒欺。',122,'宋词/ci.song.13000.json','["洒窗声未定，怪襟袖、峭寒欺。", "渐邑界空明，山河表里，玉幻琼移。", "天边占春最早，万花中、不遣一尘飞。", "清想吟鞭瘦倚，醉怜歌锦红围。", "谁知。", "未去心期。", "慵酒更慵诗。", "算可人惟有，光浮茗碗，香浸梅枝。", "长安又惊岁换，笑吹来、空点发成丝。", "一舸沧江浩渺，几回归梦参差。"]'),
('song-ci-787','木兰花慢','卢祖皋','宋','宋词','song-ci','木兰花慢','[]','嫩寒催客棹，载酒去、载诗归。',124,'宋词/ci.song.13000.json','["嫩寒催客棹，载酒去、载诗归。", "正红叶漫山，清泉漱石，多少心期。", "三生溪桥话别，怅薜萝、犹惹翠云衣。", "不似今番醉梦，帝城几度斜晖。", "鸿飞。", "烟水弥弥。", "回首处，只君知。", "念吴江鹭忆，孤山鹤怨，依旧东西。", "高峰梦醒云起，是瘦吟、窗底忆君时。", "何日还寻后约，为余先寄梅枝。"]'),
('song-ci-788','木兰花慢','卢祖皋','宋','宋词','song-ci','木兰花慢','["\u897f\u6e56"]','翠阴春昼永，乍帘幕、暖飘香。',123,'宋词/ci.song.13000.json','["翠阴春昼永，乍帘幕、暖飘香。", "正玉节来归，斑衣戏舞，□□荧煌。", "椿期始开九秩，看芝兰、奕叶早传芳。", "都把一门瑞气，酿成九酝霞觞。", "相将。", "诏墨趣星郎。", "乐事未渠央。", "渐锦封鸾诰，鱼轩象服，争贲萱堂。", "西池献桃未熟，醉西湖、日日想偏长。", "紫燕黄鹂院落，牡丹红药时光。"]'),
('song-ci-789','木兰花慢','卢祖皋','宋','宋词','song-ci','木兰花慢','[]','向蒲江佳处，报新葺、小亭轩。',122,'宋词/ci.song.13000.json','["向蒲江佳处，报新葺、小亭轩。", "有碧嶂青池，幽花瘦竹，白鹭苍烟。", "年华再周甲子，对黄庭、心事只け然。", "都占壶天岁月，便成行地神仙。", "十年。", "微禄萦牵。", "梦绕浙东船。", "更吾庐才喜，籓篱尽剖，门巷初全。", "何时归来拜寿，尽团栾、笑语玉尊前。", "吟寄疏梅驿外，思随飞雁行边。"]'),
('song-ci-790','浣溪沙','卢祖皋','宋','宋词','song-ci','浣溪沙','[]','午睡醒来策瘦筇。',48,'宋词/ci.song.13000.json','["午睡醒来策瘦筇。", "几痕茸绿径苔封。", "石榴初□舞裙红。", "中酒情怀滋味薄，肥梅天气带衣慵。", "日长门巷雨馀风。"]'),
('song-ci-791','卜算子','卢祖皋','宋','宋词','song-ci','卜算子','[]','续续露蛩鸣，索索风梧语。',52,'宋词/ci.song.13000.json','["续续露蛩鸣，索索风梧语。", "瘦骨从来不奈秋，一夜秋如许。", "簟冷卷风漪，髻滑抛云缕。", "展转无人共此情，画角吹残雨。"]'),
('song-ci-792','卜算子','卢祖皋','宋','宋词','song-ci','卜算子','[]','双鬓晚风前，一笛秋云外。',52,'宋词/ci.song.13000.json','["双鬓晚风前，一笛秋云外。", "木叶飞时看好山，山亦於人耐。", "意到偶题诗，饮少先成醉。", "笑折花枝步短檐，此意无人会。"]'),
('song-ci-793','卜算子','卢祖皋','宋','宋词','song-ci','卜算子','[]','佩解洛波遥，弦冷湘江渺。',52,'宋词/ci.song.13000.json','["佩解洛波遥，弦冷湘江渺。", "月底盈盈误不归，独立风尘表。", "窗绮护幽妍，瓶玉扶轻袅。", "别后知谁语素心，寂寞山寒峭。"]'),
('song-ci-794','卜算子','卢祖皋','宋','宋词','song-ci','卜算子','[]','寒谷耿春姿，遥夜乘幽兴。',52,'宋词/ci.song.13000.json','["寒谷耿春姿，遥夜乘幽兴。", "忆得和香载月归，醉里清魂醒。", "霜月解随人，不解将疏影。", "想见江南万斛愁，云卧衣裳冷。"]'),
('song-ci-795','满庭芳','卢祖皋','宋','宋词','song-ci','满庭芳','[]','盘谷居成，辋川图就，便从鸥鹭寻盟。',118,'宋词/ci.song.13000.json','["盘谷居成，辋川图就，便从鸥鹭寻盟。", "泛溪窈窕，游钓寄高情。", "尚忆儿童旧地，疏帘外、烟雨新晴。", "微吟罢，渔歌响答，欸乃醉中听。", "蓬瀛。", "归计早，下帆坐阅，涛浪堪惊。", "爱闲身长占，风澹波平。", "夜雪何时访戴，梅花下、同款柴扃。", "还知否，清时未许，野渡有舟横。"]'),
('song-ci-796','夜行船','卢祖皋','宋','宋词','song-ci','夜行船','[]','暖入新梢风又起。',68,'宋词/ci.song.13000.json','["暖入新梢风又起。", "秋千外、雾萦丝细。", "鸠侣寒轻，燕泥香重，人在杏花窗里。", "十二银屏山四倚。", "春醪困、共篝沈水。", "却说当时，柳啼花怨，魂梦为君迢递。"]'),
('song-ci-797','瑞鹤仙','卢祖皋','宋','宋词','song-ci','瑞鹤仙','[]','江南秋欲遍。',126,'宋词/ci.song.13000.json','["江南秋欲遍。", "正莼际鲈分，酒边螯荐。", "青林雁霜浅。", "问风流何事，试华偏晚。", "凌波步远。", "误池馆、薰风笑宴。", "梦回时，细翦荷衣，尚倚半酣妆面。", "深院。", "绮霞低映，步障横陈，暮天慵倦。", "无言笑倩。", "尊前恨，仗谁遣。", "似重来鹤驭，锦城依旧，无复仙风宛转。", "念疏星澹月，长眉甚时再见。"]'),
('song-ci-798','菩萨蛮','卢祖皋','宋','宋词','song-ci','菩萨蛮','[]','芙蓉香卸桐阴薄。',52,'宋词/ci.song.13000.json','["芙蓉香卸桐阴薄。", "水窗未雨凉先觉。", "何处理秋裳。", "月高砧杵长。", "袂罗新恨悄。", "展转屏山晓。", "长是卷帘时。", "翠禽相对飞。"]'),
('song-ci-799','菩萨蛮','卢祖皋','宋','宋词','song-ci','菩萨蛮','[]','烛房花幌参差见。',52,'宋词/ci.song.13000.json','["烛房花幌参差见。", "疏帘镇日萦愁眼。", "巫峡小山屏。", "梦云犹未成。", "带霜边雁落。", "双字宫罗薄。", "二十四阑干。", "夜来相对寒。"]'),
('song-ci-800','菩萨蛮','卢祖皋','宋','宋词','song-ci','菩萨蛮','[]','翠楼十二阑干曲。',52,'宋词/ci.song.13000.json','["翠楼十二阑干曲。", "雨痕新染蒲桃绿。", "时节又黄昏。", "东风深闭门。", "玉箫吹未彻。", "窗影梅花月。", "无语只低眉。", "闲拈双荔枝。"]'),
('song-ci-801','鹊桥仙','卢祖皋','宋','宋词','song-ci','鹊桥仙','[]','寒丛弄日，宝钿承露，篱落亭亭相倚。',68,'宋词/ci.song.13000.json','["寒丛弄日，宝钿承露，篱落亭亭相倚。", "当年彭泽未归来，料独抱、幽香一世。", "疏风冷雨，澹烟残照，日日重阳天气。", "帽檐已是半敧斜，问瓮里、新篘熟未。"]'),
('song-ci-802','鹊桥仙','卢祖皋','宋','宋词','song-ci','鹊桥仙','[]','槐阴閟暑，荷风清梦，满院双成俦侣。',68,'宋词/ci.song.13000.json','["槐阴閟暑，荷风清梦，满院双成俦侣。", "阶庭一笑玉兰新，把酒更、重逢初度。", "丹书漫启，青云垂上，莫忘八篇奇语。", "功成休驾玉霄云，且长占、赤城佳处。"]'),
('song-ci-803','鹊桥仙','卢祖皋','宋','宋词','song-ci','鹊桥仙','[]','澄江晓碧，君山秋静，人与江山俱秀。',68,'宋词/ci.song.13000.json','["澄江晓碧，君山秋静，人与江山俱秀。", "最声吹下紫泥封，看宣献、风流依旧。", "□袍对引，鱼轩徐驾，小队旌旗陪后。", "万家指点寿星明，更把菊、登高时候。"]'),
('song-ci-804','摸鱼儿','卢祖皋','宋','宋词','song-ci','摸鱼儿','[]','怪西风、晓来敧帽，年华还是重九。',140,'宋词/ci.song.13000.json','["怪西风、晓来敧帽，年华还是重九。", "天机衮衮山新瘦，客子情怀谁剖。", "微雨后。", "更雁带边寒，袅袅欺罗袖。", "慵荷倦柳。", "悄不似黄花，田田照眼，风味尽如旧。", "登临地，寂寞崇台最久。", "阑干几度搔首。", "翻云覆雨无穷事，流水斜阳知否。", "吟未就。", "但衰草荒烟，商略愁时候。", "闲愁浪有。", "总输与渊明，东篱醉舞，身世付杯酒。"]'),
('song-ci-805','夜飞鹊慢','卢祖皋','宋','宋词','song-ci','夜飞鹊慢','[]','骄嘶破清晓，分恨临期。',129,'宋词/ci.song.13000.json','["骄嘶破清晓，分恨临期。", "花下恁月明知。", "馀光是处散离思，最怜香霭霏霏。", "牵衣搵弹泪，问凄风愁露，划地东西。", "留鞭换佩，怕匆匆、已是迟迟。", "凉怯几番罗袂，还燕别文梁，萤点书帏。", "一自秋娘迢递，黄金对酒，争忍轻挥。", "新来院落，雁难寻、帘幕长垂。", "怕凋梧敲径，惊回旧梦，应也颦眉。"]'),
('song-ci-806','秋霁','卢祖皋','宋','宋词','song-ci','秋霁','[]','虹雨才收，正抱叶残蝉，渐老云木。',127,'宋词/ci.song.13000.json','["虹雨才收，正抱叶残蝉，渐老云木。", "银汉飞星，玉壶零露，万里素秋如沐。", "倚颦抱独。", "盼娇曾记郎心目。", "向艳歌偏爱，赋情多处寄衷曲。", "凄凉漫有，旧月阑干，夜凉无因，重照颓玉。", "扇纨收、鸾孤蠹损，一番愁绪黯相触。", "回首寒云空雁足。", "露井零乱，已是负了桐阴，可堪轻误，满篱种菊。"]'),
('song-ci-807','虞美人','卢祖皋','宋','宋词','song-ci','虞美人','[]','清尊黄菊红萸佩。',66,'宋词/ci.song.13000.json','["清尊黄菊红萸佩。", "两度云岩醉。", "帽檐今日更清狂。", "冷雨疏风、著意过重阳。", "故宫历历遗烟树。", "往事知何处。", "漫山秋色好题诗。", "吟罢阑干、独自立多时。"]'),
('song-ci-808','渔家傲','卢祖皋','宋','宋词','song-ci','渔家傲','[]','小阁腾腾人似醉。',72,'宋词/ci.song.13000.json','["小阁腾腾人似醉。", "鸣阶簌簌霜林坠。", "起向楼头看雪意。", "云犹未。", "雁声一片江风起。", "官里从容何日是。", "偷闲著便寻幽事。", "见说小桥清浅水。", "梅欲蕊。", "吟边陡觉添风味。"]'),
('song-ci-809','渔家傲','卢祖皋','宋','宋词','song-ci','渔家傲','[]','檐玉敲寒声不定。',72,'宋词/ci.song.13000.json','["檐玉敲寒声不定。", "水仙瓶里梅相映。", "半缕篝香云欲暝。", "窗几静。", "月华时送琅玕影。", "不用五湖寻小艇。", "吾庐剩有闲风景。", "薄醉起来行藓径。", "多幽兴。", "悠然一霎风吹醒。"]'),
('song-ci-810','渔家傲','卢祖皋','宋','宋词','song-ci','渔家傲','[]','白石山中风景异。',72,'宋词/ci.song.13000.json','["白石山中风景异。", "先生日日怀归计。", "何事黄冈飞雪地。", "偏著意。", "画堂却为东坡起。", "人说前身坡老是。", "文章气节浑相似。", "只待鼎彝勋业遂。", "梅花外。", "归来长向山中醉。"]'),
('song-ci-811','醉梅花・鹧鸪天','卢祖皋','宋','宋词','song-ci','醉梅花・鹧鸪天','[]','传得西林一派清。',64,'宋词/ci.song.13000.json','["传得西林一派清。", "年华垂过欠官称。", "居无多地花常好，客有来时鹤自鸣。", "分蕊馆，驻箳星。", "齐眉相对眼尤明。", "弄孙教子婆娑醉，岁岁疏梅入寿觥。"]'),
('song-ci-812','贺新郎','卢祖皋','宋','宋词','song-ci','贺新郎','[]','挽住风前柳。',142,'宋词/ci.song.13000.json','["挽住风前柳。", "问鸱夷、当日扁舟，近曾来否。", "月落潮生无限事，零乱茶烟未久。", "漫留得、莼鲈依旧。", "可是从来功名误，抚荒祠、谁继风流后。", "今古恨，一搔首。", "江涵雁影梅花瘦。", "四无尘、雪飞风起，夜窗如昼。", "万里乾坤清绝处，付与渔翁钓叟。", "又恰是、题诗时候。", "猛拍阑干呼鸥鹭，道他年、我亦垂纶手。", "飞过我，共尊酒。"]'),
('song-ci-813','沁园春','卢祖皋','宋','宋词','song-ci','沁园春','[]','几叶凋枫，半篙寒日，傍桥系船。',139,'宋词/ci.song.13000.json','["几叶凋枫，半篙寒日，傍桥系船。", "爱洞门深锁，人间福地，双溪分占，天上星躔。", "破帽敧寒，短鞭敲月，此地经行知几年。", "空赢得，似沈郎消瘦，还欠诗篇。", "沙鸥伴我愁眠。", "向水驿风亭红蓼边。", "有村醪可饮，且须同醉，溪鱼堪鲙，切莫论钱。", "笠泽波头，垂虹桥上，橙蟹肥时霜满天。", "相随否，算江南江北，惟有君闲。"]'),
('song-ci-814','沁园春','卢祖皋','宋','宋词','song-ci','沁园春','[]','台色齐辉，一点长庚，夜来更明。',139,'宋词/ci.song.13000.json','["台色齐辉，一点长庚，夜来更明。", "渐日添宫线，功催补衮，春回梅萼，香趁调羹。", "鹤禁班高，槐庭恩重，八帙骎骎人共荣。", "谁知道，纵身居公辅，心似书生。", "东楼见说初成。", "有帘卷江山万里横。", "想高情长羡，碧云出处，清时未计，绿野经营。", "东阁郎君，南宫进士，管领孙枝扶寿觥。", "齐眉醉，笑尊前乐事，真个全并。"]'),
('song-ci-815','贺新郎','卢祖皋','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','十顷涵空碧。',142,'宋词/ci.song.13000.json','["十顷涵空碧。", "画图中、峥嵘幻玉，乱零吹璧。", "倚遍危阑吟不尽，把酒风前岸帻。", "记当日、西湖为客。", "谁翦吴淞江上水，笑乾坤、奇事成儿剧。", "还照我，夜窗白。", "崇台目断清无极。", "引枝筇、琼瑶步软，印登临屐。", "娃馆娉婷知何在，泪粉愁浓恨积。", "故化作、飞花狼籍。", "旧事悠悠浑莫问，有玉蟾、醉里曾相识。", "聊伴我，夜吹笛。"]'),
('song-ci-816','贺新郎','卢祖皋','宋','宋词','song-ci','贺新郎','["\u5e90\u5c71", "\u897f\u6e56"]','万里岷峨路。',142,'宋词/ci.song.13000.json','["万里岷峨路。", "笑归来、野逸萧闲，旧时风度。", "玉陛金闺春引处，迟却京华步武。", "漫赢得、西湖佳趣。", "香篆琴丝帘影外，有朝云、夜月和鸥鹭。", "都辨我，醉中句。", "飞凫又报匡庐去。", "怕赤霄、班里依然，有人留取。", "头黑功名浑好在，漫浪从渠赋予。", "但爱我、襟期相遇。", "满把一觞为君寿，有风荷、万顷摇清暑。", "聊为此，釂金缕。"]'),
('song-ci-817','太常引','卢祖皋','宋','宋词','song-ci','太常引','[]','梦回金井卸梧桐。',60,'宋词/ci.song.13000.json','["梦回金井卸梧桐。", "嘶马带疏钟。", "草面露痕浓。", "渐薄袖、清寒暗通。", "天低绛阙，云浮碧海，残月尚朦胧。", "吹面桂花风。", "峭不似、红尘道中。"]'),
('song-ci-818','小阑干・少年游','卢祖皋','宋','宋词','song-ci','小阑干・少年游','[]','露华深酿古香浓。',58,'宋词/ci.song.13000.json','["露华深酿古香浓。", "一树□云丛。", "窗间试与，闲培秋事，聊寄幽悰。", "钩帘静对西风晚，尘外小房栊。", "轻阴澹日，浅寒清月，想见山中。"]'),
('song-ci-819','倚阑令・春光好','卢祖皋','宋','宋词','song-ci','倚阑令・春光好','[]','惜春心。',52,'宋词/ci.song.13000.json','["惜春心。", "步花阴。", "怕春深。", "风扬游丝吹落絮，满园林。", "日长帘幕沈沈。", "朱阑畔、斜亸琼簪。", "笑摘梨花闲照水，贴眉心。"]'),
('song-ci-820','满江红','卢祖皋','宋','宋词','song-ci','满江红','[]','楼倚晴空，炎云净、晚来风力。',115,'宋词/ci.song.13000.json','["楼倚晴空，炎云净、晚来风力。", "沧海外、等闲吹上，满轮寒璧。", "河汉低垂天欲近，乾坤浩荡秋无极。", "凭阑干、衣袂拂青冥，知何夕。", "登眺地，追畴昔。", "吴越事，皆陈迹。", "对清光祗有，醉吟消得。", "万古悠悠惟月在，浮生衮衮空头白。", "自骑鲸、仙去有谁知，遥相忆。"]'),
('song-ci-821','满江红','卢祖皋','宋','宋词','song-ci','满江红','[]','拟问扁舟，归来趁、蓬莱寿席。',115,'宋词/ci.song.13000.json','["拟问扁舟，归来趁、蓬莱寿席。", "还又向、月城迢递，岁寒为客。", "多竹襟期居已就，一川图画□堪觅。", "想玉笙、霜鹤拥蹁跹，真仙伯。", "身早退，头翻黑。", "心最懒，闲偏适。", "更新来膝下，始看袍色。", "安石正多人望在，子公何用缄书立。", "但年年、把酒为梅花，寻消息。"]'),
('song-ci-822','烛影摇红','卢祖皋','宋','宋词','song-ci','烛影摇红','[]','千载风云，庆符良月先呈瑞。',116,'宋词/ci.song.13000.json','["千载风云，庆符良月先呈瑞。", "旧家阴郭帝恩浓，圭衮公侯地。", "不道蝉联鼎贵。", "对秋灯、依然风味。", "紫囊归去，绿野闲来，青毡都未。", "琴鹤相随，小山花竹便幽意。", "满襟和气是藏春，日觉诗名起。", "已动金瓯姓字。", "早梅□，□□□□。", "□□□□，□□□□，□□□□。"]'),
('song-ci-823','月城春・四犯翦梅花','卢祖皋','宋','宋词','song-ci','月城春・四犯翦梅花','[]','五云腾晓。',114,'宋词/ci.song.13000.json','["五云腾晓。", "望凝香画戟，恍然蓬岛。", "玉露冰壶，照神仙风表。", "诗书坐啸。", "唤淮楚、满城春好。", "雨谷催耕，风帘戏鼓，家家欢笑。", "南湖细吟未了。", "看金莲夜直，丹凤飞诏。", "鬓影青青，办功名多少。", "持杯满釂。", "听千里、载歌难老。", "试问尊前，蟠桃次第，红芳犹小。"]'),
('song-ci-824','临江仙','卢祖皋','宋','宋词','song-ci','临江仙','[]','六鹤飞来松帐晓，菊迟梅早年光。',70,'宋词/ci.song.13000.json','["六鹤飞来松帐晓，菊迟梅早年光。", "西池移宴到萱堂。", "笙箫清弄玉，环佩暖回香。", "未问诰花金五色，新来乐事难量。", "双添雏凤趁称觞。", "争书八十字，分抱彩衣旁。"]'),
('song-ci-825','贺新郎','卢祖皋','宋','宋词','song-ci','贺新郎','[]','春色元无主。',144,'宋词/ci.song.13000.json','["春色元无主。", "荷东君、著意看承，等闲分付。", "多少无情风与浪，又那更、蝶欺蜂妒。", "算燕雀、眼前无数。", "从便帘栊能爱护，到如今、已是成迟暮。", "芳草碧，遮归路。", "看看做到难言处。", "怕宣郎、轻转旌旗，易歌襦裤。", "月满西楼弦索静，云蔽崑城阆府。", "便恁地、一帆轻举。", "独倚阑干愁拍碎，惨玉容、泪眼如红雨。", "去与住，两难诉。"]'),
('song-ci-826','喜迁莺','孙居敬','宋','宋词','song-ci','喜迁莺','[]','宿酲初愈。',126,'宋词/ci.song.13000.json','["宿酲初愈。", "更花焰频催，叶蕉重举。", "浓露沾丛，薰风入樾，黄叶马头飞舞。", "梦结尚依征旆，笛怨谁教渔谱。", "村路转，见寒机灯在，晨炊人语。", "无据。", "堪恨处。", "残月满襟，不念人羁旅。", "天接山光，云拖雁影，多少别离情绪。", "绣被香温密叠，罗帕粉痕重护。", "这滋味，最不堪两鬓，菱花羞觑。"]'),
('song-ci-827','临江仙','孙居敬','宋','宋词','song-ci','临江仙','["\u897f\u6e56"]','触事老来情绪懒，西湖债未曾还。',70,'宋词/ci.song.13000.json','["触事老来情绪懒，西湖债未曾还。", "试呼小艇访孤山。", "昔年鸥鹤侣，总笑鬓斓斑。", "仙去坡翁山耐久，烟霏空翠凭阑。", "日斜尚觉酒肠宽。", "水云天共色，欸乃一声间。"]'),
('song-ci-828','临江仙','孙居敬','宋','宋词','song-ci','临江仙','[]','摘索枝头何处玉，吹来万里春风。',70,'宋词/ci.song.13000.json','["摘索枝头何处玉，吹来万里春风。", "须臾陆地遍芙蓉。", "珠帘和气扑，一笑夺炉红。", "文字红裙相间出，主人钟鼎仙翁。", "清谈隽语与香浓。", "太平欢意远，人在玉壶中。"]'),
('song-ci-829','贺新郎','孙居敬','宋','宋词','song-ci','贺新郎','[]','风月为佳节。',142,'宋词/ci.song.13000.json','["风月为佳节。", "更湖光、平铺十里，水晶宫阙。", "若向孤山邀俗驾，只恐梅花凄咽。", "有图画、天然如揭。", "好看骚人冰雪句，走龙蛇、醉墨成三绝。", "尘世事，谩如发。", "真须脚踏层冰滑。", "倚高寒、身疑羽化，水平天阔。", "目送云边双白鹭，杳杳冲烟出没。", "□□□、□□□□。", "唤醒儿曹梁甑梦，把逍遥、齐物从头说。", "洗夜光，弄明月。"]'),
('song-ci-830','风入松','孙居敬','宋','宋词','song-ci','风入松','[]','王孙去后几时归。',88,'宋词/ci.song.13000.json','["王孙去后几时归。", "音信全稀。", "绿痕染遍天涯草，更小红、已破桃枝。", "此恨无人共说，梦回月满楼时。", "只应明月照心期。", "一向舒眉。", "若还早遂蓝桥约，更不举、玉盏东西。", "怎望黄金屋贮，只图夸道于飞。"]'),
('song-ci-831','风入松','孙居敬','宋','宋词','song-ci','风入松','[]','画梁燕子报新归。',88,'宋词/ci.song.13000.json','["画梁燕子报新归。", "好语全稀。", "庭芳侵亚红相对，却羞见、蕊蕊枝枝。", "说与吹箫旧侣，痴心指望多时。", "朝云暮雨失欢期。", "碧画谁眉。", "凝愁立处桐阴转，又还是、红日将西。", "谩道梅花纸帐，鸳鸯终待双飞。"]'),
('song-ci-832','好事近','孙居敬','宋','宋词','song-ci','好事近','[]','买断一川云，团结樵歌渔笛。',53,'宋词/ci.song.13000.json','["买断一川云，团结樵歌渔笛。", "莫向此中轻说，污天然寒碧。", "短蓬穿菊更移枨，香满不须摘。", "搔首断霞夕影，散银原千尺。"]'),
('song-ci-833','西江月','孙居敬','宋','宋词','song-ci','西江月','[]','翠幄轻寒护夜，寒妆靓暖宜春。',58,'宋词/ci.song.13000.json','["翠幄轻寒护夜，寒妆靓暖宜春。", "酒筹诗令逐时新。", "仙佩朋簪清兴。", "凤炬呈妍粟粟，水仙照座盈盈。", "约君策马贺升平。", "回首尊前风韵。"]'),
('song-ci-834','八声甘州','郑梦协','宋','宋词','song-ci','八声甘州','[]','大江流日夜，客心愁、不禁晚来风。',119,'宋词/ci.song.13000.json','["大江流日夜，客心愁、不禁晚来风。", "把英雄□气，兴衰馀事，吹散无踪。", "但有山围故国，依旧夕阳中。", "直北神州路，几点飞鸿。", "欲问周郎赤壁，叹沙沈断戟，烟锁艨艟。", "听波声如语，空乱荻花丛。", "甚云间、平安信少，到黄昏、偏映落霞红。", "莼鲈美，扁舟归去，相伴渔翁。"]'),
('song-ci-835','蝶恋花','真德秀','宋','宋词','song-ci','蝶恋花','[]','两岸月桥花半吐。',70,'宋词/ci.song.13000.json','["两岸月桥花半吐。", "红透肌香，暗把游人误。", "尽道武陵溪上路。", "不知迷入江南去。", "先自冰霜真态度。", "何事枝头，点点胭脂污。", "莫是东君嫌淡素。", "问花花又娇无语。"]'),
('song-ci-836','满江红','留元刚','宋','宋词','song-ci','满江红','[]','风送清篙，沿流溯、武夷九曲。',115,'宋词/ci.song.13000.json','["风送清篙，沿流溯、武夷九曲。", "回首处，虹桥无复，幔亭遗屋。", "翠壁云屏临钓石，银河雪瀑飞寒玉。", "想当年、铁笛倚林吹，秋空绿。", "褰荇带，搘筇竹。", "披荷芰，餐椒菊。", "问丹崖碧岭，底堪重辱。", "青笈不妨娱老眼，乌靴未许污吾足。", "恰仙游、一枕梦醒来，胡麻熟。"]'),
('song-ci-837','朝中措','熊节','宋','宋词','song-ci','朝中措','[]','麒麟早贵挂朝冠。',57,'宋词/ci.song.13000.json','["麒麟早贵挂朝冠。", "自合侍金銮。", "收拾经纶事业，从容游戏人间。", "祗今侍彩，符分楚甸，名在蓬山。", "直待疏封大国，秋光长映朱颜。"]'),
('song-ci-838','沁园春','范炎','宋','宋词','song-ci','沁园春','[]','襟韵何如，文雅风流，王谢辈人。',139,'宋词/ci.song.13000.json','["襟韵何如，文雅风流，王谢辈人。", "问传家何物，多书插架，放怀无可，有酒盈樽。", "一咏一谈，悠然高致，似醉当年曲水春。", "还知否，壮胸中万卷，笔下千军。", "门前我有佳宾。", "但明月、清风更此君。", "喜西庐息驾，心间胜日，东皇倚杖，目送行云。", "闻道君王，玉堂佳处，欲诏长杨奏赋孙。", "功名看，一枝丹桂，两树灵椿。"]'),
('song-ci-839','水调歌・水调','汪相如','宋','宋词','song-ci','水调歌・水调','[]','指点縠江水，遥认作琼醅。',114,'宋词/ci.song.13000.json','["指点縠江水，遥认作琼醅。", "介公眉寿，年年倾入紫霞杯。", "寿与江流无尽，人在壶天不老，谈笑领春回。", "昨夜瞻南极，列宿拱中台。", "补天工，取日手，济时材。", "不应勇退，归来绿野宴瑶台。", "天要先生调燮，人要先生休养，虚左待重来。", "再捧长生箓，依旧面三槐。"]'),
('song-ci-840','贺新郎','张敬斋','宋','宋词','song-ci','贺新郎','[]','卓茕欧阳子，是江山、毓秀锺灵，异才间世。',142,'宋词/ci.song.13000.json','["卓茕欧阳子，是江山、毓秀锺灵，异才间世。", "恰则韶光三月暮，蓂叶尧阶有四。", "正天启、悬弧盛事。", "金鸭亭亭书云篆，散非烟、南极真仙至。", "来为尔，荐嘉瑞。", "神清洞府丹书字。", "拥笙歌、绮席高张，更罗珠翠。", "个里长春人不老，仙籍玉环暗记。", "但判取、醄醄沈醉。", "拟作新诗八千首，待一年、一献称俾尔。", "耆而艾，昌而炽。"]'),
('song-ci-841','瑞鹧鸪','徐照','宋','宋词','song-ci','瑞鹧鸪','[]','雨多庭石上苔文。',64,'宋词/ci.song.13000.json','["雨多庭石上苔文。", "门外春光老几分。", "为把旧书藏宝带，误翻残酒湿绡裙。", "风头花片难装缀，愁里莺声怯听闻。", "恰似翦刀裁破恨，半随妾处半随君。"]'),
('song-ci-842','南歌子','徐照','宋','宋词','song-ci','南歌子','[]','帘影筛金线，炉烟篆翠丝。',62,'宋词/ci.song.13000.json','["帘影筛金线，炉烟篆翠丝。", "菰芽新出满盆池。", "唤起玉瓶添水、养鱼儿。", "意取钗虫碧，慵梳髻翅垂。", "相思无处说相思。", "笑把画罗小扇、觅春词。"]'),
('song-ci-843','清平乐','徐照','宋','宋词','song-ci','清平乐','[]','绿围红绕。',54,'宋词/ci.song.13000.json','["绿围红绕。", "一枕屏山晓。", "怪得今朝偏起早。", "笑道牡丹开了。", "迎人卷上珠帘，小螺未拂眉尖。", "贪教玉笼鹦鹉，杨花飞满妆奁。"]'),
('song-ci-844','阮郎归','徐照','宋','宋词','song-ci','阮郎归','[]','绿杨庭户静沈沈。',56,'宋词/ci.song.13000.json','["绿杨庭户静沈沈。", "杨花吹满襟。", "晚来闲向水边寻。", "惊飞双浴禽。", "分别后，忍登临。", "暮寒天气阴。", "妾心移得在君心。", "方知人恨深。"]'),
('song-ci-845','玉楼春','徐照','宋','宋词','song-ci','玉楼春','[]','萤飞月里无光色。',64,'宋词/ci.song.13000.json','["萤飞月里无光色。", "波水不摇楼影直。", "每怜宿粉涴啼痕，懒把旧书观字迹。", "枯荷露重时闻滴。", "君梦不来谁阻隔。", "妾身不畏浙江风，飞去飞来方瞬息。"]'),
('song-ci-846','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','曾讲弥陀经十遍。',72,'宋词/ci.song.13000.json','["曾讲弥陀经十遍。", "孤山疏钞频舒卷。", "事理圆融文义显。", "多方便。", "到头只劝生莲苑。", "本性弥陀随体现。", "唯心净土何曾远。", "十万程途从事见。", "休分辨。", "临终但自亲行转。"]'),
('song-ci-847','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','我佛莲华随步踏。',72,'宋词/ci.song.13000.json','["我佛莲华随步踏。", "黄金妙相青螺发。", "因地曾将洪誓发。", "四十八。", "众生尽度成菩萨。", "宫殿红香华影合。", "宝阶三道琉璃阔。", "水鸟树林皆念法。", "声嘈囋。", "空中零乱天华撒。"]'),
('song-ci-848','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','彼土因何名极乐。',72,'宋词/ci.song.13000.json','["彼土因何名极乐。", "莲华九品无三恶。", "虽有频伽并白鹤。", "非彰灼。", "如来变化宣流作。", "九品一生离五浊。", "自然身挂珠璎珞。", "宛转白毫生额角。", "长辉烁。", "百千业障都消却。"]'),
('song-ci-849','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','佛赞西方经现在。',72,'宋词/ci.song.13000.json','["佛赞西方经现在。", "广长舌相三千界。", "为要众生生信解。", "临终迈。", "不修净业犹何待。", "七宝池塘波一派。", "莲华朵朵车轮大。", "华内托生真自在。", "分三辈。", "阿鞞跋致长无退。"]'),
('song-ci-850','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','鹦鹉频伽知几只。',72,'宋词/ci.song.13000.json','["鹦鹉频伽知几只。", "音声和雅鸣朝夕。", "演畅五根并五力。", "令人忆。", "心飞恨不身生翼。", "从是西方十万亿。", "山长水远谁人识。", "唯是观门归路直。", "真消息。", "坐澄劫水琉璃碧。"]'),
('song-ci-851','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','清净乐邦吾本郡。',72,'宋词/ci.song.13000.json','["清净乐邦吾本郡。", "娑婆流浪因贪吝。", "冉冉思归霜入鬓。", "深嗟恨。", "塞鸿不解传音信。", "落日尽边沙隐隐。", "向西望处归应近。", "天乐是时相接引。", "宜精进。", "紫金台上谁无分。"]'),
('song-ci-852','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','理性本来长自在。',72,'宋词/ci.song.13000.json','["理性本来长自在。", "灵通昭彻光无碍。", "因被无明风恼害。", "真如海。", "等闲吹动波千派。", "五蕴山头云叆叇。", "遮藏心月无光彩。", "六贼会须知悔改。", "除贪爱。", "刹那跳出娑婆界。"]'),
('song-ci-853','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','为厌娑婆求净土。',72,'宋词/ci.song.13000.json','["为厌娑婆求净土。", "驰情送想存朝暮。", "谁信不劳移一步。", "西方去。", "楼台隐隐云深处。", "珠网为光华作雨。", "金沙布地无尘土。", "怎不教人思去路。", "心专注。", "坐观落日如悬鼓。"]'),
('song-ci-854','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','四相相催生病老。',72,'宋词/ci.song.13000.json','["四相相催生病老。", "死魔不定朝难保。", "争似寅昏持佛号。", "西方好。", "树林水鸟称三宝。", "磨灭等闲髭鬓皓。", "乐邦行计唯宜早。", "万亿国邦非远道。", "休烦恼。", "一弹指顷能行到。"]'),
('song-ci-855','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','人世罪冤知底数。',72,'宋词/ci.song.13000.json','["人世罪冤知底数。", "前程不是无冥府。", "争似静焚香一炷。", "无行住。", "声声称念弥陀父。", "罪业尽消生有处。", "弥陀愿力堪凭据。", "十念一心存旦暮。", "西方路。", "功成足步红莲去。"]'),
('song-ci-856','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','万事到头无益已。',72,'宋词/ci.song.13000.json','["万事到头无益已。", "寻思只有修行是。", "若送此心游宝地。", "还容易。", "坐观落日当西坠。", "万顷红光归眼际。", "眼开眼闭长明媚。", "此观成时知法味。", "心欢喜。", "临终决定生莲里。"]'),
('song-ci-857','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','西望乐邦云杳隔。',72,'宋词/ci.song.13000.json','["西望乐邦云杳隔。", "一钩新月弯弯白。", "意欲往生何计策。", "劳魂魄。", "弥陀一念声千百。", "金殿玉楼为屋宅。", "七重行树强松柏。", "华里托生非血脉。", "真高格。", "乐天不是蓬莱客。"]'),
('song-ci-858','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','富贵经中谈净域。',72,'宋词/ci.song.13000.json','["富贵经中谈净域。", "赤珠玛瑙为严饰。", "彼土众生当晓色。", "擎衣裓。", "妙华供养他方佛。", "稚小嬉游随没溺。", "娑婆是苦何曾识。", "忻厌迩来方有力。", "从朝夕。", "静焚一炷香凝碧。"]'),
('song-ci-859','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','文墨尖新无处用。',72,'宋词/ci.song.13000.json','["文墨尖新无处用。", "已将名利浑如梦。", "一串数珠随手弄。", "休千种。", "唯闻念佛心欢勇。", "滉漾空中仙乐动。", "笙箫声细天风送。", "接引凡夫归圣众。", "香云捧。", "男儿此日方崇重。"]'),
('song-ci-860','渔家傲','可旻','宋','宋词','song-ci','渔家傲','["\u5e90\u5c71"]','休纵心猿驰意马。',72,'宋词/ci.song.13000.json','["休纵心猿驰意马。", "牢将系念绳头把。", "说破十疑因智者。", "争传写。", "庐山又结莲华社。", "十八大贤居会下。", "功成五色云西驾。", "诸上善人都在那。", "相迎迓。", "聚头只说无生话。"]'),
('song-ci-861','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','三十六般包一袋。',72,'宋词/ci.song.13000.json','["三十六般包一袋。", "脓囊臭秽犹贪爱。", "恰似蜣螂推粪块。", "无停待。", "朝朝只在尘中め。", "若解坚心生重悔。", "宁拘恶逆并魁脍。", "一念能消千劫罪。", "生华内。", "满身璎珞鸣珂佩。"]'),
('song-ci-862','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','一点神魂初托魄。',72,'宋词/ci.song.13000.json','["一点神魂初托魄。", "青莲华里琉璃宅。", "毫相法音非间隔。", "虽明白。", "到头不似金台客。", "九品高低随报获。", "或经劫数华方拆。", "若是我生心性窄。", "应煎迫。", "未开须把莲华擘。"]'),
('song-ci-863','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','净土故乡嗟乍别。',72,'宋词/ci.song.13000.json','["净土故乡嗟乍别。", "天涯流浪经时节。", "老去染沾眉鬓雪。", "思归切。", "闻声愿寄辽天月。", "念念时时修净业。", "临终佛定来迎接。", "有誓表为诚实说。", "广长舌。", "三千遍覆红莲叶。"]'),
('song-ci-864','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','善导可嗟今已往。',72,'宋词/ci.song.13000.json','["善导可嗟今已往。", "化来老少皆归向。", "佛念一声分一镪。", "声才响。", "一声一佛虚空上。", "八万四千奇妙相。", "光明寿命皆无量。", "金色臂垂千万丈。", "鹅王掌。", "誓来迎接归安养。"]'),
('song-ci-865','渔家傲','可旻','宋','宋词','song-ci','渔家傲','[]','西土纹成东土壤。',72,'宋词/ci.song.13000.json','["西土纹成东土壤。", "星飞一点千华界。", "勿讶神魂生去快。", "无遮碍。", "乐邦只在同居内。", "八德池深华又大。", "跏趺端坐莲华载。", "耳听法音心悟解。", "低头拜。", "从今跳出胞胎外。"]'),
('song-ci-866','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，长劫受轮回。',64,'宋词/ci.song.13000.json','["娑婆苦，长劫受轮回。", "不断苦因离火宅，祗随业报入胞胎。", "辜负这灵台。", "朝又暮，寒暑急相催。", "一个幻身能几日，百端机巧衮尘埃。", "何得出头来。"]'),
('song-ci-867','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，身世一浮萍。',64,'宋词/ci.song.13000.json','["娑婆苦，身世一浮萍。", "蚊蚋睫中争小利，蜗牛角上窃虚名。", "一点气难平。", "人我盛，日夜长无明。", "地狱争头成队入，西方无个肯修行。", "空死复空生。"]'),
('song-ci-868','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，情念骤如风。',64,'宋词/ci.song.13000.json','["娑婆苦，情念骤如风。", "六贼村中无暂息，四蛇箧内更相攻。", "谁是主人公。", "无慧力，爱网转关笼。", "一向四楞低搭地，不思两脚欲梢空。", "前路更匆匆。"]'),
('song-ci-869','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，生老病无常。',64,'宋词/ci.song.13000.json','["娑婆苦，生老病无常。", "九窍腥臊流秽污，一包脓血贮皮囊。", "争弱又争强。", "随妄想，耽欲更荒唐。", "念佛看经云著相，破斋毁戒却无妨。", "祗恐有阎王。"]'),
('song-ci-870','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，终日走尘寰。',64,'宋词/ci.song.13000.json','["娑婆苦，终日走尘寰。", "不觉年光随逝水，那堪白发换朱颜。", "六趣任循环。", "今与古，谁肯死前闲。", "危脆利名才入手，虚华财色便追攀。", "荣辱片时间。"]'),
('song-ci-871','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','娑婆苦，光影急如流。',64,'宋词/ci.song.13000.json','["娑婆苦，光影急如流。", "宠辱悲欢何日了，是非人我几时休。", "生死路悠悠。", "三界里，水面一浮沤。", "纵使英雄功盖世，祗留白骨掩荒丘。", "何似早回头。"]'),
('song-ci-872','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，随念即超群。',64,'宋词/ci.song.13000.json','["西方好，随念即超群。", "一点灵光随落日，万端尘事付浮云。", "人世自纷纷。", "凝望处，决定去栖神。", "金地经行光里步，玉楼宴坐定中身。", "方好任天真。"]'),
('song-ci-873','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，琼树耸高空。',64,'宋词/ci.song.13000.json','["西方好，琼树耸高空。", "弥覆七重珠宝网，庄严百亿妙华宫。", "宫里众天童。", "金地上，栏楯绕重重。", "华雨飘颻香散漫，乐音嘹亮鼓清风。", "闻者乐无穷。"]'),
('song-ci-874','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，七宝甃成池。',64,'宋词/ci.song.13000.json','["西方好，七宝甃成池。", "四色好华敷菡萏，八功德水泛清漪。", "除渴又除饥。", "池岸上，楼殿势飞翬。", "碧玉雕栏填玛瑙，黄金危栋间玻璃。", "随处发光辉。"]'),
('song-ci-875','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，群鸟美音声。',64,'宋词/ci.song.13000.json','["西方好，群鸟美音声。", "华下和鸣歌六度，光中哀雅赞三乘。", "闻者悟无生。", "三恶道，犹自不知名。", "皆是佛慈亲变化，欲宣法语警迷情。", "心地顿圆明。"]'),
('song-ci-876','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，清旦供尤佳。',64,'宋词/ci.song.13000.json','["西方好，清旦供尤佳。", "缥缈仙云随宝仗，轻盈衣裓贮天华。", "十万去非赊。", "诸佛土，随念遍河沙。", "莲掌抚摩亲授记，潮音清妙响频伽。", "时至即还家。"]'),
('song-ci-877','望江南・忆江南','净圆','宋','宋词','song-ci','望江南・忆江南','[]','西方好，我佛大慈悲。',64,'宋词/ci.song.13000.json','["西方好，我佛大慈悲。", "但具三心圆十念，即登九品越三祗。", "神力不思议。", "临报尽，接引定无疑。", "普愿众生同系念，金台天乐共迎时。", "弹指到莲池。"]'),
('song-ci-878','哨遍','刘学箕','宋','宋词','song-ci','哨遍','[]','木叶尽凋，湖色接天，雪月明江水。',237,'宋词/ci.song.13000.json','["木叶尽凋，湖色接天，雪月明江水。", "凌万顷、一苇纵所之。", "若凭虚驭风仙子。", "听洞箫、绵延不绝如缕，馀音袅袅游丝曳。", "乃举酒赋诗，玉鳞霜蟹，是中风味偏美。", "任满头堆絮雪花飞。", "更月澹蓬窗冻云垂。", "山郁苍苍，桥卧沈沈，夜鹊惊起。", "噫。", "倚兰桨兮。", "我今恍惚遗身世。", "渔樵甘放浪，蜉蝣然、寄天地。", "叹富贵何时。", "功名浪语。", "人生寓乐虽情尔。", "知逝者如斯。", "盈虚如彼，则知变者如是。", "且物生宇宙各有司。", "非已有纤毫莫得之。", "委吾心、耳目所寄。", "用之而不竭，取则不吾禁，自色自声，本非有意。", "望东来孤鹤缟其衣。", "快乘之、从此仙矣。"]'),
('song-ci-879','蝶恋花','刘学箕','宋','宋词','song-ci','蝶恋花','[]','灯火已收正月半。',70,'宋词/ci.song.13000.json','["灯火已收正月半。", "一夜东风，吹得寒威转。", "怪得美人贪睡暖。", "飞瑛积玉千林变。", "道是柳绵春尚浅。", "比著梅花，花已都零乱。", "漠漠一天迷望眼。", "多情更把征衣点。"]'),
('song-ci-880','贺新郎','刘学箕','宋','宋词','song-ci','贺新郎','[]','午睡莺惊起。',142,'宋词/ci.song.13000.json','["午睡莺惊起。", "鬓云偏、□鬆未整，凤钗斜坠。", "宿酒残妆无意绪，春恨春愁如水。", "谁共说、厌厌情味。", "手展流苏腰肢瘦，叹黄金、两细香消臂。", "心事远，仗谁寄。", "帘栊渐是槐风细。", "对梧桐、清阴满院，夏初天气。", "回首春空梨花梦，屈指从头暗记。", "叹薄幸、抛人容易。", "目断孤鸿沈双鲤，恨萧郎、不寄相思字。", "幽恨积，黛眉翠。"]'),
('song-ci-881','忆王孙','刘学箕','宋','宋词','song-ci','忆王孙','[]','淑景韶光晴昼。',66,'宋词/ci.song.13000.json','["淑景韶光晴昼。", "帘外雨、欲无还有。", "流莺枝上转新声，梦初醒、厌厌病酒。", "天连碧草凝情久。", "思旧事、不堪搔首。", "怀人有恨水云深，又绿暗、桥西柳。"]'),
('song-ci-882','恋绣衾','刘学箕','宋','宋词','song-ci','恋绣衾','[]','柳絮风翻高下飞。',68,'宋词/ci.song.13000.json','["柳絮风翻高下飞。", "雨笼晴、香径尚泥。", "女伴笑、踏青好，凤钗偏、花压鬓垂。", "乱莺双燕春情绪，搅愁心、欲诉向谁。", "人间道、因谁瘦，拈青梅、闲敛黛眉。"]'),
('song-ci-883','惜分飞','刘学箕','宋','宋词','song-ci','惜分飞','[]','池上楼台堤上路。',58,'宋词/ci.song.13000.json','["池上楼台堤上路。", "尽日悠扬飞舞。", "欲下还重举。", "又随胡蝶墙东去。", "糁径飘空无定处。", "来往绿窗朱户。", "却被春风妒。", "送将蛛网留连住。"]'),
('song-ci-884','浣溪沙','刘学箕','宋','宋词','song-ci','浣溪沙','[]','天上仙人萼绿华。',48,'宋词/ci.song.13000.json','["天上仙人萼绿华。", "何年分种小山家。", "九秋风露溢窗纱。", "密密翠罗攒玉叶，团团黄粟刻金花。", "一枝归插鬓云斜。"]'),
('song-ci-885','贺新郎','刘学箕','宋','宋词','song-ci','贺新郎','[]','往事何堪说。',142,'宋词/ci.song.13000.json','["往事何堪说。", "念人生、消磨寒暑，漫营裘葛。", "少日功名频看镜，绿鬓鬅鬙未雪。", "渐老矣、愁生华发。", "国耻家雠何年报，痛伤神、遥望关河月。", "悲愤积，付湘瑟。", "人生未可随时别。", "守忠诚、不替天意，自能符合。", "误国诸人今何在，回首怨深次骨。", "叹南北、久成离绝。", "中夜闻鸡狂起舞，袖青蛇、戛击光磨铁。", "三太息，皆空裂。"]'),
('song-ci-886','贺新郎','刘学箕','宋','宋词','song-ci','贺新郎','[]','东阁凭诗说。',142,'宋词/ci.song.13000.json','["东阁凭诗说。", "对丰姿、飘然杖屦，澹然巾葛。", "竹外一枝斜更好，玉质冰肌粲雪。", "谁折向、满头宣发。", "水驿云窗烟庭院，更宜晴、宜雨还宜月。", "霜夜永，景萧瑟。", "孤芳敻与群芳别。", "陇程遥、攀条难寄，碧云惊合。", "桃李漫山空春艳，不比仙风道骨。", "有潇洒、清新奇绝。", "我被幽香相懊恼，宋广平、岂但心如铁。", "飞暗度，石吹裂。"]'),
('song-ci-887','贺新郎','刘学箕','宋','宋词','song-ci','贺新郎','[]','晓听儿曹说。',142,'宋词/ci.song.13000.json','["晓听儿曹说。", "道前村、疏梅莫与，蔽萧缠葛。", "急与呼童诛翦尽，趁此江天暮雪。", "唤小艇、渔翁鹤发，凛冽寒风吹酒面，与何人、共泛山阴月。", "归浩叹，御琴瑟。", "世寰恍惚山川别。", "望琼楼、玉宇相映，烂银环合。", "冰柱雪车新句就，不疗饥肠病骨。", "奈野鸟、千山飞绝。", "我笑书生贫亦甚，诵布衾、岁久寒如铁。", "儿恶卧，踏里裂。"]'),
('song-ci-888','满江红','刘学箕','宋','宋词','song-ci','满江红','[]','午转槐阴，正炎暑、侵肌似醉。',115,'宋词/ci.song.13000.json','["午转槐阴，正炎暑、侵肌似醉。", "问何处、披襟散发，解衣扬袂。", "傍沼茅亭杨柳绿，倚崖草阁梧桐翠。", "唤玉人、纤手掬清泉，生凉意。", "开枕簟，浮瓜芰。", "琼液浅，歌喉细。", "对文禽雪鹭，助成幽致。", "十顷碧莲潇洒国，万竿修竹清凉世。", "算此时、情绪有谁同，吾侬自。"]'),
('song-ci-889','满江红','刘学箕','宋','宋词','song-ci','满江红','[]','一柄双花，低翠盖、呈祥现美。',115,'宋词/ci.song.13000.json','["一柄双花，低翠盖、呈祥现美。", "人正在、薰风亭上，满襟如水。", "二陆比方夸俊少，两乔相并修容止。", "雨初晴、午永斗红酣，真奇耳。", "双白鹭，双赪鲤。", "飞与泳，俱来此。", "绾双鬟天上，侍香童子。", "双剑丰城双孕秀，双凫叶县双趋起。", "谩空谈、国士本无双，今双矣。"]'),
('song-ci-890','沁园春','刘学箕','宋','宋词','song-ci','沁园春','[]','浮利虚名，算来何用，蜗角蝇头。',139,'宋词/ci.song.13000.json','["浮利虚名，算来何用，蜗角蝇头。", "笑劳生一梦，两轮催逼，脆如朝露，轻若春沤。", "有限精神，无穷世路，劫劫忙忙谁肯休。", "堪惊叹，叹痴人未悟，终日营求。", "百年光景云浮。", "把意马心猿须早收。", "有真仙秘诀，飧霞导引，丹砂铅汞，早与身谋。", "闲是闲非，他强我弱，一任从教风马牛。", "还知道，上蓬莱稳路，八表神游。"]'),
('song-ci-891','念奴娇','刘学箕','宋','宋词','song-ci','念奴娇','[]','水轩沙岸，午风轻、飘动一天晴雪。',120,'宋词/ci.song.13000.json','["水轩沙岸，午风轻、飘动一天晴雪。", "日色晶荧光眩眼，细逐游丝明灭。", "帘幕中间，楼台侧畔，浑是瑶瑛积。", "缀松黏竹，恍然如对三绝。", "遥认仿佛飞花，花非还似，恼乱多情客。", "点染春衫无定度，又转沈香亭北。", "密密疏疏，斜斜整整，似雪难分别。", "坡仙不见，后人有口何说。"]'),
('song-ci-892','念奴娇','刘学箕','宋','宋词','song-ci','念奴娇','[]','断虹开霁，净秋容、点点初收微雨。',120,'宋词/ci.song.13000.json','["断虹开霁，净秋容、点点初收微雨。", "夕下生阴山影澹，缥渺烟云吞吐。", "乌帽风偏，青鞋沙软，误入桃溪坞。", "多情鸥鹭，偶来忽又飞去。", "日暮修竹佳人，雾绡琼佩，绰约疑仙侣。", "愧我禅心春尽絮，不逐东风飞舞。", "红叶题诗，紫云传恨，密意渠能诉。", "此情疏隔，不关楼外烟树。"]'),
('song-ci-893','菩萨蛮','刘学箕','宋','宋词','song-ci','菩萨蛮','[]','暮涛掀浪溪流急。',52,'宋词/ci.song.13000.json','["暮涛掀浪溪流急。", "单衣未试春寒力。", "是处绿阴浓。", "春深杨柳风。", "人依溪岸住。", "酒美忘归去。", "巢燕堕芹泥。", "幽禽花外啼。"]'),
('song-ci-894','菩萨蛮','刘学箕','宋','宋词','song-ci','菩萨蛮','[]','鸦儿学画犹嫌丑。',52,'宋词/ci.song.13000.json','["鸦儿学画犹嫌丑。", "佯羞步步随娘后。", "春浅瘦花枝。", "凝愁为阿谁。", "那回筵畔见。", "有意相留恋。", "只恐后期愆。", "章台飞柳绵。"]'),
('song-ci-895','鹧鸪天','刘学箕','宋','宋词','song-ci','鹧鸪天','[]','楼外银屏入望赊。',64,'宋词/ci.song.13000.json','["楼外银屏入望赊。", "楼前鸥鹭舞交加。", "穿林淅沥飞琼屑，度嶂缤纷过柳花。", "歌白雪，醉流霞。", "晚寒寒似夜来些。", "明朝酒醒掀帘幕，帘幕依然卖酒家。"]'),
('song-ci-896','西江月','刘学箕','宋','宋词','song-ci','西江月','[]','世事从来无据，人生自古难凭。',58,'宋词/ci.song.13000.json','["世事从来无据，人生自古难凭。", "茫如天水有云萍。", "聚散任他形影。", "每怪东阳瘦损，常嗤骑省多情。", "如今我也瘦棱棱。", "却喜青青两鬓。"]'),
('song-ci-897','水调歌头','刘学箕','宋','宋词','song-ci','水调歌头','[]','三载役京口，十度过松江。',114,'宋词/ci.song.13000.json','["三载役京口，十度过松江。", "垂虹亭下烟水，长是映蓬窗。", "钓得锦鳞成脍，快把双螯浩饮，豪气未能降。", "醉舞影零乱，心逐浪舂撞。", "景苍茫，歌欸乃，石空硿。", "蒹葭深处，适意鱼鸟自双双。", "便拟轻舟短棹，明月清风长共，与世绝纷龙。", "嘉遁有真隐，不羡鹿门庞。"]'),
('song-ci-898','醉落魄・一斛珠','刘学箕','宋','宋词','song-ci','醉落魄・一斛珠','[]','江头离席。',67,'宋词/ci.song.13000.json','["江头离席。", "晚潮双橹催行色。", "往来属玉双飞白。", "笑我多情，犹作未归客。", "红尘奔走何时息。", "归心还似投林翼。", "角巾醉里从敧侧。", "独立东风，天际露岑碧。"]'),
('song-ci-899','长相思','刘学箕','宋','宋词','song-ci','长相思','[]','湖山横。',44,'宋词/ci.song.13000.json','["湖山横。", "湖水平。", "买个湖船一叶轻。", "傍湖随柳行。", "秋风清。", "秋月明。", "谁捣秋砧烟外声。", "悲秋无尽情。"]'),
('song-ci-900','鹧鸪天','刘学箕','宋','宋词','song-ci','鹧鸪天','[]','芳草萋萋入眼浓。',64,'宋词/ci.song.13000.json','["芳草萋萋入眼浓。", "一年花事又匆匆。", "吐舒桃脸今朝雨，零落梅妆昨夜风。", "云接野，水连空。", "画栏十二倚谁同。", "两眉新恨无分付，独立苍苔数落红。"]'),
('song-ci-901','鹧鸪天','刘学箕','宋','宋词','song-ci','鹧鸪天','[]','梦绕天涯去意浓。',64,'宋词/ci.song.13000.json','["梦绕天涯去意浓。", "客愁春恨两匆匆。", "绿波初涨桃花浪，画鹢轻随柳絮风。", "无笔力，判虚空。", "关山千里两心同。", "鱼书雁字都休问，只看啼痕翠袖红。"]'),
('song-ci-902','鹧鸪天','刘学箕','宋','宋词','song-ci','鹧鸪天','[]','山色都如归兴浓。',64,'宋词/ci.song.13000.json','["山色都如归兴浓。", "春融融处客匆匆。", "岸花影里莺吟雾，江阁阴中燕受风。", "凭画楯，睇层空。", "情衷待说几时同。", "不如且尽樽中绿，图得醄醄醉脸红。"]'),
('song-ci-903','菩萨蛮','刘学箕','宋','宋词','song-ci','菩萨蛮','[]','昨日杏花春满树。',52,'宋词/ci.song.13000.json','["昨日杏花春满树。", "今晨雨过香填路。", "零落软胭脂。", "湿红无力飞。", "转头春易去。", "春色归何处。", "待密与春期。", "春归人也归。"]'),
('song-ci-904','浣溪沙','刘学箕','宋','宋词','song-ci','浣溪沙','[]','来日江头柳带香。',48,'宋词/ci.song.13000.json','["来日江头柳带香。", "去时篱下菊花黄。", "人生离别几凄凉。", "拂面红尘飞冉冉，背人白日去堂堂。", "尺书休负雁南翔。"]'),
('song-ci-905','眼儿媚','刘学箕','宋','宋词','song-ci','眼儿媚','[]','十年不见柳腰肢。',58,'宋词/ci.song.13000.json','["十年不见柳腰肢。", "契阔几何时。", "天遥地远，秋悲春恨，只在双眉。", "雁声今夜楼西畔，情愫渺难期。", "杏花风景，梧桐夜月，都是相思。"]'),
('song-ci-906','桃源忆故人','刘学箕','宋','宋词','song-ci','桃源忆故人','[]','暮霞散绮西溪浦。',56,'宋词/ci.song.13000.json','["暮霞散绮西溪浦。", "天上晴云开絮。", "清绝梅花几树。", "恼乱春愁处。", "小桥流水人来去。", "沙岸浴鸥飞鹭。", "谁画江南好处。", "著我闲巾屦。"]'),
('song-ci-907','糖多令・唐多令','刘学箕','宋','宋词','song-ci','糖多令・唐多令','["\u957f\u6c5f"]','何处浣离忧。',74,'宋词/ci.song.13000.json','["何处浣离忧。", "消除许大愁。", "望长江、衮衮东流。", "一去乡关能几日，才屈指、又中秋。", "芦叶满汀洲。", "沙矶小艇收。", "醉归来、明月江楼。", "欲把情怀输写尽，终不似、少年游。"]'),
('song-ci-908','小重山','刘学箕','宋','宋词','song-ci','小重山','[]','春水东流一苇杭。',70,'宋词/ci.song.13000.json','["春水东流一苇杭。", "春情翦不断，汉江长。", "江花江草为谁芳。", "浑不似，沙暖睡鸳鸯。", "且道不思量。", "怕他知得后，痛肝肠。", "路遥天阔水茫茫。", "成病也，教我怎禁当。"]'),
('song-ci-909','行香子','刘学箕','宋','宋词','song-ci','行香子','[]','雪白肥鰜。',82,'宋词/ci.song.13000.json','["雪白肥鰜。", "墨黑修鲇。", "柳穿腮、小大相兼。", "金刀批脔，鲜活甘甜。", "或时熬，或时煮，或时腌。", "揎腕佳人，玉手纤纤。", "缕银丝、取意无厌。", "羹须澹煮，滋味重添。", "滴儿醯，呷儿酒，撮儿盐。"]'),
('song-ci-910','临江仙','刘学箕','宋','宋词','song-ci','临江仙','[]','人在空江烟浪里，叶舟轻似浮沤。',70,'宋词/ci.song.13000.json','["人在空江烟浪里，叶舟轻似浮沤。", "此心无怨也无忧。", "汉江迷望眼，衮衮知东流。", "两岸荻芦青不断，四山岗岭绸缪。", "晚风吹袂冷飕飕。", "谁知三伏暑，全似菊花秋。"]'),
('song-ci-911','渔家傲','刘学箕','宋','宋词','song-ci','渔家傲','[]','汉水悠悠还漾漾。',72,'宋词/ci.song.13000.json','["汉水悠悠还漾漾。", "渔翁出没穿风浪。", "千尺丝纶垂两桨。", "收又放。", "月明长在烟波上。", "钓得活鳞鳊缩项。", "篘成玉液香浮盎。", "醉倒自歌歌自唱。", "轻袅缆。", "碧芦红蓼清滩傍。"]'),
('song-ci-912','菩萨蛮','刘学箕','宋','宋词','song-ci','菩萨蛮','[]','烟汀一抹蒹葭渚。',52,'宋词/ci.song.13000.json','["烟汀一抹蒹葭渚。", "风亭两下荷花浦。", "月色漾波浮。", "波流月自留。", "若耶溪上女。", "两两三三去。", "眉黛敛羞蛾。", "采菱随棹歌。"]'),
('song-ci-913','乌夜啼','刘学箕','宋','宋词','song-ci','乌夜啼','[]','长亭急管生愁。',45,'宋词/ci.song.13000.json','["长亭急管生愁。", "楚天秋。", "落日寒鸦飞尽、水悠悠。", "红蓼岸。", "白苹散。", "浴轻鸥。", "人在碧云深处、倚高楼。"]'),
('song-ci-914','虞美人','刘学箕','宋','宋词','song-ci','虞美人','[]','寒来暑往何时了。',66,'宋词/ci.song.13000.json','["寒来暑往何时了。", "世故催人老。", "一人口插几张匙。", "何用波波劫劫、没休时。", "饥来吃饭困来睡。", "莫把身为累。", "谁能较短与量长。", "落叶西风一梦、熟黄粱。"]'),
('song-ci-915','贺新郎','刘学箕','宋','宋词','song-ci','贺新郎','[]','莫向愁人说。',142,'宋词/ci.song.13000.json','["莫向愁人说。", "叹人生、不如意事，十常七八。", "是则中年伤怀抱，客里何堪送客。", "又添取、一襟凄咽。", "岸柳凋零秋容澹，黯消凝、怎忍轻攀折。", "重会面，甚时节。", "杏花丽日梅花雪。", "记当时、一觞一咏，楚云湘月。", "别后君休劳春梦，转眼江南塞北。", "莫漫被、闲愁萦结。", "且判离筵今夕醉，霎时间、便见兰舟发。", "空怅望，水云阔。"]'),
('song-ci-916','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','诸公台省，问先生何事，冷官如许。',120,'宋词/ci.song.13000.json','["诸公台省，问先生何事，冷官如许。", "甲第纷纷粱肉厌，应怪先生无此。", "道出羲皇，才过屈宋，空有名垂古。", "得钱沽酒，忘形欲道尔汝。", "好是清夜沈沈，共开春酌，细听檐花雨。", "茅屋石田荒已久，总待先生归去。", "司马子云，孔丘盗跖，到了俱尘土。", "不须闻此，生前杯酒相遇。"]'),
('song-ci-917','水调歌・水调','林正大','宋','宋词','song-ci','水调歌・水调','[]','人笑杜陵客，短褐鬓如丝。',114,'宋词/ci.song.13000.json','["人笑杜陵客，短褐鬓如丝。", "得钱沽酒，时赴郑老同襟期。", "清夜沈沈春酌，歌语灯前细雨，相觅不相疑。", "忘形到尔汝，痛饮真吾师。", "问先生，今去也，早归来。", "先生去后，石田茅屋恐苍苔。", "休怪相如涤器，莫学子云投阁，儒术亦佳哉。", "谁道官独冷，衮衮上兰台。"]'),
('song-ci-918','满江红','林正大','宋','宋词','song-ci','满江红','[]','衮衮诸公，嗟独冷、先生宦薄。',115,'宋词/ci.song.13000.json','["衮衮诸公，嗟独冷、先生宦薄。", "夸甲第、纷纷粱肉，谩甘寥寞。", "道出羲皇知有用，才过屈宋人谁若。", "剩得钱、沽酒两忘形，更酬酢。", "清夜永，开春酌。", "听细雨，檐花落。", "但高歌不管，饿填沟壑。", "司马逸才亲涤器，子云识字终投阁。", "且生前、相遇共相欢，衔杯乐。"]'),
('song-ci-919','一丛花','林正大','宋','宋词','song-ci','一丛花','[]','知章骑马似乘船。',94,'宋词/ci.song.13000.json','["知章骑马似乘船。", "落井眼花圆。", "汝阳三斗朝天去，左丞相、鲸吸长川。", "潇洒宗之，皎如玉树，举盏望青天。", "长斋苏晋爱逃禅，李白富诗篇。", "三杯草圣传张旭，更焦遂、五斗惊筵。", "一笑相逢，衔杯乐圣，同是饮中仙。"]'),
('song-ci-920','贺新凉・贺新郎','林正大','宋','宋词','song-ci','贺新凉・贺新郎','[]','兰亭当日事。',141,'宋词/ci.song.13000.json','["兰亭当日事。", "有崇山、茂林修竹，群贤毕至。", "湍急清流相映带，旁引流觞曲水。", "但畅叙、幽情而已。", "一咏一觞真足乐，厌管弦丝竹纷尘耳。", "春正暮，共修禊。", "惠风和畅新天气。", "骋高怀、仰观宇宙，俯察品类。", "俯仰之间因所寄，放浪形骸之外。", "曾不知、老之将至。", "感慨旧游成陈迹，念人生、行乐都能几。", "后视今，犹昔尔。"]'),
('song-ci-921','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','问陶彭泽，有田园活计，归来何晚。',120,'宋词/ci.song.13000.json','["问陶彭泽，有田园活计，归来何晚。", "昨梦皆非今觉是，实迷途其未远。", "松菊犹存，壶觞自酌，寄傲南窗畔。", "闲云出岫，更看飞鸟投倦。", "归去请息交游，驾言焉往，独把琴书玩。", "孤棹巾车邱壑趣，物与吾生何恨。", "宇内寓形，帝乡安所，富贵非吾愿。", "乐夫天命，聊乘化以归尽。"]'),
('song-ci-922','沁园春','林正大','宋','宋词','song-ci','沁园春','[]','大人先生，高怀逸兴，酒肉寓名。',142,'宋词/ci.song.13000.json','["大人先生，高怀逸兴，酒肉寓名。", "纵幕天席地，居无庐室，以八荒为域，日月为扃。", "贵介时豪，搢绅处士，未解先生酒适情。", "徒劳尔，谩是非锋起，有耳谁听。", "先生。", "挈榼提罂。", "更箕踞衔杯枕麴生。", "但无思无虑，陶陶自得，任兀然而醉，恍然而醒。", "静听无闻，熟视无睹，以醉为乡乐性真。", "谁知我，彼二豪犹是，蜾蠃螟蛉。"]'),
('song-ci-923','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','太行有盘谷，隐者所翱翔，丈夫行世，磊磊落落信行藏。',114,'宋词/ci.song.13000.json','["太行有盘谷，隐者所翱翔，丈夫行世，磊磊落落信行藏。", "遇则声名利泽，不遇采山钓水，何似两俱忘。", "谁解盘中趣，与酒为歌章。", "问何如，盘之乐，乐无央。", "远驱虎豹，蛟龙于此亦潜藏。", "盘土可耕可稼，盘水可沿可濯，饮食寿而康。", "膏车秣吾马，从子以徜徉。"]'),
('song-ci-924','摸鱼儿','林正大','宋','宋词','song-ci','摸鱼儿','[]','醉之乡、其去中国，不知其几千里。',139,'宋词/ci.song.13000.json','["醉之乡、其去中国，不知其几千里。", "其土平旷无涯际。", "其气和平一揆。", "无寒暑，无聚落居城，无怒而无喜。", "昔黄帝氏。", "仅获造其都，归而遂悟，结绳已非矣。", "及尧舜，盖亦至其边鄙。", "终身太平而治。", "武王得志於周世。", "命立酒人之氏。", "从此后，独阮籍渊明，往往逃而至。", "何其淳寂。", "岂古华胥，将游是境，余故为之记。"]'),
('song-ci-925','声声慢','林正大','宋','宋词','song-ci','声声慢','[]','暮春天气，争看长安，水边多丽人人。',119,'宋词/ci.song.13000.json','["暮春天气，争看长安，水边多丽人人。", "意远态浓，肌理骨肉轻匀。", "绣罗衣裳照映，尽蹙金、孔雀麒麟。", "夸荣贵，是椒房云幕，恩宠无伦。", "簇簇紫驼翠釜，间水精盘里，缕脍纷纶。", "御送珍羞，夹道箫鼓横陈。", "后来宾从杂遝，认青鸾、飞舞红巾。", "扶下马，似杨花、翻入锦茵。"]'),
('song-ci-926','贺新凉・贺新郎','林正大','宋','宋词','song-ci','贺新凉・贺新郎','[]','环滁皆山也。',141,'宋词/ci.song.13000.json','["环滁皆山也。", "望西南、蔚然深秀，者琅邪也。", "泉水潺潺峰路转，上有醉翁亭也。", "亭、太守自名之也。", "试问醉翁何所乐，乐在乎、山水之间也。", "得之心、寓酒也。", "四时之景无穷也。", "看林霏、日出云归，自朝暮也。", "交错觥筹酣宴处，肴蔌杂然陈也。", "知太守、游而乐也。", "太守醉归宾客从，拥苍颜白发颓然也。", "太守谁，醉翁也。"]'),
('song-ci-927','水调歌','林正大','宋','宋词','song-ci','水调歌','["\u5e90\u5c71", "\u957f\u6c5f"]','庐山几千仞，屹立并长江。',114,'宋词/ci.song.13000.json','["庐山几千仞，屹立并长江。", "杨澜左里，洪涛巨浪日舂撞。", "风止雪消冰净，相与泊舟登岸，攀磴望空谾。", "岩壑响松桧，巨石激流淙。", "事幽寻，遗世俗，绝纷痝。", "幽花野草香满，时有鹤飞双。", "羡子买田筑室，欲使浮岚暖翠，坐卧对轩窗。", "我欲为君说，安得笔如杠。"]'),
('song-ci-928','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','泛舟赤壁，正风徐波静，举尊属客。',120,'宋词/ci.song.13000.json','["泛舟赤壁，正风徐波静，举尊属客。", "渺渺予怀天一望，万顷凭虚独立。", "桂桨空明，洞箫声彻，怨慕还凄恻。", "星稀月淡，江山依旧陈迹。", "因念酾酒临江，赋诗横槊，好在今安适。", "谩寄蜉蝣天地尔，瞬目盈虚消息。", "江上清风，山间明月，与子欢无极。", "翻然一笑，不知东方既白。"]'),
('song-ci-929','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','雪堂闲步，过临皋、霜净晚林木落。',120,'宋词/ci.song.13000.json','["雪堂闲步，过临皋、霜净晚林木落。", "月白风清如此夜，与客行歌相答。", "网举松鲈，手携斗酒，赤壁重寻约。", "悲歌长啸，划然声动寥廓。", "试问日月几何，江流山色，今日应如昨。", "履遍巉岩风露冷，水面怒涛惊跃。", "一叶中流，听其所止，适有孤飞鹤。", "横江东下，问予赤壁游乐。"]'),
('song-ci-930','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','仕宦至卿相，富贵好归乡。',114,'宋词/ci.song.13000.json','["仕宦至卿相，富贵好归乡。", "高车驷马，都人夹道共瞻望。", "意气当年尤盛，荣比昔人衣锦，昼锦以名堂。", "海内知名士，久矣望馀光。", "大丈夫，荣与贵，视寻常。", "丰功令德，要将尧舜致君王。", "事业光施社稷，勋烈遍铭彝鼎，此志孰能量。", "妙语勒金石，千古一欧阳。"]'),
('song-ci-931','贺新凉・贺新郎','林正大','宋','宋词','song-ci','贺新凉・贺新郎','[]','酌以蒲城酒。',139,'宋词/ci.song.13000.json','["酌以蒲城酒。", "撷湘累、秋英满泛，介君眉寿。", "赠君点漆黟川墨，与印文章大手。", "问此别、相逢难又。", "三叠阳关声堕泪，写平时、兄弟情长久。", "离别事，古来有。", "十年骨肉情何厚。", "对江山千里，共期白首。", "夜雨连床追旧事，惟恨音书渐少。", "便只恐、炊沙不饱。", "翰墨新功收汗马，话书囊、无底何时了。", "欢未足，听鸡晓。"]'),
('song-ci-932','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','耿耿银潢净，窗月莹如冰。',114,'宋词/ci.song.13000.json','["耿耿银潢净，窗月莹如冰。", "朱丝一扣，万籁不起冷光凝。", "千古遗音犹在，一洗淫哇郑卫，北里与南陵。", "孰识兴亡事，哀乐不同情。", "咽流泉，戛鸣玉，击浮金。", "老龙啼晓，幼猿忽复暮山吟。", "为我临风再奏，仙鹄翩翻十二，感物一何灵。", "此曲谁当听，四海有知音。"]'),
('song-ci-933','满江红','林正大','宋','宋词','song-ci','满江红','[]','落魄高人，拼百万、青铜一醉。',115,'宋词/ci.song.13000.json','["落魄高人，拼百万、青铜一醉。", "挥素手、朱绳一抹，四筵惊起。", "催织寒虫秋弄月，叫群独雁天浮水。", "更黄鹂、紫燕对春风，争繁脆。", "悲楚国，羁臣意。", "怜汉女，逾千里。", "似深闺恩怨，共相汝尔。", "我有江南丘壑趣，此弦能道心中事。", "要曲肱、时听写松风，云窗里。"]'),
('song-ci-934','朝中措','林正大','宋','宋词','song-ci','朝中措','[]','凌波仙子袜生尘。',57,'宋词/ci.song.13000.json','["凌波仙子袜生尘。", "水上步轻盈。", "种作寒花愁绝，断肠谁与招魂。", "天教付与，含香体素，倾国倾城。", "寂寞岁寒为伴，藉他矾弟梅兄。"]'),
('song-ci-935','满江红','林正大','宋','宋词','song-ci','满江红','[]','太一真人，莲叶向、中流荡漾。',115,'宋词/ci.song.13000.json','["太一真人，莲叶向、中流荡漾。", "凌万顷、风为帆席，浪为轻桨。", "乱舞翠绡云雾薄，卧看玉宇琉璃晃。", "似飘然、万斛举龙骧，随波荡。", "太华顶，花十丈。", "飘一叶，借清赏。", "倩龙眠老手，为渠摹彷。", "鳌禁岧嶢谁寓直，玉堂学士今刘向。", "要清宵、特地杖青藜，来相访。"]'),
('song-ci-936','贺新凉・贺新郎','林正大','宋','宋词','song-ci','贺新凉・贺新郎','["\u897f\u6e56"]','生长湖山曲。',142,'宋词/ci.song.13000.json','["生长湖山曲。", "羡君儿、呼吸湖光，饱餐山渌。", "世外不须论隐逸，谁似先生冰玉。", "自骨冷、神清无俗。", "我不识君曾梦见，炯双瞳、碧色光相烛。", "遗妙语，看不足。", "生平高节难为续。", "到如今、凛凛风生，言犹可录。", "不作相如封禅藁，身后谁荣谁辱。", "争肯效、白头吟曲。", "好与水仙为伴侣，傍西湖、湖畔修修竹。", "时一酹，荐秋菊。"]'),
('song-ci-937','水调歌','林正大','宋','宋词','song-ci','水调歌','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','欲状巴陵胜，千古岳之阳。',114,'宋词/ci.song.13000.json','["欲状巴陵胜，千古岳之阳。", "洞庭在目，远衔山色俯长江。", "浩浩横无涯际，爽气北通巫峡，南望极潇湘。", "骚人与迁客，览物兴尤长。", "锦鳞游，汀兰郁，水鸥翔。", "波澜万顷，碧色上下一天光。", "皓月浮金千里，把酒登楼对景，喜极自洋洋。", "忧乐有谁会，宠辱两俱忘。"]'),
('song-ci-938','木兰花慢','林正大','宋','宋词','song-ci','木兰花慢','["\u9ec4\u6cb3"]','黄河天上派，到东海、去难收。',121,'宋词/ci.song.13000.json','["黄河天上派，到东海、去难收。", "况镜里堪悲，星星白发，早上人头。", "人生尽欢得意，把金尊、对月莫空休。", "天赋君材有用，千金散聚何忧。", "请君听我一清讴。", "锺鼎复奚求。", "但烂醉春风，古来惟有，饮者名留。", "陈王昔时宴乐，拼十千、斗酒恣欢游。", "莫惜貂裘将换，与消千古愁。"]'),
('song-ci-939','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','听说竹楼好，佳地占黄冈。',114,'宋词/ci.song.13000.json','["听说竹楼好，佳地占黄冈。", "月波相接，俯临江濑挹山光。", "急雨檐喧瀑布，密雪瓴敲碎玉，幽阒兴尤长。", "琴调更虚畅，诗韵转清扬。", "公退暇，披鹤氅，戴华阳。", "手披周易，消磨世虑坐焚香。", "缥缈烟云竹树，迎送夕阳素月，胜概总难量。", "欲辨骚人事，瀹茗漱清觞。"]'),
('song-ci-940','清平乐','林正大','宋','宋词','song-ci','清平乐','[]','若耶溪女。',54,'宋词/ci.song.13000.json','["若耶溪女。", "笑隔荷花语。", "日照新妆明楚楚，香袖风颻轻举。", "谁家白面游郎。", "两三遥映垂杨。", "醉踏落花归去，踌躇空断柔肠。"]'),
('song-ci-941','满江红','林正大','宋','宋词','song-ci','满江红','[]','为忆当时，沈醉里、青楼弄月。',115,'宋词/ci.song.13000.json','["为忆当时，沈醉里、青楼弄月。", "闲想像、绣帏珠箔，魂飞心折。", "羞向妲娥谈旧事，几经三五盈还缺。", "望翠眉、蝉鬓一天涯，伤离别。", "寻作梦，巫云结。", "流别泪，湘江咽。", "对花深两岸，忽添悲切。", "试与含愁弹绿绮，知音不遇弦空绝。", "忽窗前、一夜寄相思，梅花发。"]'),
('song-ci-942','满江红','林正大','宋','宋词','song-ci','满江红','[]','寂寞江城，┾只共、梅花幽独。',115,'宋词/ci.song.13000.json','["寂寞江城，┾只共、梅花幽独。", "揩病眼、佳人何许，嫣然空谷。", "幻出天姿真富贵，朱唇滞酒红生肉。", "笑漫山、繁李与夭桃，俱粗俗。", "迟日丽，春睡足。", "明月照，尤清淑。", "算移更千里，远从西蜀。", "流落天涯应可念，为渠剧饮仍歌曲。", "怕明朝、酒醒落纷纷，那忍触。"]'),
('song-ci-943','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','落日岘山下，倒着接罗罱回。',115,'宋词/ci.song.13000.json','["落日岘山下，倒着接罗罱回。", "傍人笑问山翁，日日醉归来。", "三万六千长日，一日杯倾三百，罍麴筑糟抬。", "汉水鸭头绿，变酒入金罍。", "白铜鞮，鸬鹚杓，鹦鹉杯。", "轻车快马，凤笙龙管更相催。", "自身清风明月，刚道不须钱买，对此玉山颓。", "水自东流去，猿自夜声哀。"]'),
('song-ci-944','江神子・江城子','林正大','宋','宋词','song-ci','江神子・江城子','[]','狂胡鞍马自为家。',86,'宋词/ci.song.13000.json','["狂胡鞍马自为家。", "遣宫娃。", "嫁胡沙。", "万里风烟，行不见京华。", "马上思归哀怨极，推却手，奏琵琶。", "胡儿共听亦咨嗟。", "貌如花。", "落天涯。", "谁按新声，争向汉宫夸。", "纤手不知离别苦，肠欲断，恨如麻。"]'),
('song-ci-945','意难忘','林正大','宋','宋词','song-ci','意难忘','[]','蜀道登天。',114,'宋词/ci.song.13000.json','["蜀道登天。", "望峨眉横绝，石栈相连。", "西来当鸟道，逆浪俯回川。", "猿与鹤，莫攀缘。", "九折耸岩峦。", "算咫尺、扪参历井，回首长叹。", "西游何日当还。", "听子规啼月，愁减朱颜。", "连峰天一握，飞瀑壑争喧。", "排剑阁，越天关。", "豺虎乱朝昏。", "问锦城，虽云乐土，何似家山。"]'),
('song-ci-946','沁园春','林正大','宋','宋词','song-ci','沁园春','[]','庐阜诸峰，炉峰绝胜，草堂介焉。',140,'宋词/ci.song.13000.json','["庐阜诸峰，炉峰绝胜，草堂介焉。", "敞明窗净室，素屏虚榻，要仰观山色。", "俯听流泉。", "中有池台，旁多竹卉，夹涧杉松高刺天。", "堂之北，据层崖积石，绿荫浓鲜。", "堂东瀑布飞悬。", "似雨露霏微珠贯穿。", "有春花秋月，夏云冬雪，阴晴显晦，雾吐烟吞。", "右抱琴书，左携妻子，杖屦从容尽暮年。", "平生志，赖清泉白石，实听余言。"]'),
('song-ci-947','摸鱼儿','林正大','宋','宋词','song-ci','摸鱼儿','[]','泛松江、水遥山碧，清寒微动秋浦。',140,'宋词/ci.song.13000.json','["泛松江、水遥山碧，清寒微动秋浦。", "霜云霁色横无际，别鹄惊鸿无数。", "朝又暮。", "听牧笛长吹，隐隐渔榔度。", "骚人才子。", "既览物兴怀，浮游尘外，啸傲剧清思。", "人间世。", "扰扰荣途要路。", "瀛洲琼馆安所。", "轩裳何似渔蓑兴，萧散龙游鹤渚。", "须归去。", "办双桨孤帆，云月和烟雨。", "江湖伴侣。", "趁社橘初黄，汀葭馀翠，成我莼鲈趣。"]'),
('song-ci-948','意难忘','林正大','宋','宋词','song-ci','意难忘','[]','汹汹松风。',114,'宋词/ci.song.13000.json','["汹汹松风。", "更浮云皓皓，轻度春空。", "精神新发越，宾主少从容。", "犀箸厌，涤昏懵。", "茗碗策奇功。", "待试与，平章甲乙，为问涪翁。", "建溪日铸争雄。", "笑罗山梅岭，不数严邛。", "胡桃添味永，甘菊助香浓。", "投美剂，与和同。", "雪满兔瓯溶。", "便一枕，庄周蝶梦，安乐窝中。"]'),
('song-ci-949','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','坐愁书室，谩临风、遐想蓬莱高致。',120,'宋词/ci.song.13000.json','["坐愁书室，谩临风、遐想蓬莱高致。", "抚鹤扪松长叹息，失足误来人世。", "紫禁九重，碧山万里，无路鸣珂佩。", "江山胜处，且寻花柳倾醉。", "不堪送客清川，系帆渌水，烟景供憔悴。", "更举芳尊浇别恨，逸趣浮游天外。", "雄笔横挥，素琴轻拍，一笑成扬袂。", "洛阳秋早，归时同赏鲈脍。"]'),
('song-ci-950','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','杏花春晚，散馀芳、著处萦帘穿箔。',120,'宋词/ci.song.13000.json','["杏花春晚，散馀芳、著处萦帘穿箔。", "唤起幽人明月夜，步月褰衣行乐。", "置酒花前，清香争发，雪挽长条落。", "山城薄酒，共君一笑同酌。", "且须眼底柔英，尊中清影，放待杯行数。", "莫道洞箫声断处，月落杯空牢寞。", "只恐明朝，残红栖绿，卷地东风恶。", "更须来岁，花时携酒寻约。"]'),
('song-ci-951','水调歌','林正大','宋','宋词','song-ci','水调歌','[]','华裾织翡翠，金辔闹珑璁。',114,'宋词/ci.song.13000.json','["华裾织翡翠，金辔闹珑璁。", "宝蹄轻稳，香尘满地骤隆隆。", "云是东京才子，名擅文章钜伯，一世独推雄。", "高盖拥宾从，下马气如虹。", "运元精，锺神秀，贯当中。", "磊磊落落，二十八宿列心胸。", "前殿当年奏赋，笔补天工造化，声价欲摩空。", "却笑庞眉客，垂翅附冥鸿。"]'),
('song-ci-952','虞美人','林正大','宋','宋词','song-ci','虞美人','[]','武昌七十庞眉叟。',66,'宋词/ci.song.13000.json','["武昌七十庞眉叟。", "学笛从年少。", "萧萧笛竹楚山秋。", "当日买林、曾典黑貂裘。", "一声占尽秋江月。", "天外行云绝。", "如今老去兴犹迟。", "尚想时时、一曲梦中吹。"]'),
('song-ci-953','江神子・江城子','林正大','宋','宋词','song-ci','江神子・江城子','[]','拾遗流落锦宫城。',86,'宋词/ci.song.13000.json','["拾遗流落锦宫城。", "故人情。", "眼为青。", "时向百花，潭水濯冠缨。", "韦曲杜陵行乐地，尘土暗，叹漂零。", "园翁溪友总比邻。", "酒盈尊。", "肯相亲。", "落日蹇驴，扶醉两眉颦。", "磊落平生忠义胆，诗与酒，醉还醒。"]'),
('song-ci-954','沁园春','林正大','宋','宋词','song-ci','沁园春','[]','子陵先生，故人光武，以道相忘。',140,'宋词/ci.song.13000.json','["子陵先生，故人光武，以道相忘。", "幸炎符在握，六龙在御，臣来亿兆，阳德方刚。", "自是先生，独全高节，归去江湖乐未央。", "动星象，被羊裘傲睨，一世轩裳。", "高哉不事侯王。", "爱此地山高水更长。", "盖先生心地，超乎日月，又谁如光武，器量包荒。", "立懦廉顽，有功名教，万世清风更激扬。", "无古今，想云山郁郁，江水泱泱。"]'),
('song-ci-955','临江仙','林正大','宋','宋词','song-ci','临江仙','[]','须信乾坤如逆旅，都来一梦浮生。',70,'宋词/ci.song.13000.json','["须信乾坤如逆旅，都来一梦浮生。", "夜游秉烛尽欢情。", "阳春烟景媚，乐事史来并。", "座上群公皆俊秀，高谈幽赏俱清。", "飞觞醉月莫辞频。", "休论金谷罚，七步看诗成。"]'),
('song-ci-956','酹江月・念奴娇','林正大','宋','宋词','song-ci','酹江月・念奴娇','[]','开元盛日，爱名花绝品，浅红深紫。',120,'宋词/ci.song.13000.json','["开元盛日，爱名花绝品，浅红深紫。", "云想衣裳□□映，曲槛软风微度。", "群玉山头，瑶台月下，一□香凝露。", "嫣然倾国，巫山肠断云雨。", "借问标格风流，汉宫谁似，飞燕红妆舞。", "解释春风无限恨，博得君王笑语。", "七宝杯深，蒲萄酒满，胜赏今何许。", "沈香亭北，倚阑终日凝伫。"]'),
('song-ci-957','沁园春','洪咨夔','宋','宋词','song-ci','沁园春','[]','诗不云乎，蒹葭苍苍，白露为霜。',139,'宋词/ci.song.13000.json','["诗不云乎，蒹葭苍苍，白露为霜。", "看高山乔木，青云老干，英华滋液，亦敛而藏。", "匠石操斤游林下，便一举采之充栋梁。", "须知道，是天将大任，翕处还张。", "薇郎玉佩丁当。", "问何事午桥花竹庄。", "又星回岁换，腊残春浅，锦熏笼紫，栗玉杯黄。", "唤起东风，吹醒宿酒，把甲子从头重数将。", "明朝去，趁传柑宴近，满袖天香。"]'),
('song-ci-958','沁园春','洪咨夔','宋','宋词','song-ci','沁园春','[]','归去来兮，杜宇声声，道不如归。',139,'宋词/ci.song.13000.json','["归去来兮，杜宇声声，道不如归。", "正新烟百五，雨留酒病，落红一尺，风妒花期。", "睡起绿窗，销残香篆，手板搘颐还倒持。", "无人解，自追游仙梦，作送春诗。", "风流不似年时。", "把别墅江山供弈棋。", "空一川芳草，半池晴絮，歌翻长恨，赋续怀离。", "桃叶渡头，沈香亭北，往事悠悠难重思。", "徘徊处，看鸣鸠唤妇，乳燕将儿。"]'),
('song-ci-959','沁园春','洪咨夔','宋','宋词','song-ci','沁园春','[]','饮马咸池，总辔昆仑，横鹜九州。',139,'宋词/ci.song.13000.json','["饮马咸池，总辔昆仑，横鹜九州。", "庆中兴机会，天生山甫，非常事业，天授留侯。", "左搏龙蛇，右驯虎兕，万里中原谈笑收。", "功名早，便貂蝉猎猎，飞出兜牟。", "新甿无限欢讴。", "尽卖剑卖刀归买牛。", "正麦摇熏吹，黄迷断垄，秧涵朝雨，绿遍平畴。", "眼底太平，不图再见，罗拜焚香青海头。", "从今去，愿君王万岁，元帅千秋。"]'),
('song-ci-960','沁园春','洪咨夔','宋','宋词','song-ci','沁园春','[]','秋气悲哉，薄寒中人，皇皇何之。',139,'宋词/ci.song.13000.json','["秋气悲哉，薄寒中人，皇皇何之。", "更黄花吹雨，苍苔滑屐，栏空斗鸭，床老支龟。", "静里跫音，明边眉睫，蹴踏星河天脱鞿。", "清谈久，顿两忘妍丑，嫫姆西施。", "濂溪家住江湄。", "爱出水芙蓉清绝姿。", "好光风霁月，一团和气，尸居龙见，神动天随。", "著察工夫，诚存体段，个里语言文字非。", "君家事，莫空将太极。", "散大图碑。"]'),
('song-ci-961','风流子','洪咨夔','宋','宋词','song-ci','风流子','[]','锦幄醉荼䕷。',133,'宋词/ci.song.13000.json','["锦幄醉荼䕷。", "狻猊暖、银蒜压烟霏。", "正韩范安边，欧苏领客，红芳庭院，绿荫窗扉。", "著句挽春春肯住，更判羽觞挥。", "金系花腰，玉匀人面，娇慵无力，娅姹相依。", "繁华都能几，青油幕、好与遮护晴晖。", "寄语东君，莫教一片轻飞。", "向温馨深处，留欢卜夜，月移花影，露裛人衣。", "只恐明朝西垣，有诏催归。"]'),
('song-ci-962','贺新郎','洪咨夔','宋','宋词','song-ci','贺新郎','[]','露洗秋光透。',142,'宋词/ci.song.13000.json','["露洗秋光透。", "指岷峨、无边峭碧，与君为寿。", "万里同随琴鹤到，只愿人情长久。", "尽头白、眼青如旧。", "从臾功名三尺剑，倚函关、风雨蛟龙吼。", "谈笑取，印如斗。", "从今尽展眉峰皱。", "看诸郎、翩翩黄甲，班班蓝绶。", "一簇孙枝扶膝下，翠竹碧梧争秀。", "便嘉庆、图中都有。", "花影婆娑清昼永，护新凉、更著丝簧手。", "欢未尽，剩添酒。"]'),
('song-ci-963','贺新郎','洪咨夔','宋','宋词','song-ci','贺新郎','[]','风软帘花约。',142,'宋词/ci.song.13000.json','["风软帘花约。", "玉壶天、芙蕖欲盖，篔筜初槊。", "宿霭收阴晴色定，一点星明碧落。", "光拍满、浮溪岝□。", "银栉铁冠风物古，更秧青、麦熟蚕登箔。", "欢取酒，为君酌。", "华堂衮绣今如昨。", "长官清、水晶灯照，珊瑚钩琢。", "富贵功名知有样，晨起一声檐鹊。", "便好趁、六更宫钥。", "龙尾朝回长燕喜，宝香深、醉引莱衣著。", "吹紫凤，舞黄鹤。"]'),
('song-ci-964','贺新郎','洪咨夔','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','放了孤山鹤。',142,'宋词/ci.song.13000.json','["放了孤山鹤。", "向西湖、问讯水边，嫩寒篱落。", "试粉盈盈微见面，一点芳心先著。", "正日暮、烟轻云薄。", "欲搅清香和月咽，倩冯夷、为洗黄金杓。", "花向我，劝多酌。", "单于吹彻今成昨。", "未甘渠、琢玉为堂，把春留却。", "倚遍黄昏栏十二，知被儿曹先觉。", "更笑杀、卢仝赤脚。", "但得东风先手在，管绿阴、好践青青约。", "方寸事，两眉角。"]'),
('song-ci-965','贺新郎','洪咨夔','宋','宋词','song-ci','贺新郎','[]','谁识昂昂鹤。',142,'宋词/ci.song.13000.json','["谁识昂昂鹤。", "且随缘、剩水残山，东村西落。", "世事几番新局面，看底却高三著。", "况转首、西山日薄。", "雪意压檐梅索笑，任柄长、柄短邻家杓。", "篘小瓮，动孤酌。", "见花忆得年时昨。", "正微醺、独步黄昏，被花迷却。", "冷月吹香春弄影，么凤梢头先觉。", "恍梦断、罗浮山脚。", "欲寄心期无驿使，想凌寒、不奈腰肢约，空凭暖，画栏角。"]'),
('song-ci-966','汉宫春','洪咨夔','宋','宋词','song-ci','汉宫春','[]','南极仙翁，占太微元盖，洞府为家。',114,'宋词/ci.song.13000.json','["南极仙翁，占太微元盖，洞府为家。", "身骑若木倒景，手弄青霞。", "芙蓉飞旆，映一川、新绿平沙。", "好与问，东风结子，几回开遍桃花。", "况是初元玉历，更循环数起，希有年华。", "长把清明夜气，养就丹砂。", "麻姑送酒，安期生、遗枣如瓜。", "呼儿烹试，头纲小凤团茶。"]'),
('song-ci-967','夏初临','洪咨夔','宋','宋词','song-ci','夏初临','[]','铁瓮栽荷，铜彝种菊，胆瓶萱草榴花。',120,'宋词/ci.song.13000.json','["铁瓮栽荷，铜彝种菊，胆瓶萱草榴花。", "庭户深沈，画图低映窗纱。", "数枝奇石谽谺。", "染宣和、瑞露明霞。", "於菟长啸，风林未鸣，霜草先斜。", "雪丝香里，冰粉光中，兴来进酒，睡起分茶。", "轻雷急雨，银篁迸插檐牙。", "凉入琵琶。", "枕帏开、又送蟾华。", "问生涯。", "山林朝市，取次人家。"]'),
('song-ci-968','满江红','洪咨夔','宋','宋词','song-ci','满江红','[]','送雨迎晴，花事过、一庭芳草。',115,'宋词/ci.song.13000.json','["送雨迎晴，花事过、一庭芳草。", "帘影动、归来双燕，似悲还笑。", "笑我不知人意变，悲人空为韶华老。", "满天涯、都是别离愁，无人扫。", "海棠晚，荼䕷早。", "飞絮急，青梅小。", "把风流酝藉，向谁倾倒。", "秋水盈盈魂梦远，春云漠漠音期悄。", "最关情、鹎鵊一声催，窗纱晓。"]'),
('song-ci-969','满江红','洪咨夔','宋','宋词','song-ci','满江红','[]','把酒西风，浑莫问、主宾谁恶。',115,'宋词/ci.song.13000.json','["把酒西风，浑莫问、主宾谁恶。", "千古事、几□遇合，几人流落。", "肝胆轮囷溟渤小，精神浩荡蓬莱薄。", "望拒霜、红处是东山，长如昨。", "苍苔迹，何曾削。", "黄叶梦，何难觉。", "等春云出岫，秋波归壑。", "老子婆娑风度远，佳人缥缈腰肢约。", "况登高、节过又登高，须多酌。"]'),
('song-ci-970','天香','洪咨夔','宋','宋词','song-ci','天香','[]','云母屏开，博山炉熨，人间南极星现。',117,'宋词/ci.song.13000.json','["云母屏开，博山炉熨，人间南极星现。", "酥篆千秋，灯图百子，酒浪花光照面。", "堂深戏彩，任父老、儿童争劝。", "耆艾相将潞国，精明恰如清献。", "春风飘香合殿。", "仗云齐、漏迟宫箭。", "正好簪荷入侍，帕柑传宴。", "日月华虫蒨绚。", "便与试、胸中五纹线。", "寿域长开，洪钧长转。"]'),
('song-ci-971','水调歌头','洪咨夔','宋','宋词','song-ci','水调歌头','[]','四海止斋老，百世水心翁。',114,'宋词/ci.song.13000.json','["四海止斋老，百世水心翁。", "都将不尽事业，付与道俱东。", "气脉中庸大学，体统采薇天保，几疏柘袍红，千仞倚寥碧，一点驾归鸿。", "扈江蓠，贯薜荔，制芙蓉。", "午桥绿野深处，心与境俱融。", "搏控乾坤龙马，簸弄坎离日月，苍鬓映方瞳。", "只恐又催诏，飞度橘花风。"]'),
('song-ci-972','水调歌头','洪咨夔','宋','宋词','song-ci','水调歌头','[]','如此好明月，梅里自来无。',114,'宋词/ci.song.13000.json','["如此好明月，梅里自来无。", "炎云溽雾收尽，宇宙一冰壶。", "浅濑乍分随合，清影欲连还断，滉漾玉浮图。", "风物庾楼似，秋思欠菰蒲。", "醉魂醒，尘骨换，我非吾。", "琼箫紫凤何许，风露足清都。", "君看流光多处，缥缈澼洸人立，白与藕花俱。", "只恐姮娥妒，凉透粟生肤。"]'),
('song-ci-973','念奴娇','洪咨夔','宋','宋词','song-ci','念奴娇','[]','香山老矣，正商量不下，去留蛮素。',120,'宋词/ci.song.13000.json','["香山老矣，正商量不下，去留蛮素。", "独立踌躇肠欲断，一段若耶溪女。", "水底新妆，空中香袖，斜日疏风浦。", "向人欲语，垂杨清荫多处。", "便好花里唤船，碧筒白酒，微吸荷心苦。", "佳月一钩天四碧，隐约明波横注。", "雪藕逢丝，擘莲见薏，枕簟凉如雨。", "一双宿鹭，伴人永夜翘伫。"]'),
('song-ci-974','念奴娇','洪咨夔','宋','宋词','song-ci','念奴娇','[]','光风霁月，信行窝到处，人间天上。',120,'宋词/ci.song.13000.json','["光风霁月，信行窝到处，人间天上。", "一笑唤回新造化，满眼翠舒红放。", "脑后功名，脚跟富贵，梦断春旗仗。", "辐巾萧散，任他虮虱龙象。", "正是杨柳初眠，海棠半睡，锦绣天开障。", "鹤骨松筋年望八，得醉不妨澜浪，节过烧灯，时催修禊，迎面韶华荡。", "宗文扶著，问翁马首何向。"]'),
('song-ci-975','更漏子','洪咨夔','宋','宋词','song-ci','更漏子','[]','眼生花，灯缀粟。',58,'宋词/ci.song.13000.json','["眼生花，灯缀粟。", "人在黄金列屋。", "金缕细，道冠明。", "胆瓶凉意生。", "缓歌弦，停酒斝。", "待得香风吹下。", "斜月转，断云回。", "风流不让梅。"]'),
('song-ci-976','好事近','洪咨夔','宋','宋词','song-ci','好事近','[]','二十四番风，才见一番花鸟。',53,'宋词/ci.song.13000.json','["二十四番风，才见一番花鸟。", "已是有人春瘦，正远山横峭。", "踏青底用十分晴，半阴晴方好。", "深院日长睡起，又海棠开了。"]'),
('song-ci-977','朝中措','洪咨夔','宋','宋词','song-ci','朝中措','[]','荷花香里藕丝风。',56,'宋词/ci.song.13000.json','["荷花香里藕丝风。", "人在水晶宫。", "天上桥成喜鹊，云边帆认归鸿。", "去天尺五城南社，趣对柘袍红。", "若问安边长策，莫须浪说和戎。"]'),
('song-ci-978','朝中措','洪咨夔','宋','宋词','song-ci','朝中措','[]','翠盆红药护觥筹。',57,'宋词/ci.song.13000.json','["翠盆红药护觥筹。", "风物似扬州。", "春事一声杜宇，人生能几狐裘。", "有山可买，有书可读，不愿封留。", "一任东风辇路，群公苍佩鸣璆。"]'),
('song-ci-979','朝中措','洪咨夔','宋','宋词','song-ci','朝中措','[]','滂葩七十二滩春。',57,'宋词/ci.song.13000.json','["滂葩七十二滩春。", "锺瑞石麒麟。", "流水行云才思，光风霁月精神。", "金蕉进酒，斑衣起舞，喜气津津。", "群玉峰头环佩，紫薇花底丝纶。"]'),
('song-ci-980','点绛唇','洪咨夔','宋','宋词','song-ci','点绛唇','[]','花事无多，笙歌绾取东风住。',50,'宋词/ci.song.13000.json','["花事无多，笙歌绾取东风住。", "玉彝雕俎，楼外更筹屡。", "醉唤骊驹，催上天梯去。", "君知否。", "半边铜虎。", "邓艾经行路。"]'),
('song-ci-981','西江月','洪咨夔','宋','宋词','song-ci','西江月','[]','庭下宜男萱草，墙头结子榴花。',58,'宋词/ci.song.13000.json','["庭下宜男萱草，墙头结子榴花。", "非烟非雾富平家。", "人物风流如画。", "宝月曾修玉斧，银河欲泛仙槎。", "美人睡起绿云斜。", "一笑扶将寿斝。"]'),
('song-ci-982','浣溪沙','洪咨夔','宋','宋词','song-ci','浣溪沙','[]','苍鹤飞来水竹幽。',48,'宋词/ci.song.13000.json','["苍鹤飞来水竹幽。", "初弦凉月一帘秋。", "木犀花底试新篘。", "凤味砚供无尽藏，龙飞榜占最高头。", "慈闱洗眼看封侯。"]'),
('song-ci-983','浣溪沙','洪咨夔','宋','宋词','song-ci','浣溪沙','[]','细雨斜风寂寞秋。',48,'宋词/ci.song.13000.json','["细雨斜风寂寞秋。", "黄花压鬓替人羞。", "归舟云树负箜篌。", "燕子楼寒迷楚梦，凤皇池暖惬秦讴。", "暮云凝碧可禁愁。"]'),
('song-ci-984','浣溪沙','洪咨夔','宋','宋词','song-ci','浣溪沙','[]','小雨轻霜作嫩寒。',48,'宋词/ci.song.13000.json','["小雨轻霜作嫩寒。", "蜡梅开尽菊花乾。", "清香收拾贮诗肝。", "文武两魁前样在，功名四谏后来看。", "麻姑进酒斗阑干。"]'),
('song-ci-985','浣溪沙','洪咨夔','宋','宋词','song-ci','浣溪沙','[]','六曲屏山似去年。',48,'宋词/ci.song.13000.json','["六曲屏山似去年。", "雪花欺得怕寒肩。", "小窗和月照无眠。", "笔点轻澌心欲折，烛摇斜吹泪空煎。", "伴人梅影更堪怜。"]'),
('song-ci-986','菩萨蛮','洪咨夔','宋','宋词','song-ci','菩萨蛮','[]','翠翘花艾年时昨。',52,'宋词/ci.song.13000.json','["翠翘花艾年时昨。", "斗新五采同心索。", "含笑祝千秋。", "长眉如莫愁。", "流光旋磨蚁。", "换调重拈起。", "深院竹和丝。", "皱红裁舞衣。"]'),
('song-ci-987','鹧鸪天','洪咨夔','宋','宋词','song-ci','鹧鸪天','[]','天理从来屈有信。',64,'宋词/ci.song.13000.json','["天理从来屈有信。", "东风到处物皆春。", "门前骢马权奇种，台上慈乌反哺心。", "花岛屐，柳湖尊。", "好将长健傲长贫。", "诸孙认取翁翁意，插架诗书不负人。"]'),
('song-ci-988','蝶恋花','洪咨夔','宋','宋词','song-ci','蝶恋花','[]','画斛黄花寒更好。',70,'宋词/ci.song.13000.json','["画斛黄花寒更好。", "人爱花繁，却被花催老。", "旧恨新愁谁酝造。", "带围暗减知多少。", "开眼万般浑是恼。", "只仗微醺，假寐宽怀抱。", "隔屋愁眉春思早。", "数声啼破池塘草。"]'),
('song-ci-989','临江仙','洪咨夔','宋','宋词','song-ci','临江仙','[]','万紫千红鬓上粉，聚成一撮精神。',70,'宋词/ci.song.13000.json','["万紫千红鬓上粉，聚成一撮精神。", "宣和宫样太清真。", "韶风摇斗帐，芳露湿纶巾。", "消得流莺花底滑，一声惊起梁尘。", "扶将芍药牡丹春。", "光浮金盏面，香到玉池津。"]'),
('song-ci-990','南乡子','洪咨夔','宋','宋词','song-ci','南乡子','[]','风雨过芳晨。',66,'宋词/ci.song.13000.json','["风雨过芳晨。", "多少愁红恨紫尘。", "两点眉尖凝远碧，纷纷。", "又被杨花误一春。", "金凤压娇云。", "睡起纱窗背欠伸。", "心事欲言言不尽，沈沈。", "乳燕雏莺触拨人。"]'),
('song-ci-991','眼儿媚','洪咨夔','宋','宋词','song-ci','眼儿媚','[]','平沙芳草渡头村。',58,'宋词/ci.song.13000.json','["平沙芳草渡头村。", "绿遍去年痕。", "游丝下上，流莺来往，无限销魂。", "绮窗深静人归晚，金鸭水沈温。", "海棠影下，子规声里，立尽黄昏。"]'),
('song-ci-992','眼儿媚','洪咨夔','宋','宋词','song-ci','眼儿媚','[]','花光灯影浸帘栊。',58,'宋词/ci.song.13000.json','["花光灯影浸帘栊。", "蓬岛现仙翁。", "瑶裾织翠，诗瞳点碧，酒脸潮红。", "窦郎阴德知多少，万卷奏新功。", "前庭梧竹，后园桃李，无限春风。"]'),
('song-ci-993','南乡子','洪咨夔','宋','宋词','song-ci','南乡子','[]','霜月冷婷婷。',66,'宋词/ci.song.13000.json','["霜月冷婷婷。", "夹岸芦花雪点成。", "短艇水晶宫里系，闲情。", "谁道芙蓉更有城。", "阿鹊数归程。", "人倚低窗小画屏。", "莫恨年华飞上鬓，堪凭。", "一度春风一度莺。"]'),
('song-ci-994','祝英台近','洪咨夔','宋','宋词','song-ci','祝英台近','[]','脸长红，眉半白，老鹤饱风露。',95,'宋词/ci.song.13000.json','["脸长红，眉半白，老鹤饱风露。", "岁换星移，禄运又交午。", "须知命带将来，福推不去，稳做个、荣华彭祖。", "记初度。", "谢他紫燕黄鹂，争先送好语。", "春满湖山，历历旧游处。", "管教柳外行厨，花边步屧，长占断、好晴奇雨。"]'),
('song-ci-995','谒金门','洪咨夔','宋','宋词','song-ci','谒金门','[]','春正美。',53,'宋词/ci.song.13000.json','["春正美。", "满眼万红千紫。", "收拾群香归瓮蚁。", "长年花信里。", "深院帘栊如水。", "双燕呢喃芳垒。", "唾碧轻衫人送喜。", "梅梢新结子。"]'),
('song-ci-996','谒金门','洪咨夔','宋','宋词','song-ci','谒金门','[]','开笑口。',53,'宋词/ci.song.13000.json','["开笑口。", "又是茱萸重九。", "好水佳山长似旧。", "健如黄犊走。", "菊蕊峥峥如豆。", "风雨轻寒初透。", "檐外鹊声谁送酒。", "莫闲金碗手。"]'),
('song-ci-997','卜算子','洪咨夔','宋','宋词','song-ci','卜算子','[]','簸弄柳梢春，呼吸花心露。',52,'宋词/ci.song.13000.json','["簸弄柳梢春，呼吸花心露。", "倦粉娇黄扇底风，尽向眉心度。", "唤醒海棠红，约住樱桃素。", "上到瑶台最上层，共跨青鸾去。"]'),
('song-ci-998','卜算子','洪咨夔','宋','宋词','song-ci','卜算子','[]','芍药打团红，萱草成窝绿。',52,'宋词/ci.song.13000.json','["芍药打团红，萱草成窝绿。", "帘卷疏风燕子归，依旧卢仝屋。", "贫放麴生疏，闻到青奴熟。", "扫地焚香伴老仙，人胜连环玉。"]'),
('song-ci-999','柳梢青','洪咨夔','宋','宋词','song-ci','柳梢青','[]','野服纶巾。',61,'宋词/ci.song.13000.json','["野服纶巾。", "白发红颊，无限阳春。", "二满三平，粗衣淡饭，锺鼎山林。", "尊前喜气轮囷，道蚕麦、今朝甲申。", "天放新晴，人占一饱，老子宽心。"]'),
('song-ci-0','天仙子','洪咨夔','宋','宋词','song-ci','天仙子','[]','风月分将秋一半。',80,'宋词/ci.song.14000.json','["风月分将秋一半。", "昨夜月明今夜满。", "有人笙鹤御风来，玉绳转。", "银河淡。", "凉入天孙云锦段。", "笑拈桂枝香婉娩。", "十字金书光照眼。", "看看细札促归来，漏声缓。", "珂声远。", "夜宿玉堂谁是伴。"]'),
('song-ci-1','摸鱼儿','赵与洽','宋','宋词','song-ci','摸鱼儿','[]','甚幽人、被花勾引，庭皋遥夜来去。',139,'宋词/ci.song.14000.json','["甚幽人、被花勾引，庭皋遥夜来去。", "江空岁晚谁为伴，只有琼枝玉树。", "愁绝处。", "望万里瑶台，梦断迷归路。", "花还解语。", "更雪琢精神，冰相韵度。", "粉黛尽如土。", "飘仙袂，曾缀蕊珠鹓鹭。", "云茵月障千步。", "莫教衣袖天香冷，恐怨美人迟暮。", "更起舞。", "任斗转参横，翠羽曾知否。", "尘缘自误。", "终待骖鸾，乘风共去。", "长作此花主。"]'),
('song-ci-2','江城梅花引','赵与洽','宋','宋词','song-ci','江城梅花引','[]','单衾寒引画龙声。',108,'宋词/ci.song.14000.json','["单衾寒引画龙声。", "雨初晴。", "月微明。", "竹外溪边，低见一枝横。", "澹月疏花三四点，尚春浅，早相看、似有情。", "夜来袖冷暗香凝。", "恨半销，酒半醒。", "靓妆照影，未忺整、雪艳冰清。", "只恐不禁、愁绝易飘零。", "待得南楼三弄彻、君试看，比从前、更瘦生。"]'),
('song-ci-3','碧牡丹','李致远','宋','宋词','song-ci','碧牡丹','[]','破镜重圆，分钗合钿，重寻绣户珠箔。',119,'宋词/ci.song.14000.json','["破镜重圆，分钗合钿，重寻绣户珠箔。", "说与从前，不是我情薄。", "都缘利役名牵，飘蓬无定，翻成轻负。", "别后情怀，有万千牢落。", "经时最苦分携，都为伊、甘心寂寞。", "纵满眼、闲花媚柳，终是强欢不乐。", "待凭鳞羽，说与相思，水远天长又难托。", "而今幸已再逢，把轻离断却。"]'),
('song-ci-4','失调名','张琳','宋','宋词','song-ci','失调名','[]','持节助调羹。',6,'宋词/ci.song.14000.json','["持节助调羹。"]'),
('song-ci-5','翻香令','邬虑','宋','宋词','song-ci','翻香令','[]','醉和春恨拍阑干。',68,'宋词/ci.song.14000.json','["醉和春恨拍阑干。", "宝香半灺倩谁翻。", "丁宁告、东风道，小楼空，斜月杏花寒。", "梦魂无夜不关山。", "江南千里霎时间。", "且留得、鸾光在，等归时，双照泪痕乾。"]'),
('song-ci-6','如梦令','冯熔','宋','宋词','song-ci','如梦令','[]','素养浩然之气，铁石心肠谁拟。',40,'宋词/ci.song.14000.json','["素养浩然之气，铁石心肠谁拟。", "蒿目县前江，不逐队鱼游戏。", "藏器。", "藏器。", "只等时乘奋起。"]'),
('song-ci-7','念奴娇','刘镇2','宋','宋词','song-ci','念奴娇','[]','调冰弄雪，想花神清梦，徘徊南土。',120,'宋词/ci.song.14000.json','["调冰弄雪，想花神清梦，徘徊南土。", "一夏天香收不起，付与蕊仙无语。", "秀入精神，凉生肌骨，销尽人间暑。", "稼轩愁绝，惜花还胜儿女。", "长记歌酒阑珊，开时向晚，笑浥金茎露。", "月浸栏干天似水，谁伴秋娘窗户。", "困殢云鬟，醉敧风帽，总是牵情处。", "返魂何在，玉川风味如许。"]'),
('song-ci-8','行香子','刘镇2','宋','宋词','song-ci','行香子','[]','露叶烟条。',84,'宋词/ci.song.14000.json','["露叶烟条。", "天与多娇。", "算风流、张绪难消。", "恼人春思，政自无聊。", "赖敛愁眉，酣醉眼，减围腰。", "风絮相邀。", "蝶弄莺嘲。", "最关情、是短长桥。", "解骖分袂，催上兰桡。", "更绿波平，红日坠，碧云遥。"]'),
('song-ci-9','沁园春','刘镇2','宋','宋词','song-ci','沁园春','[]','谁似花翁，长年湖海，蹇驴弊裘。',140,'宋词/ci.song.14000.json','["谁似花翁，长年湖海，蹇驴弊裘。", "想江尘醉帽，青楼歌扇，挥金谈笑，惜玉风流。", "吴下阿蒙，江南老贺，肯为良田二顷谋。", "人间世，算到头一梦，蝼蚁王侯。", "悠悠。", "吾道何求。", "况白首相逢说旧游。", "记疏风淡月，寒灯古寺，平章诗境，分付糟丘。", "聚散抟沙，炎凉转烛，归去来兮万事休。", "无何有，问从前那个，骑鹤扬州。"]'),
('song-ci-10','沁园春','刘镇2','宋','宋词','song-ci','沁园春','[]','爽气西来，玉削群峰，千杉万松。',140,'宋词/ci.song.14000.json','["爽气西来，玉削群峰，千杉万松。", "望疏林清旷，晴烟紫翠，雪边回棹，柳外闻钟。", "夜月琼田，夕阳金界，倒影楼台表里空。", "桥阴曲，是旧来忠定，手种芙蓉。", "仙翁。", "心事谁同。", "付鱼鸟相望一笑中。", "向月梅香底，招邀和靖，云山高处，问讯梁公。", "物象搜奇，风流怀古，消得文章万丈虹。", "沈吟久，想依依春树，人在江东。"]'),
('song-ci-11','花心动','刘镇2','宋','宋词','song-ci','花心动','[]','鸠雨催晴，遍园林、一番绿娇红媚。',127,'宋词/ci.song.14000.json','["鸠雨催晴，遍园林、一番绿娇红媚。", "柳外金衣，花底香须，消得艳阳天气。", "障泥步锦寻芳路，称来往、纵横珠翠。", "笑携手，旗亭问酒，更酬春思。", "还记东山乐事。", "向歌雪香中，伴春沈醉。", "粉袖殢人，彩笔题诗，陶写老来风味。", "夜深银烛明如昼，待归去、看承花睡。", "梦云散，屏山半熏沈水。"]'),
('song-ci-12','汉宫春','刘镇2','宋','宋词','song-ci','汉宫春','[]','日软风柔，望暖红连岛，晴绿平川。',118,'宋词/ci.song.14000.json','["日软风柔，望暖红连岛，晴绿平川。", "寻芳拾蕊，胜伴陌上鲜妍。", "玉骢归路，记青门、曾堕吟鞭。", "人去后，庭花弄影，一帘香月娟娟。", "追念旧游何在，叹佳期虚度，锦瑟华年。", "博山夜来烬冷，谁换沈烟。", "屏帏半掩，奈梦云、不到愁边。", "春易老，相思无据，闲情分付鱼笺。"]'),
('song-ci-13','水龙吟','刘镇2','宋','宋词','song-ci','水龙吟','[]','三山腊雪才消，夜来谁转回寅斗。',127,'宋词/ci.song.14000.json','["三山腊雪才消，夜来谁转回寅斗。", "试灯帘幕，送寒幡胜，暗香携手。", "少日欢娱，旧游零落，异乡歌酒。", "到而今，生怕春来大早，空赢得、两眉皱。", "春到兰湖少住，肯殷勤、访梅寻柳。", "相思人远，带围宽减，粉痕消瘦。", "双燕无凭，尺书难表，甚时回首。", "想画栏、倚遍东风，闲负却、桃花咒。"]'),
('song-ci-14','水龙吟','刘镇2','宋','宋词','song-ci','水龙吟','[]','老来惯与春相识，长记伤春如故。',126,'宋词/ci.song.14000.json','["老来惯与春相识，长记伤春如故。", "去年今日，旧愁新恨，送将风絮。", "粉泪羞红，黛眉颦翠，推愁不去。", "任琐窗深闭，屏山半掩，还别有、愁来路。", "回首画桥烟水，念故人、匆匆何处。", "客情怀远，云迷北树，草连南浦。", "离合悲欢，去留迟速，问春无语。", "笑刘郎，不道无桃可种，苦留春住。"]'),
('song-ci-15','水龙吟','刘镇2','宋','宋词','song-ci','水龙吟','[]','弄晴台馆收烟候，时有燕泥香坠。',126,'宋词/ci.song.14000.json','["弄晴台馆收烟候，时有燕泥香坠。", "宿酲未解，单衣初试，腾腾春思。", "前度桃花，去年人面，重门深闭。", "记彩鸾别后，青骢归去，长亭路、芳尘起。", "十二屏山遍倚。", "任苍苔、点红如缀。", "黄昏人静，暖香吹月，一帘花碎。", "芳意婆娑，绿阴风雨，画桥烟水。", "笑多情司马，留春无计，湿青衫泪。"]'),
('song-ci-16','庆春泽','刘镇2','宋','宋词','song-ci','庆春泽','[]','灯火烘春，楼台浸月，良宵一刻千金。',122,'宋词/ci.song.14000.json','["灯火烘春，楼台浸月，良宵一刻千金。", "锦步承莲，彩云簇仗难寻，蓬壶影动星球转，映两行、宝珥瑶簪。", "恣嬉游，玉漏声催，未歇芳心。", "笙歌十里夸张地，记年时行乐，憔悴而今。", "客里情怀，伴人闲笑闲吟。", "小桃未静刘郎老，把相思、细写瑶琴。", "怕归来，红紫欺风，三径成阴。"]'),
('song-ci-17','蝶恋花','刘镇2','宋','宋词','song-ci','蝶恋花','[]','谁送凉蟾消夜暑。',70,'宋词/ci.song.14000.json','["谁送凉蟾消夜暑。", "河汉迢迢，牛女何曾渡。", "乞得巧来无用处。", "世间枉费闲针缕。", "人在江南烟水路。", "头白鸳鸯，不道分飞苦。", "信远翻嗔乌鹊误。", "眉山暗锁巫阳雨。"]'),
('song-ci-18','柳梢青','刘镇2','宋','宋词','song-ci','柳梢青','[]','乾鹊收声，湿萤度影，庭院秋香。',61,'宋词/ci.song.14000.json','["乾鹊收声，湿萤度影，庭院秋香。", "步月移阴，梳云约翠，人在回廊。", "醺醺宿酒残妆。", "待付与、温柔醉乡。", "却扇藏娇，牵衣索笑，今夜差凉。"]'),
('song-ci-19','柳梢青','刘镇2','宋','宋词','song-ci','柳梢青','[]','瞥眼光阴。',61,'宋词/ci.song.14000.json','["瞥眼光阴。", "章台旧路，杨柳春深。", "尚忆风流，殢人倚玉，替客挥金。", "高阳醉后分襟。", "想妒雨、嗔云到今。", "消息真时，笑啼难处，方表人心。"]'),
('song-ci-20','江神子・江城子','刘镇2','宋','宋词','song-ci','江神子・江城子','[]','思君梦里说邯郸。',86,'宋词/ci.song.14000.json','["思君梦里说邯郸。", "未成欢。", "已炊残。", "断送春归，风雨霎时间。", "空有生前医国手，医不到，子孙寒。", "欲登诗境吊方干。", "倩谁看。", "北邙山。", "落落晨星，不见暮云还。", "莫在人间寻食客，寻见后，匹如闲。"]'),
('song-ci-21','临江仙','刘镇2','宋','宋词','song-ci','临江仙','[]','荡紫飘红芳信断，都无人问秾纤。',70,'宋词/ci.song.14000.json','["荡紫飘红芳信断，都无人问秾纤。", "吟鞭倚醉问凉蟾。", "香消金缕篆，尘压宝妆奁。", "梦峡朝云飞不到，一春离绪厌厌。", "却疑归燕碍重帘。", "心期花底误，眉恨柳边添。"]'),
('song-ci-22','浣溪沙','刘镇2','宋','宋词','song-ci','浣溪沙','[]','帘幕收灯断续红。',48,'宋词/ci.song.14000.json','["帘幕收灯断续红。", "歌台人散彩云空。", "夜寒归路噤鱼龙。", "宿醉未消花市月，芳心已逐柳塘风。", "丁宁莺燕莫匆匆。"]'),
('song-ci-23','清平乐','刘镇2','宋','宋词','song-ci','清平乐','[]','柳阴庭院。',54,'宋词/ci.song.14000.json','["柳阴庭院。", "帘约风前燕。", "著雨荷花红半敛。", "消得盈盈绿扇。", "竹光野色生寒。", "玉纤雪藕冰盘。", "长记酒醒人静，暗香吹月栏干。"]'),
('song-ci-24','贺新郎','刘镇2','宋','宋词','song-ci','贺新郎','[]','云淡天垂野。',142,'宋词/ci.song.14000.json','["云淡天垂野。", "望晴郊、疏烟半卷，断虹低跨。", "老树连阴藏远景，十里湖光照夜。", "看不尽、真山图画。", "春满轩窗无著处，更银蟾、冷浸鸳鸯瓦。", "人共境，转幽雅。", "文章太守归来也。", "似当年、和靖风流，小孤山下。", "问讯佩兰餐菊友，曾约梅兄入社。", "待付与、竹臞陶写。", "尘外闲寻行乐地，任傍人、歌舞喧台榭。", "诗世界，有王谢。"]'),
('song-ci-25','江神子・江城子','刘镇2','宋','宋词','song-ci','江神子・江城子','[]','送春曾到百花洲。',86,'宋词/ci.song.14000.json','["送春曾到百花洲。", "夕阳收。", "暮云留。", "想伴花神，骑鹤上扬州。", "回首湖山情味淡，重把酒，更登楼。", "相思南浦古津头。", "未拿舟。", "已惊鸥。", "柳外归鸦，点点是离愁。", "空倚阳关三叠曲，歌不尽，水东流。"]'),
('song-ci-26','阮郎归','刘镇2','宋','宋词','song-ci','阮郎归','[]','寒阴漠漠夜来霜。',56,'宋词/ci.song.14000.json','["寒阴漠漠夜来霜。", "阶庭风叶黄。", "归鸦数点带斜阳。", "谁家砧杵忙。", "灯弄幌，月侵廊。", "熏笼添宝香。", "小屏低枕怯更长。", "和云入醉乡。"]'),
('song-ci-27','阮郎归','刘镇2','宋','宋词','song-ci','阮郎归','[]','金茎浥露未成霜。',56,'宋词/ci.song.14000.json','["金茎浥露未成霜。", "西风只旧凉。", "蕊仙何事换霞妆。", "恼人秋思长。", "香世界，锦文章。", "花神不覆藏。", "小山骚客政清狂。", "同花入醉乡。"]'),
('song-ci-28','玉楼春','刘镇2','宋','宋词','song-ci','玉楼春','[]','泠泠水向桥东去。',64,'宋词/ci.song.14000.json','["泠泠水向桥东去。", "漠漠云归溪上住。", "疏风淡月有来时，流水行云无觅处。", "佳人独立相思苦。", "薄袖欺寒修竹暮。", "白头空负雪边春，著意问春春不语。"]'),
('song-ci-29','木兰花慢','刘镇2','宋','宋词','song-ci','木兰花慢','[]','看纤云护月，湛河汉，夜声收。',122,'宋词/ci.song.14000.json','["看纤云护月，湛河汉，夜声收。", "正玉尘生风，银床坠露，凉叶飕飕。", "襟怀静吞八表，莫登山临水易惊秋。", "闲想多情宋玉，旧来空替人愁。", "温柔。", "乡解老秋不。", "丝竹间秦讴。", "向橙橘香边，持螯把酒，聊伴清游。", "骚人自应念远，与黄花、评泊晋风流。", "明日莼鲈兴动，待寻江上归舟。"]'),
('song-ci-30','感皇恩','刘镇2','宋','宋词','song-ci','感皇恩','[]','八十最风流，那谁不喜。',81,'宋词/ci.song.14000.json','["八十最风流，那谁不喜。", "况是精神可人意。", "太公当日，未必荣华如此。", "儿孙列两行，莱衣戏。", "好景良辰，满堂和气。", "唱个新词管教美。", "愿同彭祖，尚有八百来岁。", "十分才一分，那里暨。"]'),
('song-ci-31','踏莎行','刘镇2','宋','宋词','song-ci','踏莎行','[]','兰斛藏香，梅瓶浸玉。',68,'宋词/ci.song.14000.json','["兰斛藏香，梅瓶浸玉。", "炉烟半袅屏山曲。", "谁烧银烛照黄昏，有人正倚萧萧竹。", "白雪歌翻，红牙板促。", "周郎自是难回目。", "禁寒不饮告推人，春风吹聚眉尖绿。"]'),
('song-ci-32','绛都春','刘镇2','宋','宋词','song-ci','绛都春','[]','和风乍扇，又还是去年，清明重到。',121,'宋词/ci.song.14000.json','["和风乍扇，又还是去年，清明重到。", "喜见燕子，巧说千般如人道。", "墙头陌上青梅小。", "是处有、闲花芳草。", "偶然思想，前欢醉赏，牡丹时候。", "当此三春媚景，好连宵恣乐，情怀歌酒。", "纵有珠珍，难买红颜长年少。", "从他乌兔茫茫走。", "更莫待、花残莺老。", "恁时欢笑，休把万金换了。"]'),
('song-ci-33','秦楼月・忆秦娥','张侃','宋','宋词','song-ci','秦楼月・忆秦娥','[]','冰肌削。',56,'宋词/ci.song.14000.json','["冰肌削。", "水沈香透胭脂萼。", "胭脂萼。", "怕愁贪睡，等闲梳掠。", "花前莫惜添杯酌。", "五更嫌怕春风恶。", "春风恶。", "东君不管，此情谁托。"]'),
('song-ci-34','月上海棠','张侃','宋','宋词','song-ci','月上海棠','[]','南枝消息凭谁送。',88,'宋词/ci.song.14000.json','["南枝消息凭谁送。", "北枝寒、清晓破馀冻。", "横溪浸疏影，月黄昏、暗香浮动。", "真仙种。", "不与梨华同梦。", "洛阳姚魏争先贡。", "妒纷纷、红紫眩新宠。", "尽雪压风欺，□和羹、此时须用。", "烦珍重。", "莫作桓伊三弄。"]'),
('song-ci-35','感皇恩','张侃','宋','宋词','song-ci','感皇恩','[]','佳处记曾游，十年重到。',81,'宋词/ci.song.14000.json','["佳处记曾游，十年重到。", "罨画湖山最春早。", "红梅几树，一夜东风开了。", "矮松修竹外、依然好。", "玉色醺酣，香团娇小。", "消得金尊共倾倒。", "满怀风味，前度何郎今老。", "徘徊疏影里、花应笑。"]'),
('song-ci-36','感皇恩','张侃','宋','宋词','song-ci','感皇恩','[]','换骨有丹砂，阿谁传与。',81,'宋词/ci.song.14000.json','["换骨有丹砂，阿谁传与。", "爱惜芳心不轻吐。", "客来烂熳，解得此情良苦。", "有时三两点、胭脂雨。", "旧说江南，红罗亭下，未必春光便如许。", "认桃辨杏，最是渠家低处。", "问花曾怨不、娇无语。"]'),
('song-ci-37','西江月','曾揆','宋','宋词','song-ci','西江月','[]','檐雨轻敲夜夜，墙云低度朝朝。',58,'宋词/ci.song.14000.json','["檐雨轻敲夜夜，墙云低度朝朝。", "日长天气已无聊。", "何况洞房人悄。", "眉共新荷不展，心随垂柳频摇。", "午眠仿佛见金翘。", "惊觉数声啼鸟。"]'),
('song-ci-38','谒金门','曾揆','宋','宋词','song-ci','谒金门','[]','山衔日。',53,'宋词/ci.song.14000.json','["山衔日。", "泪洒西风独立。", "一叶扁舟流水急。", "转头无处觅。", "去则而今已去，忆则如何不忆。", "明日到家应记得。", "寄书回雁翼。"]'),
('song-ci-39','谒金门','曾揆','宋','宋词','song-ci','谒金门','[]','深院寂。',53,'宋词/ci.song.14000.json','["深院寂。", "一点春灯衔壁。", "空说销愁须酒力。", "病多禁未得。", "遥望西楼咫尺。", "争信今宵思忆。", "伴我枕头双泪湿。", "梧桐秋雨滴。"]'),
('song-ci-40','眼儿媚','曾揆','宋','宋词','song-ci','眼儿媚','[]','芙蓉帐冷翠衾单。',58,'宋词/ci.song.14000.json','["芙蓉帐冷翠衾单。", "魂梦几曾闲。", "怎禁未许，茫茫烟水，叠叠云山。", "去时频把归期约，远不过春残。", "而今已是，荷花开了，犹倚栏干。"]'),
('song-ci-41','南柯子・南歌子','曾揆','宋','宋词','song-ci','南柯子・南歌子','[]','桐叶凉生夜，藕花香满时。',62,'宋词/ci.song.14000.json','["桐叶凉生夜，藕花香满时。", "几多离思有谁知。", "遥望盈盈一水、抵天涯。", "雨洒征衣泪，月颦分镜眉。", "相逢又是隔年期。", "不似画桥归燕、解于飞。"]'),
('song-ci-42','西河','曹豳','宋','宋词','song-ci','西河','[]','今日事。',124,'宋词/ci.song.14000.json','["今日事。", "何人弄得如此。", "漫漫白骨蔽川原，恨何日已。", "关河万里寂无烟，月明空照芦苇。", "谩哀痛，无及矣。", "无情莫问江水。", "西风落日惨新亭，几人堕泪。", "战和何者是良筹，扶危但看天意。", "只今寂寞薮泽里。", "岂无人、高卧闾里。", "试问安危谁寄。", "定相将、有诏催公起。", "须信前书言犹未。"]'),
('song-ci-43','红窗迥','曹豳','宋','宋词','song-ci','红窗迥','[]','春闱期近也，望帝乡迢迢，犹在天际。',79,'宋词/ci.song.14000.json','["春闱期近也，望帝乡迢迢，犹在天际。", "懊恨这一双脚底。", "一日厮赶上五六十里。", "争气。", "扶持我去，转得官归，恁时赏你。", "穿对朝靴，安排你在轿儿里。", "更选个、宫样鞋，夜间伴你。"]'),
('song-ci-44','一翦梅','周文璞','宋','宋词','song-ci','一翦梅','[]','风韵萧疏玉一团。',72,'宋词/ci.song.14000.json','["风韵萧疏玉一团。", "更著梅花，轻袅云鬟。", "这回不是恋江南。", "只是温柔，天上人间。", "赋罢闲情共倚阑。", "江月庭芜，总是销魂。", "流苏斜掩烛花寒。", "一样眉尖，两处关山。"]'),
('song-ci-45','浪淘沙','周文璞','宋','宋词','song-ci','浪淘沙','[]','还了酒家钱。',64,'宋词/ci.song.14000.json','["还了酒家钱。", "便好安眠。", "大槐宫里著貂蝉。", "行到江南知是梦，雪压渔船。", "盘礴古梅边。", "也信前缘。", "鹅黄雪白又醒然。", "一事最奇君听取。", "明日新年。"]'),
('song-ci-46','朝中措','王武子','宋','宋词','song-ci','朝中措','[]','画眉人去掩兰房。',57,'宋词/ci.song.14000.json','["画眉人去掩兰房。", "金鸭懒薰香。", "有恨只弹珠泪，无人与说衷肠。", "玉颜云鬓，春花夜月，辜负韶光。", "闲看枕屏风上，不如画底鸳鸯。"]'),
('song-ci-47','玉楼春','王武子','宋','宋词','song-ci','玉楼春','[]','红楼十二春寒恻。',64,'宋词/ci.song.14000.json','["红楼十二春寒恻。", "楼角何人吹玉笛。", "天津桥上旧曾听，三十六宫秋草碧。", "昭华人去无消息。", "江上青山空晚色。", "一声落尽短亭花，无数行人归未得。"]'),
('song-ci-48','生查子','魏子敬','宋','宋词','song-ci','生查子','[]','愁盈镜里山，心叠琴中恨。',48,'宋词/ci.song.14000.json','["愁盈镜里山，心叠琴中恨。", "露湿玉阑秋，香伴银屏冷。", "云归月正圆，雁到人无信。", "孤损凤皇钗，立尽梧桐影。"]'),
('song-ci-49','高阳台','韩','宋','宋词','song-ci','高阳台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','频听银签，重燃绛蜡，年华衮衮惊心。',122,'宋词/ci.song.14000.json','["频听银签，重燃绛蜡，年华衮衮惊心。", "饯旧迎新，能消几刻光阴。", "老来可惯通宵饮，待不眠、还怕寒侵。", "掩清尊。", "多谢梅花，伴我微吟。", "邻娃已试春妆了，更蜂腰簇翠，燕股横金。", "勾引东风，也知芳思难禁。", "朱颜那有年年好，逞艳游、赢取如今。", "恣登临。", "残雪楼台，迟日园林。"]'),
('song-ci-50','浪淘沙','韩','宋','宋词','song-ci','浪淘沙','[]','莫上玉楼看。',64,'宋词/ci.song.14000.json','["莫上玉楼看。", "花雨斑斑。", "四垂罗幕护朝寒。", "燕子不知人去也，飞认阑干。", "回首几关山。", "后会应难。", "相逢祗有梦魂间。", "可奈梦随春漏短，不到江南。"]'),
('song-ci-51','浪淘沙','韩','宋','宋词','song-ci','浪淘沙','[]','裙色草初青。',64,'宋词/ci.song.14000.json','["裙色草初青。", "鸭绿波轻。", "试花霏雨湿春晴。", "三十六梯人不到，独唤瑶筝。", "艇子忆逢迎。", "依旧多情。", "朱门只合锁娉婷。", "却逐彩鸾归去路，香陌春城。"]'),
('song-ci-52','长相思','韩','宋','宋词','song-ci','长相思','[]','郎恩深。',44,'宋词/ci.song.14000.json','["郎恩深。", "妾思深。", "祗为恩深便有今。", "回纹辜旧吟。", "云沈沈。", "水沈沈。", "一点坚如百炼金。", "郎应知妾心。"]'),
('song-ci-53','长相思','韩','宋','宋词','song-ci','长相思','[]','杜娘家。',44,'宋词/ci.song.14000.json','["杜娘家。", "谢娘家。", "楼压官桥柳半遮。", "帘波漾彩霞。", "拾飞花。", "怨飞花。", "望断郎来日又斜。", "东风吹鬓鸦。"]'),
('song-ci-54','长相思','韩','宋','宋词','song-ci','长相思','[]','夜萧萧。',40,'宋词/ci.song.14000.json','["夜萧萧。", "梦萧萧。", "又趁杨花到谢桥。", "凤沈明月箫。", "来迢迢。", "枉把吟笺寄寂寥。", "飞鸿不受招。"]'),
('song-ci-55','好事近','卓田','宋','宋词','song-ci','好事近','[]','奏赋谒金门，行尽云山无数。',53,'宋词/ci.song.14000.json','["奏赋谒金门，行尽云山无数。", "尚有江天一半，买扁舟东去。", "波神眼底识英雄，阁住半空雨。", "唤起一帆风力，去青天尺五。"]'),
('song-ci-56','昭君怨','卓田','宋','宋词','song-ci','昭君怨','[]','千里功名歧路。',48,'宋词/ci.song.14000.json','["千里功名歧路。", "几緉英雄草屦，八座与三台。", "个中来。", "壮士寸心如铁。", "有泪不沾离别。", "剑未斩楼兰。", "莫空还。"]'),
('song-ci-57','品令','卓田','宋','宋词','song-ci','品令','[]','立秋十日，早露出新凉面。',71,'宋词/ci.song.14000.json','["立秋十日，早露出新凉面。", "斜风急雨，战退炎光一半。", "月上纱窗，疑是广寒宫殿。", "无端宋玉，撩乱生悲怨。", "一年好处，都被秋光占断。", "你且思量，今夜怎生消遣。"]'),
('song-ci-58','眼儿媚','卓田','宋','宋词','song-ci','眼儿媚','[]','丈夫只手把吴钩。',58,'宋词/ci.song.14000.json','["丈夫只手把吴钩。", "能断万人头。", "如何铁石，打作心肺，却为花柔。", "尝观项籍并刘季，一怒世人愁。", "只因撞着，虞姬戚氏，豪杰都休。"]'),
('song-ci-59','酹江月・念奴娇','卓田','宋','宋词','song-ci','酹江月・念奴娇','[]','武夷山字，是使君衔上，新来带得。',119,'宋词/ci.song.14000.json','["武夷山字，是使君衔上，新来带得。", "便觉闲中多胜事，满眼烟霞泉石。", "云卷尘劳，风生芒竹，去作山中客。", "晓坛朝罢，自然五福天锡。", "当此弧矢悬门，步虚声远，直透云霄碧。", "替却燕姬皓齿，洗尽人间筝笛。", "九曲溪深，千岩壁峭，大寿应难匹。", "辑车有待，日边飞下消息。"]'),
('song-ci-60','沁园春','卓田','宋','宋词','song-ci','沁园春','[]','才大文豪，朱衣暗里，今须点头。',137,'宋词/ci.song.14000.json','["才大文豪，朱衣暗里，今须点头。", "奈兰宫一跌，槐黄时候。", "银袍逐浪，韦带随流。", "过尽鹤书，阅周鹗表，必竟都无名字留。", "空长恨，蕡终不第，齿且先侯。", "休愁。", "有路堪由。", "最喜徐卿百不忧。", "正椿松未老，芝兰竞秀，奇毛雏凤，騂角犁牛。", "汉殿少年，新丰逆旅，岂肯卑微名位休。", "行将见，长沙召贾，御史除周。"]'),
('song-ci-61','满庭芳','卓田','宋','宋词','song-ci','满庭芳','[]','柳暗千株，蓂翻三荚，当年神岳生申。',117,'宋词/ci.song.14000.json','["柳暗千株，蓂翻三荚，当年神岳生申。", "画堂庆会，今日贺生辰。", "宝鸭檀烟薰馥，颂椒觞、醽醁频斟。", "殷勤劝，歌喉宛转，恣乐醉红裙。", "荣华兼富贵，如君素享，胜似簪缨。", "虽田彭倚顿，未足多称。", "好是钱流地上，仓箱积、赈济饥贫。", "多阴德，子孙昌盛，指日绿袍新。"]'),
('song-ci-62','木兰花・玉楼春','锦溪','宋','宋词','song-ci','木兰花・玉楼春','[]','华堂庆晬。',52,'宋词/ci.song.14000.json','["华堂庆晬。", "一岁应须千百岁，乐事如何。", "寿酒斟时妹拜哥。", "爹夸利市。", "笑道看看生舍弟。", "同著莱衣。", "玉树森森奉寿卮。"]'),
('song-ci-63','壶中天・念奴娇','锦溪','宋','宋词','song-ci','壶中天・念奴娇','[]','骑鲸直上，问妲娥何日，天生英杰。',121,'宋词/ci.song.14000.json','["骑鲸直上，问妲娥何日，天生英杰。", "笑下琼楼，还报道，甫近迎长佳节。", "万里无云，一天如水，拥出新团月。", "正当此夜，文星飞下天阙。", "蟾苑元有高枝，至今犹待，自是无心折。", "只爱林泉供笑傲，吟出阳春白雪。", "冠玉精神，希夷仙种，秘受长生诀。", "蓬壶不老，待看兰玉英发。"]'),
('song-ci-64','满江红','锦溪','宋','宋词','song-ci','满江红','[]','蓬岛仙翁，元来是、神锺岳渎。',112,'宋词/ci.song.14000.json','["蓬岛仙翁，元来是、神锺岳渎。", "喜遇生申时节，一阳来复。", "蓂荚合朝曾舞翠，月华昨夜圆如玉。", "展红笺、泚笔染新章，从头录。", "渭川叟，非钩绿。", "鲁公子，非徼福。", "况家传、胡氏长生箓。", "点额婴儿腾好语，殷勤捧献杯中绿。", "更九番、屈指篯铿年，为君祝。"]'),
('song-ci-65','鹊桥仙','李仲光','宋','宋词','song-ci','鹊桥仙','[]','诗书元帅，风流人物，看取方瞳如漆。',68,'宋词/ci.song.14000.json','["诗书元帅，风流人物，看取方瞳如漆。", "铜驼陌上若相逢，当一笑、摩挲金狄。", "相门事业，中书考第，未数汾阳功绩。", "若将六十寿行年，才数得、百分之一。"]'),
('song-ci-66','百字令・念奴娇','李仲光','宋','宋词','song-ci','百字令・念奴娇','[]','小红开也，问韶华、今年何事春早。',117,'宋词/ci.song.14000.json','["小红开也，问韶华、今年何事春早。", "尽道福星临照久，勾引东风仙岛。", "一点恩光，列城生意，万物无枯槁。", "圜扉深处，也应满地芳草。", "却怪有脚阳春，如何移向崆峒了。", "父老牵衣留不住，只有攀援遮道。", "翠柏杯中，蟠桃花下，君看朱颜好。", "路人遥指，他年黄阁元老。"]'),
('song-ci-67','鹊桥仙','李仲光','宋','宋词','song-ci','鹊桥仙','[]','焚香清坐，呼童瀹茗，聊当一杯春酒。',64,'宋词/ci.song.14000.json','["焚香清坐，呼童瀹茗，聊当一杯春酒。", "不须歌舞倩红裙，为祝百千长寿。", "诗书万卷，绮琴三弄，更有新词千首。", "从今日日与遨游，便是天长地久。"]'),
('song-ci-68','失调名','孙惟信','宋','宋词','song-ci','失调名','[]','寿花戴了。',124,'宋词/ci.song.14000.json','["寿花戴了。", "山童问、华庚多少。", "待瞒来、又怕旁人笑。", "况戒腊、淳熙可考。", "大衍之用恰恰好。", "学易后、尚一年小。", "谢屐唐衣眉山帽。", "薰风送下蓬岛。", "生巧。", "吕翁昨夜锺离早。", "又曾参、两个先生道。", "又也曾偷桃啖枣。", "百屋堆钱都不要。", "更不要、衮衣茸纛。", "但要酒星花星照。", "鹘笑到老。"]'),
('song-ci-69','风流子','孙惟信','宋','宋词','song-ci','风流子','[]','三叠古阳关。',136,'宋词/ci.song.14000.json','["三叠古阳关。", "轻寒噤、清月满征鞍。", "记玉笋揽衣，翠囊亲赠，绣巾搵脸，金柳初攀。", "自回首，燕台云掩冉，凤阁雨阑珊。", "天有尽头，水无西注，鬓难留黑，带易成宽。", "啼妆，东风悄，菱花在，拟倩锦字封还。", "应想恨蛾凝黛，慵髻堆鬟。", "奈情逐事迁，心随春老，梦和香冷，欢与花残。", "闲煞唾茸窗阁，十二屏山。"]'),
('song-ci-70','烛影摇红','孙惟信','宋','宋词','song-ci','烛影摇红','[]','一朵鞓红，宝钗压髻东风溜。',116,'宋词/ci.song.14000.json','["一朵鞓红，宝钗压髻东风溜。", "年时也是牡丹时，相见花边酒。", "初试夹纱半袖。", "与花枝、盈盈斗秀。", "对花临景，为景牵情，因花感旧。", "题叶无凭，曲沟流水空回首。", "梦云不入小山屏，真个欢难偶。", "别后知他安否。", "软红街、清明还又。", "絮飞春尽，天远书沈，日长人瘦。"]'),
('song-ci-71','清平乐','孙惟信','宋','宋词','song-ci','清平乐','[]','秋娘窗户。',54,'宋词/ci.song.14000.json','["秋娘窗户。", "梦入阳台雨。", "小别殷勤留不住。", "恨满飞花落絮。", "一天晓月檐西。", "马嘶风拂罗衣。", "分付许多风致，送人行下楼儿。"]'),
('song-ci-72','阮郎归','孙惟信','宋','宋词','song-ci','阮郎归','[]','满阶红影月昏黄，玉炉催换香。',56,'宋词/ci.song.14000.json','["满阶红影月昏黄，玉炉催换香。", "碧窗娇困懒梳妆。", "粉沾金缕裳。", "鸾髻耸，黛眉长。", "烛光分两行。", "许谁骑鹤上维扬。", "温柔和醉乡。"]'),
('song-ci-73','南乡子','孙惟信','宋','宋词','song-ci','南乡子','[]','璧月小红楼。',66,'宋词/ci.song.14000.json','["璧月小红楼。", "听得吹箫忆旧游。", "霜冷阑干天似水，扬州。", "薄幸声名总是愁。", "尘暗鹔鹴裘。", "针线曾劳玉指柔。", "一梦觉来三十载，休休。", "空为梅花白了头。"]'),
('song-ci-74','夜合花','孙惟信','宋','宋词','song-ci','夜合花','[]','风叶敲窗，露蛩吟瓮，谢娘庭院秋宵。',123,'宋词/ci.song.14000.json','["风叶敲窗，露蛩吟瓮，谢娘庭院秋宵。", "凤屏半掩，钗花映烛红摇。", "润玉暖，腻云娇。", "染芳情、香透鲛绡。", "断魂留梦，烟迷楚驿，月冷蓝桥。", "谁念卖药文箫。", "望仙城路杳，莺燕迢迢。", "罗衫暗摺，兰痕粉迹都销。", "流水远，乱花飘。", "苦相思、宽尽春腰。", "几时重恁，玉骢过处，小袖轻招。"]'),
('song-ci-75','昼锦堂','孙惟信','宋','宋词','song-ci','昼锦堂','[]','薄袖禁寒。',123,'宋词/ci.song.14000.json','["薄袖禁寒。", "轻妆媚晚，落梅庭院春妍。", "映户盈盈，回倩笑整花钿。", "柳裁云剪腰支小，凤蟠鸦耸髻鬟偏。", "东风里，香步翠摇，蓝桥那日因缘。", "婵娟。", "留慧盼，浑当了、匆匆密爱深怜。", "梦过阑干，犹认冷月秋千。", "杏梢空闹相思眼，燕翎难系断肠笺。", "银屏下，争信有人，真个病也天天。"]'),
('song-ci-76','醉思凡・醉太平','孙惟信','宋','宋词','song-ci','醉思凡・醉太平','[]','吹箫跨鸾。',46,'宋词/ci.song.14000.json','["吹箫跨鸾。", "香销夜阑。", "杏花楼上春残。", "绣罗衾半闲。", "衣宽带宽。", "千山万山。", "断肠十二阑干。", "更斜阳暮寒。"]'),
('song-ci-77','水龙吟','孙惟信','宋','宋词','song-ci','水龙吟','[]','小童教写桃符，道人还了常年例。',126,'宋词/ci.song.14000.json','["小童教写桃符，道人还了常年例。", "神前灶下，祓除清净，献花酌水。", "祷告些儿，也都不是，求名求利。", "但吟诗写字，分数上面，略精进、尽足矣。", "饮量添教不醉。", "好时节、逢场作戏。", "驱傩爆竹，软饧酥豆，通宵不睡。", "四海皆兄弟，阿鹊也、同添一岁。", "愿家家户户，和和顺顺，乐升平世。"]'),
('song-ci-78','望远行','孙惟信','宋','宋词','song-ci','望远行','[]','又还到元宵台榭。',92,'宋词/ci.song.14000.json','["又还到元宵台榭。", "记轻衫短帽，酒朋诗社。", "烂漫向、罗绮丛中，驰骋风流俊雅。", "转头是、三十年话。", "量减才悭，自觉是、欢情衰谢。", "但一点难忘，酒痕香帕。", "如今雪鬓霜髭，嬉游不忺深夜。", "怕相逢、风前月下。"]'),
('song-ci-79','失调名','张端义','宋','宋词','song-ci','失调名','[]','怨春红艳冷。',6,'宋词/ci.song.14000.json','["怨春红艳冷。"]'),
('song-ci-80','倦寻芳','张端义','宋','宋词','song-ci','倦寻芳','[]','晓听社雨，犹带馀寒，尚侵襟袖。',118,'宋词/ci.song.14000.json','["晓听社雨，犹带馀寒，尚侵襟袖。", "插柳千门，相近禁烟时候。", "鬓坠搔头深旧恨，臂宽条脱添新瘦。", "卷重帘，看双飞燕羽，舞庭花昼。", "谁共语、春来怕酒。", "一段情怀，灯暗更后。", "罨画屏山，今夜梦魂还又。", "愁墨题笺鱼浪远，粉香染泪鲛绡透。", "待相逢，想鸳衾、凤帏依旧。"]'),
('song-ci-81','谒金门','卫元卿','宋','宋词','song-ci','谒金门','[]','花过雨。',53,'宋词/ci.song.14000.json','["花过雨。", "又是一番红素。", "燕子归来愁不语。", "故巢无觅处。", "谁在玉楼歌舞。", "谁在玉关辛苦。", "若使边尘吹得去。", "东风侯万户。"]'),
('song-ci-82','齐天乐','卫元卿','宋','宋词','song-ci','齐天乐','[]','藕花洲上芙蓉楫，羞郎故移深处。',125,'宋词/ci.song.14000.json','["藕花洲上芙蓉楫，羞郎故移深处。", "弄影萍开，搴香袖罥，鸂鶒双双飞去。", "垂鞭笑顾。", "问住否横塘，试窥帘户。", "妙舞妍歌，甚时相见定相许。", "归来憔悴锦帐，久尘金犊幰，连娟黛眉颦妩。", "扇底红铅，愁痕暗渍，消得腰支如杵。", "鸾弦解语。", "镇明月西南，拌人凄楚。", "闷拾杨花，等闲春又负。"]'),
('song-ci-83','满庭芳','彭止','宋','宋词','song-ci','满庭芳','[]','月闰清秋，时逢诞节，画堂瑞气多多。',118,'宋词/ci.song.14000.json','["月闰清秋，时逢诞节，画堂瑞气多多。", "遥瞻南极，瑞彩照盘坡。", "好是年才五十，身当贵、福比山河。", "无些事，方裙短揭，时复自高歌。", "欢娱，当此际，香燃宝鸭，酒酌金荷。", "恣柳腰樱口，左右森罗。", "纵有人人捧拥，争得似、正面嫦娥。", "思量取，朱颜未老，好事莫蹉跎。"]'),
('song-ci-84','留春令','彭止','宋','宋词','song-ci','留春令','[]','夜来小雨三更作。',65,'宋词/ci.song.14000.json','["夜来小雨三更作。", "近水处、小桃开却。", "玉女向晓掀朱箔。", "似与花枝有约。", "绿池上、柳腰纤弱。", "燕子过、谁家院落。", "春衫试着香罗薄。", "无奈东风太恶。"]'),
('song-ci-85','兰陵王','陈','宋','宋词','song-ci','兰陵王','[]','角声切。',158,'宋词/ci.song.14000.json','["角声切。", "何处梅梢弄雪。", "还乡梦，玉井楼前，千朵芙蕖插空碧。", "邻翁问消息。", "为说红尘倦客。", "应怜笑、弓剑旌旗，底事留人未归得。", "淮山旧相识。", "记急处笙歌，静里锋镝。", "隋堤杨柳犹春色。", "嗟十载人事，几番棋局，青油年少已鬓白。", "漫惆怅京国。", "朱墨。", "困无力。", "似病鹤樊笼，老骥羁勒。", "夕阳不系栖林翼。", "待添竹东圃，种松西陌。", "功名休问，吾老矣，付俊杰。"]'),
('song-ci-86','临江仙','陈','宋','宋词','song-ci','临江仙','[]','三十四年台榭，八千馀里江津。',68,'宋词/ci.song.14000.json','["三十四年台榭，八千馀里江津。", "去时杨柳正轻颦。", "重来桃李少，不似旧时春。", "风扫半空烟雨，玉虹翠浪如新。", "可怜笳鼓送行人。", "白头梳上见，归梦枕边频。"]'),
('song-ci-87','哨遍','陈','宋','宋词','song-ci','哨遍','[]','多病倦游，在家又贫，毕竟如何是。',244,'宋词/ci.song.14000.json','["多病倦游，在家又贫，毕竟如何是。", "十万钱，骑鹤更扬州，是人间几曾有底。", "算一生，大都能消几屐，劳神到老成何事。", "趁齿落已双，发丝在两，归寻闲里滋味。", "不见青云路有危机。", "金缕歌声，渐变成悲。", "待思大东门，忆鹤华亭，悔之晚矣。", "休，归去来兮，北山幸有闲田地。", "地瘠宜瓜菜，引泉凿成方沚。", "这仲子蔬园，三公不换，况东陵自来瓜美。", "间走马溪头，倚阑垂钓，解衣自濯清泚。", "酿山泉、时复一中之。", "琴横膝。", "古淡无弦有音徽。", "送归鸿、暮云千里。", "蓬莱自古无路，玄圃何时到，只消曲几蒲团，镇日闲庐打眭。", "这乾坤日月，更远游、问他王子。"]'),
('song-ci-88','瑞龙吟','方千里','宋','宋词','song-ci','瑞龙吟','[]','楼前路。',163,'宋词/ci.song.14000.json','["楼前路。", "愁对万点风花，数行烟树。", "依依斜日红收，暮山翠接，平芜尽处。", "小留伫。", "还是画栏凭暖，半扃朱户。", "帘栊尽日无人，消凝怅望，时时自语。", "堪恨行云难系，赋情杨柳，徘徊犹舞。", "追想向来欢娱，怀抱非故。", "题红寄绿，魂断江南句。", "何时见、轻衫雾唾，芳茵莲步。", "燕子西飞去。", "为人试道，相思闷绪。", "空有肠千缕。", "清泪满，斑斑多于春雨。", "忍看鬓发，密堆飞絮。"]'),
('song-ci-89','琐窗寒','方千里','宋','宋词','song-ci','琐窗寒','[]','燕子池塘，黄鹂院落，海棠庭户。',121,'宋词/ci.song.14000.json','["燕子池塘，黄鹂院落，海棠庭户。", "东君暗许，借与轻风柔雨。", "奈春光困人正浓，画栏小立慵无语。", "念冶游时节，融怡天气，异乡愁旅。", "朝暮。", "凝情处。", "叹聚散悲欢，岁常十五。", "连飞并羽，未抵鸳朋凤侣。", "算章台、杨柳尚存，楚娥鬓影依旧否。", "再相逢、拼解雕鞍，燕乐同杯俎。"]'),
('song-ci-90','风流子','方千里','宋','宋词','song-ci','风流子','[]','春色遍横塘。',135,'宋词/ci.song.14000.json','["春色遍横塘。", "年华巧、过雨湿残阳。", "正一带翠摇，嫩莎平野，万枝红滴，繁杏低墙。", "恼人是，燕飞盘软舞，莺语咽轻簧。", "还忆旧游，禁烟寒食，共追清赏，曲水流觞。", "回思欢娱处，人空老，花影尚占西厢。", "堪惜翠眉环坐，云鬓分行。", "看恋柳烟光，遮丝藏絮，妒花风雨，飘粉吹香。", "都为酒驱歌使，应也无妨。"]'),
('song-ci-91','渡江云','方千里','宋','宋词','song-ci','渡江云','[]','长亭今古道，水流暗响，渺渺杂风沙。',124,'宋词/ci.song.14000.json','["长亭今古道，水流暗响，渺渺杂风沙。", "倦游惊岁晚，自叹相思，万里梦还家。", "愁凝望结，但掩泪、慵整铅华。", "更漏长，酒醒人语，睥睨有啼鸦。", "伤嗟。", "回肠千缕，泪眼双垂，遏离情不下。", "还暗思、香翻香烬，深闭窗纱。", "依稀看遍江南画，记隐隐、烟霭蒹葭。", "空健羡，鸳鸯共宿丛花。"]'),
('song-ci-92','应天长','方千里','宋','宋词','song-ci','应天长','[]','嫩黄上柳，新绿涨池，东风艳冶天色。',121,'宋词/ci.song.14000.json','["嫩黄上柳，新绿涨池，东风艳冶天色。", "又见乍晴还雨，年华傍寒食。", "春依旧，身是客。", "对丽景、易伤岑寂。", "怅凝望、一带平芜，剪就茵藉。", "前度少年场，醉记旗亭，联句遍窗壁。", "调笑映墙红粉，参差水边宅。", "芦鞭懒过故陌。", "恨未老、渐成尘迹。", "谩无语，立尽斜阳，怀抱谁识。"]'),
('song-ci-93','荔枝香','方千里','宋','宋词','song-ci','荔枝香','[]','胜日登临幽趣。',92,'宋词/ci.song.14000.json','["胜日登临幽趣。", "乘兴去。", "翠壁古木千章，林影生寒雾。", "空濛冷湿人衣，山路元无雨。", "深涧、斗泻飞泉溜甘乳。", "渔唱晚，看小棹、归前浦。", "笑指官桥，风飐酒旗斜举。", "还脱宫袍，一醉芳杯倒鹦鹉。", "幸有雕章蜡炬。"]'),
('song-ci-94','荔枝香','方千里','宋','宋词','song-ci','荔枝香','[]','小园花梢雨歇，浪羞泫。',89,'宋词/ci.song.14000.json','["小园花梢雨歇，浪羞泫。", "碧瓦光霁，罗幕香浮，莺啼燕语交加，是处池馆春遍。", "风外、认得笙歌近远。", "醉魂半萦，夜酒吹未散。", "暗忆年时，正日赴、西池宴。", "笑携艳质，郢曲新声妙如剪。", "有愁容易排遣。"]'),
('song-ci-95','还京乐','方千里','宋','宋词','song-ci','还京乐','[]','岁华惯，每到和风丽日欢再理。',125,'宋词/ci.song.14000.json','["岁华惯，每到和风丽日欢再理。", "为妙歌新调，粲然一曲，千金轻费。", "记夜阑沈醉。", "更衣换酒珠玑委。", "怅画烛摇影，易积银盘红泪。", "向笙歌底。", "问何人、能道平生，聚合欢娱，离别兴味。", "谁怜露浥烟笼，尽栽培、艳桃秾李。", "谩萦牵，空坐隔千山，情遥万水。", "纵有丹青笔，应难摹画憔悴。"]'),
('song-ci-96','扫花游・扫地游','方千里','宋','宋词','song-ci','扫花游・扫地游','[]','野亭话别，恨露草芊绵，晓风酸楚。',117,'宋词/ci.song.14000.json','["野亭话别，恨露草芊绵，晓风酸楚。", "怨丝恨缕。", "正杨花碎玉，满城雪舞。", "耿耿无言，暗洒阑干泪雨。", "片帆去。", "纵百种避愁，愁早知处。", "离思都几许。", "但渐惯征尘，斗迷归路。", "乱山似俎。", "更重江浪淼，易沈书素。", "瞪目销魂，自觉孤吟调苦。", "小留伫。", "隔前村、数声箫鼓。"]'),
('song-ci-97','解连环','方千里','宋','宋词','song-ci','解连环','[]','素封谁托。',131,'宋词/ci.song.14000.json','["素封谁托。", "空寒潮浪叠，乱山云邈。", "对倦景，无语消魂，但香断露晞，絮飞风薄。", "杜宇声中，动多少、客情离索。", "远阑干伫立，暗记那回，赏遍花药。", "依依岁华自若。", "更低烟暮草，残照孤角。", "□叹息、故里春光，有幽圃名园，算也闲却。", "早早归休，渐过了芳条华萼。", "趁良时，按歌唤舞，旧家院落。"]'),
('song-ci-98','玲珑四犯','方千里','宋','宋词','song-ci','玲珑四犯','[]','倾国名妹，似晕雪匀酥，无限娇艳。',121,'宋词/ci.song.14000.json','["倾国名妹，似晕雪匀酥，无限娇艳。", "素质闲姿，天赋淡蛾丰脸。", "还是睡起慵妆。", "顾鬓影、翠云零乱。", "怅平生、把鉴惊换。", "依约琐窗逢见。", "绣帏凝想鸳鸯荐。", "画屏烘、兽烟葱蒨。", "依红傍粉怜香玉，聊慰风流眼。", "空叹倦客断肠，奈听彻、残更急点。", "仗梦魂一到，花月底、休飘散。"]'),
('song-ci-99','丹凤吟','方千里','宋','宋词','song-ci','丹凤吟','[]','宛转回肠离绪，懒倚危栏，愁登高阁。',138,'宋词/ci.song.14000.json','["宛转回肠离绪，懒倚危栏，愁登高阁。", "相思何处，人在绣帏罗幕。", "芳年艳齿，枉消虚过，会合丝轻，因缘蝉薄。", "暗想飞云骤雨，雾隔烟遮，相去还是天角。", "怅望不将梦到，素书谩说波浪恶。", "纵有青青发，渐吴霜妆点，容易凋铄。", "欢期何晚，忽忽坐惊摇落。", "顾影无言，清泪湿、但丝丝盈握。", "染斑客袖，归日须问著。"]'),
('song-ci-100','满江红','方千里','宋','宋词','song-ci','满江红','[]','为忆仙姿，相思恨、缠绵未足。',115,'宋词/ci.song.14000.json','["为忆仙姿，相思恨、缠绵未足。", "从别后、沈郎消瘦，带围如束。", "消息三年沈过处，关山千里无飞肉。", "算谁知、中有不平心，弹棋局。", "空想像，金钗卜。", "时畏玩，回纹曲。", "许何时重到，琐窗华屋。", "长得一生花里活，软红深处鸳鸯宿。", "也胜如、骑马著征衫，京尘扑。"]'),
('song-ci-101','瑞鹤仙','方千里','宋','宋词','song-ci','瑞鹤仙','[]','看青山绕郭。',127,'宋词/ci.song.14000.json','["看青山绕郭。", "更暮草萋萋，疏烟漠漠。", "无风自花落。", "欲黄昏，谁向官楼吹角。", "刚肠顿弱。", "恨别来、辜负厚约。", "想香闺念旧，还忆去年，共举杯酌。", "寂寞。", "光阴虚度，未说离愁，泪痕先阁。", "珠帘翠幕。", "除相见，是奇药。", "况中年已后，凭高临远，情怀终是易恶。", "早归休，月地云阶，剩追笑乐。"]'),
('song-ci-102','西平乐','方千里','宋','宋词','song-ci','西平乐','[]','倦踏征尘，厌驱匹马，凝望故国犹赊。',164,'宋词/ci.song.14000.json','["倦踏征尘，厌驱匹马，凝望故国犹赊。", "孤馆今宵，乱山何许，平林漠漠烟遮。", "怅过眼光阴似瞬，回首欢娱异昔，流年迅景，霜风败苇惊沙。", "无奈轻离易别，千里意，制泪独长嗟。", "绮窗人远，青门信杳，叙影何时，重见云斜。", "空怨忆、吹箫韵曲，旋锦回文，想像宫商蠹损，机杼生尘，谁为新装晕素华。", "那信自怜，悠扬梦蝶，浮没书鳞，纵有心情，尽为相思，争如傍早归家。"]'),
('song-ci-103','浪淘沙','方千里','宋','宋词','song-ci','浪淘沙','[]','素秋霁，云横旷野，浪拍孤堞。',162,'宋词/ci.song.14000.json','["素秋霁，云横旷野，浪拍孤堞。", "柔橹悲声顿发。", "骊歌恨曲未阕。", "念一寸回肠千缕结。", "柳条在、忍使攀折。", "但怅惘章台路多少，相思拼愁绝。", "凄切。", "去程浩渺空阔。", "奈断梗孤蓬，西风外、蔌蔌残吹咽。", "应暗为行人，伤念离别。", "泪波易竭。", "凝怨怀、羞睹当时明月。", "烟浪无穷青山叠。", "鱼封远、雁书渐歇。", "甚时合、金钗分处缺。", "谩飘荡、海角天涯，再见日，应怜两鬓玲珑雪。"]'),
('song-ci-104','忆旧游','方千里','宋','宋词','song-ci','忆旧游','[]','念花边玉漏，帐里鸾笙，曾款良宵。',124,'宋词/ci.song.14000.json','["念花边玉漏，帐里鸾笙，曾款良宵。", "缕鸭吹香雾，更轻风动竹，韵响潇潇。", "画檐皓月初挂，帘幕縠纹摇。", "记罢曲更衣，挑灯细语，酒晕全消。", "迢迢。", "旧时路，纵下马铜驼，谁听扬镰。", "奈可怜庭院，又徘徊虚过，清梦难招。", "断魂暗想幽会，回首渺星桥。", "试仿佛仙源，重寻当日千树桃。"]'),
('song-ci-105','蓦山溪','方千里','宋','宋词','song-ci','蓦山溪','[]','园林晴昼，花上黄峰尾。',102,'宋词/ci.song.14000.json','["园林晴昼，花上黄峰尾。", "莺语怯游人，又还傍、绿杨深避。", "曲池斜迳，草色碧於蓝，栏倦倚。", "帘半起。", "魂断斜阳里。", "江南春尽，渺渺平桥水。", "身在一天涯，问此恨、何时是已。", "飞帆轻桨，催送莫愁来，歌舞地。", "尊酒底。", "不羡东邻美。"]'),
('song-ci-106','少年游','方千里','宋','宋词','song-ci','少年游','[]','丹青闲展小屏山。',60,'宋词/ci.song.14000.json','["丹青闲展小屏山。", "香炉一丝寒。", "织锦回纹，生绡红泪，不语自羞看。", "相思念远关河隔，终日望征鞍。", "不识单栖，忍教良夜，魂梦觅长安。"]'),
('song-ci-107','少年游','方千里','宋','宋词','song-ci','少年游','[]','东风无力扬轻丝。',60,'宋词/ci.song.14000.json','["东风无力扬轻丝。", "芳草雨馀姿。", "浅绿还池，轻黄归柳，老去愿春迟。", "栏干凭暖慵回首，闲把小花枝。", "怯酒情怀，恼人天气，消瘦有谁知。"]'),
('song-ci-108','秋蕊香','方千里','宋','宋词','song-ci','秋蕊香','[]','一枕盘莺锦暖。',56,'宋词/ci.song.14000.json','["一枕盘莺锦暖。", "初起懒匀妆面。", "绿云袅娜映娇眼。", "酒入桃腮晕浅。", "翠帘半卷香萦线。", "碍飞燕。", "画屏浅立意闲远。", "春锁深沈小院。"]'),
('song-ci-109','渔家傲','方千里','宋','宋词','song-ci','渔家傲','[]','烛彩花光明似昼。',72,'宋词/ci.song.14000.json','["烛彩花光明似昼。", "罗帏夜出倾城秀。", "红锦纹茵双凤斗。", "看舞后。", "腰肢宛胜章台柳。", "眼尾春娇波态溜。", "金樽笑捧纤纤袖。", "一阵粉香吹散酒。", "更漏久。", "消魂独自归时候。"]'),
('song-ci-110','渔家傲','方千里','宋','宋词','song-ci','渔家傲','[]','冷叶啼螀声恻恻。',72,'宋词/ci.song.14000.json','["冷叶啼螀声恻恻。", "银床晓起清霜积。", "魂断江南烟水国。", "书难得。", "相思此意无人识。", "绿鬓金钗年少客。", "愁来懒傍菱花仄。", "雾阁云窗闲枕席。", "情何适。", "杯盈珠泪还偷滴。"]'),
('song-ci-111','南乡子','方千里','宋','宋词','song-ci','南乡子','[]','西北有高楼。',66,'宋词/ci.song.14000.json','["西北有高楼。", "淡霭残烟渐渐收。", "几阵凉风生客袖，飕飕。", "心逐年华衮衮流。", "花卉满前头。", "老懒心情万事休。", "独倚栏干无一语，回眸。", "鼓角声中唤起愁。"]'),
('song-ci-112','望江南・忆江南','方千里','宋','宋词','song-ci','望江南・忆江南','[]','春色暮，短艇舣长堤。',64,'宋词/ci.song.14000.json','["春色暮，短艇舣长堤。", "飞絮空随花上下，啼莺占断水东西。", "来往燕争泥。", "桑柘绿，归去觅前溪。", "夜瓮酒香从蚁斗，晓窗眠足任鸡啼。", "犹胜旅情凄。"]'),
('song-ci-113','浣沙溪・浣溪沙','方千里','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','杨柳依依窣地垂。',48,'宋词/ci.song.14000.json','["杨柳依依窣地垂。", "鞠尘波影渐平池。", "霏微细雨出鱼儿。", "先自别来容易瘦，那堪春去不胜悲。", "腰肢宽尽缕金衣。"]'),
('song-ci-114','浣沙溪・浣溪沙','方千里','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','无数流莺远近飞。',48,'宋词/ci.song.14000.json','["无数流莺远近飞。", "垂杨袅袅弄晴晖。", "断肠声里送春归。", "鬓影空思香雾湿，袜尘还想步波微。", "去年花下酒阑时。"]'),
('song-ci-115','浣沙溪・浣溪沙','方千里','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','清泪斑斑著意垂。',48,'宋词/ci.song.14000.json','["清泪斑斑著意垂。", "消魂迢递一天涯。", "谁能万里布长梯。", "先自楼台飞粉絮，可堪帘幕卷金泥。", "相思心上乳莺啼。"]'),
('song-ci-116','迎春乐','方千里','宋','宋词','song-ci','迎春乐','[]','参差凤铎鸣高屋。',64,'宋词/ci.song.14000.json','["参差凤铎鸣高屋。", "渐惊觉、清眠熟。", "看夕阳倒影花阴速。", "双燕子、归来宿。", "几曲危肠愁易束。", "问雪鬓、何时重绿。", "料想此情同，应暗损、香肌玉。"]'),
('song-ci-117','迎春乐','方千里','宋','宋词','song-ci','迎春乐','[]','红深绿暗春无迹。',64,'宋词/ci.song.14000.json','["红深绿暗春无迹。", "芳心荡、冶游客。", "记摇鞭跋马铜驼陌。", "凝睇认、珠帘侧。", "絮满愁城风卷白。", "递多少、相思消息。", "何处约欢期，芳草外、高楼北。"]'),
('song-ci-118','点绛唇','方千里','宋','宋词','song-ci','点绛唇','[]','池馆春深，海棠枝上斑斑雨。',50,'宋词/ci.song.14000.json','["池馆春深，海棠枝上斑斑雨。", "酒旗斜举。", "风滚杨花絮。", "游子征衫，凭暖阑干处。", "空凝伫。", "杜鹃啼苦。", "还报南楼鼓。"]'),
('song-ci-119','一落索','方千里','宋','宋词','song-ci','一落索','[]','月影娟娟明秀。',56,'宋词/ci.song.14000.json','["月影娟娟明秀。", "帘波吹皱。", "徘徊空度可怜宵，谩问道、因谁瘦。", "不见芳音长久。", "鳞鸿空有。", "渭城西路恨依然，尚梦想、青青柳。"]'),
('song-ci-120','洞仙歌','吴泳','宋','宋词','song-ci','洞仙歌','[]','翠柔香嫩，乍春风庭院。',103,'宋词/ci.song.14000.json','["翠柔香嫩，乍春风庭院。", "换却幽人读书眼。", "淡鹅黄袅袅，玉破梢头，莺未啭，绿皱池波尚浅。", "王孙才别后，长负芳时，碧草萋萋绣裀软。", "海棠桃花雨，红湿青衫，春心荡，不省花飞减半。", "待持酒高堂、劝东皇，且爱惜芳菲，留春借暖。"]'),
('song-ci-121','上西平・金人捧露盘','吴泳','宋','宋词','song-ci','上西平・金人捧露盘','[]','跨征鞍，横战槊，上襄州。',98,'宋词/ci.song.14000.json','["跨征鞍，横战槊，上襄州。", "便匹马、蹴踏高秋。", "芙蓉未折，笛声吹起塞云愁。", "男儿若欲树功名，须向前头。", "凤雏寒，龙骨朽，蛟渚暗，鹿门幽。", "阅人物、渺渺如沤。", "棋头已动，也须高著局心筹。", "莫将一片广长舌，博取封侯。"]'),
('song-ci-122','贺新凉・贺新郎','吴泳','宋','宋词','song-ci','贺新凉・贺新郎','[]','额扣龙墀苦。',142,'宋词/ci.song.14000.json','["额扣龙墀苦。", "对南宫、春风侍女，掉头不顾。", "烽火连营家万里，漠漠黄沙吹雾。", "莽关塞、白狼玄兔。", "如此江山俱破碎，似输棋、局满枰无路。", "弹血泪，迸如雨。", "轻帆且问夔州戍。", "俯江流、桑田屡改，阵图犹故。", "抱此孤忠长耿耿，痛恨年华不与。", "但月落、荒洲绝屿。", "君与鹤山皆人杰，倘功名、到手还须做。", "平滟澦，洗石鼓。"]'),
('song-ci-123','青玉案','吴泳','宋','宋词','song-ci','青玉案','[]','玉骢已响关头路。',81,'宋词/ci.song.14000.json','["玉骢已响关头路。", "待携取、功名去。", "慷慨不歌桃叶渡。", "囊书犹在，剑花未落，富有经纶处。", "从军缅想当年赋。", "纵局局翻新只如许。", "但恐归来秋色暮。", "薰炉茗碗，葵根瓠叶，落莫灯前雨。"]'),
('song-ci-124','满江红','吴泳','宋','宋词','song-ci','满江红','[]','白鹤山人，被推作、诸军都督。',114,'宋词/ci.song.14000.json','["白鹤山人，被推作、诸军都督。", "对朔雪边云，上马龙光醲郁。", "戊己营西连太白，甲丁旗尾扪箕宿。", "倚梅花、听得凯歌声，横吹曲。", "船易漏，袽难沃。", "柯易烂，棋难复。", "阅勋名好样，只推吾蜀。", "风撼藕塘猩鬼泣，月吞采石鲸鲵戮。", "管明年、缚取敌人回，持钧轴。"]'),
('song-ci-125','满江红','吴泳','宋','宋词','song-ci','满江红','[]','倦客无家，且随寓、瞻乌爰止。',115,'宋词/ci.song.14000.json','["倦客无家，且随寓、瞻乌爰止。", "浪占得，清溪一曲，水鲜山美。", "菡萏香浮几案上，芙蓉月落吟窗里。", "纵结庐、虽不是吾庐，聊复尔。", "人似玉，神如水。", "歌古调，传新意。", "问老庞何日，携家来此。", "后著岂无棋对待，前锋自有诗当底。", "若新秋、京口酒船来，仍命寄。"]'),
('song-ci-126','八声甘州','吴泳','宋','宋词','song-ci','八声甘州','[]','每逢人、都道早归休，何曾猛归来。',119,'宋词/ci.song.14000.json','["每逢人、都道早归休，何曾猛归来。", "有邵平瓜圃，渊明菊径，谁肯徘徊。", "底是无波去处，空弄一竿桅。", "富贵非吾事，野马浮埃。", "况值清和时候，正青梅未熟，煮酒新开。", "共倒冠落佩，宁使别人猜。", "满朱檐、残花败絮，欲问君、移取石榴栽。", "青湖上，低低架屋，浅浅衔杯。"]'),
('song-ci-127','贺新郎','吴泳','宋','宋词','song-ci','贺新郎','[]','一片湖光净。',142,'宋词/ci.song.14000.json','["一片湖光净。", "被游人、撑船刺破，宝菱花镜。", "和靖不来东坡去，欠了骚人逸韵。", "但翠葆、玉钗横鬓。", "碧藕花中人家住，恨幽香、可爱不可近。", "沙鹭起，晚风进。", "功名得手真奇隽。", "黯离怀、长堤翠柳，系愁难尽。", "世上浮荣一时好，人品百年论定。", "且牢守、文章密印。", "秘馆词人能度曲，更不消、檀板标苏姓。", "凌浩渺，纳光景。"]'),
('song-ci-128','满江红','吴泳','宋','宋词','song-ci','满江红','[]','风约湖船，微摆撼、水光山色。',115,'宋词/ci.song.14000.json','["风约湖船，微摆撼、水光山色。", "纵夹岸、秋芳冷淡，亦随风拆。", "荷芰尚堪骚客制，兰苕犹许诗人摘。", "最关情、疏雨画桥西，宜探索。", "蓬岛上，神仙宅。", "苍玉佩，青城客。", "把从前文字，委诸河伯。", "涵浸胸中今古藏。", "编排掌上乾坤策。", "却仍携、新草阜陵书，归山泽。"]'),
('song-ci-129','洞庭春色・沁园春','吴泳','宋','宋词','song-ci','洞庭春色・沁园春','[]','金柝声中，铁衣影里，仍旧上元。',136,'宋词/ci.song.14000.json','["金柝声中，铁衣影里，仍旧上元。", "况银花亸鬓，看承春色，蜡珠照坐，暖熟丰年。", "宝月分明无缺玷，须洗尽黄云别看天。", "无限意，且平开莲浦，小作桃源。", "灯花夜来有喜，捷书便驰至军前。", "响乐棚高处，何妨颂圣，体筵侧傍，仍与中贤。", "不会山人行乐意，道刚把风花作事权。", "言不尽，倩梅吹汉曲，莺答虞弦。"]'),
('song-ci-130','洞庭春色・沁园春','吴泳','宋','宋词','song-ci','洞庭春色・沁园春','[]','兰切膏凝，柳沟燧落，光景乍新。',136,'宋词/ci.song.14000.json','["兰切膏凝，柳沟燧落，光景乍新。", "正石坛人静，风清绮陌，朱筵灯闹，雨压香尘。", "不似潘郎花作县，且管勾江山当主人。", "看承处，有帘犀透月，蜡凤烧云。", "裴回五花泉上，问谁解攻打愁城。", "算人生行乐，不须富贵，官居游适，必就高明。", "山寺归来簪花笑，笑老去犹能强作春。", "无限事，愿长开醉眼，饱看升平。"]'),
('song-ci-131','菩萨蛮','吴泳','宋','宋词','song-ci','菩萨蛮','[]','莺花旧恨凭谁雪。',52,'宋词/ci.song.14000.json','["莺花旧恨凭谁雪。", "也须管句灯时节。", "黄已上眉峰。", "小槽初滴红。", "好天佳月夕。", "结佩飞霞客。", "醒恐不如酲。", "何妨独屡更。"]'),
('song-ci-132','点绛唇','李铨','宋','宋词','song-ci','点绛唇','[]','一朵千金，帝城谷雨初晴后。',50,'宋词/ci.song.14000.json','["一朵千金，帝城谷雨初晴后。", "粉拖香透。", "雅称群芳首。", "把酒题诗，遐想欢如旧。", "花知否。", "故人清瘦。", "长忆同携手。"]'),
('song-ci-133','鹊桥仙','王大烈','宋','宋词','song-ci','鹊桥仙','[]','银潢流派，嫦娥出世。',68,'宋词/ci.song.14000.json','["银潢流派，嫦娥出世。", "正是麦秋天气。", "荧煌一点寿星明，又恰向、今宵呈瑞。", "佳儿龙跳，荣封迩止。", "试问遐龄知几。", "从今旋数一千年，待足了、依前数起。"]'),
('song-ci-134','蓦山溪','王大烈','宋','宋词','song-ci','蓦山溪','[]','东风吹物，渐入韶华媚。',102,'宋词/ci.song.14000.json','["东风吹物，渐入韶华媚。", "和气散千门，更灵鹊、前村报喜。", "月宫仙子，昨夜下瑶台，人传道，诞兰房，喜把金盆洗。", "中郎传业，此事今如意。", "遥想画堂中，有葱葱、云烟滃瑞。", "休言前日，玉燕不来投，看释氏，到明年，又送麒麟至。"]'),
('song-ci-135','念奴娇','程公许','宋','宋词','song-ci','念奴娇','[]','晓凉散策，恨西风不贷，一池残绿。',120,'宋词/ci.song.14000.json','["晓凉散策，恨西风不贷，一池残绿。", "谁与冰轮撝玉斧，恰好今宵圆足。", "树杪翻光，莎庭转影，零乱昆台玉。", "荡胸清露，闲须浇下醽醁。", "休问湖海飘零，老人心事，似倚岩枯木。", "万里亲知应健否，脉脉此情谁属。", "世虑难平，天高难问，倚遍阑干曲。", "不妨随寓，买园催种松竹。"]'),
('song-ci-136','沁园春','程公许','宋','宋词','song-ci','沁园春','[]','万里飘萍，送江入海，过古润州。',139,'宋词/ci.song.14000.json','["万里飘萍，送江入海，过古润州。", "正羁怀无奈，凭高纵览，濛濛烟雨，簇簇渔舟。", "南北区分，江山形胜，忧愤令人扶上楼。", "沈凝久，任斜飞雪片，急洒貂裘。", "英风追想孙刘。", "似黑白两奁棋未收。", "把烟霞饶与，坡仙米老，丹青难觅，摩诘营邱。", "斗野号风，海门残照，长与人间管领愁。", "凭谁问，借天河一挽，洗甲兵休。"]'),
('song-ci-137','水调歌头','程公许','宋','宋词','song-ci','水调歌头','[]','驼褐倚禅榻，丝鬓扬茶烟。',114,'宋词/ci.song.14000.json','["驼褐倚禅榻，丝鬓扬茶烟。", "谁知老子方寸，历历著千年。", "试问汗青馀几，一笑腰黄萦梦，我自乐天全。", "出处两无累，赢取日高眠。", "八千里，西望眼，断霞边。", "弁苍苕碧，随分风月不论钱。", "执手还成轻别，何日归来投社，玉海得同编。", "经世付时杰，觅个钓鱼船。"]'),
('song-ci-138','水调歌头','包恢','宋','宋词','song-ci','水调歌头','[]','羽觞随曲水，佳气溢双清。',114,'宋词/ci.song.14000.json','["羽觞随曲水，佳气溢双清。", "真贤瑞世，恰与真圣日同生。", "出侍红云一朵，出按皇华六辔，特地福吾闽。", "底是长生箓，八郡咏歌声。", "奏天子，倾义廪，济饥民。", "南州指使，青州公案一般仁。", "却恐紫泥有诏，社稷重臣事业，非晚觐岩宸。", "来岁这般节，宣劝玉堂人。"]'),
('song-ci-139','水调歌头','岳甫','宋','宋词','song-ci','水调歌头','["\u9ec4\u9e64\u697c"]','鲁口天下壮，襟楚带三吴。',114,'宋词/ci.song.14000.json','["鲁口天下壮，襟楚带三吴。", "山川表里营垒，屯列拱神都。", "鹦鹉洲前处士，黄鹤楼中仙客，拍手试招呼。", "莫诵昔人句，不食武昌鱼。", "望樊冈，过赤壁，想雄图。", "寂寥霸气，应笑当日阿瞒疏。", "收拾周黄策略，成就孙刘基业，未信赏音无。", "我醉君起舞，明日隔江湖。"]'),
('song-ci-140','满江红','岳甫','宋','宋词','song-ci','满江红','[]','碧海迢遥，曾窥见、赤城楼堞。',114,'宋词/ci.song.14000.json','["碧海迢遥，曾窥见、赤城楼堞。", "因傲睨尘寰，犹带凭虚仙骨。", "武库胸中兵十万，文场笔阵诗千百。", "记向来、小是听胪传，居前列。", "世间事，都未说。", "亲为大，官毫末。", "况诸郎锺庆，凤龄英发。", "银菟颁符方易地，金銮寓直行趋阙。", "更相期、尽节早归来，传丹诀。"]'),
('song-ci-141','木兰花慢','岳珂','宋','宋词','song-ci','木兰花慢','[]','试晨妆淡伫，正疏雨、过含章。',122,'宋词/ci.song.14000.json','["试晨妆淡伫，正疏雨、过含章。", "早巧额回春，岭云护雪，十里清香。", "何人剪冰缀玉，仗化工、施巧付东皇。", "瘦尽绮窗寒魄，凄凉画角斜阳。", "孤山西畔水云乡。", "篱落亚疏篁。", "问多少幽姿，半归图画，半入诗囊。", "如今梦回帝国，尚迟迟、依约带湖光。", "多谢胆瓶重见，不堪三弄横羌。"]'),
('song-ci-142','六州歌头','岳珂','宋','宋词','song-ci','六州歌头','[]','海棠开后，红雨洒江濆。',182,'宋词/ci.song.14000.json','["海棠开后，红雨洒江濆。", "春风路，窥杏非，剪葵榛。", "绕梅魂。", "满院禽声悄，扶醉起，初睡足，诮不似，玉奴辈，负东昏。", "回首曲江，多少花边卧，高塚麒麟。", "谩名缰利锁，何日濯尘缨。", "几绊浮生。", "遣区惊。", "试从今数，春归日，留不住，掩重门。", "风雨遇，归阆女，战吴军。", "费温存。", "总被流莺笑，英烂熳，误间关。", "诗卷债，负便腹，遂吟肝。", "长记风光流转，问少陵、曾与春言。", "便联镳相约，一醉卧红云。", "画角城阍。"]'),
('song-ci-143','醉落魄・一斛珠','岳珂','宋','宋词','song-ci','醉落魄・一斛珠','[]','铜彝绣箔。',67,'宋词/ci.song.14000.json','["铜彝绣箔。", "风流不到临春阁。", "婆娑清影来岩壑。", "梅魄兰魂，香染九秋萼。", "蕊仙拥下青瑶幕。", "粟肌透入黄金约。", "有人奚酉逢鱼摸。", "欲插还羞，重把鬓云掠。"]'),
('song-ci-144','满江红','岳珂','宋','宋词','song-ci','满江红','[]','小院深深，悄镇日、阴晴无据。',114,'宋词/ci.song.14000.json','["小院深深，悄镇日、阴晴无据。", "春未足、闺愁难寄，琴心谁与。", "曲径穿花寻蛱蝶，虚栏傍日教鹦鹉。", "笑十三、杨柳女儿腰，东风舞。", "云外月，风前絮。", "情与恨，长如许。", "想绮窗今夜，为谁凝伫。", "洛浦梦回留佩客，秦楼声断吹箫侣。", "正黄昏时候杏花寒，廉纤雨。"]'),
('song-ci-145','生查子','岳珂','宋','宋词','song-ci','生查子','[]','芙蓉清夜游，杨柳黄昏约。',48,'宋词/ci.song.14000.json','["芙蓉清夜游，杨柳黄昏约。", "小院碧苔深，润透双鸳薄。", "暖玉惯春娇，簌簌花钿落。", "缺月故窥人，影转阑干角。"]'),
('song-ci-146','祝英台近','岳珂','宋','宋词','song-ci','祝英台近','["\u957f\u6c5f"]','瓮城高，盘径近。',95,'宋词/ci.song.14000.json','["瓮城高，盘径近。", "十里笋舆稳。", "欲驾还休，风雨苦无准。", "古来多少英雄，平沙遗恨。", "又总被、长江流尽。", "倩谁问。", "因甚衣带中分，吾家自畦畛。", "落日潮头，慢写属镂愤。", "断肠烟树扬州，兴亡休论。", "正愁尽、河山双鬓。"]'),
('song-ci-147','祝英台近','岳珂','宋','宋词','song-ci','祝英台近','[]','澹烟横，层雾敛。',95,'宋词/ci.song.14000.json','["澹烟横，层雾敛。", "胜概分雄占。", "月下鸣榔，风急怒涛飐。", "关河无限清愁，不堪临鉴。", "正霜鬓、秋风尘染。", "漫登览。", "极目万里沙场，事业频看剑。", "古往今来，南北限天堑。", "倚楼谁弄新声，重城正掩。", "历历数、西州更点。"]'),
('song-ci-148','酹江月・念奴娇','岳珂','宋','宋词','song-ci','酹江月・念奴娇','[]','天然灵种，遍尘寰、不许一枝分植。',120,'宋词/ci.song.14000.json','["天然灵种，遍尘寰、不许一枝分植。", "瀛海沈沈群玉宴，迥出八仙标格。", "珠幄留云，翠绡笼雪，浅露宫黄额。", "无双亭下，未容凡卉连璧。", "犹是射虎归来，朱阑独倚，曾作东风客。", "素态自羞时态改，何必铅华倾国。", "舞影鸾孤，绕心蝶倦，占断春消息。", "月明十里，坐中还记曾识。"]'),
('song-ci-149','采桑子','朱藻','宋','宋词','song-ci','采桑子','[]','障泥油壁人归后，满院花阴。',52,'宋词/ci.song.14000.json','["障泥油壁人归后，满院花阴。", "楼影沈沈。", "中有伤春一片心。", "闲穿绿树寻梅子，斜日笼明。", "团扇风轻。", "一径杨花不避人。"]'),
('song-ci-150','水龙吟','陈以庄','宋','宋词','song-ci','水龙吟','[]','晚来江阔潮平，越船吴榜催人去。',126,'宋词/ci.song.14000.json','["晚来江阔潮平，越船吴榜催人去。", "稽山滴翠，胥涛溅恨，一襟离绪。", "访柳章台，问桃仙浦，物华如故。", "向秋娘渡口，泰娘桥畔，依稀是、相逢处。", "窈窕青门紫曲，蒨罗新、衣翻金缕，旧音恍记，轻拢慢拈，哀弦危柱。", "金屋难成，阿娇已远，不堪春暮。", "听一声杜宇，红殷绿老，雨花风絮。"]'),
('song-ci-151','贺新郎','陈以庄','宋','宋词','song-ci','贺新郎','[]','晓梦莺呼起。',141,'宋词/ci.song.14000.json','["晓梦莺呼起。", "便安排、诗家厨传，酒家行李。", "点检花边新雨露，春在万家生齿。", "道官似、锦溪清驶。", "但便有人耕绿野，正不妨、鼓吹频来此。", "方觅句，且夷俟。", "画桥西畔多春意。", "记年年、曾来几度，落花流水。", "信到水穷云起处，依约辋川竹里。", "兴未属、王孙公子。", "料想明年端门里，有传柑宴罢黄封醉。", "肯回首，万杉底。"]'),
('song-ci-152','蓦山溪','陈以庄','宋','宋词','song-ci','蓦山溪','[]','亭兰风蕙，昨日山阴曲。',102,'宋词/ci.song.14000.json','["亭兰风蕙，昨日山阴曲。", "又过五峰来，听华堂、管弦丝竹。", "今年风物，著意庆生朝，□鹤舞，黑猿吟，花下眠青鹿。", "九龄五福，盛事人皆祝。", "谁识种春翁，等浮云、飞蟁过目。", "上方渴士，忠节起闻孙，金坡近，玉堂深，莫羡春田绿。"]'),
('song-ci-153','摸鱼儿','苏','宋','宋词','song-ci','摸鱼儿','[]','望关河、试穷遥眼，新愁似丝千缕。',140,'宋词/ci.song.14000.json','["望关河、试穷遥眼，新愁似丝千缕。", "刘郎豪气今何在，应是九疑三楚。", "堪恨处。", "便拚得、一生寂寞长羁旅。", "无人寄语。", "但吊麦伤桃，边松倚竹，空忆旧诗句。", "文章事，到底将身自误。", "功名难料迟暮。", "鹑衣箪食年年瘦，受侮世间儿女。", "君信否。", "尽县簿高门，岁晚谁青顾。", "何如引起。", "任槎上张骞，山中李广，商略尽风度。"]'),
('song-ci-154','雨中花・夜行船','苏','宋','宋词','song-ci','雨中花・夜行船','[]','十载尊前，放歌起舞，人间酒户诗流。',118,'宋词/ci.song.14000.json','["十载尊前，放歌起舞，人间酒户诗流。", "尽期君凌厉，羽翮高秋。", "世事几如人意，儒冠还负身谋。", "叹天生李广，才气无双，不得封侯。", "榆关万里，一去飘然，片云甚处神州。", "应怅望、家人父子，重见无由。", "陇水寂寥传恨，淮山宛转供愁。", "这回休也，燕鸿南北，长隔英游。"]'),
('song-ci-155','菩萨蛮','许','宋','宋词','song-ci','菩萨蛮','[]','西风又转芦花雪。',52,'宋词/ci.song.14000.json','["西风又转芦花雪。", "故人犹隔关山月。", "金雁一声悲。", "玉腮双泪垂。", "绣衾寒不暖。", "愁远天无岸。", "夜夜卜灯花。", "几时郎到家。"]'),
('song-ci-156','水调歌头','王迈','宋','宋词','song-ci','水调歌头','[]','天上一灯满，引起万灯明。',114,'宋词/ci.song.14000.json','["天上一灯满，引起万灯明。", "不知今夕何夕，平地有蓬瀛。", "西母瑶池称寿，南守锋车催觐，二美一时并。", "一点魁星现，长侍老人星。", "心事好，天与寿，鬓长青。", "不将锺鼎为乐，念念在朝廷。", "此母宜生此子，须有医时良策，寿国福苍生。", "子自坐黄阁，母自课黄庭。"]'),
('song-ci-157','沁园春','王迈','宋','宋词','song-ci','沁园春','[]','人物渺然，蕙兰椒艾，孰臭孰香。',139,'宋词/ci.song.14000.json','["人物渺然，蕙兰椒艾，孰臭孰香。", "昔尹公和靖，与龟山老，虽同名节，却异行藏。", "尹在当年，深居养道，亲见兵戈兴洛阳。", "杨虽出，又何畀於蔡，何救於章。", "公今为尹为杨。", "这一著须平心较量。", "正南洲潢弄，西淮鼎沸，廷绅噤舌，举国如狂。", "招鹤亭前，居然高卧，许大乾坤谁主张。", "公须起，要擎天一柱，支架明堂。"]'),
('song-ci-158','贺新郎','王迈','宋','宋词','song-ci','贺新郎','[]','出了罗浮洞。',151,'宋词/ci.song.14000.json','["出了罗浮洞。", "有多情、梅花雪片，殷勤相送。", "见说け然琴鹤外，诗压牛腰较重。", "去管甚、群儿嘲弄。", "岭海三年持翠节，料无时、不作家山梦。", "驰玉勒，归金凤。", "金凤池，乃所居也。", "一门朱紫环昆仲。", "看阶庭、森森兰玉，慈颜欢动。", "宰相时来须著做，且舞莱衣侍奉。", "却不信、大才难用。", "时事多艰人物少，便中兴、谁辨浯溪颂。", "为大厦，要梁栋。"]'),
('song-ci-159','贺新郎','王迈','宋','宋词','song-ci','贺新郎','[]','此是河清宴。',142,'宋词/ci.song.14000.json','["此是河清宴。", "觉朝来、薰风满入，生绡团扇。", "太守愁眉才一展，且喜街头米贱。", "且莫管、官租难办。", "绕砌苔钱无限数，更莲池、雨过珠零乱。", "尽买得，凌波面。", "家山乐事真堪羡。", "记年时、荔支新熟，荷筒齐劝。", "底事来寻蕉鹿梦，赢得乾忙似箭。", "笑富贵、都如邮传。", "做了丰年还百姓，便莼鲈、归兴催张翰。", "看卿等，上霄汉。"]'),
('song-ci-160','贺新郎','王迈','宋','宋词','song-ci','贺新郎','[]','忆昔同时召。',142,'宋词/ci.song.14000.json','["忆昔同时召。", "正青山、亲提玉尺，量材廊庙。", "当日班行比元祐，北玉西珠照耀。", "一转首、宫商移调。", "君自乌台登骑省，觉精神、风采增清峭。", "数贤者，一不肖。", "酒酣耳热惟长啸。", "便翩翩、辍班荷橐，一麾闽峤。", "堪笑狂生无用处，垂老云耕月钓。", "这富贵、非由人要。", "畴昔评君如玉雪，好け然、琴鹤风尘表。", "清献后，又有赵。"]'),
('song-ci-161','贺新郎','王迈','宋','宋词','song-ci','贺新郎','[]','璎珞珠垂缕。',155,'宋词/ci.song.14000.json','["璎珞珠垂缕。", "看花冠、端容丽服，补陀岩主。", "只坐尘缘蹉一念，朱紫丛中得度。", "人世福、夫人兼五。", "银鹿诸孙来定省，对金屏、绣幕辉云母。", "人顶礼，柳行路。", "所居地名柳行。", "朝朝口诵琅函句。", "觉从来、寿人福善，老夭无误。", "消得天恩封福国，锦诰鸾翔凤舞。", "听来岁、日边佳语。", "上殿肩舆帘蹙绣，遣佳儿、扶掖天应许。", "笑陈媪，三题柱。", "有陈夫人者，"]'),
('song-ci-162','摸鱼儿','王迈','宋','宋词','song-ci','摸鱼儿','[]','昔元城、一生清峭，南都高卧坚壁。',140,'宋词/ci.song.14000.json','["昔元城、一生清峭，南都高卧坚壁。", "留耕便是元城样，何肯枉吾寻尺。", "曾直笔。", "说社稷安危，屡叩龙墀额。", "明时逐客。", "却惠顾丹山，来持翠节，对此一湾碧。", "澄清暇，无奈登临有癖。", "梅山时访仙迹。", "神仙偏喜公心事，一见莞然前席。", "闲不得。", "有先见蓍龟，消得君王忆。", "天阍不隔。", "要济险孤舟，支倾一柱，公外向谁觅。"]'),
('song-ci-163','沁园春','王迈','宋','宋词','song-ci','沁园春','[]','首尾四年，台省好官，都做一回。',139,'宋词/ci.song.14000.json','["首尾四年，台省好官，都做一回。", "便前头更有，合当做底，何妨且恁，猛省归来。", "甲第新成，开尊行乐，脆管繁弦十二钗。", "回头笑，这狂生无用，削尽官阶。", "狂生真个狂哉。", "泼性气年来全未灰。", "有龙鳞凤翼，不能攀附，牛衣渔具，早已安排。", "烂煮园蔬，熟煨山芋，白发苍颜穷秀才。", "官休做，莫狂无处著，送去琼崖。"]'),
('song-ci-164','念奴娇','王迈','宋','宋词','song-ci','念奴娇','[]','层台云外，阅古今、多少兴衰成败。',121,'宋词/ci.song.14000.json','["层台云外，阅古今、多少兴衰成败。", "老木千章，若个是、南国甘棠遗爱。", "群籁号风，繁阴蔽日，有此清凉界。", "宾朋在坐，朗然心目明快。", "更向会景亭前，登高吊古，此景何人会。", "岁岁春来春又去，独有灵台春在。", "早稻炊香，晚禾摇穗，管取三登泰。", "酿成春酒，把杯行乐须再。"]'),
('song-ci-165','沁园春','王迈','宋','宋词','song-ci','沁园春','[]','一笑樽前，数雄甲辰，几位上台。',139,'宋词/ci.song.14000.json','["一笑樽前，数雄甲辰，几位上台。", "有唐裴相，徜徉绿野，我朝富老，游戏昆台。", "淮蔡功成，惊天动地，似胜单车和虏回。", "谁知道，活流民数万，赛过平淮。", "君侯初度奇哉。", "五百岁、三贤前后来。", "任朱幡西向，不妨为富，义旗北指，也解为裴，将相功名，时来便做，且醉红蕖三百杯。", "相期处，要千年汗竹，名节崔嵬。"]'),
('song-ci-166','贺新郎','王迈','宋','宋词','song-ci','贺新郎','[]','曾侍螭头立。',142,'宋词/ci.song.14000.json','["曾侍螭头立。", "吐危言、婴鳞编虎，扶持鳌极。", "谁炼精金铸刚卯，气节毅然镇国。", "肯顾恋、眼前官职。", "碧水丹山持翠节，这福星、特为吾闽出。", "发义廪，无难色。", "如今世道难扶植。", "直还他、温公德量，魏公风力。", "此事又关宗社福，仍系苍生休戚。", "且称寿、公生人日。", "炼得内丹成熟后，看河车、常运方瞳碧。", "五百岁，作良弼。"]'),
('song-ci-167','瑞鹤仙','王迈','宋','宋词','song-ci','瑞鹤仙','[]','芳菲春二月。',126,'宋词/ci.song.14000.json','["芳菲春二月。", "正软红尘里，踏青时节。", "山川孕人杰。", "好赤城丹洞，丰姿奇绝。", "云霄阀阅。", "个精神、清如玉雪。", "看谈兵议论，风霆舞剑，刚肠如铁。", "闻说。", "年方英妙，已向城边，飞书驰捷。", "誓清击楫。", "宁久此，淹车辙。", "对花朝称寿，朱颜未老，尽有功名事业。", "便张韩刘岳传名，何如一叶。"]'),
('song-ci-168','满江红','王迈','宋','宋词','song-ci','满江红','[]','明日元宵，蔼佳气、清凉金粟。',115,'宋词/ci.song.14000.json','["明日元宵，蔼佳气、清凉金粟。", "人道是、史君寿母，宴瑶池曲。", "九十春来萱草茂，三千年后蟠桃熟。", "看鳌头、名字未多时，分符竹。", "熏宝篆，张银烛。", "佳庆事，人人祝。", "况平反阴德，在长生箓。", "最喜芸香怀玉燕，安排锦帐骑银鹿。", "待雕轩、文驷上堤沙，如天福。"]'),
('song-ci-169','满江红','王迈','宋','宋词','song-ci','满江红','[]','轻暖轻寒，正春满、河阳花县。',115,'宋词/ci.song.14000.json','["轻暖轻寒，正春满、河阳花县。", "谁报道，金铃声响，百花开遍。", "天上谪仙人瑞世，佛中有宰官身现。", "好看承、金母上瑶池，开华宴。", "争捧取，金樽劝。", "更把取，丹砂炼。", "要朱颜长对，舞裙歌扇。", "准拟来年称寿日，沈香亭里春生面。", "有安期、大枣伴蟠桃，年年献。"]'),
('song-ci-170','念奴娇','王迈','宋','宋词','song-ci','念奴娇','[]','见山堂上，画帘卷、犹是清和天气。',121,'宋词/ci.song.14000.json','["见山堂上，画帘卷、犹是清和天气。", "绿水红莲，雅称得、瑶碧冰壶标致，名在丹台，籍通紫府，游戏人间世。", "三洪华阀，自应生此人瑞。", "好是佳旦称觞，班衣拜舞，有鹓雏相对。", "后院婵娟争劝酒，端午彩丝双系。", "管取来年，雪罗风葛，荣被君恩赐。", "黑头公相，直须眉寿千岁。"]'),
('song-ci-171','水龙吟','王迈','宋','宋词','song-ci','水龙吟','[]','橙黄橘绿佳期，诘朝又报阳来复。',126,'宋词/ci.song.14000.json','["橙黄橘绿佳期，诘朝又报阳来复。", "笼葱瑞气，天教蟠绕，名门乔木。", "上界仙人，来游西塾，骖鸾跨鹤。", "有如椽彩笔，笺天万字，□呈了、琅玕腹。", "不愿班行鸣玉。", "问君王、再分符竹。", "棣华辉映，庭萱春好，举杯相属。", "伯氏乘轺，诸公须又，安排除目。", "这堆床牙笏，人人道是，太夫人福。"]'),
('song-ci-172','沁园春','王迈','宋','宋词','song-ci','沁园春','[]','臞老今朝，载酒渡江，送孟吉州。',140,'宋词/ci.song.14000.json','["臞老今朝，载酒渡江，送孟吉州。", "遇舟之人士，来前问政，此公官去，莫也宜留。", "老子曰嘻，我游宦海，几度遭他风打头。", "君休问，但正因遇坎，行则乘流。", "江皋一叶惊秋。", "雁过也、严明白鹭洲。", "笑如今休顾，从前堕甑，无心相逐，等是虚舟。", "啄黍鸡肥，新篘酒熟，且作山中万户侯。", "林泉好，却输公一著，先我归休。"]'),
('song-ci-173','南歌子','王迈','宋','宋词','song-ci','南歌子','[]','家里逢重九，新篘熟浊醪。',62,'宋词/ci.song.14000.json','["家里逢重九，新篘熟浊醪。", "弟兄乘兴共登高。", "右手茱杯、左手笑持螯。", "官里逢重九，归心切大刀。", "美人痛饮读离骚。", "因感秋英、饷我菊花糕。"]'),
('song-ci-174','沁园春','王迈','宋','宋词','song-ci','沁园春','[]','夜来斗庵，左顾绿云，右盼素娥。',141,'宋词/ci.song.14000.json','["夜来斗庵，左顾绿云，右盼素娥。", "好态浓意远，随宜梳洗，轻轻莲步，艳艳秋波。", "妒宠争妍，娇痴无际，齐劝诗翁金叵罗。", "翁微笑、□一时饮尽，谁少谁多。", "月娥。", "唱后颜酡。", "莫也怕、浮云妒月麽。", "问苏州刺史，旧欢如梦，江州司马，衫湿如何。", "翠幕空垂，唾花无迹，忍听樽前飞燕歌。", "销凝处，正潇潇烟雨，偏恼东坡。"]'),
('song-ci-175','贺新凉・贺新郎','叶路钤','宋','宋词','song-ci','贺新凉・贺新郎','[]','伛指循良吏。',140,'宋词/ci.song.14000.json','["伛指循良吏。", "祗吴公、传不书名，一人而已。", "彷佛三生来展骥。", "就种棠阴千里。", "又还是、治平为最。", "绣线渐添红日影，恰搀前、七日冬书至。", "吾道长，佛出世。", "公清但酌螺川水。", "屏星躔次吴头，极星先比。", "节谊家声香国史。", "中有千秋生意。", "宜衮衮、公侯昌炽。", "充育登庸元有样，况甬东、一脉山东气。", "珠峰畔，又呈瑞。"]'),
('song-ci-176','水调歌头','叶路钤','宋','宋词','song-ci','水调歌头','[]','天启黄旗运，复见汉黄香。',114,'宋词/ci.song.14000.json','["天启黄旗运，复见汉黄香。", "名高黄榜，飞黄腾踏入鸳行。", "文彩苏黄而上，政事龚黄而右，黄纸选循良。", "黄见眉间色，卿月照黄堂。", "调黄锺，舞黄鹤，醉鹅黄。", "黄云催熟，黄童老叟庆金穰。", "闲展黄庭一卷，自爱黄花晚节，黄阁日偏长。", "印佩黄金斗，黄发半苍苍。"]'),
('song-ci-177','摸鱼儿','曾开国','宋','宋词','song-ci','摸鱼儿','[]','望层霄、五云开处。',142,'宋词/ci.song.14000.json','["望层霄、五云开处。", "屏星光射螺浦。", "复来七日冬将至，恰则岳神生甫。", "梅半吐。", "试索笑巡檐，稍稍香风度。", "花娇欲语。", "问昔日治平，吴公无传，今请为公歌襦裤。", "□□□，玉粒家家丰贮。", "因人岂关天数。", "金城千里谁能护，前召又逢后杜。", "□□□。", "见说道、长安新筑沙堤路。", "班催鹭序。", "垂色醉蟠桃，胸中色线，待把衮衣补。"]'),
('song-ci-178','十二时・忆少年','彭耜','宋','宋词','song-ci','十二时・忆少年','[]','素馨花、在枝无几。',172,'宋词/ci.song.14000.json','["素馨花、在枝无几。", "秋入阑干十二。", "那茉莉、如今已矣。", "只有兰英菊蕊。", "霜蟹年时，香橙天气。", "总是悲秋意。", "问宋玉、当日如何，对此凄凉风月，怎生存济。", "还未知、幽人心事。", "望得眼穿心碎。", "青鸟不来，彩鸾何处，云锁三山翠。", "是碧霄有路，要归归又无计。", "奈何他、水长天远，身又何曾生翼。", "手拈芙蓉，耳听鸿雁，怕有丹书至。", "纵人间富贵，一岁复一岁。", "此心终日绕香盘，在篆畦儿里。"]'),
('song-ci-179','喜迁莺','彭耜','宋','宋词','song-ci','喜迁莺','[]','吾家何处。',126,'宋词/ci.song.14000.json','["吾家何处。", "对落日残鸦，乱花飞絮。", "五湖四海，千岩万壑，已把此生分付。", "怎得海棠心绪，更没鸳鸯债负。", "春正好，叹流光有限，老山无数。", "归去。", "君试觑。", "紫燕黄鹂，愁怕韶华暮。", "细雨斜风，断烟芳草，暑往寒来几度。", "锁却心猿意马，缚住金鸟玉兔。", "今古事，似一江流水，此怀难诉。"]'),
('song-ci-180','婆罗门引','彭耜','宋','宋词','song-ci','婆罗门引','[]','中秋皓月，隔霄光倍照尘寰。',47,'宋词/ci.song.14000.json','["中秋皓月，隔霄光倍照尘寰。", "九龙喷香水，胜沈檀。", "白家珠明协瑞，尊者诞人间。", "世称生佛子、派接清原。"]'),
('song-ci-181','南乡子','赵葵','宋','宋词','song-ci','南乡子','["\u94b1\u5858\u6c5f"]','束发领西藩。',66,'宋词/ci.song.14000.json','["束发领西藩。", "百万雄兵掌握间，召到庙堂无一事，遭弹。", "昨日公卿今日闲。", "拂晓出长安。", "莫待西风割面寒。", "羞见钱塘江上柳，何颜。", "瘦仆牵驴过远山。"]'),
('song-ci-182','庄椿岁・水龙吟','方味道','宋','宋词','song-ci','庄椿岁・水龙吟','[]','纶巾少驻家山，北窗睡觉南薰起。',125,'宋词/ci.song.14000.json','["纶巾少驻家山，北窗睡觉南薰起。", "黄庭细看，长生秘诀，神仙奇趣。", "奈此苍生，愿苏炎熟，仰为霖雨。", "趁丹心未老，将整顿乾坤，手为经理。", "好是今年庆事。", "抱奇孙、一门佳气。", "蓬山振佩，麟符重锡，褒纶新美。", "玉树参庭，桂枝分种，香浮兰芷。", "看他年、接武三槐，长是伴、庄椿岁。"]'),
('song-ci-183','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','问讯西园，一春几何，君今再游。',139,'宋词/ci.song.14000.json','["问讯西园，一春几何，君今再游。", "记流觞亭北，偷拈酒戏，凌云台上，暗度诗阄。", "略略花痕，差差柳意，十日不来红绿稠。", "须重醉，便功名了后，白发争休。", "定谁骑鹤扬州。", "任书放床头盏瓮头。", "况殷勤莺燕，能歌更舞，轻狂蜂蝶，欲去还留。", "岁月易忘，姓名须载，笔势翩翩回万牛。", "归来晚，有烛明金剪，香暖珠篝。"]'),
('song-ci-184','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','六月云初，人争议公，公无阻伤。',140,'宋词/ci.song.14000.json','["六月云初，人争议公，公无阻伤。", "记传飞急羽，舟还海道，弥漫白水，路入沙场。", "万姓三军，倚公为命，法有逗遛公自当。", "君还信，似崔嵬砥柱，屹立瞿塘。", "此行阴德难量。", "到论定才知滋味长。", "看鱼肥蟹健，妻孥共乐，酒�璧臼欤�翁媪相将。", "何以报公，祝公千岁，多少人家烧夜香。", "凌烟上，更声名凛凛，冠剑堂堂。"]'),
('song-ci-185','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','问讯梅梢，小春近也，花应渐开。',139,'宋词/ci.song.14000.json','["问讯梅梢，小春近也，花应渐开。", "记华堂此日，红牙丝竹，欢声昨夜，翠玉樽罍。", "雾节童童，金旓曳曳，人自阆风玄圃来。", "嬉游处，任沧波变陆，劫火成灰。", "行天看取龙媒。", "笑卫霍当年如此哉。", "有笔头文字，何妨挥洒，胸中兵甲，解洗氛埃。", "见说君王，防秋才了，便著芝泥封诏催。", "功名事，付孱颜燕石，突兀云台。"]'),
('song-ci-186','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','日过西窗，客枕梦回，庭空放衙。',139,'宋词/ci.song.14000.json','["日过西窗，客枕梦回，庭空放衙。", "记海棠洞里，泥金宝斝，酴醿架下，油壁钿车。", "醉墨题诗，蔷薇露重，满壁飞鸦行整斜。", "争知道，向如今漂泊，望断天涯。", "小桃一半蒸霞。", "更两岸垂杨浑未花。", "便解貂贳酒，消磨春恨，量珠买笑、酬答年华。", "对面青山，招之不至，说与浮云休苦遮。", "山深处，见炊烟又起，知有人家。"]'),
('song-ci-187','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','暑风清微，梅腮渐红，麦须未黄。',140,'宋词/ci.song.14000.json','["暑风清微，梅腮渐红，麦须未黄。", "恨牡丹多病，医治费巧，酴醿易老，点缀无方。", "客里光阴，愁中意绪，想美人兮山水长。", "销凝处，有龙丝坠简，来唤持觞。", "华堂。", "剩贮春光。", "粲一行珠玑时样妆。", "更燕留轻态，词翻古调，莺娇欲啭，曲度新腔。", "玉漏声沈，银潢影泻，殢酒犹烧心字香。", "归来也，判明虬永日，瑞锦鸳鸯。"]'),
('song-ci-188','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','问讯仙翁，殷勤为底，来万山中。',139,'宋词/ci.song.14000.json','["问讯仙翁，殷勤为底，来万山中。", "想橘边丹井，鹤寻旧约，松间碧洞，鹿养新茸。", "雾节亭亭，星旓曳曳，导以浮丘双玉童。", "嬉游处，尽祥烟瑞雨，霁月光风。", "欢声已与天通。", "更日夜郴江流向东。", "定催归有谓，泥香芝检，留行无计，路熟花骢。", "如侍严凝，密陪清燕，吴水欢然相会逢。", "年年里，对春如酒好，酒似春浓。"]'),
('song-ci-189','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','人物眇然，落落晓星，如君几何。',139,'宋词/ci.song.14000.json','["人物眇然，落落晓星，如君几何。", "有飘摇长袖，工持月斧，寂寥遗韵，妙鼓云和。", "政事文章，特其馀事，英气横空时浩歌。", "还堪笑，似龙文古鼎，谁复摩挲。", "青丝系马庭柯。", "为小驻寿君金叵罗。", "说一时伟望，齐高岳麓，二年遗爱，拍满湘波。", "世事多端，细凭商略，痛处不须言语多。", "从今去，好经从乌府，躐上銮坡。"]'),
('song-ci-190','沁园春','黄机','宋','宋词','song-ci','沁园春','[]','有美一人，昔在何居，今方见之。',139,'宋词/ci.song.14000.json','["有美一人，昔在何居，今方见之。", "俨琼缨翠弁，气清芬只，珠幢绛节，光陆离兮。", "吾道非耶，世情复尔，天骥昂藏不受羁。", "还知否，定曲高寡和，才大难施。", "行吟湘水之湄。", "看云卷云舒无定姿。", "想粲然长笑，物皆有用，时哉易失，我亦奚为。", "袖手旁观，何如小试，欲脱囊中失利锥。", "君休叹，正梅花将发，尘满征衣。"]'),
('song-ci-191','八声甘州','黄机','宋','宋词','song-ci','八声甘州','[]','问讯翁、底事到人间，人间足嬉游。',119,'宋词/ci.song.14000.json','["问讯翁、底事到人间，人间足嬉游。", "向文边书意，诗边著语，□满南州。", "逸韵高情总似，野水荡孤舟。", "所未能忘者，药鼎茶瓯。", "政恐功名相慁，便扶摇直上，龙尾螭头。", "想尘缘终薄，归去老菟裘。", "有当年、东邻西舍，办鸡豚、相与燕春秋。", "阶庭里，儿孙衮衮，飞度骅骝。"]'),
('song-ci-192','乳燕飞・贺新郎','黄机','宋','宋词','song-ci','乳燕飞・贺新郎','[]','击碎珊瑚树。',142,'宋词/ci.song.14000.json','["击碎珊瑚树。", "为留春、怕春欲去，驶如风雨。", "春不留兮君休问，付与流莺自语。", "但莫赋、绿波南浦。", "世上功名花梢露。", "政何如、一笑翻金缕。", "系白日，莫教暮。", "苍头引马城西路。", "趁池亭、荻芽尚短，梅心未苦。", "小雨欲晴晴不定，漠漠云飞轻絮。", "算行乐、春来几度。", "鞭影不摇鞍小据。", "过横塘、试把前山数。", "双白鹭，忽飞去。"]'),
('song-ci-193','乳燕飞・贺新郎','黄机','宋','宋词','song-ci','乳燕飞・贺新郎','[]','兴泼元同宇。',142,'宋词/ci.song.14000.json','["兴泼元同宇。", "唤君来、浮君大白，为君起舞。", "满袖斑斑功名泪，百岁风吹急雨。", "愁与恨、凭谁分付。", "醉里狂歌空漫触，且休歌、只倩琵琶诉。", "人不语，弦自语。", "诗成更将君自赋。", "渺楼头、烟迷碧草，云连芳树。", "草树那能知人意，怅望关河梦阻。", "有心事、笺天天许。", "绣帽轻裘真男子，政何须、纸上分今古。", "未办得，赋归去。"]'),
('song-ci-194','乳燕飞・贺新郎','黄机','宋','宋词','song-ci','乳燕飞・贺新郎','[]','秋意今如许。',142,'宋词/ci.song.14000.json','["秋意今如许。", "怪征鞍、底事匆匆，翩然难驻。", "斗帐屏围山六曲，怕见琐窗欲暮。", "倩谁伴、梧桐疏雨。", "路入衡阳天一角，更山环、水绕无重数。", "容易□，便难阻。", "相思才信相思苦。", "省疏狂、迷歌殢酒，把人轻误。", "问取归期何日是，指点庭前幽树。", "定冷蕊、疏花将吐。", "此去西风吹雁过，家身心、别后安平否。", "聊慰我，至诚处。"]'),
('song-ci-195','摸鱼儿','黄机','宋','宋词','song-ci','摸鱼儿','[]','惜春归、送春惟有，乱红扑蔌如雨。',140,'宋词/ci.song.14000.json','["惜春归、送春惟有，乱红扑蔌如雨。", "乱红也怨春狼藉，搵得泪痕无数。", "肠断处。", "更唤起、琼鹊催发长亭路。", "征鞍难驻。", "但脉脉含颦，嗔人底事，刚爱逐春去。", "阑干凭，芳草斜阳凝伫。", "愁连满眼堰树。", "□鬆不理金钗溜。", "鸾镜一奁香雾。", "花谁主。", "怅□□、玉容寂寞春知否。", "单衣懒御。", "任门外东风，流莺声里，尽日搅飞絮。"]'),
('song-ci-196','水龙吟','黄机','宋','宋词','song-ci','水龙吟','[]','晴江衮衮东流，为谁流得新愁去。',126,'宋词/ci.song.14000.json','["晴江衮衮东流，为谁流得新愁去。", "新愁都在，长亭望际，扁舟行处。", "歌罢翻香，梦回呵酒，别来无据。", "恨荼䕷吹尽，樱桃过了，便只恁、成孤负。", "须信情锺易感，数良辰、佳期应误。", "才高自叹，彩云空咏，凌波谩赋。", "团扇尘生，吟笺泪渍，一觞慵举。", "但丁宁双燕，明年还解，寄平安否。"]'),
('song-ci-197','喜迁莺','黄机','宋','宋词','song-ci','喜迁莺','[]','平湖百亩。',126,'宋词/ci.song.14000.json','["平湖百亩。", "种满湖莲叶，绕堤杨柳。", "冉冉波光，辉辉烟影，空翠湿沾襟袖。", "静惬邻鸡啼午，暖逼沙鸥眠昼。", "西园路，更红尘不断，蝶酣蜂瘦。", "知否。", "堪画处，野荠芜菁，罥地铺茵绣。", "桃李阴边，桑麻丛里，斜矗酒帘夸酒。", "竹寺小依山趾，茅店平窥津口。", "春又晚，正香风有客，倚阑搔首。"]'),
('song-ci-198','木兰花慢','黄机','宋','宋词','song-ci','木兰花慢','[]','叹镜中白发，元不向、酒边栽。',122,'宋词/ci.song.14000.json','["叹镜中白发，元不向、酒边栽。", "奈诗习未除，客愁易感，剩要安排。", "浮名任他有命，怕青山、颇怪不归来。", "出屋长松招鹤，绕渠流水行杯。", "浪驱羸马踏江淮。", "幽梦苦相催。", "甚狭路嶔崎，雄心突兀，谁忍徘徊。", "此事正烦公等，笑曹刘、只合作舆台。", "我自人间屈曲，青云有眼休回。"]'),
('song-ci-199','木兰花慢','黄机','宋','宋词','song-ci','木兰花慢','[]','政胡尘满野，问谁与、作坚城。',123,'宋词/ci.song.14000.json','["政胡尘满野，问谁与、作坚城。", "有老子行年，平头六十，无限声名。", "向来试陈大略，便群儿、啁哳耳边鸣。", "争识规模先定，破羌终属营平。", "吾心惟有忠城。", "羞媚妩，做逢迎。", "谓干戈锋镝，动关民命，此不宜轻。", "听渠自分勇怯，奈何他、天理若持衡。", "只把从前不杀，也应换得长生。"]'),
('song-ci-200','木兰花慢','黄机','宋','宋词','song-ci','木兰花慢','[]','问功名何处，算只合、付悠悠。',122,'宋词/ci.song.14000.json','["问功名何处，算只合、付悠悠。", "怕僮仆揶揄，长年为客，楚尾吴头。", "春来故园渐好，似不应、不醉把春休。", "剩买蒌蒿荻笋，河豚已上渔舟。", "人间太半足闲愁。", "蓑笠梦汀洲。", "向桃杏花边，招邀同社，秉烛来游。", "连台听渠拗倒，更麴生、元不厌诛求。", "世事翻云覆雨，满怀何止离忧。"]'),
('song-ci-201','满江红','黄机','宋','宋词','song-ci','满江红','[]','芽鼓声中，又妆点、千红万绿。',115,'宋词/ci.song.14000.json','["芽鼓声中，又妆点、千红万绿。", "春试手，银花影粲，雪梅香馥。", "归梦不知家近远，飞帆正挂天西北。", "记年时、歌舞绮罗丛，凭谁续。", "烟水迥，云山簇。", "劳怅望，伤追逐。", "把蛛丝鹊喜，意□占卜。", "月正圆时羞独照，夜偏长处怜孤宿。", "悔从前、轻被利名牵，征尘扑。"]'),
('song-ci-202','满江红','黄机','宋','宋词','song-ci','满江红','[]','万灶貔貅，便直欲、扫清关洛。',115,'宋词/ci.song.14000.json','["万灶貔貅，便直欲、扫清关洛。", "长淮路、夜亭警燧，晓营吹角。", "绿鬓将军思饮马，黄头奴子惊闻鹤。", "想中原、父老已心知，今非昨。", "狂鲵剪，於菟缚。", "单于命，春冰薄。", "政人人自勇，翘关还槊。", "旗帜倚风飞电影，戈铤射月明霜锷。", "且莫令、榆柳塞门秋，悲摇落。"]'),
('song-ci-203','满江红','黄机','宋','宋词','song-ci','满江红','[]','云暗山昏，西风撼、一天悲雨。',115,'宋词/ci.song.14000.json','["云暗山昏，西风撼、一天悲雨。", "隐君问、短墙修竹，故园何处。", "九月江南无雁到，素书封了谁传与。", "待从头、拚却把心宽，还如故。", "吴姬唱，燕姬舞。", "持玉斝，温琼醑。", "恨人生欢会，一年几许。", "莫上小楼高处望，楼前诘曲来时路。", "便直须、匹马两苍头，东归去。"]'),
('song-ci-204','酹江月・念奴娇','黄机','宋','宋词','song-ci','酹江月・念奴娇','[]','春愁几许，似春云蔼蔼，连空无数。',120,'宋词/ci.song.14000.json','["春愁几许，似春云蔼蔼，连空无数。", "□□眉尖偏易得，没个因由分付。", "杨柳烟浓，海棠花暗，绿涨墙头路。", "小楼应是，有人和泪凝伫。", "长记宝轴妆成，鸳鸯绣懒，轻笑歌金缕。", "香雪精神依旧否，风月谁怜虚度。", "带减衣宽，十分憔悴，两下平分取。", "黄昏可更，子规声碎烟坞。"]'),
('song-ci-205','酹江月・念奴娇','黄机','宋','宋词','song-ci','酹江月・念奴娇','[]','东篱成趣，有西风解事，催开丛菊。',120,'宋词/ci.song.14000.json','["东篱成趣，有西风解事，催开丛菊。", "碎摺黄金谁试手，一一清香堪掬。", "露湿凉轻，霞凝寒重，秀发如新沐。", "宫妆匀就，岂知红紫粗俗。", "因念昔日渊明，微官不受，归伴花幽独。", "弹压秋光三径里，浊酒床头初熟。", "饮剧肠宽，醉深吻燥，更把纶巾漉。", "此翁无恙，唤渠同醉船玉。"]'),
('song-ci-206','水调歌头','黄机','宋','宋词','song-ci','水调歌头','[]','此日足可惜，心事正崔嵬。',114,'宋词/ci.song.14000.json','["此日足可惜，心事正崔嵬。", "江淮踏遍，经岁相识定谁来。", "每向酒边长叹，更向花边长笑，意虑叵能猜。", "邂逅忽相遇，有客在尘埃。", "脱儒冠，著武弁，太多才。", "笔墨争似，钩戟容易到云台。", "馀子何须转手，便把平生胸臆，勇去莫徘徊。", "事业上金石，人世自叹哀。"]'),
('song-ci-207','水调歌头','黄机','宋','宋词','song-ci','水调歌头','[]','金篆锁岩穴，玉斧凿山湫。',114,'宋词/ci.song.14000.json','["金篆锁岩穴，玉斧凿山湫。", "飞泉溅沫无数，六月自生秋。", "夭矫长松千岁，上有泠然天籁，清响眇难收。", "亭屋创新观，客鞅棹还留。", "推名利，付飘瓦，寄虚舟。", "蒸羔酿秫，醅瓮戢戢蚁花浮。", "唤取能歌能舞，乘兴携将高处，杯酌荐崑球。", "径醉双股直，白眼视庸流。"]'),
('song-ci-208','六州歌头','黄机','宋','宋词','song-ci','六州歌头','[]','百年忠愤，无泪洒江濆。',182,'宋词/ci.song.14000.json','["百年忠愤，无泪洒江濆。", "曹刘事，埋露草，锁烟榛。", "哭英魂。", "此恨谁知者，时把剑，频看镜，徒自苦，拳破裂，眼眵昏。", "从古时哉去速，鄹人子、反袂伤麟。", "望家山何在，衮衮已鞶缨。", "欲划还生。", "猛堪惊。", "膏肓危病，宁有药，针匕具，献无门。", "荆州启，条旧画，汉将军。", "已不存。", "便合囊封去，苍庾地，尚间关。", "此不用，心漫有，恐无干。", "人世欢哀数耳，天或者、又假人言。", "又一番春尽，高柳暗如云。", "梦断重阍。"]'),
('song-ci-209','六州歌头','黄机','宋','宋词','song-ci','六州歌头','[]','将军何日，去筑受降城。',182,'宋词/ci.song.14000.json','["将军何日，去筑受降城。", "三万骑，貔貅虎，戮鲵鲸。", "洗沧溟。", "试上金山望，中原路，平於掌，百年事，心未语，泪先倾。", "若若累累印绶，偏安久、大义谁明。", "倚危栏欲遍，江水亦吞声。", "目断苹汀。", "海门青。", "停杯与问，焉用此，手虽子，积如京。", "波神怒，风浩浩，勃然兴。", "卷龙腥。", "似把渠忠愤，伸恳请，翠华巡。", "呼壮士，挽河汉，荡材枪。", "长算直须先定，如细故、休苦营营。", "正清愁满抱，鸥鹭却多情。", "飞过邮亭。"]'),
('song-ci-210','永遇乐','黄机','宋','宋词','song-ci','永遇乐','[]','别院春深，华堂昼永，嘉宴初启。',128,'宋词/ci.song.14000.json','["别院春深，华堂昼永，嘉宴初启。", "翠玉樽罍，红牙丝管，睡鸭沈烟里。", "弄晴云态，行空絮影，漠漠似飞如坠。", "最多情，紫绵团就，错落乱星流地。", "史君自有，元龙豪气，唤客且休辞醉。", "蝶困蜂酣，燕娇莺姹，欢意浓如此。", "侃其笑语，止乎礼义，衣佩细纫兰芷。", "遥归去，残更欲尽，晓鸦又起。"]'),
('song-ci-211','传言玉女','黄机','宋','宋词','song-ci','传言玉女','[]','日薄风柔，池面欲平还皱。',91,'宋词/ci.song.14000.json','["日薄风柔，池面欲平还皱。", "纹楸玉子，磔磔敲春昼。", "衾绣半卷，花气浓薰香兽。", "小团初试，辘轳银甃。", "梦断阳台，甚情怀、似病酒。", "风奁羞对，比年时更瘦。", "双燕乍归，寄与绿笺红豆。", "那堪又是、牡丹时候。"]'),
('song-ci-212','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','西园啼鸟。',54,'宋词/ci.song.14000.json','["西园啼鸟。", "留得春多少。", "客里情怀无日好。", "愁损连天芳草。", "博山灰冷香残。", "微风吹满银笺。", "卓午花阴不动，一双蝴蝶团圞。"]'),
('song-ci-213','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','晓窗晴日。',54,'宋词/ci.song.14000.json','["晓窗晴日。", "一点黄金橘。", "万事如毛随日出。", "多少人间头白。", "未春长恨春迟。", "春来生怕春归。", "办取揭天箫鼓，莫教孤负荼䕷。"]'),
('song-ci-214','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','烟融雨腻。',54,'宋词/ci.song.14000.json','["烟融雨腻。", "春去三之二。", "了却兰亭修禊事。", "判与仙翁一醉。", "方壶日月偏长。", "清容花草吹香。", "办取此身强健，功名饱看诸郎。"]'),
('song-ci-215','眼儿媚','黄机','宋','宋词','song-ci','眼儿媚','[]','粉墙朱阁映垂杨。',58,'宋词/ci.song.14000.json','["粉墙朱阁映垂杨。", "晴绿小池塘。", "东风颺暖，单衣初试，昼日偏长。", "鬔鬆两鬓飞云影，钿合未梳妆。", "阑干侧畔，闲抛荔子，惊散鸳鸯。"]'),
('song-ci-216','眼儿媚','黄机','宋','宋词','song-ci','眼儿媚','[]','东风挟雨苦无端。',58,'宋词/ci.song.14000.json','["东风挟雨苦无端。", "恻恻送轻寒。", "那堪更向，湘湾六六，浅处留船。", "诗阄酒戏成孤负，春事已阑珊。", "离愁都在，落花枝上，杜宇声边。"]'),
('song-ci-217','眼儿媚','黄机','宋','宋词','song-ci','眼儿媚','[]','莫嗔日日话思归。',58,'宋词/ci.song.14000.json','["莫嗔日日话思归。", "归也却便宜。", "东邻招茗，西邻唤酒，一笑开眉。", "人生万事无缘足，待足是何时。", "妻能纺绩，儿能耕获，未必寒饥。"]'),
('song-ci-218','谒金门','黄机','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.14000.json','["风又雨。", "墙外落红无数。", "人不归来春不住。", "佳期还已误。", "细细一团愁绪，薄幸疏狂何处。", "化作青鸾飞得去。", "问天天亦许。"]'),
('song-ci-219','谒金门','黄机','宋','宋词','song-ci','谒金门','[]','风雨后。',53,'宋词/ci.song.14000.json','["风雨后。", "枝上绿肥红瘦。", "乐事参差团不就。", "一春如病酒。", "楼外暖烟杨柳。", "忆得年时携手。", "燕子双双来未久。", "颇知人意否。"]'),
('song-ci-220','谒金门','黄机','宋','宋词','song-ci','谒金门','[]','愁万叠。',53,'宋词/ci.song.14000.json','["愁万叠。", "春在雨条烟叶。", "翠袖倚风寒霎霎。", "傍阑看乳鸭。", "何处一声啼鴂。", "架上荼䕷欲雪。", "绣被薰香香未歇。", "可怜音信绝。"]'),
('song-ci-221','谒金门','黄机','宋','宋词','song-ci','谒金门','[]','冬十月。',53,'宋词/ci.song.14000.json','["冬十月。", "记取生申时节。", "梅傍小春融绛雪。", "浅寒犹未却。", "且醉笙歌蕉叶。", "富贵不须频说。", "国太夫人头半白。", "看君金印烨。"]'),
('song-ci-222','霜天晓角','黄机','宋','宋词','song-ci','霜天晓角','[]','玉粲冰寒。',53,'宋词/ci.song.14000.json','["玉粲冰寒。", "月痕侵画栏。", "客里安愁无地，为徙倚、到更残。", "问花花不言。", "嗅香香欲阑。", "消得个温存处，山六曲、翠屏间。"]'),
('song-ci-223','霜天晓角','黄机','宋','宋词','song-ci','霜天晓角','[]','寒江夜宿。',53,'宋词/ci.song.14000.json','["寒江夜宿。", "长啸江之曲。", "水底鱼龙惊动，风卷地、浪翻屋。", "诗情吟未足。", "酒兴断还续。", "草草兴亡休问，功名泪、欲盈掬。"]'),
('song-ci-224','霜天晓角','黄机','宋','宋词','song-ci','霜天晓角','["\u957f\u6c5f"]','长江千里。',53,'宋词/ci.song.14000.json','["长江千里。", "中有英雄泪。", "却笑英雄自苦，兴亡事、类如此。", "浪高风又起。", "歌悲声未止。", "但愿诸公强健，吞海上、醉而已。"]'),
('song-ci-225','霜天晓角','黄机','宋','宋词','song-ci','霜天晓角','[]','江涵落日。',53,'宋词/ci.song.14000.json','["江涵落日。", "风转飞帆急。", "问讯蛾眉好在，无一语、送行客。", "闲情眠未得。", "倚窗消酒力。", "却怕鱼龙惊动，且莫要、夜吹笛。"]'),
('song-ci-226','夜行船','黄机','宋','宋词','song-ci','夜行船','[]','红溅罗裙三月二。',68,'宋词/ci.song.14000.json','["红溅罗裙三月二。", "露桃开、柳眠又起。", "百尺游丝，罥莺留燕，判与南园一醉。", "历历斜阳明野水。", "倚危阑、暮云千里。", "说似游人，直须烧烛，早晚绿阴青子。"]'),
('song-ci-227','长相思','黄机','宋','宋词','song-ci','长相思','["\u957f\u6c5f"]','东梁山。',44,'宋词/ci.song.14000.json','["东梁山。", "西梁山。", "占断长江相对闲。", "古今双鬓斑。", "天漫漫。", "水漫漫。", "人事如潮多往还。", "浅颦深恨间。"]'),
('song-ci-228','乌夜啼','黄机','宋','宋词','song-ci','乌夜啼','[]','云容晓色相涵。',45,'宋词/ci.song.14000.json','["云容晓色相涵。", "趣征骖。", "碎点遥山如豆、是淮南。", "路渐远。", "家渐远。", "恨难堪。", "□见窗花叶底、鬓毵毵。"]'),
('song-ci-229','祝英台近','黄机','宋','宋词','song-ci','祝英台近','[]','试单衣，扶短策，沙路净如洗。',95,'宋词/ci.song.14000.json','["试单衣，扶短策，沙路净如洗。", "乍雨还晴，花柳自多丽。", "争知话别南楼，片帆天际，便孤了、同心连理。", "镇萦系。", "谩有罗带香囊，殷红斗轻翠。", "一纸浓愁，无处倩双鲤。", "可堪飞梦悠悠，春风无赖，时吹过、乱莺声里。"]'),
('song-ci-230','鹊桥仙','黄机','宋','宋词','song-ci','鹊桥仙','[]','黄花似钿，芙蓉如面，秋事凄然向晚。',68,'宋词/ci.song.14000.json','["黄花似钿，芙蓉如面，秋事凄然向晚。", "风流从古记登高，又处处、悲丝急管。", "有愁万斛，有才八斗，慷慨时惊俗眼。", "明年一笑复谁同，料天远、争如人远。"]'),
('song-ci-231','西江月','黄机','宋','宋词','song-ci','西江月','[]','漠漠波浮云影，遥遥天接山痕。',58,'宋词/ci.song.14000.json','["漠漠波浮云影，遥遥天接山痕。", "一声渔唱起苹汀。", "名利缘渠唤醒。", "短棹拟携西子，长吟时吊湘灵。", "白鸥容我作同盟。", "占取两湖清影。"]'),
('song-ci-232','西江月','黄机','宋','宋词','song-ci','西江月','[]','拈翠低垂嫩萼，匀红倒簇繁英。',58,'宋词/ci.song.14000.json','["拈翠低垂嫩萼，匀红倒簇繁英。", "秾纤消得比佳人。", "酒入香肌成晕。", "帘幕阴阴窗牖，阑干曲曲池亭。", "枝头不起梦春酲。", "莫遣流莺唤醒。"]'),
('song-ci-233','忆秦娥','黄机','宋','宋词','song-ci','忆秦娥','[]','秋萧索。',56,'宋词/ci.song.14000.json','["秋萧索。", "梧桐落尽西风恶。", "西风恶。", "数声新雁，数声残角。", "离愁不管人飘泊。", "年年孤负黄花约。", "黄花约。", "几重庭院，几重帘幕。"]'),
('song-ci-234','定风波','黄机','宋','宋词','song-ci','定风波','[]','短策飘飘胜著鞭。',70,'宋词/ci.song.14000.json','["短策飘飘胜著鞭。", "携壶与客洗愁颜。", "兴到为君拚剧饮。", "狂甚。", "论诗说剑口澜翻。", "画烛烧残花影褪。", "长鲸要使百川乾。", "醉处不知谁氏子。", "只记。", "开窗临水便迎山。"]'),
('song-ci-235','虞美人','黄机','宋','宋词','song-ci','虞美人','["\u6d1e\u5ead\u6e56"]','三年万里黄尘路。',66,'宋词/ci.song.14000.json','["三年万里黄尘路。", "只欠江湖去。", "扁舟二月下湘湾。", "过了洞庭青草、又春残。", "□□□□□□□。", "□□□□□。", "□□□□□□□。", "□□□□□□、□□□。"]'),
('song-ci-236','踏莎行','黄机','宋','宋词','song-ci','踏莎行','[]','云树参差，烟芜平远。',68,'宋词/ci.song.14000.json','["云树参差，烟芜平远。", "沙头只欠飞来雁。", "西风方做一分秋，凄凉已觉难消遣。", "窗底灯寒，帐前香暖。", "回肠偏学车轮转。", "剩衾闲枕自无眠，谯门更著梅花怨。"]'),
('song-ci-237','蝶恋花','黄机','宋','宋词','song-ci','蝶恋花','[]','碧树凉飔惊画扇。',70,'宋词/ci.song.14000.json','["碧树凉飔惊画扇。", "窗户齐开，秋意参差满。", "先自离愁裁不断。", "蛩螀更作声声怨。", "山绕千重溪百转。", "隔了溪山，梦也无由见。", "归计凭谁占近远。", "银缸昨夜花如糁。"]'),
('song-ci-238','好事近','黄机','宋','宋词','song-ci','好事近','[]','鸿雁几时来，目断暮山凝碧。',53,'宋词/ci.song.14000.json','["鸿雁几时来，目断暮山凝碧。", "别后故园无恙，定芙蓉堪折。", "休文多病废吟诗，有酒怕浮白。", "不是孤他诗酒，更孤他风月。"]'),
('song-ci-239','小重山','黄机','宋','宋词','song-ci','小重山','[]','梧竹因依山尽头。',70,'宋词/ci.song.14000.json','["梧竹因依山尽头。", "潇潇疏雨后，几分秋。", "轻凉无数入西楼。", "凭栏久，满眼动离愁。", "飞鹭下汀洲。", "怕知鸿雁到，带书否。", "诗阄酒戏一齐休。", "人如削，身在水边洲。"]'),
('song-ci-240','丑奴儿・采桑子','黄机','宋','宋词','song-ci','丑奴儿・采桑子','[]','绿阴窗几明如拭，粉黛初匀。',52,'宋词/ci.song.14000.json','["绿阴窗几明如拭，粉黛初匀。", "无限芳心。", "翻动牙签却殢人。", "多娇爱学秋来曲，微颤朱唇。", "别后销魂。", "字底依稀记指痕。"]'),
('song-ci-241','更漏子','黄机','宋','宋词','song-ci','更漏子','[]','秋点长，秋梦短。',58,'宋词/ci.song.14000.json','["秋点长，秋梦短。", "怕见黄昏庭院。", "风窸窣，雨萧骚。", "倚窗魂欲销。", "候蛛丝，占鹊喜。", "依旧浓愁一纸。", "红袖黦，翠钿蔫。", "泪痕犹未乾。"]'),
('song-ci-242','减字木兰花','黄机','宋','宋词','song-ci','减字木兰花','[]','西风淅淅。',52,'宋词/ci.song.14000.json','["西风淅淅。", "满眼芙蓉红欲滴。", "无限相思。", "百叠青山百曲溪。", "凭谁说与。", "依带别来宽几许。", "好片心肠。", "不道秋来早晚凉。"]'),
('song-ci-243','临江仙','黄机','宋','宋词','song-ci','临江仙','[]','上已清明都过了，客愁惟有心知。',70,'宋词/ci.song.14000.json','["上已清明都过了，客愁惟有心知。", "子规昨夜忽催归。", "驿程那复记，魂梦已先飞。", "回首故园花与柳，枝枝叶叶相思。", "归来拚得典春衣。", "绿阴幽远处，不管尽情啼。"]'),
('song-ci-244','临江仙','黄机','宋','宋词','song-ci','临江仙','[]','凤翥鸾飞空燕子，宝香犹惹流苏。',70,'宋词/ci.song.14000.json','["凤翥鸾飞空燕子，宝香犹惹流苏。", "旧欢凄断数行书。", "终山方种玉，合浦忽还珠。", "午枕梦圆春寂寂，依然刻雪肌肤。", "觉来烟雨满平芜。", "客情殊索莫，肯唤一尊无。"]'),
('song-ci-245','南乡子','黄机','宋','宋词','song-ci','南乡子','[]','帘幕閟深沈。',66,'宋词/ci.song.14000.json','["帘幕閟深沈。", "灯暗香销夜正深。", "花落画檐鸣细雨，岑岑。", "滴破相思万里心。", "晓色未平分。", "翠被寒生不自禁。", "待得梦成翻恶况，堪颦。", "飞雁新来也误人。"]'),
('song-ci-246','鹧鸪天','黄机','宋','宋词','song-ci','鹧鸪天','[]','细听楼头漏箭移。',64,'宋词/ci.song.14000.json','["细听楼头漏箭移。", "客床寒枕不胜敧。", "凄凉夜角偏多恨，吹到梅花第几枝。", "人间阔，雁参差。", "相思惟有梦相知。", "谢他窗外芭蕉雨，叶叶声声伴别离。"]'),
('song-ci-247','鹧鸪天','黄机','宋','宋词','song-ci','鹧鸪天','[]','柳际梅边腊雪乾。',64,'宋词/ci.song.14000.json','["柳际梅边腊雪乾。", "钗头蝴蝶又成团。", "飘零萍梗江湖客，冷落笙箫灯火天。", "浇浊酒，惜流年。", "牙旗夜市几时穿。", "太平乐事终须在，老去心情恐不然。"]'),
('song-ci-248','鹧鸪天','黄机','宋','宋词','song-ci','鹧鸪天','[]','济楚偏宜淡薄妆。',64,'宋词/ci.song.14000.json','["济楚偏宜淡薄妆。", "冰涵清润玉生香。", "祗因梦峡成云雨，便拟吹箫跨凤皇。", "新间阻，旧思量。", "多情翻不似垂杨。", "年年才到春三月，百计飞花入洞房。"]'),
('song-ci-249','菩萨蛮','黄机','宋','宋词','song-ci','菩萨蛮','[]','池落开遍莲房老。',52,'宋词/ci.song.14000.json','["池落开遍莲房老。", "秋声已入梧桐表。", "葵扇与桃笙。", "尚宜相带行。", "危亭三百尺。", "爽气真堪挹。", "瀹茗且盘旋。", "翩翩吾欲仙。"]'),
('song-ci-250','菩萨蛮','黄机','宋','宋词','song-ci','菩萨蛮','[]','相思绕遍天涯路。',52,'宋词/ci.song.14000.json','["相思绕遍天涯路。", "相思不识行人处。", "多病怕逢春。", "那堪春正深。", "日高梳洗懒。", "鸾镜香尘掩。", "双鬓绿鬔鬆。", "一帘花信风。"]'),
('song-ci-251','菩萨蛮','黄机','宋','宋词','song-ci','菩萨蛮','[]','惜山不厌山行远。',52,'宋词/ci.song.14000.json','["惜山不厌山行远。", "山中禽鸟频惊见。", "小雨似怜春。", "霏霏容易晴。", "青裙田舍妇。", "饁饷前村去。", "溪水想平腰。", "唤船依断桥。"]'),
('song-ci-252','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','绿锁窗前双凤奁。',48,'宋词/ci.song.14000.json','["绿锁窗前双凤奁。", "调朱匀粉玉纤纤。", "妆成谁解尽情看。", "柳转光风丝袅娜，花明晴日锦斓斑。", "一春心事在眉尖。"]'),
('song-ci-253','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','绿绮空弹恨未平。',56,'宋词/ci.song.14000.json','["绿绮空弹恨未平。", "可堪执手送行人。", "碧酒谩将珍重意，莫辞斟。", "我定忆君吟渭北，君须思我赋停云。", "未信高山流水曲，断知音。"]'),
('song-ci-254','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','流转春光又一年。',56,'宋词/ci.song.14000.json','["流转春光又一年。", "春愁尽日两眉尖。", "草草幽欢能几许，已天边。", "会得音书生羽翼，免教魂梦役关山。", "帘卷落花千万点，雨如烟。"]'),
('song-ci-255','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','日转雕栏午漏分。',48,'宋词/ci.song.14000.json','["日转雕栏午漏分。", "井梧落尽小窗明。", "宝床丝索懒关心。", "愁压春山应脉脉，困凝秋水想沈沈。", "低头时露一湾金。"]'),
('song-ci-256','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','墨绿衫儿窄窄裁。',47,'宋词/ci.song.14000.json','["墨绿衫儿窄窄裁。", "翠荷斜领云堆。", "几时踪迹下阳台。", "歌罢樱桃和露小，舞馀杨柳趁风回。", "唤人休诉十分杯。"]'),
('song-ci-257','浣溪沙','黄机','宋','宋词','song-ci','浣溪沙','[]','著破春衫走路尘。',48,'宋词/ci.song.14000.json','["著破春衫走路尘。", "子规啼断不禁闻。", "功名似我却羞人。", "象板且须歌皓齿，袅蹄何苦惜黄金。", "尊前休负此生身。"]'),
('song-ci-258','卜算子','黄机','宋','宋词','song-ci','卜算子','[]','忆自别郎时，数到郎归日。',52,'宋词/ci.song.14000.json','["忆自别郎时，数到郎归日。", "及至郎归郎又行，泪脸香红湿。", "残梦怕寻思，罥绣慵收拾。", "夏簟青青白昼长，背倚阑干立。"]'),
('song-ci-259','醉蓬莱','黄机','宋','宋词','song-ci','醉蓬莱','["\u8861\u5c71"]','政槐云浓翠，榴火殷红，暑风凉细。',120,'宋词/ci.song.14000.json','["政槐云浓翠，榴火殷红，暑风凉细。", "紫府神仙，向人间游戏。", "瑞节珠幢，琼缨宝佩，炯冰壶标致。", "经济规模，登庸衣钵，家传如此。", "礼乐醇儒，诗书元帅，尽洗凡踪，平吞馀子。", "敬简堂深，且从容一醉。", "庆社绵绵，功名衮衮，比衡山湘水。", "更把阳和，从头付与，满门桃李。"]'),
('song-ci-260','醉落魄・一斛珠','黄机','宋','宋词','song-ci','醉落魄・一斛珠','[]','初藕花发。',66,'宋词/ci.song.14000.json','["初藕花发。", "薰风庭院凉成霎。", "碧纱金缕笼香雪。", "记得年时，心事凭栏说。", "如今陡顿音书绝。", "夜窗羞见团团月。", "锦囊尘暗黄金玦。", "留取多情，归好时节。"]'),
('song-ci-261','虞美人','黄机','宋','宋词','song-ci','虞美人','[]','十年不作湖湘客。',66,'宋词/ci.song.14000.json','["十年不作湖湘客。", "亭堠催行色。", "浅山荒草记当时。", "篠竹篱边羸马、向人嘶。", "书生万字平戎策。", "苦泪风前滴。", "莫辞衫袖障征尘。", "自苦英雄之楚、又之秦。"]'),
('song-ci-262','虞美人','黄机','宋','宋词','song-ci','虞美人','[]','云情雨意才端的。',66,'宋词/ci.song.14000.json','["云情雨意才端的。", "津鼓催行色。", "因缘虽浅是因缘。", "犹胜当初无分、小留连。", "刘郎双鬓青堪照。", "君也方年少。", "尊前不用苦沾衣。", "未信桃源别后、路成迷。"]'),
('song-ci-263','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','钗头蝴蝶。',54,'宋词/ci.song.14000.json','["钗头蝴蝶。", "趁舞梅边雪。", "酒泻黄縢光夺月。", "岁岁年年蕉叶。", "边城莺唤春归。", "沙场马到秋肥。", "□□熊韬虎略，换渠金甲牙旗。"]'),
('song-ci-264','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','风韶烟腻。',54,'宋词/ci.song.14000.json','["风韶烟腻。", "春事三之二。", "说与人生行乐耳。", "富贵古来如此。", "西园已有心期。", "姚黄魏紫开时。", "纤指金荷潋滟，香唇银竹参差。"]'),
('song-ci-265','江城子','黄机','宋','宋词','song-ci','江城子','[]','醉来玉树倚风前。',86,'宋词/ci.song.14000.json','["醉来玉树倚风前。", "举吟鞭。", "指青帘。", "乌帽低昂，摇兀似乘船。", "傍路谁家妆束巧，斜映日，半窥帘。", "寻欢端合趁芳年。", "对鵾弦。", "且陶然。", "纸上从渠，刘蹶与嬴颠。", "漠漠绿阴春复夏，多少事，总悬天。"]'),
('song-ci-266','鹊桥仙','黄机','宋','宋词','song-ci','鹊桥仙','[]','松梢擎雪，竹枝溥露，炯炯照人清韵。',68,'宋词/ci.song.14000.json','["松梢擎雪，竹枝溥露，炯炯照人清韵。", "仙家谱系合长生，元不藉、药炉丹井。", "凌云壮志，垂天健翮，九万扶摇路稳。", "发闻政最有公车，定飞下、日边音信。"]'),
('song-ci-267','鹊桥仙','黄机','宋','宋词','song-ci','鹊桥仙','[]','一番雨过，江头绿涨，催唤扁舟解去。',68,'宋词/ci.song.14000.json','["一番雨过，江头绿涨，催唤扁舟解去。", "重来言语是相宽，怎得似、而今且住。", "阳关声断，同心未绾，簌簌泪珠无数。", "秋鸿春燕往还时，莫忘了、锦笺分付。"]'),
('song-ci-268','鹊桥仙','黄机','宋','宋词','song-ci','鹊桥仙','[]','薄情也见，多情也见，不似这番著相。',68,'宋词/ci.song.14000.json','["薄情也见，多情也见，不似这番著相。", "如何容易买归舟，报南浦、桃花绿涨。", "随君无计，留君无计，赢得泪珠两行。", "夕阳明处一回头，有人在、高楼凝望。"]'),
('song-ci-269','诉衷情','黄机','宋','宋词','song-ci','诉衷情','[]','子规声老又残春。',54,'宋词/ci.song.14000.json','["子规声老又残春。", "犹作未归人。", "天意不能怜客，何事苦教贫。", "归去也，莫逡巡。", "好从今。", "秧田车水，麦陇腰镰，总是关心。"]'),
('song-ci-270','临江仙','黄机','宋','宋词','song-ci','临江仙','[]','寒食清明都过了，客中无计留春。',70,'宋词/ci.song.14000.json','["寒食清明都过了，客中无计留春。", "东风吹雨更愁人。", "系船芳草岸，始信是官身。", "怅望故园烟水阔，几时匹马骎骎。", "别肠何止似车轮。", "殢天天不管，转作两眉颦。"]'),
('song-ci-271','朝中措','黄机','宋','宋词','song-ci','朝中措','[]','驳云行雨苦无多。',57,'宋词/ci.song.14000.json','["驳云行雨苦无多。", "晴也快如梭。", "春思正难拘束，客愁谁为销磨。", "寻花觅谶，传杯托意，种种蹉跎。", "消息不来云锦，泪痕湿满香罗。"]'),
('song-ci-272','朝中措','黄机','宋','宋词','song-ci','朝中措','[]','逢逢船鼓绿杨津。',57,'宋词/ci.song.14000.json','["逢逢船鼓绿杨津。", "彼此是行人。", "先自离愁无数，那堪病酒伤春。", "岸花樯燕，低飞款语，满面殷勤。", "后会不知何日，因风时惠嘉音。"]'),
('song-ci-273','柳梢青','黄机','宋','宋词','song-ci','柳梢青','[]','征路迢迢，征旗猎猎，征袖徘徊。',61,'宋词/ci.song.14000.json','["征路迢迢，征旗猎猎，征袖徘徊。", "扑簌珠泪，怕闻别语，慵举离杯。", "春风花柳齐开。", "只唤做、愁端恨媒。", "一片衷肠，十分好事，等待回来。"]'),
('song-ci-274','丑奴儿・采桑子','黄机','宋','宋词','song-ci','丑奴儿・采桑子','[]','绮窗拨断琵琶索，一一相思。',52,'宋词/ci.song.14000.json','["绮窗拨断琵琶索，一一相思。", "一一相思。", "无限柔情说似谁。", "银钩欲写回文曲，泪满乌丝。", "泪满乌丝。", "薄幸知他知不知。"]'),
('song-ci-275','满庭芳','黄机','宋','宋词','song-ci','满庭芳','[]','二十年间，旧游踪迹，梦飞岳麓湘湾。',118,'宋词/ci.song.14000.json','["二十年间，旧游踪迹，梦飞岳麓湘湾。", "征衫再理，秋老菊花天。", "为客问君何好，爱水光、山色争妍。", "经行处，旗亭酤酒，曾记屋东偏。", "噫其，吾甚矣，不渐蹇拙，欲斗婵娟。", "办轻舆短艇，强载衰颜。", "人道郴阳无雁，奈情锺、藕断丝联。", "须相忆，新诗赋就，时复寄吴笺。"]'),
('song-ci-276','清平乐','黄机','宋','宋词','song-ci','清平乐','[]','西风猎猎。',54,'宋词/ci.song.14000.json','["西风猎猎。", "又是登高节。", "一片情怀无处说。", "秋满江头红叶。", "谁怜鬓影凄凉。", "新来更点吴霜。", "孤负萸囊菊盏，年年客里重阳。"]'),
('song-ci-277','谒金门','黄机','宋','宋词','song-ci','谒金门','[]','秋向晚。',53,'宋词/ci.song.14000.json','["秋向晚。", "秋晚蕙根犹暖。", "碧染罗裙湘水浅。", "羞红微到脸。", "窣窣绣帘围遍。", "月薄霜明庭院。", "妆罢宝奁慵不掩。", "无风香自满。"]'),
('song-ci-278','木兰花慢','黄机','宋','宋词','song-ci','木兰花慢','[]','づ文王前子，自不与、世人同。',123,'宋词/ci.song.14000.json','["づ文王前子，自不与、世人同。", "况地望既华，天资更伟，云骥行空。", "年少才名蜚动，泛星槎、曾到广寒宫。", "桂子香浓秋月，桃花浪暖春风。", "神仙之说朦胧。", "铅与汞、亦何功。", "政磐石规模，维城事业，倚重周宗。", "休要碧油红旆，趁黑头、时节做三公。", "堂上双亲未老，稳看金紫重重。"]'),
('song-ci-279','满江红','严羽','宋','宋词','song-ci','满江红','["\u94b1\u5858\u6c5f"]','日近觚棱，秋渐满、蓬莱双阙。',112,'宋词/ci.song.14000.json','["日近觚棱，秋渐满、蓬莱双阙。", "正钱塘江上，潮头如雪。", "把酒送君天上去，琼裾玉佩鹓鸿列。", "丈夫儿、富贵等浮云，看名节。", "天下事，吾能说。", "今老矣，空凝绝。", "对西风慷慨，唾壶歌缺。", "不洒世间儿女泪，难堪亲友中年别。", "问相思、他日镜中看，萧萧发。"]'),
('song-ci-280','沁园春','严羽','宋','宋词','song-ci','沁园春','[]','问讯溪庄，景如之何，吾为平章。',137,'宋词/ci.song.14000.json','["问讯溪庄，景如之何，吾为平章。", "自月湖不见，江山零落，骊塘去后，烟月凄凉。", "有老先生，如梅峰者，健笔纵横为发扬。", "还添得，石屏诗句，一段风光。", "主人雅兴徜徉。", "每携客临流泛羽觞。", "想归来松菊，小烦管领，同盟鸥鹭，未许相忘。", "我道其间，如斯人物，只合盛之白玉堂。", "还须把，扁舟借我，散发沧浪。"]'),
('song-ci-281','贺新郎','严仁','宋','宋词','song-ci','贺新郎','["\u6d1e\u5ead\u6e56"]','兰芷湘东国。',142,'宋词/ci.song.14000.json','["兰芷湘东国。", "正愁予、一江红叶，水程孤驿。", "欲写潇湘无限意，那得如椽彩笔。", "但满眼、西风萧瑟。", "我所思兮何处所，在镡津、津上沧湾侧。", "谁氏子，阆风客。", "阆风仙客才无敌。", "赋悲秋、抑扬顿挫，流篱沈郁。", "百赋千诗朝复暮，解道波涛春力。", "忆共尔、乘槎吹笛。", "八表神游吾梦见，渺洞庭、青草烟波隔。", "空怅望，楚天碧。"]'),
('song-ci-282','贺新郎','严仁','宋','宋词','song-ci','贺新郎','[]','碧浪摇春渚。',142,'宋词/ci.song.14000.json','["碧浪摇春渚。", "浸虚檐、蒲萄滉漾，翠绡掀舞。", "委曲经过台下路，载取落花东去。", "问花亦、漂流良苦。", "花不能言应有恨，恨十分、都被春风误。", "同此恨，有飞絮。", "人生聚散元无据。", "尽凭阑、一尊相对，苹州春暮。", "嫉色冲冲空怅望，泪尽世间儿女。", "君不见、千金求赋。", "飞燕婕妤今何在，看黏云、江影伤千古。", "流不去，断魂处。"]'),
('song-ci-283','贺新郎','严仁','宋','宋词','song-ci','贺新郎','[]','说到城南杜。',142,'宋词/ci.song.14000.json','["说到城南杜。", "尽风流、至今人号，去天尺五。", "家世联翩苍玉佩，自有文章机杼。", "看鸾凤、九霄轩翥。", "文阵堂堂新得隽，正少年、壮气虹霓吐。", "拈彩笔，月城去。", "出关相送梅千树。", "雪连空、马蹄特特，晓寒人度。", "帝里春浓花似海，催入明光奏赋。", "须快展、亨衢阔步。", "随世功名真漫浪，要平生、所学期无负。", "须记得，别时语。"]'),
('song-ci-284','归朝欢','严仁','宋','宋词','song-ci','归朝欢','[]','五月人间挥汗雨。',122,'宋词/ci.song.14000.json','["五月人间挥汗雨。", "离恨一襟何处去。", "双溪楼下碧千寻，双溪楼上匏尊举。", "晚凉生绿树。", "渔灯几点依洲渚。", "莫狂歌，潭空月净，惨惨瘦蛟舞。", "变化往来无定所。", "求剑刻舟应笑汝。", "只今谁是晋司空，斗牛奕奕红光吐。", "我来空吊古，与君同记凭阑语。", "问沧波，乘槎此去，流到天河否。"]'),
('song-ci-285','归朝欢','严仁','宋','宋词','song-ci','归朝欢','[]','云表金茎珠璀璨。',122,'宋词/ci.song.14000.json','["云表金茎珠璀璨。", "当日投怀惊玉燕。", "文章议论压西廱，风流姓字翔东观。", "紫皇嗟见晚。", "祥麟五色留金殿。", "大江西，铜章墨绶，暂尔烦君绾。", "十二金钗扶玉盏。", "锦瑟摐摐随急管。", "兽炉烟动彩云高，秋声拍碎红牙板。", "趣君归翰苑。", "莱衣焕烂潘舆稳。", "任方瞳，从今看到，弱水波清浅。"]'),
('song-ci-286','归朝欢','严仁','宋','宋词','song-ci','归朝欢','[]','朱户绿窗深窈窕。',122,'宋词/ci.song.14000.json','["朱户绿窗深窈窕。", "闪闪华旗红干小。", "相逢斜柳绊轻舟，渚香不断苹花老。", "西风吹梦草。", "题诗未了还惊觉。", "独伤心，凄凉故馆，月过西楼悄。", "楼外斜河低浸斗。", "夜已如何夜将晓。", "心期欲寄赤鳞鱼，秋云不动秋江渺。", "相思千里道。", "多情直被无情恼。", "玉台前，请君试看，华发添多少。"]'),
('song-ci-287','水龙吟','严仁','宋','宋词','song-ci','水龙吟','[]','翼然新榜高亭，翰林铁画燕公手。',126,'宋词/ci.song.14000.json','["翼然新榜高亭，翰林铁画燕公手。", "滁阳盛事，何人重继，湟川太守。", "太守谓谁，文章的派，醉翁贤胃。", "对千峰削翠，双溪注玉，端不减、琅琊秀。", "坐啸清香画戟，听丁丁、滴花晴漏。", "棠阴昼寂，细赓宾客，竹枝杨柳。", "只恐明朝，绨封趣觐，未容借寇。", "尽江山识赏，盐梅事业，焕青毡旧。"]'),
('song-ci-288','水龙吟','严仁','宋','宋词','song-ci','水龙吟','[]','飚车飞上蓬莱，不须更跨琴高鲤。',126,'宋词/ci.song.14000.json','["飚车飞上蓬莱，不须更跨琴高鲤。", "砉然长啸，天风澒洞，云涛无际。", "我欲乘桴，从兹浮海，约任公子。", "办虹竿千丈，犗钩五十，亲点对、连鳌饵。", "谁榜佳名空翠。", "紫阳仙、去骑箕尾。", "银钩铁画，龙拿凤翥，留人间世。", "更忆东山，哀筝一曲，洒沾襟泪。", "到而今，幸有高亭遗爱，寓甘棠意。"]'),
('song-ci-289','水龙吟','严仁','宋','宋词','song-ci','水龙吟','[]','城头杰观峥嵘，重阑下瞰苍龙脊。',126,'宋词/ci.song.14000.json','["城头杰观峥嵘，重阑下瞰苍龙脊。", "镂珉盘础，雕檀竦楶，玲珑金碧。", "华子冈头，麻源谷口，神仙窟宅。", "道至今清夜，月明风冷，常隐隐、闻笙笛。", "翠壁烟霞缥缈，更寒泉、飞空千尺。", "数峰江上，孤舟天际，夕阳红湿。", "抖擞征尘，浩然长啸，跨青鸾翼。", "向凤岗西望，遥酾斗酒，酹文章伯。"]'),
('song-ci-290','水调歌头','严仁','宋','宋词','song-ci','水调歌头','[]','惨淡望京阙，慷慨梦天山。',114,'宋词/ci.song.14000.json','["惨淡望京阙，慷慨梦天山。", "引杯中夜看剑，壮气刷幽燕。", "鼍鼓满天催曙，画角连云啸月，吹断戍瓶烟。", "犀角赤兔马，虎帐绿熊毡。", "仗汉节，伸大义，伐可汗。", "青冥更下斧钺，赤子要君安。", "铁骑千群观猎，宫样十眉环座，礕礰听鸣弦。", "莫厌兜鍪冷，归去又貂蝉。"]'),
('song-ci-291','木兰花慢','严仁','宋','宋词','song-ci','木兰花慢','[]','东风吹雾雨，更吹起、夹衣寒。',123,'宋词/ci.song.14000.json','["东风吹雾雨，更吹起、夹衣寒。", "正莽莽丛林，潭潭伐鼓，郁郁焚兰。", "阑干曲、多少意，看青烟如篆绕溪湾。", "桑柘绿阴犹薄，杏桃红雨初翻。", "飞花片片走潺湲。", "问何日西还。", "叹扰扰人生，纷纷离合，渺渺悲欢。", "想云軿、何处也，对芳时、应只在人间。", "惆怅回纹锦字，断肠斜日云山。"]'),
('song-ci-292','蝶恋花','严仁','宋','宋词','song-ci','蝶恋花','["\u957f\u6c5f"]','杰阁青红天半倚。',70,'宋词/ci.song.14000.json','["杰阁青红天半倚。", "万里归舟，更近阑干舣。", "木落山寒凫雁起。", "一声渔笛沧洲尾。", "千古文章黄太史。", "扪虱高风，长照冰壶里。", "何以荐君秋菊蕊。", "癯瓢为酌西江水。"]'),
('song-ci-293','蝶恋花','严仁','宋','宋词','song-ci','蝶恋花','[]','院静日长花气暖。',70,'宋词/ci.song.14000.json','["院静日长花气暖。", "一簇娇红，得见春深浅。", "风送生香来近远。", "笑声只在秋千畔。", "目力未穷肠已断。", "一寸芳心，更逐游丝乱。", "朱户对开帘卷半。", "日斜江上春风晚。"]'),
('song-ci-294','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','一径萧条落叶深。',64,'宋词/ci.song.14000.json','["一径萧条落叶深。", "离肠凄断月明砧。", "征鸿送恨连云起，促织惊秋傍砌吟。", "风悄悄，夜沈沈。", "鸳机坐冷晓霜侵。", "挑成锦字心相向，未必君心似妾心。"]'),
('song-ci-295','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','多病春来事事慵。',64,'宋词/ci.song.14000.json','["多病春来事事慵。", "偶因扑蝶到庭中。", "落红万叠花经雨，斜碧千条柳因风。", "深院宇，小帘栊。", "几年离别恰相逢。", "擎觞未饮心先醉，为有春愁似酒浓。"]'),
('song-ci-296','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','行尽春山春事空。',64,'宋词/ci.song.14000.json','["行尽春山春事空。", "别愁离恨满江东。", "三更鼓润官楼雨，五夜灯残客舍风。", "寒淡淡，晓胧胧。", "黄鸡催断丑时钟。", "紫骝嚼勒金衔响，冲破飞花一道红。"]'),
('song-ci-297','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','一曲危弦断客肠。',64,'宋词/ci.song.14000.json','["一曲危弦断客肠。", "津桥捩柂转牙樯。", "江心云带蒲帆重，楼上风吹粉泪香。", "瑶草碧，柳芽黄。", "载将离恨过潇湘。", "请君看取东流水，方识人间别意长。"]'),
('song-ci-298','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','病去那知春事深。',64,'宋词/ci.song.14000.json','["病去那知春事深。", "流莺唤起惜春心。", "桐舒碧叶悭三寸，柳引金丝可一寻。", "怜绣阁，对云岑。", "苦无多力懒登临。", "翠罗衫底寒犹在，弱骨难支瘦不禁。"]'),
('song-ci-299','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','高杏酣酣出短墙。',64,'宋词/ci.song.14000.json','["高杏酣酣出短墙。", "垂杨袅袅蘸池塘。", "文鸳藉草眠春昼，金鲫吹波弄夕阳。", "闲倚镜，理明妆。", "自翻银叶炷衙香。", "鸣鞭已过青楼曲，不是刘郎定阮郎。"]'),
('song-ci-300','鹧鸪天','严仁','宋','宋词','song-ci','鹧鸪天','[]','公子诗成著锦袍。',64,'宋词/ci.song.14000.json','["公子诗成著锦袍。", "王家桃叶旧妖娆。", "檀槽摐急斜金雁，彩袖翩跹□翠翘。", "沈水过，懒重烧。", "十分浓醉十分娇。", "复罗帐里春寒少，只恐香酥拍渐消。"]'),
('song-ci-301','玉楼春','严仁','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','春风只在园西畔。',64,'宋词/ci.song.14000.json','["春风只在园西畔。", "荠菜花繁胡蝶乱。", "冰池晴绿照还空，香径落红吹已断。", "意长翻恨游丝短。", "尽日相思罗带缓。", "宝奁明月不欺人，明日归来君试看。"]'),
('song-ci-302','阮郎归','严仁','宋','宋词','song-ci','阮郎归','[]','鳃花轻拂紫绵香。',56,'宋词/ci.song.14000.json','["鳃花轻拂紫绵香。", "琼杯初暖妆。", "贪凭雕槛看鸳鸯。", "无心上绣床。", "风絮乱。", "恣轻狂。", "恼人依旧忙。", "梦随残雨下高唐。", "悠悠春梦长。"]'),
('song-ci-303','婆罗门引','严仁','宋','宋词','song-ci','婆罗门引','[]','花明柳暗，一天春色绕朱楼。',93,'宋词/ci.song.14000.json','["花明柳暗，一天春色绕朱楼。", "断鸿声唤人愁。", "欲问归鸿何处，身世自悠悠。", "正东风留滞，楚尾吴头。", "追思旧游。", "叹双鬓、飒惊秋。", "可惜等闲孤了，酒令花筹。", "断弦难续，谩题诗、分付水东流。", "流不到、蓬岛瀛洲。"]'),
('song-ci-304','醉桃源・阮郎归','严仁','宋','宋词','song-ci','醉桃源・阮郎归','[]','拍堤春水蘸垂杨。',56,'宋词/ci.song.14000.json','["拍堤春水蘸垂杨。", "水流花片香。", "弄花喈柳小鸳鸯。", "一双随一双。", "帘半卷，露新妆。", "春衫是柳黄。", "倚阑看处背斜阳。", "风流暗断肠。"]'),
('song-ci-305','好事近','严仁','宋','宋词','song-ci','好事近','[]','晓色未分明，敲动月边鼍鼓。',53,'宋词/ci.song.14000.json','["晓色未分明，敲动月边鼍鼓。", "卯酒一杯径醉，又别君南浦。", "春江如席照晴空，大舶夹双橹。", "肠断斜阳渡口，正落红如雨。"]'),
('song-ci-306','诉衷情','严仁','宋','宋词','song-ci','诉衷情','[]','一声水调解兰舟。',55,'宋词/ci.song.14000.json','["一声水调解兰舟。", "人间无此愁。", "无情江水东流去，与我泪争流。", "人已远，更回头。", "苦凝眸。", "断魂何处，梅花岸曲，小小红楼。"]'),
('song-ci-307','多丽','严仁','宋','宋词','song-ci','多丽','[]','最无端，官楼画角轻吹。',173,'宋词/ci.song.14000.json','["最无端，官楼画角轻吹。", "一声来、深闺深处，把人好梦惊回。", "许多愁、尽教奴受，些个事、未必君知。", "泪滴兰衾，寒生珠幌，翠云撩乱枕频敧。", "窗儿上、几条残月，斜玉界罗帷。", "更堪听，霜摧败叶，静扣朱扉。", "念别离、千里万里，问何日是归期。", "关情处、鱼来雁往，断肠是、兔走乌飞。", "美景良辰，赏心乐事，风流孤负缕金衣。", "谩赢得、花颜玉骨，瘦损为相思。", "归须早，刘郎双鬓，莫遣成丝。"]'),
('song-ci-308','一落索','严仁','宋','宋词','song-ci','一落索','[]','清晓莺啼红树。',58,'宋词/ci.song.14000.json','["清晓莺啼红树。", "又一双飞去。", "日高花气扑人来，独自价、伤春无绪。", "别后暗宽金缕。", "倩谁传语。", "一春不忍上高楼，为怕见、分携处。"]'),
('song-ci-309','南柯子・南歌子','严仁','宋','宋词','song-ci','南柯子・南歌子','[]','柳陌通云径，琼梳启翠楼。',62,'宋词/ci.song.14000.json','["柳陌通云径，琼梳启翠楼。", "桃花纸薄渍冰油。", "记得年时诗句、为君留。", "晓绿千层出，春红一半休。", "门前溪水泛花流。", "流到西州犹是、故家愁。"]'),
('song-ci-310','菩萨蛮','严仁','宋','宋词','song-ci','菩萨蛮','[]','征鸿点破空云碧。',52,'宋词/ci.song.14000.json','["征鸿点破空云碧。", "丹霞染出新秋色。", "返照落平洲。", "半江红锦流。", "风清渔笛晚。", "寸寸愁肠断。", "寄语笛休横。", "只消三两声。"]'),
('song-ci-311','沁园春','严参','宋','宋词','song-ci','沁园春','[]','曰归去来，归去来兮，吾将安归。',138,'宋词/ci.song.14000.json','["曰归去来，归去来兮，吾将安归。", "但有东篱菊，有西园桂，有南溪月，有北山薇。", "蜂则有房，鱼还有穴，蚁有楼台兽有依。", "吾应有、云中旧隐，竹里柴扉。", "人间征路熹微。", "看处处丹枫白露晞。", "况寒原衰草，牛羊来下，淡烟秋水，鲈鳜初肥。", "自笑平生，颓然骨相，只合持竿坐钓矶。", "都休也，对西风无语，落日斜晖。"]'),
('song-ci-312','沁园春','严参','宋','宋词','song-ci','沁园春','[]','竹焉美哉，爱竹者谁，曰君子欤。',139,'宋词/ci.song.14000.json','["竹焉美哉，爱竹者谁，曰君子欤。", "向佳山水处，筑宫一亩，好风烟里，种玉千馀。", "朝引轻霏，夕延凉月，此外尘埃一点无。", "须知道，有乐其乐者，吾爱吾庐。", "竹之清也何如。", "应料得诗人清矣乎。", "况满庭秀色，对拈彩笔，半窗凉影，伴读残书。", "休说龙吟，莫言凤啸，且道高标谁胜渠。", "君试看，正绕坡云气，似渭川图。"]'),
('song-ci-313','疏帘淡月・桂枝香','张辑','宋','宋词','song-ci','疏帘淡月・桂枝香','[]','梧桐雨细。',124,'宋词/ci.song.14000.json','["梧桐雨细。", "渐滴作秋声，被风惊碎。", "润逼衣篝，线袅蕙炉沈水。", "悠悠岁月天涯醉。", "一分秋、一分憔悴。", "紫箫吟断，素笺恨切，夜寒鸿起。", "又何苦、凄凉客里。", "负草堂春绿，竹溪空翠。", "落叶西风，吹老几番尘世。", "从前谙尽江湖味。", "听商歌、归兴千里。", "露侵宿酒，疏帘淡月，照人无寐。"]'),
('song-ci-314','貂裘换酒・贺新郎','张辑','宋','宋词','song-ci','貂裘换酒・贺新郎','[]','笛唤春风起。',142,'宋词/ci.song.14000.json','["笛唤春风起。", "向湖边、腊前折柳，问君何意。", "孤负梅花立晴昼，一舸凄凉雪底。", "但小阁、琴棋而已。", "佳客清朝留不住，为康庐、只在家窗里。", "湓浦去，两程耳。", "草堂旧日谈经地。", "更从容、南山北水，庾楼重倚。", "万卷心胸几今古，牛斗多年紫气。", "正江上、风寒如此。", "且趁霜天鲈鱼好，把貂裘、换酒长安市。", "明夜去，月千里。"]'),
('song-ci-315','淮甸春・念奴娇','张辑','宋','宋词','song-ci','淮甸春・念奴娇','[]','短髯怀古，更文游台上，秋生吟兴。',120,'宋词/ci.song.14000.json','["短髯怀古，更文游台上，秋生吟兴。", "闻说坡仙来把酒，月底频留清影。", "极目平芜，孤城四水，画角西风劲。", "曲阑犹在，十分心事谁领。", "词卷空落人间，黄楼何处，回首愁深省。", "斜照寒鸦知几度，梦想当年名胜。", "只有山川，曾窥翰墨，仿佛馀风韵。", "旧游休问，柳花淮甸春冷。"]'),
('song-ci-316','如此江山・齐天乐','张辑','宋','宋词','song-ci','如此江山・齐天乐','[]','西风扬子江头路。',123,'宋词/ci.song.14000.json','["西风扬子江头路。", "扁舟雨晴呼渡。", "岸隔瓜洲，津横蒜石，摇尽波声千古。", "诗仙一去。", "但对峙金焦，断矶青树。", "欲下斜阳，长淮渺渺正愁予。", "中流笑与客语。", "把貂裘为浣，半生尘土。", "品水烹茶，看碑忆鹤，恍似旧曾游处。", "聊凭陆諝。", "问八极神游，肯重来否。", "如此江山，更苍烟白露。"]'),
('song-ci-317','钓船笛・好事近','张辑','宋','宋词','song-ci','钓船笛・好事近','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','载酒岳阳楼，秋入洞庭深碧。',53,'宋词/ci.song.14000.json','["载酒岳阳楼，秋入洞庭深碧。", "极目水天无际，正白苹风急。", "月明不见宿鸥惊，醉把玉阑拍。", "谁解百年心事，恰钓船横笛。"]'),
('song-ci-318','广寒秋・鹊桥仙','张辑','宋','宋词','song-ci','广寒秋・鹊桥仙','[]','杯行将半，月来犹未，潇洒水亭无暑。',68,'宋词/ci.song.14000.json','["杯行将半，月来犹未，潇洒水亭无暑。", "清宵数客一阑秋，对冰雪、荷花似语。", "雄边台上，文游台上，咫尺红云容与。", "天风吹送广寒秋，正画舸、湖光佳处。"]'),
('song-ci-319','月当窗・霜天晓角','张辑','宋','宋词','song-ci','月当窗・霜天晓角','[]','看朱成碧。',54,'宋词/ci.song.14000.json','["看朱成碧。", "曾醉梅花侧。", "相遇匆匆相别，又争似、不相识。", "南北。", "千里隔。", "几时重见得。", "最苦子规啼处，一片月、当窗白。"]'),
('song-ci-320','山渐青・长相思','张辑','宋','宋词','song-ci','山渐青・长相思','[]','山无情。',44,'宋词/ci.song.14000.json','["山无情。", "水无情。", "杨柳飞花春雨晴。", "征衫长短亭。", "拟行行。", "重行行。", "吟到江南第几程。", "江南山渐青。"]'),
('song-ci-321','碧云深・忆秦娥','张辑','宋','宋词','song-ci','碧云深・忆秦娥','[]','风凄凄。',56,'宋词/ci.song.14000.json','["风凄凄。", "井阑络纬惊秋啼。", "惊秋啼。", "凉侵好梦，月正楼西。", "卷帘望月知心谁。", "关河空隔长相思。", "长相思。", "碧云暮合，有美人兮。"]'),
('song-ci-322','南浦月・点绛唇','张辑','宋','宋词','song-ci','南浦月・点绛唇','[]','来翦莼丝，江头一阵鸣蓑雨。',50,'宋词/ci.song.14000.json','["来翦莼丝，江头一阵鸣蓑雨。", "孤篷归路。", "吹得苹花暮。", "短发萧萧，笑与沙鸥语。", "休归去。", "玉龙嘶处。", "邀月过南浦。"]'),
('song-ci-323','沙头雨・点绛唇','张辑','宋','宋词','song-ci','沙头雨・点绛唇','[]','带醉归时，月华犹在吹箫处。',50,'宋词/ci.song.14000.json','["带醉归时，月华犹在吹箫处。", "晚愁情绪。", "忘却匆匆语。", "客里风霜，诗鬓空如许。", "江南去。", "岸花迎橹。", "遥隔沙头雨。"]'),
('song-ci-324','花自落・谒金门','张辑','宋','宋词','song-ci','花自落・谒金门','[]','春寂寞。',53,'宋词/ci.song.14000.json','["春寂寞。", "帘底蕙炉烟薄。", "听尽归鸿书怎托。", "相思天一角。", "象笔鸾笺闲却。", "秀句与谁商略。", "睡起愁怀何处著。", "无风花自落。"]'),
('song-ci-325','垂杨碧・谒金门','张辑','宋','宋词','song-ci','垂杨碧・谒金门','[]','花半湿。',53,'宋词/ci.song.14000.json','["花半湿。", "睡起一窗晴色。", "千里江南真咫尺。", "醉中归梦直。", "前度兰舟送客。", "双鲤沈沈消息。", "楼外垂杨如此碧。", "问春来几日。"]'),
('song-ci-326','阑干万里心・忆王孙','张辑','宋','宋词','song-ci','阑干万里心・忆王孙','[]','小楼柳色未春深。',36,'宋词/ci.song.14000.json','["小楼柳色未春深。", "湘月牵情入苦吟。", "翠袖风前冷不禁。", "怕登临。", "几曲阑干万里心。"]'),
('song-ci-327','杏梁燕・解连环','张辑','宋','宋词','song-ci','杏梁燕・解连环','[]','小楼春浅。',131,'宋词/ci.song.14000.json','["小楼春浅。", "记钓帘看雪，袖沾芳片。", "似不似、柳絮因风，更细与品题，屡呵冰砚。", "宛转吟情，纵真草、凤笺都遍。", "到灯前笑谑，酒祓峭寒，移尽更箭。", "而今柳阴满院。", "知花空雪似，人隔春远。", "叹万事、流水斜阳，谩赢得前诗，醉污团扇。", "脉脉重来，算惟有、画阑曾见。", "把千种旧愁，付与杏梁语燕。"]'),
('song-ci-328','比梅・如梦令','张辑','宋','宋词','song-ci','比梅・如梦令','[]','深夜沉沉尊酒。',40,'宋词/ci.song.14000.json','["深夜沉沉尊酒。", "酒醒客衾寒透。", "城角挟霜飞，吹得月如清昼。", "僝僽。", "僝僽。", "比著梅花谁瘦。"]'),
('song-ci-329','月上瓜洲・相见欢','张辑','宋','宋词','song-ci','月上瓜洲・相见欢','[]','江头又见新秋。',45,'宋词/ci.song.14000.json','["江头又见新秋。", "几多愁。", "塞草连天何处、是神州。", "英雄恨，古今泪，水东流。", "惟有渔竿明月、上瓜洲。"]'),
('song-ci-330','月底修箫谱・祝英台近','张辑','宋','宋词','song-ci','月底修箫谱・祝英台近','["\u897f\u6e56"]','客西湖，听夜雨。',95,'宋词/ci.song.14000.json','["客西湖，听夜雨。", "更向别离处。", "小小船窗，香雪照尊俎。", "断肠一曲秋风，行云不语。", "总写入、征鸿无数。", "认眉妩。", "唤醒岩壑风流，丹砂有奇趣。", "羞杀秦郎，淮海谩千古。", "要看自作新词，双鸾飞舞。", "趁月底、重修箫谱。"]'),
('song-ci-331','一丝风・诉衷情令','张辑','宋','宋词','song-ci','一丝风・诉衷情令','[]','卧虹千尺界湖光。',54,'宋词/ci.song.14000.json','["卧虹千尺界湖光。", "冷浸月茫茫。", "当日三高何处，渔唱入凄凉。", "人世事，纵轩裳。", "梦黄梁。", "有谁蓑笠，一钓丝风，吹尽荷香。"]'),
('song-ci-332','忆萝月・清平乐','张辑','宋','宋词','song-ci','忆萝月・清平乐','[]','新凉窗户。',54,'宋词/ci.song.14000.json','["新凉窗户。", "闲对琴言语。", "弹到无人知得处。", "两袖五湖烟雨。", "坐中斗转参横。", "珠躔碎落瑶觥。", "忆著故山萝月，今宵应为谁明。"]'),
('song-ci-333','倚秋千・好事近','张辑','宋','宋词','song-ci','倚秋千・好事近','[]','人在玉屏闲，逗晓柳丝风急。',53,'宋词/ci.song.14000.json','["人在玉屏闲，逗晓柳丝风急。", "帘外杏花微雨，罩春红愁湿。", "单衣初试曲尘罗，中酒病无力。", "应是绣床慵困，倚秋千斜立。"]'),
('song-ci-334','断肠声・南歌子','张辑','宋','宋词','song-ci','断肠声・南歌子','[]','柳户朝云湿，花窗午篆清。',62,'宋词/ci.song.14000.json','["柳户朝云湿，花窗午篆清。", "东风未放十分晴。", "留恋海棠颜色、过清明。", "垒润栖新燕，笼深锁旧莺。", "琵琶可是不堪听。", "无奈愁人把做、断肠声。"]'),
('song-ci-335','念奴娇','张辑','宋','宋词','song-ci','念奴娇','[]','嫩凉生晓，怪今朝湖上，秋风无迹。',120,'宋词/ci.song.14000.json','["嫩凉生晓，怪今朝湖上，秋风无迹。", "古寺桂香山色外，肠断幽丛金碧。", "骤雨俄来，苍烟不见，苔径孤吟屐。", "系船高柳，晚蝉嘶破愁寂。", "且约携酒高歌，与鸥相好，分坐渔矶石。", "算只藕花知我意，犹把红芳留客。", "楼阁空濛，管弦清润，一水盈盈隔。", "不如休去，月悬良夜千尺。"]'),
('song-ci-336','祝英台近','张辑','宋','宋词','song-ci','祝英台近','[]','竹间棋，池上字。',95,'宋词/ci.song.14000.json','["竹间棋，池上字。", "风日共清美。", "谁道春深，湘绿涨沙觜。", "更添杨柳无情，恨烟颦雨，却不把、扁舟偷系。", "去千里。", "明日知几重山，后朝几重水。", "对酒相思、争似且留醉。", "奈何琴剑匆匆，而今心事，在月夜、杜鹃声里。"]'),
('song-ci-337','忆秦娥','张辑','宋','宋词','song-ci','忆秦娥','[]','春寂寂。',56,'宋词/ci.song.14000.json','["春寂寂。", "画阑背倚春风立。", "春风立。", "楚山无数，暮天云碧。", "琴心写遍愁何极。", "断肠谁与传消息。", "传消息。", "当年情墨，泪痕犹湿。"]'),
('song-ci-338','浣溪沙','张辑','宋','宋词','song-ci','浣溪沙','[]','夏果初收唤绿华。',48,'宋词/ci.song.14000.json','["夏果初收唤绿华。", "冰盘巧簇映金瓜。", "荷香飞上玉流霞。", "明月长留千岁色，蟠桃多结几番花。", "谁知罗带有丹砂。"]'),
('song-ci-339','霜天晓角','张辑','宋','宋词','song-ci','霜天晓角','[]','暮天云阔。',54,'宋词/ci.song.14000.json','["暮天云阔。", "懒泛琴三叠。", "恰有梅花相伴，窗儿上、一枝月。", "忆别。", "恁时节。", "吟情谁共说。", "敧枕偶成清梦，画角晓、更愁绝。"]'),
('song-ci-340','临江仙','张辑','宋','宋词','song-ci','临江仙','["\u5e90\u5c71"]','迢递关山身历遍，烟霞胜处曾游。',70,'宋词/ci.song.14000.json','["迢递关山身历遍，烟霞胜处曾游。", "九江江畔系孤舟。", "匡庐如画里，南望插天浮。", "瀑布香炉齐五老，层层爽气陵秋。", "何须魂梦觅瀛洲。", "云松终可卜，我与谪仙俦。"]'),
('song-ci-341','洞仙歌','张辑','宋','宋词','song-ci','洞仙歌','[]','莲舟玉字，得真人亲授。',101,'宋词/ci.song.14000.json','["莲舟玉字，得真人亲授。", "圯上家风又还有。", "问因何五马，踏月云台。", "秋色里，却赏烟霞袖手。", "酒边听说剑，歌舞升平，方许君为赤松友。", "任浊世纷纭，海水扬尘，再相见、雪髯依旧。", "且岁岁、中秋后逾旬，更半月东离，菊花重九。"]'),
('song-ci-342','满江红','张辑','宋','宋词','song-ci','满江红','[]','醉发吹凉，但拂剑、狂歌而已。',115,'宋词/ci.song.14000.json','["醉发吹凉，但拂剑、狂歌而已。", "倩谁问、九霄黄鹤，更曾来未。", "玉女窗深松昼静，研朱重点参同契。", "记前回、赤水得玄珠，骊龙睡。", "空扰扰，人间世。", "除学道，无真是。", "把洪崖肩拍，挹浮丘袂。", "朝驾长风沧岛上，夜骑明月青天际。", "更几时、回首旧山川，三千岁。"]'),
('song-ci-343','东风第一枝','张辑','宋','宋词','song-ci','东风第一枝','[]','雨蕊方桃，晴梢渐杏，东风娇语弦管。',123,'宋词/ci.song.14000.json','["雨蕊方桃，晴梢渐杏，东风娇语弦管。", "爱香帘约馀寒，唤舞袖翻嫩暖。", "红颜清健，旧墨竹、扶疏手段。", "且碧窗、写就黄庭，画楫海山开卷。", "春自好、得花不淡。", "花又好、得春不浅。", "晓莺瑶佩秋生，月蘸翠尊波满。", "长逢花处，笑西母、霜娥偷换。", "要日边、争看貂蝉，彩侍更迎宣劝。"]'),
('song-ci-344','瑞鹤仙','张辑','宋','宋词','song-ci','瑞鹤仙','[]','柳风双燕语。',127,'宋词/ci.song.14000.json','["柳风双燕语。", "问有谁留人，岸花去橹。", "星辰快平步。", "俯圜扉草色，青青如许。", "儿童拥路。", "玉溪边、当年杜母。", "料从今、指点山川，总是绣衣行处。", "回顾。", "东堂深窈，楚帖长春，竹尊清午。", "红云帝所。", "摇佩玉，更容与。", "把蓬莱一笑，几番清浅，绿野为花作谱。", "向花前、三叠琴心，看苍鹤舞。"]'),
('song-ci-345','绮罗香','张辑','宋','宋词','song-ci','绮罗香','[]','欲雨凉生，初弦月在，画戟香中清啸。',128,'宋词/ci.song.14000.json','["欲雨凉生，初弦月在，画戟香中清啸。", "旋种芙蕖，深夏木兰芳沼。", "银汉入、天镜搀秋，福星度、雪阑争照。", "又谁写、万幅莼波，一江佳思到鱼鸟。", "吴儿眉语笑里，要见圜扉绿遍，平畴青绕。", "羽扇纶巾，萧洒玉貌长好。", "问千年、庆会风云，正此日、静春花草。", "更弦管、非雾非烟，鹤声帘幕晓。"]'),
('song-ci-346','沁园春','张辑','宋','宋词','song-ci','沁园春','[]','东泽先生，谁说能诗，兴到偶然。',139,'宋词/ci.song.14000.json','["东泽先生，谁说能诗，兴到偶然。", "但平生心事，落花啼鸟，多年盟好，白石清泉。", "家近宫亭，眼中庐阜，九叠屏开云锦边。", "出门去，且掀髯大笑，有钓鱼船。", "一丝风里婵娟。", "爱月在沧波上下天。", "更丛书观遍，笔床静昼，篷窗睡起，茶灶疏烟。", "黄鹤来迟，丹砂成未，何日风流葛稚川。", "人间世，听江湖诗友，号我东仙。"]'),
('song-ci-347','贺新郎','张辑','宋','宋词','song-ci','贺新郎','[]','绿阴凉尊俎。',142,'宋词/ci.song.14000.json','["绿阴凉尊俎。", "映双旌、飞翻新带，日边恩露。", "千里湖山添鲜碧，玉宇光浮眉妩。", "料范老、应难独步。", "君亦胸中兵十万，把甘霖、小小春东楚。", "江上早，一犁雨。", "赤城霞起连天姥。", "有丹经、亲曾密授，八篇奇语。", "道骨仙风骑鲸客，合侍红云帝所。", "且画戟、清香时度。", "散入邦人箫鼓里，恰春留、芍药丛歌舞。", "还更咏，大鹏赋。"]'),
('song-ci-348','贺新郎','张辑','宋','宋词','song-ci','贺新郎','[]','鹊喜花间晓。',142,'宋词/ci.song.14000.json','["鹊喜花间晓。", "惜凝香、低将帘卷，海棠开早。", "前度登楼清啸月，吹入春风不老。", "后五日、花朝方到。", "趁舞罗衣花讯暖，拈吟髭、玉勒迎东笑。", "留肯往，春邮小。", "庐峰青里壶天好。", "一千春、棋声昼永，剑光云表。", "绛雪骊珠看丹转，金鼎龙盘虎绕。", "且未可、飞仙蓬岛。", "河洛烟芜眠狐兔，握风雪、办此升平了。", "却共我，拾瑶草。"]'),
('song-ci-349','徵招','张辑','宋','宋词','song-ci','徵招','[]','飞鸿又作秋空字，凄凄旧游湘浦。',117,'宋词/ci.song.14000.json','["飞鸿又作秋空字，凄凄旧游湘浦。", "凉思带愁深，渺苍茫何许。", "岁华知几度。", "奈双鬓、不禁吟苦。", "独倚危楼，叶声摇暮，玉阑无语。", "尺素。", "欲传将，故人远、天涯屡惊回顾。", "心事只琴知，漫闲相尔汝。", "甚时江海去。", "算空负、白苹鸥侣。", "更谁与、翦烛西窗，且醉听山雨。"]'),
('song-ci-350','木兰花慢','张辑','宋','宋词','song-ci','木兰花慢','[]','望瀛洲尺五，听海客、诧登临。',121,'宋词/ci.song.14000.json','["望瀛洲尺五，听海客、诧登临。", "记岛月分秋，天星降夕，神璧精金。", "他年作霖雨手，且明光奏赋寓良箴。", "槐府黑头旧业，芹宫青岁雄襟。", "骎骎。", "宝勒向东吟。", "戏彩看而今。", "更袜步黄云，琴弹碧玉，汇泽杯斟。", "争先长至几日，料春风多喜鹊传音。", "梅蕴和羹心在，线添补衮工深。"]'),
('song-ci-351','醉蓬莱','张辑','宋','宋词','song-ci','醉蓬莱','[]','记澄湖抱练，画舫参差，闹花时节。',120,'宋词/ci.song.14000.json','["记澄湖抱练，画舫参差，闹花时节。", "油壁鸣堤，有障萦屏列。", "燕草香融，鸦条香浅，似渭城烟雪。", "急管斜阳，卫娘葱蒨，带围寒怯。", "苏小闲情，绿杨如织，阑槛东边，好山千叠。", "料得如今，也翠销红歇。", "何限繁华，春来都付与，数声啼鴂。", "谩怆羁魂，扁舟买醉，谢公明月。"]'),
('song-ci-352','好溪山','张辑','宋','宋词','song-ci','好溪山','[]','孤鸿遥下夕阳寒。',56,'宋词/ci.song.14000.json','["孤鸿遥下夕阳寒。", "秋清怀抱宽。", "篱根香满菊金团。", "客中邀客看。", "呼浊酒，共清欢。", "五弦随意弹。", "西窗仍见好溪山。", "几年谁倚栏。"]'),
('song-ci-353','山庄劝酒','张辑','宋','宋词','song-ci','山庄劝酒','["\u897f\u6e56"]','清吟湘碧。',53,'宋词/ci.song.14000.json','["清吟湘碧。", "马首春风驿。", "闻说西湖梅早，又邀我、能诗客。", "书尺知到日。", "月随人合璧。", "儿拟山庄劝酒，田家酿，尽篘得。"]'),
('song-ci-354','临江仙','张辑','宋','宋词','song-ci','临江仙','[]','忆昔风流秋社里，几人冰雪襟期。',70,'宋词/ci.song.14000.json','["忆昔风流秋社里，几人冰雪襟期。", "凉风吹散梦参差。", "寒灯多少恨，长笛不堪吹。", "别去化龙潭上水，东来不寄相思。", "白鸥应笑太忘机。", "沙头重载酒，休负桂花枝。"]'),
('song-ci-355','琐窗寒','张辑','宋','宋词','song-ci','琐窗寒','[]','露漏沈沈，洞房灯悄，鹊翻庭树。',120,'宋词/ci.song.14000.json','["露漏沈沈，洞房灯悄，鹊翻庭树。", "夜凉如水，人倚玉箫何处。", "澹纵横、疏星断河，点衣黄叶飞四五。", "向此时感旧，非关宋玉，悲秋情绪。", "追念章台路。", "共缓辔芳尘，妒花惹絮。", "旧游梦寐，总付相思新句。", "想风流还在匆匆，暗惊鬓底霜几缕。", "凭危栏、立尽归鸿，脆角凝清曙。"]'),
('song-ci-356','画娥眉・忆王孙','张辑','宋','宋词','song-ci','画娥眉・忆王孙','[]','清明小院杏花开。',36,'宋词/ci.song.14000.json','["清明小院杏花开。", "半启朱扉燕子来。", "晓起梳头对玉台。", "照香腮。", "羞睹惊鸿瘦影回。"]'),
('song-ci-357','琐窗寒','苏茂一','宋','宋词','song-ci','琐窗寒','[]','云浦苍寒，烟堤幕翠，旧痕新涨。',122,'宋词/ci.song.14000.json','["云浦苍寒，烟堤幕翠，旧痕新涨。", "春愁十里，冉冉碧丝摇荡。", "记登临、少年思豪，唾壶击玉歌清壮。", "到如今梦里，秋风鸿阵，晚波渔唱。", "惆怅。", "重来处，望画舫天边，辔丝原上。", "山阴秀句，付与一声云响。", "正东湖、谁家柳下，午阴漠漠人荡桨。", "最堪怜、白发周郎，为江山自赏。"]'),
('song-ci-358','点绛唇','苏茂一','宋','宋词','song-ci','点绛唇','[]','竹翠藏烟，杏红流水归何处。',50,'宋词/ci.song.14000.json','["竹翠藏烟，杏红流水归何处。", "透帘穿户。", "更洒黄昏雨。", "织锦题书，谁寄愁情去。", "浑无绪。", "绿杨千缕。", "不似真眉妩。"]'),
('song-ci-359','祝英台近','苏茂一','宋','宋词','song-ci','祝英台近','[]','结垂杨，临广陌，分袂唱阳关。',95,'宋词/ci.song.14000.json','["结垂杨，临广陌，分袂唱阳关。", "稳上征鞍。", "目极万重山。", "归鸿欲到伊行，丁宁须记，写一封、书报平安。", "渐春残。", "是他红褪香收，绡泪点斑斑。", "枕上盟言。", "都做梦中看。", "销魂啼鴂声中，杨花飞处，斜阳下、愁倚阑干。"]'),
('song-ci-360','谒金门','史愚','宋','宋词','song-ci','谒金门','[]','深院宇。',53,'宋词/ci.song.14000.json','["深院宇。", "寂寂不禁风雨。", "苔迳流钱青莫数。", "银泥蜗篆古。", "满院多应无主。", "却被痴儿拈取。", "穿向柳丝喧笑语。", "买将春色去。"]'),
('song-ci-361','满江红','赵灌园','宋','宋词','song-ci','满江红','[]','看尽公卿，都输与、云山居士。',115,'宋词/ci.song.14000.json','["看尽公卿，都输与、云山居士。", "肯掉了、龙章金印，归来闾里。", "云染笔头成五色，山来胸次堆空翠。", "更结庐、近在白鸥边，弄烟水。", "祗恐怕，明天子。", "黄纸唤，先生起。", "教依前插脚，孔鸾丛里。", "岩壑烟沙真作戏，貂蝉衮绣从兹始。", "酌凤凰、池沼九天浆，三千岁。"]'),
('song-ci-362','兰陵王','葛长庚','宋','宋词','song-ci','兰陵王','[]','一溪碧。',158,'宋词/ci.song.14000.json','["一溪碧。", "何处桃花流出。", "春光好，寻个□□，小小篮舆漫行适。", "苍苔满白石。", "涧底阴风凛栗。", "疑无路，幽壑琮琤，峡转山回入林僻。", "千峰呈翠色。", "时亦有声声，樵唱渔笛。", "忽然一树樱桃白。", "又回头一顾，掀髯一笑，诗情酒思正豪逸。", "虎蹄过新迹。", "幂幂。", "雾如织。", "见异草珍禽，问名不识。", "山灵勒驾雨来急。", "欲游观未已，仆言日夕。", "看来看去，似那里，似少室。"]'),
('song-ci-363','兰陵王','葛长庚','宋','宋词','song-ci','兰陵王','[]','三峰碧。',158,'宋词/ci.song.14000.json','["三峰碧。", "缥渺烟光树色。", "高寒处，上有猿啼，鹤唳天风夜萧瑟。", "山形似笔格。", "人道江南第一。", "游紫观，月殿星坛，积翠楼前吹铁笛。", "客来访灵迹。", "闻王郭当年，曾此驻锡。", "二仙为谒浮丘伯。", "从骖鸾去后，云深难觅。", "丹炉灰冷杵声寂。", "依然旧泉石。", "泉石。", "最幽阒。", "更禽静花闲，松茂竹密。", "清都绛阙无消息。", "共羽衣挥麈，感今怀昔。", "堪嗟人世，似梦里，驹过隙。"]'),
('song-ci-364','兰陵王','葛长庚','宋','宋词','song-ci','兰陵王','[]','桃花瘦。',158,'宋词/ci.song.14000.json','["桃花瘦。", "寒食清明前后。", "新燕子，禁得馀寒，风雨把人苦僝僽。", "梅粒今如豆。", "减却春光多少。", "空自有，满树山茶，似语如愁卧晴昼。", "幽人展襟袖。", "惜莺花未老，江山如旧。", "杜鹃声里同携手。", "叹陌上芳草，堤边垂柳。", "一春十病九因酒。", "愁来独搔首。", "豆蔻。", "枝头小。", "应可惜年华，孤负时候。", "九十韶光那得久。", "问芍药觅醉，牡丹索笑。", "三万六千，能几度，君知否。"]'),
('song-ci-365','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','嫩雨如尘，娇云似织，未肯便晴。',140,'宋词/ci.song.14000.json','["嫩雨如尘，娇云似织，未肯便晴。", "见海棠花下，飞来双燕，垂杨深处，啼断孤莺。", "绿砌苔香，红桥水暖，笑拈吟髭行复行。", "幽寻懒、就半窗残睡，一枕初醒。", "消凝。", "次第清明。", "渺南北东西草又青。", "念镜中勋业，韶光冉冉，尊前今古，银发星星。", "青鸟无凭，丹霄有约，独倚东风无限情。", "谁知有，这春山万点，杜宇千声。"]'),
('song-ci-366','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','暂聚如萍，忽散似云，无可奈何。',139,'宋词/ci.song.14000.json','["暂聚如萍，忽散似云，无可奈何。", "向天涯海角，两行别泪，风前月下，一片离骚。", "啼罢栖乌，望穷芳草，此恨与之谁较多。", "昏黄后，对青灯感慨，白酒悲歌。", "梦中作梦知麽。", "忆往事落花流水呵。", "更凭高□远，沈腰不瘦，怅今怀昔，潘鬓须皤。", "去燕来鸿，寻梅问柳，寸念从他寒暑熬。", "消魂处，但烟光缥渺，山色周遭。"]'),
('song-ci-367','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','锦绣文章，圭璋闻望，碧落侍郎。',138,'宋词/ci.song.14000.json','["锦绣文章，圭璋闻望，碧落侍郎。", "昨履声渐近，星辰避次，竹符重剖，湖海生光。", "委羽天空，石桥水冷，每为众生时雨滂。", "君知否，是民心襦库，吏胆冰霜。", "少须召入鹓行。", "也不念无人荷紫囊。", "有本朝曾旦，移春手段，旧家羲献，补月心肠。", "此去三山，却登八座，已准金瓯姓氏香。", "还朝处，双凫作对，五马成行。"]'),
('song-ci-368','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','大丈夫儿，冰肝玉胆，砺山带河。',139,'宋词/ci.song.14000.json','["大丈夫儿，冰肝玉胆，砺山带河。", "算此身此世，无过驹隙，一名一利，未值鸿毛。", "相府如潭，侯门似海，那得烟霄尔许高。", "当初我，是乘云御气，几百千遭。", "此生勋业无多。", "也手种梅花三百窠。", "又底曾嗅著，庙堂钟鼎，底曾拈得，帏幄弓刀。", "玉帝遥知，金书何晚，时有鹤鸣於九皋。", "如今且，向风前浪舞，月下高歌。"]'),
('song-ci-369','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','三径就荒，松菊犹存，归去来兮。',139,'宋词/ci.song.14000.json','["三径就荒，松菊犹存，归去来兮。", "叹折腰为米，弃家因酒，往之不谏，来者堪追。", "形役奚悲，途迷未远，今是还知悟昨非。", "舟轻扬，问征夫前路，晨色熹微。", "欢迎童稚嘻嘻。", "羡出岫云闲鸟倦飞。", "有南窗寄傲，东皋舒啸，西畴春事，植杖耘耔。", "矫首遐观，壶觞自酌，寻壑临流聊赋诗。", "琴书外，且乐天知命，复用何疑。"]'),
('song-ci-370','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','乍雨还晴，似寒而暖，春事已深。',140,'宋词/ci.song.14000.json','["乍雨还晴，似寒而暖，春事已深。", "是妇鸠乳燕，说教鱼跃，豪蜂醉蝶，撩得莺吟。", "斗茗分香，脱禅衣夹，回首清明上已临。", "芳菲处，在梨花金屋，杨柳琼林。", "如今。", "诗酒心襟。", "对好景良辰似有妊。", "念恨如芳草，知他多少，梦和飞絮，何处追寻。", "病酒时光，困人天气，早有秋秧吐嫩针。", "兰亭路，渐流觞曲水，修禊山阴。"]'),
('song-ci-371','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','吹面无寒，沾衣不湿，岂不快哉。',140,'宋词/ci.song.14000.json','["吹面无寒，沾衣不湿，岂不快哉。", "正杏花雨嫩，红飞香砌，柳枝风软，绿映芳台。", "燕似谈禅，莺如演史，犹有海棠连夜开。", "清明也，尚阴晴莫准，蜂蝶休猜。", "朝来。", "应问苍苔。", "甚几日都成锦绣堆。", "念四方宾友，不堪渭树，一年春事，已属庭槐。", "宿酒难醒，多情易老，争奈传杯不放杯。", "如何好，看秋千戏剧，蹴鞠恢谐。"]'),
('song-ci-372','沁园春','葛长庚','宋','宋词','song-ci','沁园春','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','渭水秋深，湓江春老，洞庭一湖。',141,'宋词/ci.song.14000.json','["渭水秋深，湓江春老，洞庭一湖。", "问城南古树，如今在否，洛中狂客，还更来无。", "独上君山，渺观岩石，八百里鲸波泛巨区。", "何曾错，有茶中上灶，酒里仙姑。", "终须。", "度了肩吾。", "稽首终南锺大夫。", "自太平寺里，题诗去后，东林沈宅，大醉归欤。", "天上筵多，人间到少，更不向庐山索鳜鱼。", "如何好，好借君黄鹤，上我清都。"]'),
('song-ci-373','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','且说罗浮，自从石洞，水帘以还。',142,'宋词/ci.song.14000.json','["且说罗浮，自从石洞，水帘以还。", "是向时景泰，初来卓锡，旧家勾漏，曾此修丹。", "药院空存，铁桥如故，上更有朱仙朝斗坛。", "飞云顶，在石桥高处，杳霭之间。", "山前。", "拾得清闲。", "也分我烟霞数亩宽。", "自竹桥人去，青莲馥郁，柴门闭了，绿柳回环。", "白酒初篘，清风徐至，有桃李时新饤几盘。", "仙家好，这许多快活，做甚时官。"]'),
('song-ci-374','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','要做神仙，炼丹工夫，亦有何难。',139,'宋词/ci.song.14000.json','["要做神仙，炼丹工夫，亦有何难。", "向雷声震处，一阳来复，玉炉火炽，金鼎烟寒。", "奼女乘龙，金公跨虎，片晌之间结大还。", "丹田里，有白鸦一个，飞入泥丸。", "河车运入崑山。", "全不动纤毫过玉关。", "把龟蛇乌兔，生擒活捉，霎时云雨，一点成丹。", "白雪漫天，黄芽满地，服此刀圭永驻颜。", "常温养，使脱胎换骨，身在云端。"]'),
('song-ci-375','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','岁去年来，思量人生，空自沈埋。',137,'宋词/ci.song.14000.json','["岁去年来，思量人生，空自沈埋。", "既这回冬至，一阳来复，便须修炼，更莫疑猜。", "好个鼎炉，见成铅汞，片晌工夫结圣胎。", "人身里，三千世界，十二楼台。", "周年造化安排。", "只在这些些真妙哉。", "要先擒日月，后攒星斗，黄庭中畔，化作琼瑰。", "谁会天机，分明说破，恰似江头雪里梅。", "丹成后，做些功行，归去蓬莱。"]'),
('song-ci-376','沁园春','葛长庚','宋','宋词','song-ci','沁园春','["\u5e90\u5c71", "\u8861\u5c71", "\u9ec4\u9e64\u697c"]','黄鹤楼前，吹笛之时，先生朗吟。',142,'宋词/ci.song.14000.json','["黄鹤楼前，吹笛之时，先生朗吟。", "想剑光飞过，朝游南岳，墨篮放下，夜醉东邻。", "铛煮山川，粟藏世界，有明月清风知此音。", "呵呵笑，笑酿成白酒，散尽黄金。", "知音。", "自有相寻。", "休踏破葫芦折断琴。", "唱白苹红蓼，庐山日暮，西风黄叶，渭水秋深。", "三入岳阳，再游湓浦，自一去优游直至今。", "桃源路，尽不妨来往，时共登临。"]'),
('song-ci-377','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','客里家山，记踏来时，水曲山崖。',140,'宋词/ci.song.14000.json','["客里家山，记踏来时，水曲山崖。", "被滩声喧枕，鸡声破晓，匆匆惊觉，依旧天涯。", "抖擞征衣，寒欺晓袂，回首银河西未斜。", "尘埃债，叹有如此发，空为伊华。", "古来客况堪嗟。", "尽贫也输他□在家。", "料驿舍旁边，月痕白处，暗香微度，应是梅花。", "拣折一枝，路逢南雁，和两字平安寄与他。", "教知道，有长亭短堠，五饭三茶。"]'),
('song-ci-378','水龙吟','葛长庚','宋','宋词','song-ci','水龙吟','[]','层峦叠巘浮空，断崖直下分三井。',126,'宋词/ci.song.14000.json','["层峦叠巘浮空，断崖直下分三井。", "苍苔路古，鹿鸣芝涧，猿号松岭。", "露浥凤箫，烟迷枸杞，绿深翠冷。", "笑携筇一到，登高眺远，是多少、仙家景。", "长念青春易老，尚区区、枯蓬断梗。", "人间天上，喟然俯仰，只身孤影。", "世事空花，春心泥絮，此回还省。", "向琼台双阙，结间茅屋，坐千峰顶。"]'),
('song-ci-379','水龙吟','葛长庚','宋','宋词','song-ci','水龙吟','[]','云屏漫锁空山，寒猿啼断松枝翠。',126,'宋词/ci.song.14000.json','["云屏漫锁空山，寒猿啼断松枝翠。", "芝英安在，术苗已老，徒劳屐齿。", "应记洞中，凤箫锦瑟，镇常歌吹。", "怅苍苔路杳，石门信断，无人问、溪头事。", "回首暝烟无际，但纷纷、落花如泪。", "多情易老，青鸾何处，书成难寄。", "欲问双娥，翠蝉金凤，向谁娇媚。", "想分香旧恨，刘郎去后，一溪流水。"]'),
('song-ci-380','瑞鹤仙','葛长庚','宋','宋词','song-ci','瑞鹤仙','[]','残蟾明远照。',127,'宋词/ci.song.14000.json','["残蟾明远照。", "正一番霜讯，四山秋老。", "孤村带清晓。", "有鸣鞭归骑，乱林啼鸟。", "青帘缥缈。", "懒行时，持杯自笑。", "甚年来、破帽凋裘，惯得淡烟荒草。", "多少。", "客愁羁思，雨泊风餐，水边云杪。", "西窗正好。", "疏竹外，粉墙小。", "念归期相近，梦魂无奈，不为罗轻寒悄。", "怕无人、料理黄花，等闲过了。"]'),
('song-ci-381','瑞鹤仙','葛长庚','宋','宋词','song-ci','瑞鹤仙','[]','赋情多懒率。',127,'宋词/ci.song.14000.json','["赋情多懒率。", "每醉后疏狂，醒来瓢忽。", "无心恋簪祓。", "漫才高子建，韵欺王勃。", "胸中绝物。", "所容者、诗兵酒卒。", "一两时，调发将来，扫尽闷妖愁孽。", "莫说。", "杀人一万，自损三千，到底臲亶。", "悬河口讷。", "非夙世，无灵骨。", "把湖山牌印，莺花权柄，牒过清风朗月。", "且束之、高阁休休，这回更不。"]'),
('song-ci-382','祝英台近','葛长庚','宋','宋词','song-ci','祝英台近','[]','月如酥，天似玉，长啸弄孤影。',95,'宋词/ci.song.14000.json','["月如酥，天似玉，长啸弄孤影。", "十二楼台，昨梦暗寻省。", "自怜露满衣襟，风吹毛发，浑无寐、寒宵漏永。", "捧香鼎。", "翻起一片龙涎，梅花对人冷。", "庭户冰清，何处鹤声警。", "少时烛暗梧窗，烟生苔砌，晓钟动。", "忽然心醒。"]'),
('song-ci-383','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','二月一番雨，昨夜一声雷。',114,'宋词/ci.song.14000.json','["二月一番雨，昨夜一声雷。", "枪旗争展，建溪春色占先魁。", "采取枝头雀舌，带露和烟捣碎，炼作紫金堆。", "碾破香无限，飞起绿尘埃。", "汲新泉，烹活火，试将来。", "放下兔毫瓯子，滋味舌头回。", "唤醒青州从事，战退睡魔百万，梦不到阳台。", "两腋清风起，我欲上蓬莱。"]'),
('song-ci-384','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','渺渺烟霄风露冷，夜未艾、凉蟾似水。',119,'宋词/ci.song.14000.json','["渺渺烟霄风露冷，夜未艾、凉蟾似水。", "海山外、五云散彩，三峰凝翠。", "一鹤横空何缥缈，见殿阁、笙歌拥罗绮。", "笑劳生，空如尺鷃，恋槿花篱。", "於中青鸾唱美。", "丹鹤舞奇。", "有粉娥琼女，齐捧芳卮。", "天真皇人陈玳席，宴太姥，思之暗生悲。", "念如今，红尘满面，漫洒晚风泪。"]'),
('song-ci-385','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','十二楼台，但前回旧迹。',97,'宋词/ci.song.14000.json','["十二楼台，但前回旧迹。", "想琪花似雪，忘了还思。", "朝暮痴痴地。", "只有老天知。", "却自省、玉阶金砌。", "错抛离。", "梧桐声颤，窗外草蛩吟细。", "醉魂觉，又听秋鸿悲呖。", "极目寒空，叹未有紫云梯。", "绛阙消息子。", "也无一二、枉垂涕。"]'),
('song-ci-386','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','宝鸭温香，诉丝城寸意。',94,'宋词/ci.song.14000.json','["宝鸭温香，诉丝城寸意。", "记当年事，闷本愁基。", "人间天上，只争得那些儿。", "吃禁持。", "却念九霄风味。", "清晨雁字。", "一句句在天如在纸。", "只得向风前，默默自喈惜。", "业债俱消，还未了、甚时已。", "一日里。", "滴了俺儿来泪。"]'),
('song-ci-387','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','念我东皇大帝儿。',93,'宋词/ci.song.14000.json','["念我东皇大帝儿。", "是操觚弄翰之职。", "飞落尘寰，似此度，算应希。", "向这里。", "安能便、策景御气。", "灰头土面、千河水。", "把我如何洗。", "纵便有铢衣，已失眉峰翠。", "看看皓首，瞒不过镜台儿。", "除是去、青松下、碧云底。"]'),
('song-ci-388','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','弱水去蓬莱，四万八千里。',98,'宋词/ci.song.14000.json','["弱水去蓬莱，四万八千里。", "远漠漠，俯仰天水青无际。", "鸟飞不到船去难，渺无依。", "翦锦字。", "云信待凭鸾翼。", "青芝素瀑，草舍儿、隐隐烟霞里。", "向闲处，批风切月烹天地，三岛十洲，去有日，几何时。", "胎仙就，直待鹤书来至。"]'),
('song-ci-389','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','铜壶四水。',93,'宋词/ci.song.14000.json','["铜壶四水。", "寒生素被。", "夜迢迢，烟月熹微。", "池浸霜荷，槛竹响，井枫飞。", "宝枕潭无梦，念忡忡地。", "形留神往，镇日价、忘食应忘寐。", "省得起，都是天上仙家事。", "珠歌舞，酌玉液，饭云子。", "怎得麒麟脯，更教知味。"]'),
('song-ci-390','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','有个闷甚处，一向如痴醉。',96,'宋词/ci.song.14000.json','["有个闷甚处，一向如痴醉。", "独倚住危阑，坐咬无名指。", "金鱼玉雁一从去，绝消息。", "念念怀天帝。", "密与冥契。", "晴霞照水。", "叹细草新蒲寒萋萋。", "对夕照，树色烟光相紫翠。", "花落莺啼。", "把往事似川逝。", "光阴速，何时是伊归日。"]'),
('song-ci-391','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','雪牖风轩度岁。',88,'宋词/ci.song.14000.json','["雪牖风轩度岁。", "时听芭蕉，雨声凄恻。", "情多易感，渐不觉鬓成丝。", "忽又成千古，诮如梦里。", "西山南浦尽秋意。", "一望芦花飞。", "有一点沙鸥，点破松梢翠。", "凄然念起。", "觉两腋凉飙细。", "诗兴浑飞在渔乡橘里。"]'),
('song-ci-392','菊花新','葛长庚','宋','宋词','song-ci','菊花新','[]','忽水远天长，笑把玉龙嘶。',92,'宋词/ci.song.14000.json','["忽水远天长，笑把玉龙嘶。", "一声声，吹断寒云沧波里。", "幽愁暗恨，弄皓月，怨白日。", "问太虚不尚，则成休矣。", "云心鹤性，死也要冲霄，乘风去。", "分自有、终合仙飞。", "感古怀今聊把笔。", "落叶寒蝉悲。", "使人增怨抑。"]'),
('song-ci-393','菩萨蛮','葛长庚','宋','宋词','song-ci','菩萨蛮','[]','阁山云冷风萧瑟。',52,'宋词/ci.song.14000.json','["阁山云冷风萧瑟。", "野猿啼罢蟾光白。", "听彻太清弦。", "断肠云水天。", "金陵君此去。", "秋入蒹葭浦。", "兴满即回辕。", "明年二月春。"]'),
('song-ci-394','谒金门','葛长庚','宋','宋词','song-ci','谒金门','[]','春又去。',53,'宋词/ci.song.14000.json','["春又去。", "愁杀一声杜宇。", "昨夜海棠无□□。", "晓来闻燕语。", "缥缈佳人何处。", "镇日愁肠万缕。", "千里无家归未得，春风知我苦。"]'),
('song-ci-395','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','金液还丹诀，无中养就儿。',114,'宋词/ci.song.14000.json','["金液还丹诀，无中养就儿。", "别无他术，只要神水入华池。", "采取天真铅汞，片晌自然交媾，一点紫金脂。", "十月周天火，玉鼎产琼芝。", "你休痴，今说破，莫生疑。", "乾坤运用，大都不过坎和离。", "石里缘何怀玉，因甚珠藏蚌腹，借此显天机。", "何况妙中妙，未易与君知。"]'),
('song-ci-396','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','吃了几辛苦，学得这些儿。',114,'宋词/ci.song.14000.json','["吃了几辛苦，学得这些儿。", "蓬头赤脚，街头巷尾打无为。", "都没蓑衣笠子，多少风烟雨雪，便是活阿鼻。", "一具骷髅骨，忍尽万千饥。", "头不梳，面不洗，且憨痴。", "自家屋里，黄金满地有谁知。", "这里一声惭愧，那里一声调数，满面笑嘻嘻。", "白鹤青云上，记取这般时。"]'),
('song-ci-397','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','有一修行法，不用问师傅。',114,'宋词/ci.song.14000.json','["有一修行法，不用问师傅。", "教君只是，饥来吃饭困来眠。", "何必移精运气，也莫行功打坐，但去净心田。", "终日无思虑，便是活神仙。", "不憨痴，不狡诈，不风颠。", "随缘饮啄，算来命也付之天。", "万事不由计较，造物主张得好，凡百任天然。", "世味只如此，拚做几千年。"]'),
('song-ci-398','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','一个清闲客，无事挂心头。',114,'宋词/ci.song.14000.json','["一个清闲客，无事挂心头。", "包巾纸袄，单瓢只笠自逍遥。", "只把随身风月，便做自家受用，此外复何求。", "倒指两三载，行过百来州。", "百来州，云渺渺，水悠悠。", "水流云散，於今几度蓼花秋。", "一任乌飞兔走，我亦不知寒暑，万事总休休。", "问我金丹诀，石女跨泥牛。"]'),
('song-ci-399','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','不用寻神水，也莫问华池。',114,'宋词/ci.song.14000.json','["不用寻神水，也莫问华池。", "黄芽白雪，算来总是假名之。", "只这坤牛乾马，便是离龙坎虎，不必更猜疑。", "药物无斤两，火候不须时。", "偃月炉，朱砂鼎，总皆非。", "真铅真汞不炼，之炼要何为。", "自己金公奼女，渐渐打成一块。", "胎息象婴儿。", "不信张平叔，你更问他谁。"]'),
('song-ci-400','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','要做神仙去，工夫譬似闲。',114,'宋词/ci.song.14000.json','["要做神仙去，工夫譬似闲。", "一阳初动，玉炉起火炼还丹。", "捉住天魂地魄，不与龙腾虎跃，满鼎汞花乾。", "一任河车运，径路入泥丸。", "飞金精，采木液，过三关。", "金木间隔，如何上得玉京山。", "寻得曹溪路脉，便把华池神水，结就紫金团。", "免得饥寒了，天上即人间。"]'),
('song-ci-401','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','草涨一湖绿，天ぇ四山青。',114,'宋词/ci.song.14000.json','["草涨一湖绿，天ぇ四山青。", "这千年里，几多兴废不容声。", "无分貂金佩玉，不梦歌钟食鼎，何处有车旌。", "便念旌阳剑，枉自染蛟腥。", "生诸葛，少马援，尚云萍。", "醉乡日月，飘然身世付刘伶。", "知道东门黄犬，不似西山白鹭，风月了平生。", "起来忽清啸，惊落夜潭星。"]'),
('song-ci-402','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','杜宇伤春去，蝴蝶喜风清。',114,'宋词/ci.song.14000.json','["杜宇伤春去，蝴蝶喜风清。", "一犁梅雨，前村布谷正催耕。", "天际银蟾映水，谷口锦云横野，柳外乱蝉鸣。", "人在斜阳里，几点晚鸦声。", "采杨梅，摘卢橘，饤朱樱。", "奉陪诸友，今宵烂饮过三更。", "同入醉中天地，松竹森森翠幄，酣睡绿苔茵。", "起舞弄明月，天籁奏箫笙。"]'),
('song-ci-403','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','一个江湖客，万里水云身。',114,'宋词/ci.song.14000.json','["一个江湖客，万里水云身。", "鸟啼春去，烟光树色正黄昏。", "洞口寒泉漱石，岭外孤猿啸月，四顾寂无人。", "梦魂归碧落，泪眼看红尘。", "烟濛濛，风惨惨，暗消魂。", "南中诸友，而今何处问浮萍。", "青鸟不来松老，黄鹤何之石烂，叹世一伤神。", "回首南柯梦，静对北山云。"]'),
('song-ci-404','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','昔在虚皇府，被谪下人间。',114,'宋词/ci.song.14000.json','["昔在虚皇府，被谪下人间。", "笑骑白鹤，醉吹铁笛落星湾。", "十二玉楼无梦，三十六天夜静，花雨洒琅玕。", "瑶台归未得，忍听洞中猿。", "也休休，无情绪，炼金丹。", "从来天上，神仙官府更严难。", "翻忆三千神女，齐唱霓裳一曲，月里舞青鸾。", "此恨凭谁诉，云满武夷山。"]'),
('song-ci-405','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','昔在虚皇府，啸咏紫云中。',114,'宋词/ci.song.14000.json','["昔在虚皇府，啸咏紫云中。", "不知何事，误蒙天谪与公同。", "偶到金华洞口，忽见懒翁老子，挺挺众中龙。", "握手归仙隐，谈笑起天风。", "忽相逢，一转瞬，酒杯空。", "几时再会，唱赓词翰倒金锺。", "只恐武夷山里，千古猿啼鹤唳，未便蹑飞虹。", "公欲归仙去，我欲继公踪。"]'),
('song-ci-406','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','误触紫清帝，谪下汉山川。',114,'宋词/ci.song.14000.json','["误触紫清帝，谪下汉山川。", "既来尘世，奇奇怪怪被人嫌。", "懒去蓬莱三岛，且看江南风月，一住数千年。", "天风自霄汉，吹到剑峰前。", "做些诗，吃些酒，放些颠。", "木精石怪，时时唤作地行仙。", "朝隐四山猿鹤，夜枕一天星斗，纸被裹云眠。", "梦为蝴蝶去，依约在三天。"]'),
('song-ci-407','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','一叶飞何处，天地起西风。',114,'宋词/ci.song.14000.json','["一叶飞何处，天地起西风。", "夜来酒醒，月华千顷浸帘栊。", "塞外宾鸿来也，十里碧莲香满，泽国蓼花红。", "万象正萧爽，秋雨滴梧桐。", "钓台边，人把钓，兴何浓。", "吴江波上，烟寒水冷翦丹枫。", "光景暗中催去，览镜朱颜犹在，回首鹫巢空。", "铁笛一声晓，唤起玉渊龙。"]'),
('song-ci-408','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','江上春山远，山下暮云长。',114,'宋词/ci.song.14000.json','["江上春山远，山下暮云长。", "相留相送，时见双燕语风樯。", "满目飞花万点，回首故人千里，把酒沃愁肠。", "回雁峰前路，烟树正苍苍。", "漏声残，灯焰短，马蹄香。", "浮云飞絮，一身将影向潇湘。", "多少风前月下，迆逦天涯海角，魂梦亦凄凉。", "又是春将暮，无语对斜阳。"]'),
('song-ci-409','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','两鬓青丝发，双眼黑方瞳。',114,'宋词/ci.song.14000.json','["两鬓青丝发，双眼黑方瞳。", "人皆道是，昭庆一个老仙翁。", "暂别蓬莱弱水，自把星冠月帔，玉佩舞薰风。", "醉入桃源路，归去不知踪。", "举云璈，鸣铁笛，抚丝桐。", "满前剑弁森列，稽首捧金锺。", "挺挺松形鹤貌，任待桑田变海，宝鼎粒丹红。", "玉帝下明诏，独骑上瑶空。"]'),
('song-ci-410','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','忆昔秦时，中秋日、武夷九曲。',115,'宋词/ci.song.14000.json','["忆昔秦时，中秋日、武夷九曲。", "烟寂寂、斜阳数尺，寒鸦枯木。", "三十六峰凝晓翠，一溪流水生秋绿。", "正满林、桂子散天香，飞金粟。", "神仙客，金丹熟。", "玉诏下，云生足。", "岩头新换骨，尚粘红肉。", "夜半月华明似昼，玉皇降辇铺淆餗。", "笑曾孙、回首幔亭前，空松竹。"]'),
('song-ci-411','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','昨夜姮娥，游洞府、醉归天阙。',115,'宋词/ci.song.14000.json','["昨夜姮娥，游洞府、醉归天阙。", "缘底事、玉簪坠地，水神不说。", "持向水晶宫里去，晓来捧出将饶舌。", "被薰风、吹作满天香，谁分别。", "芳而润，清且洁。", "白似玉，寒於雪。", "想玉皇后苑，应无此物。", "只得赋诗空赏叹，教人不敢轻攀折。", "笑李粗、梅瘦不如他，真奇绝。"]'),
('song-ci-412','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','树色冥濛，山烟暮、鸟归日落。',115,'宋词/ci.song.14000.json','["树色冥濛，山烟暮、鸟归日落。", "凭阑处、眼空宇宙，心游碧落。", "古往今来天地里，人间那有扬州鹤。", "幸而今、天付与青山，甘寥寞。", "好花木，多岩壑。", "得萧散，耐淡泊。", "把他人比并，我还不错。", "一曲瑶琴知此意，从前心事都忘却。", "况新秋、不饮更何时，何时乐。"]'),
('song-ci-413','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','明日如今，我已是、天涯行客。',115,'宋词/ci.song.14000.json','["明日如今，我已是、天涯行客。", "相别后、麻姑山上，齐云亭侧。", "几个黄昏劳怅想，几宵皓月遥思忆。", "与二仙、不但此今生，皆畴昔。", "频到此，欢无极。", "今去也，来无的。", "念浪萍风絮，东西南北。", "七八年中相契密，三千里外来将息。", "怅金丹、未就玉天辽，还凄恻。"]'),
('song-ci-414','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','钧天高处，元自有、琼楼玉阙。',115,'宋词/ci.song.14000.json','["钧天高处，元自有、琼楼玉阙。", "又那更、九霞隐映，五云斗绝。", "八面玲珑光不夜，四围晃耀寒如月。", "有广寒、宫殿隐姮娥，冰壶洁。", "飘飘去，天风冽。", "星河外，花飞雪。", "见三千神女，尊前一阕。", "来到人间浑似梦，未能归去空悲咽。", "问仙都、此去几由旬，归心热。"]'),
('song-ci-415','满江红','葛长庚','宋','宋词','song-ci','满江红','[]','豆蔻丁香，待则甚、如今休也。',115,'宋词/ci.song.14000.json','["豆蔻丁香，待则甚、如今休也。", "争知道、本来面目，风光洒洒。", "底事到头鸾凤侣，不如躲脱鸳鸯社。", "好说与、几个正迷人，休嗟讶。", "纱窗外，梅花下。", "酒醒也，教人怕。", "把翠云翦却，缁衣披挂。", "柳翠已参弥勒了，赵州要勘台山话。", "想而今、心似白芙蕖，无人画。"]'),
('song-ci-416','摸鱼儿','葛长庚','宋','宋词','song-ci','摸鱼儿','[]','问苍江、旧盟鸥鹭。',140,'宋词/ci.song.14000.json','["问苍江、旧盟鸥鹭。", "年来景物谁主。", "悠悠客鬓知何似，吹满西风尘土。", "浑未悟。", "漫自许。", "功名谈笑侯千户。", "春衫戏舞。", "怕三径都荒，一犁未把，猿鹤笑君误。", "君且住。", "未必心期尽负。", "江山秋事如许。", "月明风静苹花路。", "敧枕试听鸣橹。", "还又去。", "道唤取。", "陶泓要草归来赋。", "相思最苦。", "是野水连天，渔榔四处，蓑笠占烟雨。"]'),
('song-ci-417','摸鱼儿','葛长庚','宋','宋词','song-ci','摸鱼儿','[]','雨肥梅、亭台初夏。',140,'宋词/ci.song.14000.json','["雨肥梅、亭台初夏。", "昙花开向前夜。", "纯阳鹤会先三日，何处神仙降驾。", "知得也。", "□□是、西山彭抗来胎化。", "平生性野。", "自倒指今年，七旬有六，使节半天下。", "焚金兽，毋惜满斟玉斝。", "儿孙况又潇洒。", "公今骨相如松在，一掬精神堪画。", "於今且。", "□□炼、金丹成了为凭藉。", "归心莲社。", "便做得乃翁，年登八百，未是寿长者。"]'),
('song-ci-418','摸鱼儿','葛长庚','宋','宋词','song-ci','摸鱼儿','[]','这身儿、从来业障。',140,'宋词/ci.song.14000.json','["这身儿、从来业障。", "一生空自劳攘。", "生生死死皆如梦，更莫别生妄想。", "没伎俩。", "只管去、天台雁荡寻方广。", "几人不省。", "被妻子萦缠，生涯拘束，甘自归黄壤。", "世间事，一斤两个八两。", "问谁能去俯仰。", "道义重了轻富贵，却笑输回来往。", "休勉强。", "老先生、从来恬淡无妆幌。", "一声长啸，把拄杖横肩，草鞋贴脚，四海平如掌。"]'),
('song-ci-419','摸鱼儿','葛长庚','宋','宋词','song-ci','摸鱼儿','[]','跨飞鸾、醉吹瑶笛，蓬莱知在何处。',140,'宋词/ci.song.14000.json','["跨飞鸾、醉吹瑶笛，蓬莱知在何处。", "薰风飘散荷花露。", "梦觉已非帝所，忘归路。", "谁知道、人间别有神仙侣。", "身游枢府。", "奈诏入玉楼，猛骑箕尾，四海忆霖雨。", "问王母。", "天上桃红几度。", "蕊宫今是谁主。", "明年甲子从头数，春入鬟云鬓雾。", "如今去。", "是处里、福田都著黄金布。", "庭前玉树。", "看子早生孙，孙还生子，岁岁彩衣舞。"]'),
('song-ci-420','洞仙歌','葛长庚','宋','宋词','song-ci','洞仙歌','[]','南枝漏泄，一点春光别。',103,'宋词/ci.song.14000.json','["南枝漏泄，一点春光别。", "无蝶无蜂正霜雪。", "向竹梢疏处，瘦影横斜，真个是、潇洒冰肌玉骨。", "黄昏人静，踏碎阶前月。", "忍冻相看惜攀折。", "巡檐空索笑，似笑无言，夜悄悄、仙入寒风清冽。", "更那堪、画角恼幽人，又满地落英，愁肠万结。"]'),
('song-ci-421','满庭芳','葛长庚','宋','宋词','song-ci','满庭芳','[]','百雉城边，乱花深处，竹间一笑双清。',118,'宋词/ci.song.14000.json','["百雉城边，乱花深处，竹间一笑双清。", "天公解事，为我弄阴晴。", "雨过槐阴绿净，女墙外、杨柳丝轻。", "堪嗟惜，诗尤酒殢，镜里失青春。", "清和，如许在，莺莺燕燕，相与忘情。", "谪仙风度，命代万人英。", "游戏琴棋书画，人间世、别有方瀛。", "酕醄后，玄裳效舞，所欠董双成。"]'),
('song-ci-422','瑶台月','葛长庚','宋','宋词','song-ci','瑶台月','[]','烟霄凝碧。',154,'宋词/ci.song.14000.json','["烟霄凝碧。", "问紫府清都，今夕何夕。", "桐阴下、幽情远，与秋无极。", "念陈迹、虎殿虬宫，记往事、龙箫凤笛。", "露华冷，蟾光白。", "云影净，天籁息。", "知得。", "是蓬莱不远，身无羽翼。", "广寒宫、舞彻霓裳，白玉台、歌罢瑶席。", "争不思下界，有人岑寂。", "羡博望、两泛仙槎，与曼倩、三偷蟠实。", "把丹鼎，暗融液。", "乘云气，醉挥斥。", "嗟惜。", "但城南老树，人谁我识。"]'),
('song-ci-423','永遇乐','葛长庚','宋','宋词','song-ci','永遇乐','[]','懒散家风，清虚活计，与君说破。',128,'宋词/ci.song.14000.json','["懒散家风，清虚活计，与君说破。", "淡酒三杯，浓茶一碗，静处乾坤大。", "倚藤临水，步屧登山，白日只随缘过。", "自归来，曲肱隐几，但祗恁和衣卧。", "柴扉草户，包巾纸袄，未必有人似我。", "我醉还歌，我歌且舞，一恁憨痴好。", "绿水青山，清风明月，自有人间仙岛。", "且偎随、补破遮寒，烧榾柮火。"]'),
('song-ci-424','永遇乐','葛长庚','宋','宋词','song-ci','永遇乐','[]','银月凄凉，绮霞明灭，秋色如此。',128,'宋词/ci.song.14000.json','["银月凄凉，绮霞明灭，秋色如此。", "露满清襟，风生衰鬓，夜已三更矣。", "寻思往事，千头万绪，回首诮如梦里。", "指烟霄，不如归去，不知今夕何夕。", "鹑衣百结，膱脂垢腻，犹是小蛮针指。", "对酒逢诗，高吟大笑，四海今谁似。", "荷亭竹阁，共风同月，此会今生能几。", "君须记，去来聚散，只□底是。"]'),
('song-ci-425','好事近','葛长庚','宋','宋词','song-ci','好事近','[]','行到竹林头，探得梅花消息。',53,'宋词/ci.song.14000.json','["行到竹林头，探得梅花消息。", "冷蕊疏英如许，更无人知得。", "冰枯雪老岁年徂，俯仰自嗟惜。", "醉卧梅花影里，有何人相识。"]'),
('song-ci-426','好事近','葛长庚','宋','宋词','song-ci','好事近','[]','何事雁来迟，独步秋园默默。',53,'宋词/ci.song.14000.json','["何事雁来迟，独步秋园默默。", "莫恨桂花开尽，有菊花堪惜。", "回头顾影背斜阳，听西风萧瑟。", "无限诗情酒思，那早梅知得。"]'),
('song-ci-427','桂枝香','葛长庚','宋','宋词','song-ci','桂枝香','[]','楼前凝望。',123,'宋词/ci.song.14000.json','["楼前凝望。", "见水满一溪，云满千嶂。", "将晚欲行无绪，欲眠无况。", "岩花涧草春无极，倚东风、忽然惆怅。", "淡烟飞过，幽禽叫断，远钟嘹亮。", "为底事、沈吟一晌。", "念只影飘浮，寸心虚旷。", "无限游丝落絮，此怀难状。", "江湖淮海行将遍，觉诗肠、酒胆超畅。", "一丘一壑归来，念我旧家天上。"]'),
('song-ci-428','南乡子','葛长庚','宋','宋词','song-ci','南乡子','[]','夜月照千峰。',66,'宋词/ci.song.14000.json','["夜月照千峰。", "影满荷池静袅风。", "明日今宵还感慨，梧桐。", "叶叶随云扬碧空。", "聚散与谁同。", "野鹤孤云有底踪。", "别处要知相忆处，无穷。", "总在青山夕照中。"]'),
('song-ci-429','南乡子','葛长庚','宋','宋词','song-ci','南乡子','[]','前度几相逢。',66,'宋词/ci.song.14000.json','["前度几相逢。", "此日游从乐不同。", "竹阁荷亭欢聚处，雍容。", "如在蓬莱第一宫。", "夜半月朦胧。", "秉烛东园风露中。", "明日匆匆还入浙，忡忡。", "却把音书寄远鸿。"]'),
('song-ci-430','霜天晓角','葛长庚','宋','宋词','song-ci','霜天晓角','[]','五羊安在。',53,'宋词/ci.song.14000.json','["五羊安在。", "城市何曾改。", "十万人家圜闠，东亦海、西亦海。", "年年蒲涧会。", "地接蓬莱界。", "老树知他一剑，千山外、万山外。"]'),
('song-ci-431','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','且尽杯中酒。',142,'宋词/ci.song.14000.json','["且尽杯中酒。", "问平生、湖海心期，更如君否。", "渭树江云多少恨，离合古今非偶。", "更风雨、十常八九。", "长铗歌弹明月堕，对萧萧、客鬓闲携手。", "还怕折，渡头柳。", "小楼夜久微凉透。", "倚危阑、一池倒影，半空星斗。", "此会明年知何处，苹未秋风未久。", "漫输与、鹭朋鸥友。", "已办扁舟松江去，与鲈鱼、莼菜论交旧。", "因念此，重回首。"]'),
('song-ci-432','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','梦绕荷花国。',142,'宋词/ci.song.14000.json','["梦绕荷花国。", "遍□□、橘州柳市，芙蓉巷陌。", "桂社兰乡白苹里，月冷波寒之夕。", "有孤鹜、落霞知得。", "一鹤横空云漠漠，见梅梢、万粒真珠滴。", "犹未把，寒香惜。", "画楼何处吹瑶笛。", "便□□、酥颦玉笑，露松霜瘠。", "姑射真人游紫府，下戏三江七泽。", "此莫是、冰魂雪魄。", "半逐风飞半随水，半在枝、半落苍苔白。", "酒醒后，晓窗碧。"]'),
('song-ci-433','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','是雨还堪拾。',142,'宋词/ci.song.14000.json','["是雨还堪拾。", "道非花、又从帘外，受风吹入。", "扑落梅梢穿度竹，恐是鲛人诉泣。", "积至暮、萤光熠熠。", "色映万山迷远近，满空浮、似片应如粒。", "忘炼得，我双睫。", "吟肩耸处飞来急。", "故撩人、粘衣噀袖，嫩香堪浥。", "细听疑无伊复有，贪看一行一立。", "见僧舍、茶烟飘湿。", "天女不知维摩事，漫三千、世界缤纷集。", "是翦水、谁能及。"]'),
('song-ci-434','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','晓雾须收霁。',142,'宋词/ci.song.14000.json','["晓雾须收霁。", "牡丹花、如人半醉，抬头不起。", "雪炼作冰冰作水。", "十朵未开三四。", "又加以、风禁雨制。", "□是东吴春色盛，尽移根、换叶分黄紫。", "所贵者，称姚魏。", "其间一种尤姝丽。", "似佳人、素罗裙在，碧罗衫底。", "中有一花边两蕊。", "恰似妆成小字。", "看不足、如何可比。", "白玉杯将青玉绿，据晴香、暖艳还如此。", "微笑道，有些是。"]'),
('song-ci-435','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','飞尽桃花片。',142,'宋词/ci.song.14000.json','["飞尽桃花片。", "倚东风、高吟大啸，开怀消遣。", "芍药牡丹开未遍。", "不道韶华如电。", "无心向、小庭幽院。", "秉烛夜游虽不倦，奈一番、风雨花容变。", "春去也，无人见。", "何处莺莺啼不断。", "探后园、红稀翠减，青稠绿满。", "蝶在花间犹死恋。", "早有行人摇扇。", "故自要、与春为饯。", "笑指白云归去好，对夕阳、泻酒凭谁荐。", "柳深处，有双燕。"]'),
('song-ci-436','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','谓是无情者。',142,'宋词/ci.song.14000.json','["谓是无情者。", "又如何、临歧欲别，泪珠如洒。", "此去兰舟双桨急，两岸秋山似画。", "况已是、芙蓉开也。", "小立西风杨柳岸，觉衣单、略说些些话。", "重把我，袖儿把。", "小词做了和愁写。", "送将归、要相思处，月明今夜。", "客里不堪仍送客，平昔交游亦寡。", "况惨惨、苍梧之野。", "未可凄凉休哽咽，更明朝、后日才方罢。", "却默默，斜阳下。"]'),
('song-ci-437','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','风雨今如此。',142,'宋词/ci.song.14000.json','["风雨今如此。", "问行人、如何有得，许多儿泪。", "为探木犀开也未，只有芙蓉而已。", "九十日、秋光能几。", "千里送人须一别，却思量、我了思量你。", "去则是，住则是。", "归归我亦行行矣。", "便行行、不须回首，也休萦系。", "一似天边双鸣雁，一个飞从东际。", "那一个、又飞西际。", "毕竟人生都是梦，再相逢、除是青霄里。", "却共饮，却共醉。"]'),
('song-ci-438','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','露白天如洗。',141,'宋词/ci.song.14000.json','["露白天如洗。", "淡烟轻、疏林映带，远山横翠。", "对此情怀成甚也，云断小楼风细。", "独倚遍、画阑十二。", "花馆云窗成憔悴。", "听宾鸿、天外声嘹唳。", "但不过，闷而已。", "房栊深静难成寐。", "夜迢迢、银台绛蜡，伴人垂泪。", "巴得暂时朦胧地。", "还又匆匆惊起。", "漫自展、云间锦字。", "往后各收千张纸。", "念梦劳魂役空凝睇。", "终不负，骖鸾志。"]'),
('song-ci-439','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','醉见千山面。',142,'宋词/ci.song.14000.json','["醉见千山面。", "晚晴初、蝉声未了，鸟声尤远。", "知道仙人丹灶在，尚有陈灰犹暖。", "但只恐、松枯石烂。", "笑问年华应不换，又如何、洞里笙箫断。", "还念我，去归晚。", "千岩万壑猿啼遍。", "一思量、一回懊恨，一回泪眼。", "岂是自家无仙骨，尚被红尘牵绊。", "要分此、烟霞一半。", "当日朱仙和葛老，更老黄、亦合同萧散。", "上帝近，永容懒。"]'),
('song-ci-440','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','仙鹊梁银汉。',140,'宋词/ci.song.14000.json','["仙鹊梁银汉。", "见青原白鹭一点，秋光犹嫩。", "青鸟密传云外信，王母夜临香案。", "与河鼓、天孙为伴。", "太素真人乘此景，到芗城、即嗣胡忠简。", "南极上，星璀璨。", "松溪居士多词翰。", "是神仙风骨，元自无心仕宦。", "人道月卿临总饷，便合机廷揆馆。", "还又爱、山林萧散。", "玉女金钟萦暖响，指灵椿、仙鹤祈遐算。", "公自有，青精饭。"]'),
('song-ci-441','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','倏又西风起。',141,'宋词/ci.song.14000.json','["倏又西风起。", "这一年光景，早过三分之二。", "燕去鸿来何日了，多少世间心事。", "待则甚、功成名遂。", "枫叶荻花动凉思，又寻思、江上琵琶泪。", "还感慨，劳梦寐。", "愁来长是朝朝醉。", "划地成、宋玉伤感，三闾憔悴。", "况是凄凉寸心碎。", "目断水苍山翠。", "更送客、长亭分袂。", "阁皂山前梧桐雨，起风樯、露舶无穷意。", "君此去，趁秋霁。"]'),
('song-ci-442','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','一别蓬莱馆。',141,'宋词/ci.song.14000.json','["一别蓬莱馆。", "看桑田成海，又见松枯石烂。", "目断虚皇无极处，安得殿头宣唤。", "指归路、钧天早晚。", "此去罡风三万里，但九霞、渺渺青云远。", "望不极，空泪眼。", "瑶池昔会群仙宴。", "此秋来、荻花枫叶，令人凄惋。", "满面朱尘那忍见，酒病花愁何限。", "知几度、春莺秋雁。", "从此飞神腾碧落，向清都、来往应无间。", "丹渐熟，骨将换。"]'),
('song-ci-443','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','遥想阳明洞。',141,'宋词/ci.song.14000.json','["遥想阳明洞。", "夜深时、猿啼鹤唳，露寒烟重。", "家在神霄归未得，十二玉楼无梦。", "梦里听、瑶琴三弄。", "醉卧长安人不识，晚秋天、此意西风共。", "黄金印，吾何用。", "云衢高策青鸾鞚。", "把天书玉篆，留与世人崇奉。", "垂手入廛长是醉，醉则从教懵懂。", "那些子、凝然不动。", "一剑行空神鬼惧，金粟儿、日向丹田种。", "把得稳，任放纵。"]'),
('song-ci-444','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','万顷湖光绿。',141,'宋词/ci.song.14000.json','["万顷湖光绿。", "是处里、芙蓉金盏，木犀金粟。", "鹢御飘飘行水谷，正是蟹香橙熟。", "山色似、风梳雨沐。", "携取阿娇命豪杰，过北山、疃处南山曲。", "寒烟淡，晴鸦浴。", "巨觥数引苍髭矗。", "便论诗说剑，人各有怀西北。", "两见西风客京国，多在红楼金屋。", "凝情处、落霞孤鹜。", "蒲柳凄凉今如许，问功名、志在何时足。", "更簪取，一枝菊。"]'),
('song-ci-445','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','极目神霄路。',142,'宋词/ci.song.14000.json','["极目神霄路。", "斗柄南、丹华翠景，红霞紫雾。", "手折琪花今似梦，十二楼台何处。", "犹记得、当时伴侣。", "东府西台知谁主，忆当时、自泻金瓶雨。", "人间事，等风絮。", "上皇赫赫雷霆主。", "我何缘、清都绛阙，遽成千古。", "白鹤青乌消息断，梦想鸾歌凤舞。", "应未得、翻身归去。", "业债须教还净尽，这一回、尝遍红尘苦。", "归举似，西王母。"]'),
('song-ci-446','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','昔在神霄府。',141,'宋词/ci.song.14000.json','["昔在神霄府。", "是上皇娇惜，便自酣歌醉舞。", "来此人间不知岁，仍是酒龙诗虎。", "做弄得、襟情如许。", "俯仰红尘几今古。", "算风灯、泡沫无凭处。", "即有这，烟霄路。", "淮山浙岸潇湘浦。", "一寻思、柳亭枫驿，泪珠溅俎。", "此去何时又相会，离恨萦人如缕。", "更天也、愁人风雨。", "语燕啼莺莫相管，请各家、占取闲亭坞。", "人事尽，天上去。"]'),
('song-ci-447','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','倚剑西湖道。',141,'宋词/ci.song.14000.json','["倚剑西湖道。", "望弥漫、苍葭绿苇，翠芜青草。", "华表凄凉市朝古，极目暗伤怀抱。", "秋色与、芰荷俱老。", "桂棹兰舟聊遣兴，仗金风、吹使芙蓉破。", "柳阴里，堪少坐。", "衷肠底事君知那。", "要繁弦急管，又且沈酣则个。", "烟水冥茫黄叶断，嘹唳数声雁过。", "醉归去、山寒云暮。", "整日消闲镇来往，问城南、老树知渠麽。", "黄鹤氅，青纱帽。"]'),
('song-ci-448','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','风送寒蟾影。',142,'宋词/ci.song.14000.json','["风送寒蟾影。", "望银河、一轮皎洁，宛如金饼。", "料得故人千里共，使我寸心耿耿。", "浑无奈、天长夜永。", "万树萧森猿啸罢，觉水边、林下非人境。", "睡不著，酒方醒。", "芙蓉池馆梧桐井。", "悄不知、今夕何夕，寒光万顷。", "年少风流多感慨，况此良辰美景。", "须对此、大拼酩酊。", "满目新寒舞黄落，嗟此身、何事如萍梗。", "桂花下，露华冷。"]'),
('song-ci-449','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','俯仰天粘水。',142,'宋词/ci.song.14000.json','["俯仰天粘水。", "尽□□、山河大地，光涵表里。", "一夜春风搜万象，檐外雨声不已。", "到晓来、六花靡靡。", "瑶树琪林寒彻骨，知谁家、娇女慵梳洗。", "且捏个，小狮子。", "琼楼架就东皇喜。", "□□使、玉龙战罢，柳绵飞起。", "千古佳人诗句在，一任如盐似米。", "君试看、岩头溪底。", "刹刹尘尘银世界，记当年、曾赴瑶池会。", "玉清境，还如此。"]'),
('song-ci-450','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','银汉千丝雨。',141,'宋词/ci.song.14000.json','["银汉千丝雨。", "被东风作恶，吹落满空柳絮。", "恰自江南消息断，才此六花飞舞。", "最好是、鹅毛鹤羽。", "万顷平田三尺玉，月明中、不见沙头鹭。", "苍烟里，一渔父。", "鹊桥半夜寒云妒。", "到晓来、千岩万壑，了无认处。", "极目四方银世界，五凤楼前如许。", "应自感、伤心凝伫。", "人在神霄玉清府，小狮儿、捏就无佳句。", "骑汗漫，好归去。"]'),
('song-ci-451','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','月插青螺髻。',142,'宋词/ci.song.14000.json','["月插青螺髻。", "柳梢头、夕阳荏苒，西风摇曳。", "数粒苍山粘远汉，树色烟光紫翠。", "飞骑气、半醒半醉。", "剑跨秋空磨星斗，指琼童、不得鸣金辔。", "恐惊动，紫清帝。", "浮云飞度蓬莱水。", "忆山中、松寒露冷，猿啼鹤唳。", "家在武夷岩谷里，一亩烟霞活计。", "叹拈指、人生百岁。", "兰畹芝田几今古，洞门前、小鹿衔花戏。", "不知有，人间世。"]'),
('song-ci-452','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','静看春容瘦。',142,'宋词/ci.song.14000.json','["静看春容瘦。", "未清明、荼䕷避席，蔷薇出昼。", "花里流莺骂桃李，似与东风管句。", "怕虚度、兰亭时候。", "我也别来天上夕，向年时、感叹湖山旧。", "旧日事，君知否。", "玉皇驾出清都晓。", "就御前、三千神女，指麾八九。", "化作花神下人世，如把粉团搦就。", "又一似、玉盘在手。", "莫是蕊珠亲付属，教小心、劝我杯儿酒。", "也只得，为陪笑。"]'),
('song-ci-453','贺新郎','葛长庚','宋','宋词','song-ci','贺新郎','[]','极目飙尘表。',141,'宋词/ci.song.14000.json','["极目飙尘表。", "醉酣时、楼中起舞，楼前舒啸。", "坐见四山烟雾散，是处落花啼鸟。", "忽惊下、九天星斗。", "双鹤飞来风露爽，一声声、清唳苍松杪。", "奈对景，不酾酒。", "旧家三点蓬莱小。", "有琼台双阙，长是香花缭绕。", "铁笛夜吹金剑吼，恨此瀛洲路杳。", "知几度、琪林春老。", "闲倚朱阑思昨梦，对江山、感慨无人晓。", "但千里，月华皎。"]'),
('song-ci-454','柳梢青','葛长庚','宋','宋词','song-ci','柳梢青','[]','一夜清寒，千红晓粲，春不曾知。',61,'宋词/ci.song.14000.json','["一夜清寒，千红晓粲，春不曾知。", "细看如何，醉时西子，睡底杨妃。", "尽皆蜀种垂丝。", "晴日暖、薰成锦围。", "说与东风，也须爱惜，且莫吹飞。"]'),
('song-ci-455','柳梢青','葛长庚','宋','宋词','song-ci','柳梢青','[]','鹤使南翔。',61,'宋词/ci.song.14000.json','["鹤使南翔。", "词珍翰绮，谊暖情香。", "如在琼台，梦回初饮，月液云浆。", "风吹芦叶冥茫。", "夕照外、山高水长。", "遥想东楼，琪花玉树，梅影昏黄。"]'),
('song-ci-456','柳梢青','葛长庚','宋','宋词','song-ci','柳梢青','[]','五马风流，销金帐暖，药玉船宽。',61,'宋词/ci.song.14000.json','["五马风流，销金帐暖，药玉船宽。", "放下荷囊，携来铜虎，又举熊幡。", "棠阴已接三山。", "此列郡、彼食大藩。", "柳雪萦旗，东风拦马，父老争看。"]'),
('song-ci-457','一剪梅・一翦梅','葛长庚','宋','宋词','song-ci','一剪梅・一翦梅','[]','剑倚青天笛倚楼。',72,'宋词/ci.song.14000.json','["剑倚青天笛倚楼。", "云影悠悠。", "鹤影悠悠。", "好同携手上瀛洲。", "身在阎浮。", "业在阎浮。", "一段红云绿树愁。", "今也休休。", "古也休休。", "夕阳西去水东流。", "富又何求。", "贵又何求。"]'),
('song-ci-458','虞美人','葛长庚','宋','宋词','song-ci','虞美人','[]','苹花零乱秋亭暮。',66,'宋词/ci.song.14000.json','["苹花零乱秋亭暮。", "篱落江村路。", "棹歌摇曳钓船归。", "搅碎清风千顷、碧琉璃。", "山衔初月明疏柳。", "平野垂星斗。", "莫辞沈醉伴孤吟。", "他日江南江北、两关心。"]'),
('song-ci-459','阮郎归','葛长庚','宋','宋词','song-ci','阮郎归','[]','淡烟凝翠锁寒芜。',56,'宋词/ci.song.14000.json','["淡烟凝翠锁寒芜。", "斜阳挂碧梧。", "沙头三两雁相呼。", "萧萧风卷芦。", "何处笛，一声孤。", "岸边人钓鱼。", "快帆一夜泊桐庐。", "问人沽酒无。"]'),
('song-ci-460','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','["\u8861\u5c71"]','思量世事，几千般翻覆，是非多少。',120,'宋词/ci.song.14000.json','["思量世事，几千般翻覆，是非多少。", "随分随缘天地里，心与江山不老。", "道在天先，神游物外，自有长生宝。", "洞门无锁，悄无一个人到。", "一条柱杖横肩，芒鞋紧峭，正风清月好。", "惊觉百年浑似梦，空被利名萦绕。", "野鹤纵横，孤云自在，对落花芳草。", "来朝拂袖，谁来南岳寻我。"]'),
('song-ci-461','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','孤村篱落，玉亭亭、为问何其清瘦。',120,'宋词/ci.song.14000.json','["孤村篱落，玉亭亭、为问何其清瘦。", "欲语还愁谁索笑，临水嫣然自照。", "甘受凄凉，不求识赏，风致何高妙。", "松挨竹拶，更堪霜雪僝僽。", "争奈终是冰肌，也过了几个，晴昏雨晓。", "冷艳寒香空自惜，后夜山高月小。", "满地苍苔，一声哀角，疏影归幽渺。", "世无和靖，三花两蕊不少。"]'),
('song-ci-462','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','当初误触，紫微君、谪下神霄玉府。',120,'宋词/ci.song.14000.json','["当初误触，紫微君、谪下神霄玉府。", "醉后骑龙吹铁笛，酒醒不知何处。", "绛阙寥寥，红尘扰扰，老泪滂如雨。", "人间天上，桑田沧海如许。", "遥想十二楼前，琪花开已遍，鸾歌鹤舞。", "梦到三天还又落，愁听空中箫鼓。", "独倚阑干，笑拈花片，细写思归字。", "东风还会，为伊吹上天去。"]'),
('song-ci-463','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','寄言天上，石麒麟、化作人间英物。',120,'宋词/ci.song.14000.json','["寄言天上，石麒麟、化作人间英物。", "醉拥诗兵驱笔阵，百万词锋退壁。", "世事空花，赏心泥絮，一点红炉雪。", "识时务者，当今惟有俊杰。", "我本浩气天成，才逢知已，便又清狂发。", "富贵於我如浮云，且看云生云灭。", "羊石论交，鹅湖惜别，别恨多於发。", "共君千里，登楼何患无月。"]'),
('song-ci-464','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','罗浮山下，正秋高气爽，凄凉风物。',120,'宋词/ci.song.14000.json','["罗浮山下，正秋高气爽，凄凉风物。", "瘦落丹枫飞紫翠，峭拔青山石壁。", "客鬓萧疏，诗肠清苦，病骨如冰雪。", "怒髯铁立，有怀不下三杰。", "袖里宝剑生寒，中宵起舞，引酒清歌发。", "襟曲屡兴猿鹤梦，坐看月痕生灭。", "露沁桃花，云笼芝草，任长莓苔发。", "如今话别，橙黄橘绿时月。"]'),
('song-ci-465','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','旧家宋玉，是何人、偏到秋来凄惨。',120,'宋词/ci.song.14000.json','["旧家宋玉，是何人、偏到秋来凄惨。", "细雨疏风天气冷，离别令人销黯。", "樯燕飞归，岸花吹送，自是生怀感。", "挑灯酌酒，平生明目张胆。", "二十年在江湖，枫亭柳驿，往事都曾览。", "胸次可吞云梦九，也没尘埃一糁。", "木落山高，云寒雁断，水瘦溪痕减。", "不知把菊，又在何处轩槛。"]'),
('song-ci-466','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','海天秋老，夜凄清、坐对香温金鸭。',120,'宋词/ci.song.14000.json','["海天秋老，夜凄清、坐对香温金鸭。", "听得寒蝉声断续，一似离歌相答。", "鸿雁初来，骅骝欲去，永夜烧红蜡。", "不须别酒，有时亦呷一呷。", "丈夫南北东西，何天不可，鸣剑雄开匣。", "岂特东湖徐孺子，下得陈蕃之榻。", "黄叶声乾，碧莲香减，枕上凉萧飒。", "出门一笑，四方风起云合。"]'),
('song-ci-467','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','道人於世，已忘情、尚更区区饯别。',120,'宋词/ci.song.14000.json','["道人於世，已忘情、尚更区区饯别。", "栖碧先生辞蕙帐，夜夜猿声凄切。", "剑上星寒，琴中风惨，眉宇飞黄色。", "一杯判袂，出门烟水空阔。", "我今流落江南，朝朝还暮暮，千愁万结。", "那更荻花枫叶景，又见长亭短驿。", "世事空花，人情风絮，山外云千叠。", "君还到阙，为言踪迹风雪。"]'),
('song-ci-468','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','桃花开尽，正溪南溪北，春风春雨。',120,'宋词/ci.song.14000.json','["桃花开尽，正溪南溪北，春风春雨。", "寒食清明都过了，愁杀一声杜宇。", "醉跨蹇驴，踏翻芳草，满满斟鹦鹉。", "游仙梦觉，不知身在何处。", "因甚青鸟不来，一年春事，拈指都如许。", "人在白云流水外，多少莺啼燕语。", "遣兴成诗，烹茶解酒，日落蔷薇坞。", "玉龙嘶断，乱鸦惊起无数。"]'),
('song-ci-469','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','["\u9ec4\u9e64\u697c"]','汉江北泻，下长淮、洗尽胸中今古。',120,'宋词/ci.song.14000.json','["汉江北泻，下长淮、洗尽胸中今古。", "楼橹横波征雁远，谁见鱼龙夜舞。", "鹦鹉洲云，凤凰池月，付与沙头鹭。", "功名何处，年年惟见春絮。", "非不豪似周瑜，壮如黄祖，亦随秋风度。", "野草闲花无限数，渺在西山南浦。", "黄鹤楼人，赤乌年事，江汉亭前路。", "浮萍无据，水天几度朝暮。"]'),
('song-ci-470','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','绿菏十里吐秋香，湖水掌平如镜。',119,'宋词/ci.song.14000.json','["绿菏十里吐秋香，湖水掌平如镜。", "日落云收天似洗，况又月明风静。", "露逼葭蒲，烟迷菱芡，缩尽寒鸦颈。", "两枝画桨，柳阴浓处乘兴。", "遥想和靖东坡，当年曾胜赏，一觞一咏。", "是则湖山常不老，前辈风流去尽。", "我兴还诗，我欢则酒，醉则还草圣。", "明朝却去，冷泉天竺双径。"]'),
('song-ci-471','促拍满路花','葛长庚','宋','宋词','song-ci','促拍满路花','[]','多才夸李白，美貌说潘安。',106,'宋词/ci.song.14000.json','["多才夸李白，美貌说潘安。", "一朝成万古，又徒闲。", "如何猛省，心地种仙蟠。", "堪叹人间事，泡沫风灯，阿谁肯做飞仙。", "莫思量、骏马与高轩。", "快乐任天然。", "最坚似松柏、更凋残。", "有何凭据，谁易复谁难。", "长啸青云外，自嗟自笑，了无恨海愁山。"]'),
('song-ci-472','行香子','葛长庚','宋','宋词','song-ci','行香子','[]','满洞苔钱。',83,'宋词/ci.song.14000.json','["满洞苔钱。", "买断风烟。", "笑桃花流落晴川。", "石楼高处，夜夜啼猿。", "看二更云，三更月，四更天。", "细草如毡。", "独枕空拳。", "与山糜、野鹿同眠。", "残霞未散，淡雾沈绵。", "是晋时人，唐时洞，汉时仙。"]'),
('song-ci-473','八六子','葛长庚','宋','宋词','song-ci','八六子','[]','倚危亭。',105,'宋词/ci.song.14000.json','["倚危亭。", "恨如芳草，萋萋划尽还生。", "念柳外青鸾去后，洞中白鹤归来，恍然暗惊。", "吾家渺在瑶京。", "夜月一帘花影，春风十里松鸣。", "奈昨梦、前尘渐随流水，凤箫歌杳，水长天远，那堪片片飞霞弄晚，丝丝细雨笼晴。", "正消凝。", "子规又啼数声。"]'),
('song-ci-474','汉宫春','葛长庚','宋','宋词','song-ci','汉宫春','[]','潇洒江梅，似玉妆珠缀，密蕊疏枝。',118,'宋词/ci.song.14000.json','["潇洒江梅，似玉妆珠缀，密蕊疏枝。", "霜风应是，不许蝶近蜂欺。", "嫣然自笑，与山矾、共水仙期。", "还亦有，青松翠竹，同今凛冽年时。", "何事向人如恨，带苍苔，半倚临水荒篱。", "孤山嫩寒放晓，尚忆前诗。", "黄昏顾影，说横斜、清浅今谁。", "他自是，移春手段，微云淡月应知。"]'),
('song-ci-475','卜算子','葛长庚','宋','宋词','song-ci','卜算子','[]','云散雨初晴，蝉噪林逾静。',52,'宋词/ci.song.14000.json','["云散雨初晴，蝉噪林逾静。", "古寺敲钟暮掩门，灯映琉璃影。", "浩气镇长存，昨梦还重省。", "独倚阑干啸一声，毛发萧萧冷。"]'),
('song-ci-476','卜算子','葛长庚','宋','宋词','song-ci','卜算子','[]','古寺枕空山，楼上昏钟静。',52,'宋词/ci.song.14000.json','["古寺枕空山，楼上昏钟静。", "饥鼠偷灯尾蘸油，悄悄无人影。", "长剑匣中鸣，今古深思省。", "此夕行藏独倚楼，风雨凄凄冷。"]'),
('song-ci-477','卜算子','葛长庚','宋','宋词','song-ci','卜算子','[]','渔火海边明，烟锁千山静。',52,'宋词/ci.song.14000.json','["渔火海边明，烟锁千山静。", "独坐僧窗夜未央，寂寞孤灯影。", "感慨辄兴怀，往事无人省。", "江汉飘浮二十年，一枕西风冷。"]'),
('song-ci-478','鹧鸪天','葛长庚','宋','宋词','song-ci','鹧鸪天','[]','雨过山花向晚香。',64,'宋词/ci.song.14000.json','["雨过山花向晚香。", "烟丝空翠柳微茫。", "旧家丹灶何人葛，今日帘泉阿姥黄。", "犀角枕，象牙床。", "椰心织簟昼生凉。", "杯行无算何曾醉，不觉罗浮日月长。"]'),
('song-ci-479','鹧鸪天','葛长庚','宋','宋词','song-ci','鹧鸪天','[]','西畔双松百尺长。',64,'宋词/ci.song.14000.json','["西畔双松百尺长。", "当时亲自见刘王。", "山前今日莲花水，往者将军洗马塘。", "南粤路，汉宫墙。", "晚风历历说兴亡。", "摩挲东晋苍苔灶，细说仙翁炼药方。"]'),
('song-ci-480','鹧鸪天','葛长庚','宋','宋词','song-ci','鹧鸪天','[]','翠幄张天见未曾。',64,'宋词/ci.song.14000.json','["翠幄张天见未曾。", "驼峰鹅掌出庖烹。", "醉酣浑是迷天地，但见尊前万点星。", "人似玉，酒如饧。", "果盘簇饤不知名。", "东风吹我三山下，如在神霄上帝庭。"]'),
('song-ci-481','蝶恋花','葛长庚','宋','宋词','song-ci','蝶恋花','[]','冷雨疏风凉漠漠。',70,'宋词/ci.song.14000.json','["冷雨疏风凉漠漠。", "云去云来，万里秋阴薄。", "笑倚玉阑呼白鹤。", "烟笼素月青天角。", "竹影松声浑似昨。", "醉胆如天，谁道词源涸。", "满地苍苔霜叶落。", "今宵不饮何时乐。"]'),
('song-ci-482','蝶恋花','葛长庚','宋','宋词','song-ci','蝶恋花','[]','绿暗红稀春已暮。',70,'宋词/ci.song.14000.json','["绿暗红稀春已暮。", "燕子衔泥，飞入谁家去。", "柳絮欲停风不住。", "杜鹃声里山无数。", "白马青衫无定据。", "好底林泉，信脚随缘寓。", "拼却此生心已许。", "一川风月聊为主。"]'),
('song-ci-483','蝶恋花','葛长庚','宋','宋词','song-ci','蝶恋花','[]','楼上风光都占断。',70,'宋词/ci.song.14000.json','["楼上风光都占断。", "楼下风光，还许诗人管。", "管领风光谁是伴。", "一堤杨柳开青眼。", "波面琉璃花影乱。", "玉笋持杯，画舸歌声颤。", "醉里寻春春不见。", "夕阳芳草连天远。"]'),
('song-ci-484','杨柳枝','葛长庚','宋','宋词','song-ci','杨柳枝','[]','挼碎梅花一断肠。',48,'宋词/ci.song.14000.json','["挼碎梅花一断肠。", "送斜阳。", "风烟缥缈月微茫。", "又昏黄。", "平野寒芜何处断，接天长。", "短篱浅水橘青黄。", "度清香。"]'),
('song-ci-485','沁园春','葛长庚','宋','宋词','song-ci','沁园春','[]','要做神仙，炼丹工夫，譬之似闲。',140,'宋词/ci.song.14000.json','["要做神仙，炼丹工夫，譬之似闲。", "耽姹女乘龙，金公御虎，玉炉火炽，土釜灰寒。", "铅里藏银，砂中取汞，神水华池上下间。", "山田内，有一条径路，直透泥丸。", "一声雷震崑山。", "真橐龠、飞冲夹脊关。", "见白雪漫天，黄芽满地，龟蛇缭绕，乌兔掀翻。", "自古乾坤，这些离坎，九转烹煎结大还。", "灵丹就，未飞升上阙，且在人寰。"]'),
('song-ci-486','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','土釜温温火，橐龠动春雷。',114,'宋词/ci.song.14000.json','["土釜温温火，橐龠动春雷。", "三田升降，一条径路属灵台。", "自有真龙真虎，和合天然铅汞，赤子结真胎。", "水里捉明月，心地觉花开。", "一转功，三十日，九旬来。", "抽添气候，炼成白血换骷骸。", "四象五形聚会，只在一方凝结，方寸绝纤埃。", "人在泥丸上，归路入蓬莱。"]'),
('song-ci-487','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','一个奇男子，万象落心胸。',114,'宋词/ci.song.14000.json','["一个奇男子，万象落心胸。", "学书学剑，两般都没个成功。", "要去披缁学佛，首下一拳轻快，打破太虚空。", "末后生华发，再拜玉清翁。", "二十年，空挫过，只飘蓬。", "这回归去，武夷山下第三峰。", "住我旧时庵子，碗水把柴升米，活火煮教浓。", "笑指归时路，弱水海之东。"]'),
('song-ci-488','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','苦苦谁知苦，难难也是难。',114,'宋词/ci.song.14000.json','["苦苦谁知苦，难难也是难。", "寻思访道，不知行过几重山。", "吃尽风﹀雨︽，那见霜凝雪冻，饥了又添寒。", "满眼无人问，何处扣玄关。", "好因缘，传口诀，炼金丹。", "街头巷尾，无言暗地自生欢。", "虽是蓬头垢面，今已九旬来地，尚且是童颜。", "未下飞升诏，且受这清闲。"]'),
('song-ci-489','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','天下云游客，气味偶相投。',114,'宋词/ci.song.14000.json','["天下云游客，气味偶相投。", "暂时相聚，忽然云散水空流。", "饱饫闽中风月，又爱浙间山水，杖屦且逍遥。", "太上包中下，只得个无忧。", "是和非，名与利，一时休。", "自家醒了，不成得恁地埋头。", "任是南州北郡，不问大张小李，过此便相留。", "且吃随缘饭，莫作俗人愁。"]'),
('song-ci-490','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','未遇明师者，日夜苦忧惊。',114,'宋词/ci.song.14000.json','["未遇明师者，日夜苦忧惊。", "及乎遇了，得些口诀又忘情。", "可惜蹉跎过了，不念精衰气竭，碌碌度平生。", "何不回头看，下手采来烹。", "天下人，知得者，不能行。", "可怜埋没，如何恁地不惺惺。", "只见口头说著，方寸都无些子，只管看丹经。", "地狱门开了，急急办前程。"]'),
('song-ci-491','水调歌头','葛长庚','宋','宋词','song-ci','水调歌头','[]','堪笑廛中客，都总是迷流。',114,'宋词/ci.song.14000.json','["堪笑廛中客，都总是迷流。", "冤家缠缚，算来不是你风流。", "不解去寻活路，只是担枷负锁，不肯放教休。", "三万六千日，受尽百年忧。", "得人身，休蹉过，急须修。", "乌飞兔走刹那，又是死临头。", "只这眼前快乐，难免无常两字，何似出尘囚。", "炼就金丹去，万劫自逍遥。"]'),
('song-ci-492','念奴娇','葛长庚','宋','宋词','song-ci','念奴娇','[]','广寒宫里，散天花、点点空中柳絮。',124,'宋词/ci.song.14000.json','["广寒宫里，散天花、点点空中柳絮。", "是处楼台皆似玉，半夜风声不住。", "万里盐城，千家珠瓦，无认蓬莱处。", "但呼童、且去探梅花，攀那树。", "垂帘未敢掀开，狮儿初捏就，佳人偷觑。", "溪畔渔翁蓑又重，几点沙鸥无语。", "竹折庭前，松僵路畔，满目都如许。", "问要晴，更待积痕消，须无雨。"]'),
('song-ci-493','满庭芳','葛长庚','宋','宋词','song-ci','满庭芳','[]','鼎用乾坤，药须乌兔，恁时方炼金丹。',119,'宋词/ci.song.14000.json','["鼎用乾坤，药须乌兔，恁时方炼金丹。", "水中虎吼，火里赤龙蟠。", "况是兑铅震汞，自元谷、上至泥丸。", "些儿事，坎离复垢，返老作童颜。", "五行，全四象，不调停火候，间断如闲。", "六天罡所指，玉出崑山。", "不动纤毫云雨，顷刻处、直透三关。", "黄庭内，一阳来复，丹就片时间。"]'),
('song-ci-494','满庭芳','葛长庚','宋','宋词','song-ci','满庭芳','[]','两种汞铅，黄婆感合，如如真虎真龙。',119,'宋词/ci.song.14000.json','["两种汞铅，黄婆感合，如如真虎真龙。", "周年造化，蹙在片时中。", "炉里温温种子，玄珠象、气透三宫。", "金木处，炼成赤水，白血自流通。", "无中。", "胎已兆，见龟蛇乌兔，恍惚相逢。", "但坎离既济，复垢交融。", "了得真空命脉，天地里、万物春风。", "阴阳外，天然夫妇，一点便成功。"]'),
('song-ci-495','酹江月・念奴娇','葛长庚','宋','宋词','song-ci','酹江月・念奴娇','[]','因看斗柄，运周天、顿悟神仙妙诀。',120,'宋词/ci.song.14000.json','["因看斗柄，运周天、顿悟神仙妙诀。", "一点真阳生坎位，点却离宫之缺。", "造物无声，水中起火，妙在虚危穴。", "今年冬至，梅花依旧凝雪。", "先圣此日闭关，不通来往，皆为群生设。", "物物□含生育意，正在子初亥末。", "自古乾坤，这些离坎，日日无休歇。", "如今识破，金乌飞入蟾窟。"]'),
('song-ci-496','珍珠帘・真珠帘','葛长庚','宋','宋词','song-ci','珍珠帘・真珠帘','[]','阴阳内感相交结。',120,'宋词/ci.song.14000.json','["阴阳内感相交结。", "有铅汞、分八卦罗列。", "金鼎炼黄芽，正一阳时节。", "子后午前方进火，向玉炉、烹成白雪。", "通彻。", "这玄关、深奥难轻泄。", "因师指诀幽微，把金丹大药，将来分说。", "捉住虎龙精，自然日月。", "造化天机人怎晓，换俗骨、永无魔折。", "超越。", "望仙都稽首，朝元金阙。"]'),
('song-ci-497','哨遍','刘克庄','宋','宋词','song-ci','哨遍','[]','胜处可宫，平处可田，泉土尤甘美。',247,'宋词/ci.song.14000.json','["胜处可宫，平处可田，泉土尤甘美。", "深复深，路绝住人稀。", "有人兮、盘旋於此。", "送子归。", "是他隐居求志。", "是要明主媒当世。", "嗟此意谁论，其言甚壮，孔颜犹有遗旨。", "大丈夫之被遇於时。", "入则坐庙朝出旗麾。", "列屋名姬，夹道武夫，满前才子。", "噫。", "有命存焉，吾非恶此而逃之。", "富贵人所欲，如之何、幸而致。", "向茂树堪休，清泉可濯，谷中别有闲天地。", "况脍细於丝，蕨甜似蜜，采於山，钓於水。", "大丈夫不遇之所为。", "唐处士、依稀是吾师。", "觉山林、尊如朝市。", "五侯门下宾客，扰扰趋形势。", "嗟盘之乐，谁争子所，占断千秋万岁。", "呼童秣马更膏车，便与君，从此逝矣。"]'),
('song-ci-498','六州歌头','刘克庄','宋','宋词','song-ci','六州歌头','[]','维摩病起，兀坐等枯株。',182,'宋词/ci.song.14000.json','["维摩病起，兀坐等枯株。", "清晨里，谁来问，是文殊。", "遣名姝。", "夺尽群花色，浴才出，酲初解，千万态，娇无力，困相扶。", "绝代佳人，不入金张室，却访吾庐。", "对茶铛禅榻，笑杀此翁臞。", "珠髻金壶。", "始消渠。", "忆承平日，繁华事，修成谱，写成图。", "奇绝甚，欧公记，蔡公书。", "古来无。", "一自京华隔，问姚魏、竟何如。", "多应是，彩云散，劫灰馀。", "野鹿衔将花去，休回首、河洛丘墟。", "漫伤春吊古，梦绕汉唐都。", "歌罢欷歔。"]'),
('song-ci-499','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','敕使竟空反，公不出梅关。',114,'宋词/ci.song.14000.json','["敕使竟空反，公不出梅关。", "当年玉座记忆，仄席问平安。", "羽扇尉佗城上，野服仙游阁下，辽鹤几时还。", "赖有蜀耆旧，健笔与书丹。", "青油士，珠履客，各凋残。", "四方蹙蹙靡骋，独此尚宽闲。", "丞相祠堂何处，太傅石碑堕泪，木老瀑泉寒。", "往者不可作，置酒且登山。"]'),
('song-ci-500','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','遣作岭头使，似戍玉门关。',114,'宋词/ci.song.14000.json','["遣作岭头使，似戍玉门关。", "来时送者，举酒珍重祝身安。", "街畔小儿拍笑，马上是翁矍铄，头与璧俱还。", "何处得仙诀，发白颊犹丹。", "屋茅破，篱菊瘦，架签残。", "老夫自计甚审，忙定不如闲。", "客难扬雄拓落，友笑王良来往，面汗背芒寒。", "再拜谢不敏，早晚乞还山。"]'),
('song-ci-501','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','老子颇更事，打透利名关。',114,'宋词/ci.song.14000.json','["老子颇更事，打透利名关。", "百年扰扰于役，何异入槐安。", "梦里偶然得意，醒后才堪发笑，蚁穴驾车还。", "恰佩南柯印，彷佛毂曾丹。", "客未散，日初昳，酒犹残。", "向来幻境安在，回首总成闲。", "莫问浮云起灭，且跨刚风游戏，露冷玉箫寒。", "寄语抱朴子，候我石楼山。"]'),
('song-ci-502','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','半世惯歧路，不怕唱阳关。',114,'宋词/ci.song.14000.json','["半世惯歧路，不怕唱阳关。", "朝来印绶解去，今夕枕初安。", "莫是散场优孟，又似下棚傀儡，脱了戏衫还。", "老去事多忘，公莫笑师丹。", "笔端花，胸中锦，两消残。", "江湖水草空旷，何必养天闲。", "久苦诸君共事，更尽一杯别酒，风露夜深寒。", "回首行乐地，明日隔云山。"]'),
('song-ci-503','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','落日几呼渡，佳夕每留关。',114,'宋词/ci.song.14000.json','["落日几呼渡，佳夕每留关。", "有时来照清浅，鬓云似潘安。", "一曲亲蒙君赐，两岸更无人迹，惟见鹭飞还。", "隙地欠栽接，蕉荔杂黄丹。", "柳全疏，松尚幼，怕摧残。", "旁人笑我痴计，管钥费防闲。", "翁意在乎林壑，客亦知夫水月，满腹贮清寒。", "赋咏差有愧，赤壁与滁山。"]'),
('song-ci-504','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','羯虏问周鼎，柱史出秦关。',114,'宋词/ci.song.14000.json','["羯虏问周鼎，柱史出秦关。", "苦求句漏，何意身世远差安。", "不见跕鸢堕水，时有飞鸿遵渚，乐此久忘还。", "采药寓言耳，胸次有灵丹。", "钓游处，榕叶暗，荻花残。", "自翁仙后千载，输与水鸥闲。", "我读内篇未竟，忽被急符驱去，洞闭白云寒。", "回首愧幽子，隐约海中山。"]'),
('song-ci-505','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','怪事广寒殿，此夕不开关。',114,'宋词/ci.song.14000.json','["怪事广寒殿，此夕不开关。", "林间乌鹊相贺，暂得一枝安。", "只在浮云深处，谁驾长风挟取，明镜忽飞还。", "玉兔呼不应，难觅臼中丹。", "酒行深，歌听彻，笛吹残。", "嫦娥老去孤另，离别匹如闲。", "待得银盘擎出，只怕玉峰醉倒，衰病不禁寒。", "卿去我欲睡，孤负此湖山。"]'),
('song-ci-506','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','老年有奇事，天放两中秋。',114,'宋词/ci.song.14000.json','["老年有奇事，天放两中秋。", "使君飞榭千尺，缥缈见麟洲。", "景物东徐城上，岁月北征诗里，圆缺几时休。", "俯仰慨今昔，惟酒可浇愁。", "风露高，河汉澹，素光流。", "贾胡野老相庆，四海十分收。", "竞看姮娥金镜，争信仙人玉斧，费了一番修。", "衰晚笔无力，谁伴赋黄楼。"]'),
('song-ci-507','水调歌头','刘克庄','宋','宋词','song-ci','水调歌头','[]','岁晚太玄草，深悔赋长杨。',114,'宋词/ci.song.14000.json','["岁晚太玄草，深悔赋长杨。", "向来户外之屦，已饱各飞扬。", "阁上青藜安在，院里金莲去矣，且爱短檠光。", "衰懒倦宾客，谁访老任棠。", "叹时人，怜黠小，笑鲐黄。", "汝曹变灭臭腐，侬底愈芬香。", "苦羡阿龙则甚，学取幼安亦可，坐穴几藜床。", "零落雁行小，敢不举君觞。"]'),
('song-ci-508','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','何处相逢，登宝钗楼，访铜雀台。',139,'宋词/ci.song.14000.json','["何处相逢，登宝钗楼，访铜雀台。", "唤厨人斫就，东溟鲸脍，圉人呈罢，西极龙媒。", "天下英雄，使君与操，馀子谁堪共酒杯。", "车千两，载燕南赵北，剑客奇才。", "饮酣画鼓如雷。", "谁信被晨鸡轻唤回。", "叹年光过尽，功名未立，书生老去，机会方来。", "使李将军，遇高皇帝，万户侯何足道哉。", "披衣起，但凄凉感旧，慷慨生哀。"]'),
('song-ci-509','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','岁暮天寒，一剑飘然，幅巾布裘。',139,'宋词/ci.song.14000.json','["岁暮天寒，一剑飘然，幅巾布裘。", "尽缘云鸟道，跻攀绝顶，拍天鲸浸，笑傲中流。", "畴昔奇君，紫髯铁面，生子当如孙仲谋。", "争知道，向中年犹未，建节封侯。", "南来万里何求。", "因感慨桥公成远游。", "叹名姬骏马，都成昨梦，只鸡斗酒，谁吊新丘。", "天地无情，功名有命，千古英雄只麽休。", "平生客，独羊昙一个，洒泪西州。"]'),
('song-ci-510','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','我羡君归，一路秋风，芙蓉木犀。',139,'宋词/ci.song.14000.json','["我羡君归，一路秋风，芙蓉木犀。", "想慈颜望久，灵乌乍噪，新眉画就，郎马频嘶。", "忙脱征衫，快呼斗酒，细为家人说建溪。", "争知道，这中年怀抱，最怕分携。", "丈夫南北东西。", "应笑杀离筵粉泪啼。", "怅佳人来未，碧云冉冉，王孙去后，芳草萋萋。", "明日相思，山重水复，古道人稀茅店鸡。", "元龙老，有高楼百尺，谁共登梯。"]'),
('song-ci-511','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','一卷阴符，二石硬弓，百斤宝刀。',139,'宋词/ci.song.14000.json','["一卷阴符，二石硬弓，百斤宝刀。", "更玉花骢喷，鸣鞭电抹，乌丝阑展，醉墨龙跳。", "牛角书生，虬髯豪客，谈笑皆堪折简招。", "依稀记，曾请缨系粤，草檄征辽。", "当年目视云霄。", "谁信道凄凉今折腰。", "怅燕然未勒，南归草草，长安不见，北望迢迢。", "老去胸中，有些磊块，歌罢犹须著酒浇。", "休休也，但帽边鬓改，镜里颜凋。"]'),
('song-ci-512','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','我梦见君，戴飞霞冠，著宫锦袍。',139,'宋词/ci.song.14000.json','["我梦见君，戴飞霞冠，著宫锦袍。", "与牧之高会，齐山诗酒，谪仙同载，采石风涛。", "万卷星罗，千篇电扫，肯学穷儿事楚骚。", "掀髯啸，有鱼龙鼓舞，狐兔悲嗥。", "英雄埋没蓬蒿。", "谁摸索当年刘与曹。", "叹事机易失，功名难偶，诛茅西崦，种秫东皋。", "栅有鸡豚，庭无羔雁，道是先生索价高。", "人间窄，待相期海上，共摘蟠桃。"]'),
('song-ci-513','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','有个头陀，形等枯株，心犹死灰。',139,'宋词/ci.song.14000.json','["有个头陀，形等枯株，心犹死灰。", "幸春山笋贱，无人争吃，夜炉芋美，与客同煨。", "何处旛花，忽相导引，莫是天宫迎赴斋。", "又疑道，向毗耶城里，讲席初开。", "这边尚自徘徊。", "笑那里纷纷早见猜。", "有尊神奋杵，拳粗似钵，名缁竖拂，喝猛如雷。", "老子无能，山僧不会，谁误檀那举请哉。", "山中去，便百千亿劫，休下山来。"]'),
('song-ci-514','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','我所思兮，延陵季子，别来九春。',139,'宋词/ci.song.14000.json','["我所思兮，延陵季子，别来九春。", "笑是非浮论，白衣苍狗，文章定价，秋月华星。", "独步岷峨，后身坡颍，何必荀家有二仁。", "中朝里，看叔兮衮斧，伯也丝纶。", "洛中曾识机云。", "记玉立堂堂九尺身。", "叹苕溪渔艇，幽人孤往，雁山马鬣，吊客谁经。", "宣室厘残，玄都花谢，回首旧游存几人。", "新腔美，堪洗空恩怨，唤起交情。"]'),
('song-ci-515','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','莫羡渠侬，白玉成楼，黄金筑台。',139,'宋词/ci.song.14000.json','["莫羡渠侬，白玉成楼，黄金筑台。", "也不消颠怪，骑驎被发，谁能委曲，令鸠为媒。", "鬓有二毛，袖闲双手，只了持螯与把杯。", "公过矣，赏陈登豪气，杜牧粗才。", "便烦问讯张雷。", "甚斗宿无光剑不回。", "想阁中鸣佩，时携客去，壁间悬榻，近有谁来。", "撤我虎皮，让君牛耳，谁道两贤相厄哉。", "中年后，向歌阑易感，乐极生哀。"]'),
('song-ci-516','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','辽鹤重来，不见繁华，只见凋残。',139,'宋词/ci.song.14000.json','["辽鹤重来，不见繁华，只见凋残。", "甚都无人咏，何郎诗句，也无人报，书记平安。", "闾里俱非，江山略是，纵有高楼莫倚栏。", "沈吟处，但萤飞草际，雁起芦间。", "不辞露宿风餐。", "怕万里归来双鬓斑。", "算这边赢得，黑貂裘敞，那边输了，翡翠衾寒。", "檄草流传，吟笺倚阁，开到琼花亦懒看。", "君记取，向中州差乐，塞地无欢。"]'),
('song-ci-517','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','华发萧萧，归碧鸡坊，出金马门。',139,'宋词/ci.song.14000.json','["华发萧萧，归碧鸡坊，出金马门。", "把一枝色笔，掷还郭璞，些儿残锦，回乞天孙。", "永免朝参，更无宣锁，送老三家水竹村。", "休休也，任巫阳来下，未易招魂。", "茅檐安得庖阍。", "倩便了沽来酒满樽。", "叹角巾东路，吾寻初服，上书北阙，子漫危言。", "漏院霜靴，火城雪辔，得似先生败絮温。", "安危事，付布衣融泰，鼎足膺蕃。"]'),
('song-ci-518','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','载籍以来，於宇宙间，有功者谁。',139,'宋词/ci.song.14000.json','["载籍以来，於宇宙间，有功者谁。", "自唐尧咨禹，水行由地，宗周微管，夏变为夷。", "谢傅棋边，莱公骰畔，淝水澶渊送捷旗。", "天不偶，生堂堂国老，真太平基。", "雅怀厌倦台司。", "新天子殷勤留帝师。", "向朝堂衮绣，万羊非泰，湖山绦褐，两鹤相随。", "寿过磻溪，德如淇澳，进了丹书作抑诗。", "蒯缑客，愿年年岁岁，来献新词。"]'),
('song-ci-519','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','驯於蹇驴，清於赐驹，我行尔从。',140,'宋词/ci.song.14000.json','["驯於蹇驴，清於赐驹，我行尔从。", "幸柴车堪驾，何惭韩众，药苗可采，长伴庞公。", "野涧泉甘，阳坡草暖，有柏叶松枝充短供。", "修梦想，去游灵囿沼，入望夷宫。", "与夸夺子争雄。", "生与死未知谁手中。", "况嗾獒者众，放麑人少，大将触网，小亦伤弓。", "风月和柔，山林深密，折角何如且养茸。", "二虫喜，各衔花拜跪，来寿樗翁。"]'),
('song-ci-520','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','剥啄谁欤，户外一宾，布衣麻鞋。',140,'宋词/ci.song.14000.json','["剥啄谁欤，户外一宾，布衣麻鞋。", "有舌端雄辨，机锋破的，袖中行卷，锦绣成堆。", "阍启上宾，侬观诸老，个主人公喜挽推。", "怎奈向，今十分衰飒，非昔形骸。", "阍言宾怒如雷。", "因底事朱门晏未开。", "假使汝主公，做他将相，懒迎揖客，紧闭翘材。", "病叟惭惶，尊官宁耐，待铁拐先生旋出来。", "宾性急，怀生毛名纸，兴尽而回。"]'),
('song-ci-521','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','老子衰颓，晚与亲朋，约法三章。',139,'宋词/ci.song.14000.json','["老子衰颓，晚与亲朋，约法三章。", "有谈除目者，勒回车马，谈时事者，麾出门墙。", "已挂衣冠，怕言轩冕，犯令先当举罚觞。", "书尺里，但平安二字，多少深长。", "溪翁苦未相忘。", "我今有双鱼烦寄将。", "道荒芜羞对，宫中莲烛，昏花难映，阁上藜光。", "闻庙瑟音，识关雎乱，诗学专门尽不妨。", "百年后，尚庶几申白，不数韦康。"]'),
('song-ci-522','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','天造梅花，有许孤高，有许芬芳。',139,'宋词/ci.song.14000.json','["天造梅花，有许孤高，有许芬芳。", "似湘娥凝望，敛君山黛，明妃远嫁，作汉宫妆。", "冷艳谁知，素标难亵，又似夷齐饿首阳。", "幽雅意，纵写之缣楮，未得毫芒。", "曾经诸老平章。", "只一个孤山说影香。", "便诏书存问，漫招处士，节旄落尽，早屈中郎。", "日暮天寒，山空月堕，茅舍清於白玉堂。", "宁淡杀，不敢凭羌笛，告诉凄凉。"]'),
('song-ci-523','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','畴昔遭逢，薰殿之琴，清庙之璋。',139,'宋词/ci.song.14000.json','["畴昔遭逢，薰殿之琴，清庙之璋。", "谢锦袍打扮，佯狂太白，黄冠结裹，老大知章。", "种杏仙人，看桃君子，得似篱边嗅晚香。", "从人笑，笑安车迎晚，只履归忙。", "后身定作班扬。", "彼撼树蚍蜉不自量。", "偶有时戏笔，官奴藏去，有时醉坠，宗武扶将。", "永别鹓鸾，已盟猿鹤，肯学周顒出草堂。", "从人笑，我韩公齿豁，张镐眉苍。"]'),
('song-ci-524','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','惭愧清朝，罢贡包茅，住发牙璋。',139,'宋词/ci.song.14000.json','["惭愧清朝，罢贡包茅，住发牙璋。", "便羊裘归去，难留严子，牛衣病卧，肯泣王章。", "畴昔忧天，如今怀土，田舍鸡肥社酒香。", "甘雨足，且免扶锄苦，免踏车忙。", "先生少拟荀扬。", "晚自觉才衰可斗量。", "甚都无白凤，飞来玄草，亦无紫气，下烛干将。", "待得新亭，倒持手版，何似抽还政事堂。", "荣与辱，算到头由我，不属苍苍。"]'),
('song-ci-525','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','吉梦维何，男子之祥，载弄之璋。',139,'宋词/ci.song.14000.json','["吉梦维何，男子之祥，载弄之璋。", "嗟我辰安在，斯文后死，力侔元气，手抉天章。", "学稼田荒，炼丹灶壤，稽首南华一瓣香。", "休休也，免王良友笑，屑往来忙。", "浮名斗挹箕扬。", "世岂有明珠百斛量。", "叹种来瑶草，年深未熟，挑成锦字，道远难将。", "迁转不行，形容尽变，盍改称呼号瞎堂。", "遗弓远，怆帝乡云白，禹会山苍。"]'),
('song-ci-526','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','余少之时，赋如仲宣，檄如孔璋。',139,'宋词/ci.song.14000.json','["余少之时，赋如仲宣，檄如孔璋。", "也曾观万舞，铺陈商颂，曾闻九奏，制作尧章。", "抖擞空囊，存留谏笏，犹带虚皇案畔香。", "今归矣，省听鸡骑马，趁早朝忙。", "榻前密启明扬。", "宰物者方持玉尺量。", "元未尝弃汝，自云耄及，无宁寿我，或者天将。", "富有图书，贫无钗泽，不似安昌列后堂。", "新腔好，任伊川看见，非亵穹苍。"]'),
('song-ci-527','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','昔卧龙公，北走曹瞒，西克刘璋。',139,'宋词/ci.song.14000.json','["昔卧龙公，北走曹瞒，西克刘璋。", "看沙头八阵，百神呵护，渭滨一表，三代文章。", "绝笑渠侬，平生奸伪，死未忘情履与香。", "筹笔处，遣子丹引去，仲达奔忙。", "纷纷跋扈飞扬。", "这老子高深未易量。", "但纶巾指授，关河震动，灵旗征讨，夷汉宾将。", "到得市朝，变为陵谷，千载烝尝丞相堂。", "锦城外，有啭鹂音好，古柏皮苍。"]'),
('song-ci-528','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','少工艺文，朱丝练弦，黄流在璋。',139,'宋词/ci.song.14000.json','["少工艺文，朱丝练弦，黄流在璋。", "值虞廷戛击，箫韶之乐，周王寿考，追琢其章。", "汾水雁飞，鼎湖龙远，魂返今无异域香。", "浮生短，更两轮屋角，来去荒忙。", "人言八十鹰扬。", "笑千岁如何尺捶量。", "但负图龟马，藏之为宝，舐丹鸡犬，去不能将。", "友鲁申公，师浮丘伯，尚可教书村学堂。", "投老泪，瞻越山紫翠，陵树青苍。"]'),
('song-ci-529','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','安得奇材，颈系单于，首提子璋。',139,'宋词/ci.song.14000.json','["安得奇材，颈系单于，首提子璋。", "便做些功业，胜穷措大，聚萤武子，吞凤君章。", "笑杀竖儒，错翻故纸，屈马何曾有艳香。", "榆塞外，恰枣红时候，想羽书忙。", "腰钱骑鹤维扬。", "分表事谁能预测量。", "叹防身一剑，壮图濩落，建侯万里，老境相将。", "读枕函书，宝家藏笏，免使他人笑弗堂。", "吾衰矣，虽尚存右臂，不解擎苍。"]'),
('song-ci-530','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','帝赐玄圭，臣妾潘衡，奴隶侯璋。',139,'宋词/ci.song.14000.json','["帝赐玄圭，臣妾潘衡，奴隶侯璋。", "因封还除目，见瞋鬼质，窜涂贽卷，取怨奇章。", "肯比寒儒，自夸秘宝，十袭庭邽寸许香。", "下岩石，要朝朝磨试，不论闲忙。", "何须狗监揄扬。", "这衡尺曾经圣手量。", "纵埋之地下，居然光怪，栖之梁上，亦恐偷将。", "蓬户无人，花村有犬，添几重茅覆野堂。", "交游少，约文房四友，泛浩摩苍。"]'),
('song-ci-531','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','历事三朝，觐而执圭，祭而裸璋。',139,'宋词/ci.song.14000.json','["历事三朝，觐而执圭，祭而裸璋。", "更宫莲引入，视淮南草，御屏录了，露会稽章。", "贪膜外荣，遗身后臭，晔也平生漫传香。", "颜发改，独丹基无恙，事在休忙。", "曹丘生莫游扬。", "这瞎汉还曾自配量。", "已化为胡蝶，穿花栩栩，懒陪鹓鹭，佩玉锵锵。", "机蹉面前，钟闻饭后，我上堂时众下堂。", "从前错，欲区区手援，天下黔苍。"]'),
('song-ci-532','沁园春','刘克庄','宋','宋词','song-ci','沁园春','[]','莫信人言，虺不如熊，瓦不如璋。',139,'宋词/ci.song.14000.json','["莫信人言，虺不如熊，瓦不如璋。", "为孟坚补史，班昭才学，中郎传业，蔡琰词章。", "尽洗铅华，亦无璎珞，犹带栴檀国里香。", "笑贫女，尚寒机轧轧，催嫁衣忙。", "好逑不数潘杨。", "占梦者曾言大秤量。", "待银河浪静，金针穿了，蓝桥路近，玉杵携将。", "倩似凝之，媲如道韫，帘卷燕飞王谢堂。", "恁时节，看孙皆朱紫，翁未皤苍。"]'),
('song-ci-533','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','青女初晴，向丑梢枯干，幻出妍姿。',118,'宋词/ci.song.14000.json','["青女初晴，向丑梢枯干，幻出妍姿。", "休烦苑史翦彩，别有神司。", "东皇太乙，敕瑶姬、淡傅胭脂。", "还似得、华清汤暖，薄绡半卸冰肌。", "应笑楚宫痴绝，略施朱则个，便妒蛾眉。", "唐人更无籍在，浪比红儿。", "祥云难聚，且丁宁、铁笛轻吹。", "拼醉倒，花间一霎，莫教绛雪离披。"]'),
('song-ci-534','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','多谢句芒，露十分春信，一种仙姿。',118,'宋词/ci.song.14000.json','["多谢句芒，露十分春信，一种仙姿。", "主人领客卜夜，也唤分司。", "天葩国艳，几曾烦、薄粉浓脂。", "微似有，酒潮玉颊，更无粟起香肌。", "犹记老婆年少，爱斜簪宝髻，浅印红眉。", "回头笑他桃杏，太赤些儿。", "而今零落，更禁当、多少风吹。", "君看取，梢头点滴，绝胜树下纷披。"]'),
('song-ci-535','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','酷爱名花，本不贪妖艳，惟赏幽姿。',118,'宋词/ci.song.14000.json','["酷爱名花，本不贪妖艳，惟赏幽姿。", "乌台旧案累汝，牵惹随司。", "冰层雪积，独伊家、点绛凝脂。", "应冷笑，海棠醉睡，牡丹未免丰肌。", "舞殿歌台此际，各新涂妆额，别画宫眉。", "那知有人淡泊，不识虫儿。", "春莺去也，玉参差、分付谁吹。", "空传得，暗香疏影，琐窗卷了还披。"]'),
('song-ci-536','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','墙角残红，恍徐娘虽老，尚有丰姿。',118,'宋词/ci.song.14000.json','["墙角残红，恍徐娘虽老，尚有丰姿。", "纷纶绛节导从，不要街司。", "随波万点，似阿房、漂出残脂。", "休懊恼，丹铅褪尽，本来冰雪为肌。", "老子平生心铁，被色香牵动，愁上双眉。", "且祝东风小缓，沥酒芒儿。", "道伊解冻，甚潘郎、鬓雪难吹。", "犹忆侍，钧天广宴，万红舞袖披披。"]'),
('song-ci-537','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','京辇相逢，忆茂陵临御，俱诣天官。',118,'宋词/ci.song.14000.json','["京辇相逢，忆茂陵临御，俱诣天官。", "绛纱玉斧咫尺，先引头班。", "桃花满观，与贞元、朝士同看。", "归骑晚，春城笳吹，冶游侵晓方还。", "回首龙髯何在，漫共谈前事，泪洒桥山。", "谁怜白头柱史，独出函关。", "君如春柳，到而今、也带苍颜。", "凭寄语，江州司马，琵瑟且止休弹。"]'),
('song-ci-538','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','老子今年，忽七旬加七，饱阅炎凉。',118,'宋词/ci.song.14000.json','["老子今年，忽七旬加七，饱阅炎凉。", "夜窗犹坐书案，点勘偏旁。", "浮荣膜外，这些儿、感谢苍苍。", "试看取，名园甲第，主人几个还乡。", "淇澳磻溪二叟，向王朝抑抑，牧野洋洋。", "申公被蒲轮算，来议明堂。", "平章前哲，驾青牛、去底差强。", "自櫽括，山歌送酒，不消假手长房。"]'),
('song-ci-539','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','此老先生，尚不留东阁，肯博西凉。',118,'宋词/ci.song.14000.json','["此老先生，尚不留东阁，肯博西凉。", "我侬争敢，来近思旷之旁。", "朱颜未改，绝胜如、蔡义张苍。", "元自有，安丹灶地，何须求白云乡。", "欲缀小词称寿，□譬如河伯，观海盳洋。", "遥知垂弧甲第，置酒华堂。", "且吟梁甫，谁管他、冶子田强。", "试问取，壶翁仙诀，几时传与君房。"]'),
('song-ci-540','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','吉语西来，已衮归行阙，册拜头厅。',118,'宋词/ci.song.14000.json','["吉语西来，已衮归行阙，册拜头厅。", "唐家岂可，一日轻去玄龄。", "洛英蜀客，老成人、几半朝廷。", "但管取，三边无警，活他百万生灵。", "槐第安排敕设，有藕如船大，有枣如瓶。", "瑶环瑜珥绕席，个个宁馨。", "一般奇特，中台星、拜老人星。", "谁知得，眉攒万国，华筵少醉多醒。"]'),
('song-ci-541','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','公似寒梅，向层冰积雪，越样清奇。',118,'宋词/ci.song.14000.json','["公似寒梅，向层冰积雪，越样清奇。", "仙溪前辈相望，可比方谁。", "百篇剀切，似君谟、又似当时。", "更正简，相君颛面，崇清老子庞眉。", "未可卷怀袖手，续平泉庄记，绿野堂诗。", "苦言譬如食榄，回味方思。", "嗣皇访落，怪鹤书、直恁来迟。", "烦借问，二童一马，几时入尉瞻仪。"]'),
('song-ci-542','汉宫春','刘克庄','宋','宋词','song-ci','汉宫春','[]','谢病归来，便文殊相问，懒下禅床。',118,'宋词/ci.song.14000.json','["谢病归来，便文殊相问，懒下禅床。", "雀罗晨有剥啄，颠倒衣裳。", "袖中贽卷，原夫辈、安敢争强。", "若不是，子期苗裔，也应通谱元常。", "村叟鸡鸣籁动，更休烦箫管，自协宫商。", "酒边唤回柳七，压倒秦郎。", "一觞一咏，老尚书、闲杀何妨。", "烦问讯，雪洲健否，别来莫有新腔。"]'),
('song-ci-543','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','绕篱寻菊，菊犹迟、舍北芙蓉浑未。',120,'宋词/ci.song.14000.json','["绕篱寻菊，菊犹迟、舍北芙蓉浑未。", "却是小山丛桂里，一夜天香飘坠。", "约束奴兵，丁宁稚子，莫扫青苔砌。", "风高露冷，倚栏疑匪人世。", "客有载酒过余，朗吟招隐，洗尽悲秋意。", "白发长官穷似虱，刚被天公调戏。", "遍地堆金，满空雨粟，不济渊明事。", "残英剩馥，明朝犹可同醉。"]'),
('song-ci-544','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','老夫白首，尚儿嬉、废圃一番料理。',120,'宋词/ci.song.14000.json','["老夫白首，尚儿嬉、废圃一番料理。", "餐饮落英并坠露，重把离骚拈起。", "野艳幽香，深黄浅白，占断西风里。", "飞来双蝶，绕丛欲去还止。", "尝试诠次群芳，梅花差可，伯仲之间耳。", "佛说诸天金色界，未必庄严如此。", "尚友灵均，定交元亮，结好天随子。", "篱边坡下，一杯聊泛霜蕊。"]'),
('song-ci-545','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','比如去岁前年，今朝差觉门庭静。',119,'宋词/ci.song.14000.json','["比如去岁前年，今朝差觉门庭静。", "玉轴锦标无一首，知道先生远佞。", "假使文殊，携诸菩萨，来问维摩病。", "无花堪散，亦无香积斋衬。", "回首雪浪惊心，黄茅过顶，瘴毒如炊甑。", "山鬼海神俱长者，饶得书生穷命。", "不慕飞仙，不贪成佛，不要钻天令。", "年年今日，白头母子家庆。"]'),
('song-ci-546','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','卯君来处，与眉州仙子，依稀同日。',120,'宋词/ci.song.14000.json','["卯君来处，与眉州仙子，依稀同日。", "一自前朝龚蔡后，颇觉壶山岑寂。", "谁料端平，继居遗补，复有斯人出。", "幅巾林下，姓名玉座长忆。", "须信谄语尤甘，忠言最苦，橄榄何如蜜。", "诸老萧疏星欲晓，留取南都铁壁。", "洛社自佳，镜湖虽好，莫问君王乞。", "年年岁岁，大家同做真率。"]'),
('song-ci-547','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','禁中张宴，苦留公、未许归寻初服。',120,'宋词/ci.song.14000.json','["禁中张宴，苦留公、未许归寻初服。", "千载君臣鱼有水，不比严光文叔。", "火德中天，客星一夕，草草聊同宿。", "重来凝碧，依然赓载相属。", "过眼夸夺纷纷，浮云野马，几度棋翻局。", "客话凤池三入事，洗耳湖光一曲。", "伯始泉荒，稚珪圃冷，占断西风菊。", "年年岁岁，金英常泛芳醁。"]'),
('song-ci-548','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','素馨茉莉，向炎天、别有一般标致。',120,'宋词/ci.song.14000.json','["素馨茉莉，向炎天、别有一般标致。", "淡妆绰约堪□□，导引海山大士。", "从者谁欤，青藜阁下，汉卯金之子。", "云阶月地，夜深凉意如水。", "客又疑这仙翁，唐玄都观里，咏桃花底。", "且赌樽前身见在，休管汉唐时事。", "坡颍归迟，机云发早，得似侬兄弟。", "屦来户外，但言二叟犹醉。"]'),
('song-ci-549','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','天风浩动，扫残暑、推上一轮圆魄。',120,'宋词/ci.song.14000.json','["天风浩动，扫残暑、推上一轮圆魄。", "爱举眉山公旧话，与客泛舟赤壁。", "一自奎星，去朝帝所，叹洞箫声息。", "空馀二赋，至今凄动金石。", "长记诗境平生，诗豪酒圣，亦自仙中谪。", "畴昔停桡追欢处，忍听邻人吹笛。", "董相林荒，贺公湖在，俯仰成陈迹。", "两翁已矣，年年孤负今夕。"]'),
('song-ci-550','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','少时独步词场，引弦百发无虚矢。',119,'宋词/ci.song.14000.json','["少时独步词场，引弦百发无虚矢。", "岁晚却蒙崑体力，世业工修鞋底。", "曾裂白麻，曾涂墨敕，谪堕俄徵起。", "鼎湖龙去，老臣何以堪此。", "回首当日遭逢，譬如春梦，误入华胥里。", "推枕黄粱犹未熟，封拜几王侯矣。", "似瓮中蛇，似蕉中鹿，又似槐中蚁。", "先人书在，尚堪追补遗史。"]'),
('song-ci-551','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','此翁双手，顿闲处、且把香篝笼袖。',120,'宋词/ci.song.14000.json','["此翁双手，顿闲处、且把香篝笼袖。", "西掖北门辞不要，肯要南柯太守。", "小小亭台，些些竹木，何必灵和柳。", "地行仙里，合推侬做班首。", "取次著绝交书，续归田录，谁掣先生肘。", "莫遣朝衣梅醭了，留祝南山之寿。", "苍妓上厅，老僧封院，得似樗庵叟。", "虚名身后，生前且一杯酒。"]'),
('song-ci-552','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','梦中忘却，已闲退、谏草犹藏怀袖。',121,'宋词/ci.song.14000.json','["梦中忘却，已闲退、谏草犹藏怀袖。", "文不会、铺张粉饰，武又安能战守。", "秃似葫芦，辣於姜桂，衰飒同蒲柳。", "没安顿处，不如归去丘首。", "岁晚筋力都非，任空花眩眼，枯杨生肘。", "客举前修三数个，待与刘君为寿。", "或号憨郎，或称钝汉，或自呼聱叟。", "一篇齐物，读时咽以卮酒。"]'),
('song-ci-553','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','戏衫抛了，下棚去、谁笑郭郎长袖。',120,'宋词/ci.song.14000.json','["戏衫抛了，下棚去、谁笑郭郎长袖。", "小小草庵无宝贝，何必神呵鬼守。", "黄奶篝灯，青奴拂榻，莫要他桃柳。", "客来问字，此翁高卧摇首。", "彷佛曾子当年，商歌满屋，衣不完衿肘。", "混沌若教休凿窍，巧历安知其寿。", "文叔故人，仲华几个，输与羊裘叟。", "浮生如寄，切身之物惟酒。"]'),
('song-ci-554','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','老逢初度，小儿女、盘问翁翁年纪。',122,'宋词/ci.song.14000.json','["老逢初度，小儿女、盘问翁翁年纪。", "屈指先贤，彷佛似，当日申公归邸。", "跛子形骸，瞎堂顶相，更折当门齿。", "麒麟阁上，定无人物如此。", "追忆太白知章，自骑鲸去后，酒徒无几。", "恶客相寻，道先生、清晓中酲慵起。", "不袖青蛇，不骑黄鹤，混迹红尘里。", "彭聃安在，吾师淇澳君子。"]'),
('song-ci-555','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','并游英俊，从头数、富贵消磨谁纪。',122,'宋词/ci.song.14000.json','["并游英俊，从头数、富贵消磨谁纪。", "道眼看来，叹人生如寄，家如旅邸。", "教婢羹藜，课奴种韭，聊诳残牙齿。", "草堂绵蕝，百年栖托於此。", "岁晚笔秃无花，探怀中残锦，翦裁馀几。", "腰脚顽麻，赐他灵寿杖，也难扶起。", "离绝交游，变更名姓，日暮空山里。", "老儋复出，不知谁氏之子。"]'),
('song-ci-556','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','四朝遗老，须眉白、巧历不知其纪。',121,'宋词/ci.song.14000.json','["四朝遗老，须眉白、巧历不知其纪。", "真唤九重为座主，肯谒侯门王邸。", "晚会耆英，未论爵德，乡曲无如齿。", "酒酣度曲，妙音久不闻此。", "堪叹化鹤重来，但累累华表，旧人存几。", "散尽黄金，留箧中团扇，怕秋风起。", "结绮歌阑，披香宴悄，放出深宫里。", "颠毛虽秃，尚堪封管城子。"]'),
('song-ci-557','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','太丘晚节，把家事、一切传他谌纪。',122,'宋词/ci.song.14000.json','["太丘晚节，把家事、一切传他谌纪。", "业已休休，又谁解露绶，会稽郡邸。", "张丈殷兄，阮生朱老，相与为唇齿。", "酒楼犹记，谪仙尝醉於此。", "一二耆旧贻书，新来强健否，问年今几。", "谢傅当时，却因个甚，抛了东山起。", "对局含嚬，闻筝堕泪，围在愁城里。", "吾评晋士，不如归去来子。"]'),
('song-ci-558','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','隆乾间事，两翁有、手泽遗编曾纪。',121,'宋词/ci.song.14000.json','["隆乾间事，两翁有、手泽遗编曾纪。", "余掌兰台修纂到，景定初开忠邸。", "抔起复麻，奋涂归笔，嚼碎张巡齿。", "德音犹在，非卿何足语此。", "老来兹事都休，问门前宾客，今朝来几。", "达汝空函，投伊大瓮内，谁曾提起。", "丹汞灰飞，黄粱炊熟，跳出槐宫里。", "儿童不识，秃翁定是谁子。"]'),
('song-ci-559','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','轮云世故，千万态、过眼谁能殚纪。',121,'宋词/ci.song.14000.json','["轮云世故，千万态、过眼谁能殚纪。", "只履携归消许急，日暮行人问邸。", "麝以脐灾，绒为尾累，焚象都因齿。", "后之览者，亦将有感於此。", "检点洛下同盟，萧疏甚，白发戴花人几。", "一觉齁齁，笑仆家越石，闻鸡而起。", "颜发俱非，头皮犹在，胜捉来官里。", "俗间俚耳，未曾闻这腔子。"]'),
('song-ci-560','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','自填曲子，自歌之、岂是行家官样。',120,'宋词/ci.song.14000.json','["自填曲子，自歌之、岂是行家官样。", "眼瞎背驼方引去，羞杀陈搏种放。", "摺起残编，寄声太乙，不必烦藜杖。", "陈人束阁，让他来者居上。", "安乐值几多钱，且幅巾绦褐，准云台象。", "长扇矮壶山南北，忘却晓随天仗。", "六逸七贤，五更三老，元不论资望。", "香山误矣，渔翁何减为相。"]'),
('song-ci-561','念奴娇','刘克庄','宋','宋词','song-ci','念奴娇','[]','小孙盘问翁翁，今朝怎不陈弧矢。',119,'宋词/ci.song.14000.json','["小孙盘问翁翁，今朝怎不陈弧矢。", "翁道暮年惟只眼，不比六根全底。", "常日谈玄，馀龄守黑，赤眚从何起。", "鬓须雪白，可堪委顿如此。", "心知病有根苗，短檠吹了，世界朦胧里。", "纵有金篦能去翳，不敢复囊萤矣。", "但愿从今，疾行如鹿，更细书如蚁。", "都无用处，留他教传麟史。"]'),
('song-ci-562','解连环','刘克庄','宋','宋词','song-ci','解连环','[]','旁人嘲我。',132,'宋词/ci.song.14000.json','["旁人嘲我。", "甚鬓毛都秃，齿牙频堕。", "不记是、何代何年，尽元祐熙宁，侬常喑麽。", "退下驴儿，今老矣、岂堪推磨。", "要挂冠神武，几番说了，这回真个。", "亲朋纷纷来贺。", "况弟兄对榻，儿女团坐。", "愿世世、相守茅檐，便宰相时来，二郎休作。", "白伫乌巾，谁信道、神仙曾过。", "拣人间、有松风处，曲肱高卧。"]'),
('song-ci-563','解连环','刘克庄','宋','宋词','song-ci','解连环','[]','揆余初度。',132,'宋词/ci.song.14000.json','["揆余初度。", "笑汝曹绯绿，乃翁苍素。", "一甲子、带水拖泥，今岁谢君恩，放还山去。", "政事堂中，把手版、分明抽付。", "向门前客道，老子出游，人不知处。", "小车万花引路。", "又谁能记得，观里千树。", "老冉冉、欢意阑珊，纵桃叶多情，难唤同渡。", "买只船儿，稳载取、笔床茶具。", "便芸瓜、一生一世，胜侯千户。"]'),
('song-ci-564','解连环','刘克庄','宋','宋词','song-ci','解连环','[]','悬弧之旦。',131,'宋词/ci.song.14000.json','["悬弧之旦。", "忆争骑竹马，各怀金弹。", "恨岁月、去我堂堂，向酒畔愁生，镜中颜换。", "灶壤丹飞，慢追悔、邺侯婚宦。", "已发心忏悔，免去猴冠，卸下麟楦。", "依稀仆家铁汉。", "虽未梢老寿，初节魔难。", "幸闻早、省了柳枝，更送了朝云，尘念俱断。", "丈室萧然，独病与、乐天相伴。", "但归依西方，拈起向来一瓣。"]'),
('song-ci-565','解连环','刘克庄','宋','宋词','song-ci','解连环','[]','左弧悬了。',132,'宋词/ci.song.14000.json','["左弧悬了。", "把柴门闩定，悄无人到。", "惭傀得、一二亲朋，□□□□□，温存枯槁。", "玉轴银钩，撺掇我、比磻溪老。", "乏琼琚可报，惟有声声，司马称好。", "卷收绒鞯锦袄。", "且行拾遗穗，醉藉芳草。", "做一个、物外闲人，省山重担擎，天大烦恼。", "昔似龙鸾，今踏飒、不惊鱼鸟。", "愿从兹、享回仙寿，准汾阳考。"]'),
('song-ci-566','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','瀛洲真学士，为底事、在红尘。',121,'宋词/ci.song.14000.json','["瀛洲真学士，为底事、在红尘。", "为语触宫围，沈香亭里，瞋谪仙人。", "为亲近君侧者，见万言策子惎刘蕡。", "为是尚方请剑，汉廷多惮朱云。", "君言往事勿重陈。", "且斗酒边身。", "也不会区区，算他甲子，记甚庚寅。", "尔曹譬如朝菌，又安知、老柏与灵椿。", "世上荣华难保，古来名节如新。"]'),
('song-ci-567','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','病翁将耳顺，牙齿落、鬓毛疏。',122,'宋词/ci.song.14000.json','["病翁将耳顺，牙齿落、鬓毛疏。", "也惭愧君恩，放还田舍，免诣公车。", "儿时某丘某水，到如今、老矣可樵渔。", "宝马华轩无分，蹇驴破帽如初。", "俘名箕斗竟成虚。", "磨折总因渠。", "帝锡余别号，江湖聱叟，山泽仙臞。", "樽前未宜感慨，事犹须、看岁晏何如。", "卫武耄年作戒，伏生九十传书。"]'),
('song-ci-568','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','古人吾不见，君莫是、郑当时。',121,'宋词/ci.song.14000.json','["古人吾不见，君莫是、郑当时。", "更筑就山房，躬耕谷口，名动京师。", "诸公任他衮衮，与杜陵野老共襟期。", "有客至门先喜，得钱沽酒何疑。", "昔年连辔柳边归。", "陈迹恍难追。", "况种桃道士，看花君子，回首皆非。", "相逢故人问讯，道刘郎、老去久无诗。", "把作一场春梦，觉来莫要寻思。"]'),
('song-ci-569','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','水亭凝望久，期不至、拟还差。',120,'宋词/ci.song.14000.json','["水亭凝望久，期不至、拟还差。", "隔翠幌银屏，新眉初画，半面犹遮。", "须臾淡烟薄霭，被西风扫不留些。", "失了白衣苍狗，夺回雪兔金蟆。", "乘云径到玉皇家。", "人世鼓三挝。", "试自判此生，更看几度，小住为佳。", "何须如钩似玦，便相将、只有半菱花。", "莫遣素娥知道，和他发也苍华。"]'),
('song-ci-570','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','海滨蓑笠叟，驼背曲、鹤形臞。',122,'宋词/ci.song.14000.json','["海滨蓑笠叟，驼背曲、鹤形臞。", "定不是凡人，古来贤哲，多隐於渔。", "任公子、龙伯氏，思量来岛大上钩鱼。", "又说巨鳌吞饵，牵翻员峤方壶。", "磻溪老子雪眉须。", "肘后有丹书。", "被西伯载归，营丘茅土，牧野檀车。", "世间久无是事，问苔矶、痴坐待谁欤。", "只怕先生渴睡，钓竿拂著珊瑚。"]'),
('song-ci-571','木兰花慢','刘克庄','宋','宋词','song-ci','木兰花慢','[]','郡人元未识，新太守、定何如。',121,'宋词/ci.song.14000.json','["郡人元未识，新太守、定何如。", "待说向诸贤，西桥人物，个个清臞。", "相将下车许久，但凝香之乐一些无。", "残漏几筹视事，浓油一盏观书。", "旁人徒见两轮朱。", "玉色未尝腴。", "有无穷阴骘，三农衣食，万衲钟鱼。", "尔侬迎新送旧，似君侯、清约更谁欤。", "欲举一杯寿酒，却愁破费兵厨。"]');
